/**
 * Purchase Return Detail API Route
 */

import { NextRequest } from 'next/server';
import { prisma } from '@/lib/prisma';
import { requireAuth, apiSuccess, apiError, apiNotFound } from '@/lib/api-utils';

type RouteParams = {
  params: Promise<{ systemId: string }>;
};

// GET - Get single purchase return
export async function GET(request: NextRequest, { params }: RouteParams) {
  const session = await requireAuth();
  if (!session) return apiError('Unauthorized', 401);

  try {
    const { systemId } = await params;

    const purchaseReturn = await prisma.purchaseReturn.findUnique({
      where: { systemId },
      include: {
        items: true,
        suppliers: true,
      },
    });

    if (!purchaseReturn) {
      return apiNotFound('PurchaseReturn');
    }

    return apiSuccess(purchaseReturn);
  } catch (error) {
    console.error('[Purchase Returns API] GET by ID error:', error);
    return apiError('Failed to fetch purchase return', 500);
  }
}

// PATCH - Update purchase return (approve/reject/update status)
export async function PATCH(request: NextRequest, { params }: RouteParams) {
  const session = await requireAuth();
  if (!session) return apiError('Unauthorized', 401);

  try {
    const { systemId } = await params;
    const body = await request.json();

    const { status, reason, approvalNotes, refundAmount, updatedBy } = body;

    // Get existing return
    const existingReturn = await prisma.purchaseReturn.findUnique({
      where: { systemId },
      include: { items: true, suppliers: true },
    });

    if (!existingReturn) {
      return apiNotFound('PurchaseReturn');
    }

    // Validate status transition
    const currentStatus = existingReturn.status;
    const _newStatus = status || currentStatus;

    // Define valid transitions
    const validTransitions: Record<string, string[]> = {
      DRAFT: ['PENDING', 'CANCELLED'],
      PENDING: ['APPROVED', 'CANCELLED'],
      APPROVED: ['COMPLETED', 'CANCELLED'],
      COMPLETED: [], // Cannot transition from completed
      CANCELLED: [], // Cannot transition from cancelled
    };

    if (
      status &&
      status !== currentStatus &&
      !validTransitions[currentStatus]?.includes(status)
    ) {
      return apiError(
        `Invalid status transition from ${currentStatus} to ${status}`,
        400
      );
    }

    // Perform update with transaction if status is changing to APPROVED or CANCELLED
    const purchaseReturn = await prisma.$transaction(async (tx) => {
      // Prepare update data
      const updateData: any = {
        updatedAt: new Date(),
        updatedBy: updatedBy || session.user?.id || null,
      };

      if (status !== undefined) updateData.status = status;
      if (reason !== undefined) updateData.reason = reason;
      if (refundAmount !== undefined) updateData.refundAmount = refundAmount;

      // Handle approval logic
      if (status === 'APPROVED' && currentStatus !== 'APPROVED') {
        // Approval processing already done during creation
        // Just update status and record who approved
        updateData.status = 'APPROVED';
      }

      // Handle cancellation logic
      if (status === 'CANCELLED' && currentStatus !== 'CANCELLED') {
        // Reverse inventory changes
        const returnItems = (existingReturn.returnItems as any) || [];
        for (const item of returnItems) {
          // Restore inventory
          if (existingReturn.branchSystemId) {
            await tx.productInventory.updateMany({
              where: {
                productId: item.productSystemId,
                branchId: existingReturn.branchSystemId,
              },
              data: {
                onHand: { increment: item.returnQuantity },
              },
            });
          }

          // Restore general inventory
          const inventory = await tx.inventory.findFirst({
            where: { productId: item.productSystemId },
          });

          if (inventory) {
            await tx.inventory.update({
              where: { systemId: inventory.systemId },
              data: {
                quantity: { increment: item.returnQuantity },
              },
            });
          }
        }

        // Reverse supplier balance
        if (Number(existingReturn.refundAmount) > 0) {
          await tx.supplier.update({
            where: { systemId: existingReturn.supplierId },
            data: {
              currentDebt: { increment: existingReturn.refundAmount },
              totalDebt: { increment: existingReturn.refundAmount },
            },
          });
        }
      }

      // Build activity history entry
      const activityEntry = {
        timestamp: new Date().toISOString(),
        action: status ? 'STATUS_UPDATED' : 'UPDATED',
        field: status ? 'status' : 'general',
        oldValue: currentStatus,
        newValue: status || currentStatus,
        userId: session.user?.id || null,
        userName: session.user?.name || 'System',
        description:
          approvalNotes ||
          (status === 'APPROVED'
            ? 'Purchase return approved'
            : status === 'CANCELLED'
            ? 'Purchase return cancelled'
            : 'Purchase return updated'),
      };

      // Append to existing activity history
      const existingHistory = (existingReturn.activityHistory as any) || [];
      updateData.activityHistory = [...existingHistory, activityEntry];

      // Perform update
      const updated = await tx.purchaseReturn.update({
        where: { systemId },
        data: updateData,
        include: {
          items: true,
          suppliers: true,
        },
      });

      return updated;
    });

    return apiSuccess(purchaseReturn);
  } catch (error) {
    console.error('[Purchase Returns API] PATCH error:', error);
    if (error instanceof Error) {
      return apiError(error.message, 500);
    }
    return apiError('Failed to update purchase return', 500);
  }
}

// DELETE - Delete purchase return (with inventory and supplier balance reversal)
export async function DELETE(request: NextRequest, { params }: RouteParams) {
  const session = await requireAuth();
  if (!session) return apiError('Unauthorized', 401);

  try {
    const { systemId } = await params;

    // Get return details for reversal
    const purchaseReturn = await prisma.purchaseReturn.findUnique({
      where: { systemId },
      include: { items: true },
    });

    if (!purchaseReturn) {
      return apiNotFound('PurchaseReturn');
    }

    // Only allow deletion if status is DRAFT or CANCELLED
    if (!['DRAFT', 'CANCELLED'].includes(purchaseReturn.status)) {
      return apiError(
        'Cannot delete purchase return with status ' + purchaseReturn.status,
        400
      );
    }

    await prisma.$transaction(async (tx) => {
      // If not cancelled, reverse the inventory and supplier balance changes
      if (purchaseReturn.status !== 'CANCELLED') {
        const returnItems = (purchaseReturn.returnItems as any) || [];

        // Restore inventory
        for (const item of returnItems) {
          if (purchaseReturn.branchSystemId) {
            await tx.productInventory.updateMany({
              where: {
                productId: item.productSystemId,
                branchId: purchaseReturn.branchSystemId,
              },
              data: {
                onHand: { increment: item.returnQuantity },
              },
            });
          }

          const inventory = await tx.inventory.findFirst({
            where: { productId: item.productSystemId },
          });

          if (inventory) {
            await tx.inventory.update({
              where: { systemId: inventory.systemId },
              data: {
                quantity: { increment: item.returnQuantity },
              },
            });
          }
        }

        // Restore supplier balance
        if (Number(purchaseReturn.refundAmount) > 0) {
          await tx.supplier.update({
            where: { systemId: purchaseReturn.supplierId },
            data: {
              currentDebt: { increment: purchaseReturn.refundAmount },
              totalDebt: { increment: purchaseReturn.refundAmount },
            },
          });
        }
      }

      // Delete items first (cascade should handle this, but being explicit)
      await tx.purchaseReturnItem.deleteMany({
        where: { returnId: systemId },
      });

      // Delete the return
      await tx.purchaseReturn.delete({
        where: { systemId },
      });
    });

    return apiSuccess({ success: true, message: 'Purchase return deleted' });
  } catch (error) {
    console.error('[Purchase Returns API] DELETE error:', error);
    if (error instanceof Error) {
      return apiError(error.message, 500);
    }
    return apiError('Failed to delete purchase return', 500);
  }
}

/**
 * Purchase Returns API Route
 * 
 * POST /api/purchase-returns - Create return with inventory/supplier balance updates
 * GET  /api/purchase-returns - List returns with advanced filtering
 * 
 * Business Logic:
 * - Validates purchase order and items exist
 * - Checks return quantities don't exceed received quantities  
 * - Creates return with atomic transaction:
 *   - Deducts inventory from warehouse
 *   - Updates supplier balance (debit for return)
 *   - Creates purchase return record
 *   - Updates purchase order return status
 * - Handles approval workflow (DRAFT → PENDING → APPROVED → COMPLETED)
 */

import { NextRequest } from 'next/server';
import { prisma } from '@/lib/prisma';
import type { Prisma } from '@/generated/prisma/client';
import { PurchaseReturnStatus } from '@/generated/prisma/client';
import { requireAuth, validateBody, apiSuccess, apiPaginated, apiError, parsePagination } from '@/lib/api-utils';
import { createPurchaseReturnSchema } from './validation';
import { generateIdWithPrefix } from '@/lib/id-generator';
import { v4 as uuidv4 } from 'uuid';

// Interface for purchase return item input
interface _PurchaseReturnItemInput {
  productSystemId: string;
  productId?: string;
  productName?: string;
  orderedQuantity?: number;
  returnQuantity: number;
  unitPrice: number;
  note?: string;
}

// GET - List purchase returns with advanced filtering
export async function GET(request: NextRequest) {
  const session = await requireAuth();
  if (!session) return apiError('Unauthorized', 401);

  try {
    const searchParams = request.nextUrl.searchParams;
    const { page, limit, skip } = parsePagination(searchParams);
    const search = searchParams.get('search') || '';
    const status = searchParams.get('status');
    const supplierId = searchParams.get('supplierId');
    const purchaseOrderId = searchParams.get('purchaseOrderId');
    const branchId = searchParams.get('branchId');
    const startDate = searchParams.get('startDate');
    const endDate = searchParams.get('endDate');

    const where: Prisma.PurchaseReturnWhereInput = {};
    
    if (search) {
      where.OR = [
        { id: { contains: search, mode: 'insensitive' } },
        { reason: { contains: search, mode: 'insensitive' } },
        { supplierName: { contains: search, mode: 'insensitive' } },
      ];
    }

    if (status) {
      where.status = status as PurchaseReturnStatus;
    }

    if (supplierId) {
      where.supplierId = supplierId;
    }

    if (purchaseOrderId) {
      where.purchaseOrderSystemId = purchaseOrderId;
    }

    if (branchId) {
      where.branchSystemId = branchId;
    }

    if (startDate || endDate) {
      where.returnDate = {};
      if (startDate) {
        where.returnDate.gte = new Date(startDate);
      }
      if (endDate) {
        where.returnDate.lte = new Date(endDate);
      }
    }

    const [data, total] = await Promise.all([
      prisma.purchaseReturn.findMany({
        where,
        skip,
        take: limit,
        orderBy: { createdAt: 'desc' },
        include: {
          items: true,
          suppliers: true,
        },
      }),
      prisma.purchaseReturn.count({ where }),
    ]);

    return apiPaginated(data, { page, limit, total });
  } catch (error) {
    console.error('[Purchase Returns API] GET error:', error);
    return apiError('Failed to fetch purchase returns', 500);
  }
}

// POST - Create new purchase return with inventory and supplier balance updates
export async function POST(request: NextRequest) {
  const session = await requireAuth();
  if (!session) return apiError('Unauthorized', 401);

  const result = await validateBody(request, createPurchaseReturnSchema);
  if (!result.success) return apiError(result.error, 400);

  try {
    const {
      purchaseOrderSystemId,
      reason,
      items,
      refundAmount,
      refundMethod,
      accountSystemId,
      branchSystemId,
    } = result.data;

    // Validate purchase order exists
    const purchaseOrder = await prisma.purchaseOrder.findUnique({
      where: { systemId: purchaseOrderSystemId },
      include: {
        supplier: true,
        items: {
          include: {
            product: {
              select: {
                systemId: true,
                id: true,
                name: true,
                unit: true,
              },
            },
          },
        },
      },
    });

    if (!purchaseOrder) {
      return apiError('Purchase order not found', 404);
    }

    // Validate return items
    if (!items || items.length === 0) {
      return apiError('At least one return item is required', 400);
    }

    for (const item of items) {
      if (item.returnQuantity <= 0) {
        return apiError('Return quantity must be greater than 0', 400);
      }

      const poItem = purchaseOrder.items.find(
        (poi) => poi.productId === item.productSystemId
      );

      if (!poItem) {
        return apiError(
          `Product ${item.productSystemId} not found in purchase order`,
          400
        );
      }

      // Check if return quantity exceeds ordered quantity
      if (item.returnQuantity > poItem.quantity) {
        return apiError(
          `Return quantity (${item.returnQuantity}) exceeds ordered quantity (${poItem.quantity}) for product ${poItem.product.name}`,
          400
        );
      }
    }

    // Calculate total return value
    const totalReturnValue = items.reduce(
      (sum, item) => sum + item.unitPrice * item.returnQuantity,
      0
    );

    // Validate refund amount
    const finalRefundAmount = refundAmount || 0;
    if (finalRefundAmount > totalReturnValue) {
      return apiError(
        'Refund amount cannot exceed total return value',
        400
      );
    }

    // Create purchase return with atomic transaction
    const purchaseReturn = await prisma.$transaction(async (tx) => {
      // Generate IDs
      const systemId = uuidv4();
      const businessId = await generateIdWithPrefix('TH', tx); // TH = Trả Hàng NCC

      // Get branch info if specified
      let branchName: string | undefined = undefined;
      if (branchSystemId) {
        const branch = await tx.branch.findUnique({
          where: { systemId: branchSystemId },
          select: { name: true },
        });
        branchName = branch?.name ?? undefined;
      }

      // Create purchase return record
      const newReturn = await tx.purchaseReturn.create({
        data: {
          systemId,
          id: businessId,
          supplierId: purchaseOrder.supplierId,
          supplierSystemId: purchaseOrder.supplierId,
          supplierName: purchaseOrder.supplier.name,
          purchaseOrderId: purchaseOrder.id,
          purchaseOrderSystemId: purchaseOrder.systemId,
          purchaseOrderBusinessId: purchaseOrder.id,
          branchId: branchSystemId || null,
          branchSystemId: branchSystemId || null,
          branchName: branchName,
          returnDate: new Date(),
          status: PurchaseReturnStatus.PENDING, // Start as PENDING for approval
          reason: reason || null,
          subtotal: totalReturnValue,
          total: totalReturnValue,
          totalReturnValue,
          refundAmount: finalRefundAmount,
          refundMethod: refundMethod || null,
          accountSystemId: accountSystemId || null,
          createdBy: session.user?.id || null,
          creatorName: session.user?.name || null,
          // Store items as JSON for flexible structure
          returnItems: items.map((item) => ({
            productSystemId: item.productSystemId,
            productId: item.productId || item.productSystemId,
            productName: item.productName || 'Unknown Product',
            orderedQuantity: item.orderedQuantity || 0,
            returnQuantity: item.returnQuantity,
            unitPrice: item.unitPrice,
            note: item.note || null,
          })),
          // Create individual item records for relational queries
          items: {
            create: items.map((item) => {
              const _poItem = purchaseOrder.items.find(
                (poi) => poi.productId === item.productSystemId
              );
              return {
                systemId: uuidv4(),
                productId: item.productSystemId,
                quantity: item.returnQuantity,
                unitPrice: item.unitPrice,
                total: item.unitPrice * item.returnQuantity,
                reason: item.note || reason || null,
              };
            }),
          },
        },
        include: {
          items: true,
          suppliers: true,
        },
      });

      // Update inventory - deduct returned quantities
      for (const item of items) {
        // Update product inventory for the branch
        if (branchSystemId) {
          await tx.productInventory.updateMany({
            where: {
              productId: item.productSystemId,
              branchId: branchSystemId,
            },
            data: {
              onHand: { decrement: item.returnQuantity },
            },
          });
        }

        // Update general inventory if exists
        const inventory = await tx.inventory.findFirst({
          where: { productId: item.productSystemId },
        });

        if (inventory) {
          await tx.inventory.update({
            where: { systemId: inventory.systemId },
            data: {
              quantity: { decrement: item.returnQuantity },
            },
          });
        }
      }

      // Update supplier balance - debit for return (they owe us)
      if (finalRefundAmount > 0) {
        await tx.supplier.update({
          where: { systemId: purchaseOrder.supplierId },
          data: {
            currentDebt: { decrement: finalRefundAmount }, // Reduce debt or increase credit
            totalDebt: { decrement: finalRefundAmount },
          },
        });
      }

      // Update purchase order return status
      // Calculate if this is partial or full return
      const totalOrdered = purchaseOrder.items.reduce(
        (sum, item) => sum + item.quantity,
        0
      );
      const totalReturned = items.reduce(
        (sum, item) => sum + item.returnQuantity,
        0
      );

      let returnStatus = 'Hoàn hàng một phần';
      if (totalReturned >= totalOrdered) {
        returnStatus = 'Hoàn hàng toàn bộ';
      }

      await tx.purchaseOrder.update({
        where: { systemId: purchaseOrder.systemId },
        data: {
          returnStatus: returnStatus as any,
        },
      });

      // Create activity history entry
      const activityEntry = {
        timestamp: new Date().toISOString(),
        action: 'CREATED',
        field: 'status',
        oldValue: null,
        newValue: 'PENDING',
        userId: session.user?.id || null,
        userName: session.user?.name || 'System',
        description: `Purchase return created for order ${purchaseOrder.id}`,
      };

      await tx.purchaseReturn.update({
        where: { systemId },
        data: {
          activityHistory: [activityEntry],
        },
      });

      return newReturn;
    });

    return apiSuccess(purchaseReturn, 201);
  } catch (error) {
    console.error('[Purchase Returns API] POST error:', error);
    if (error instanceof Error) {
      return apiError(error.message, 500);
    }
    return apiError('Failed to create purchase return', 500);
  }
}

/**
 * Sales Return Detail API Route
 * 
 * GET    /api/sales-returns/[systemId] - Get single sales return
 * PATCH  /api/sales-returns/[systemId] - Update sales return
 * DELETE /api/sales-returns/[systemId] - Delete sales return (soft/hard)
 */

import { NextRequest } from 'next/server';
import { prisma } from '@/lib/prisma';
import { SalesReturnStatus } from '@/generated/prisma/enums';
import { requireAuth, apiSuccess, apiError, apiNotFound } from '@/lib/api-utils';

type RouteParams = {
  params: Promise<{ systemId: string }>;
};

// GET - Get single sales return
export async function GET(request: NextRequest, { params }: RouteParams) {
  const session = await requireAuth();
  if (!session) return apiError('Unauthorized', 401);

  try {
    const { systemId } = await params;

    const salesReturn = await prisma.salesReturn.findUnique({
      where: { systemId },
      include: {
        items: true,
      },
    });

    if (!salesReturn) {
      return apiNotFound('SalesReturn');
    }

    return apiSuccess(salesReturn);
  } catch (error) {
    console.error('[Sales Returns API] GET by ID error:', error);
    return apiError('Failed to fetch sales return', 500);
  }
}

// PATCH - Update sales return (approve, reject, update status)
export async function PATCH(request: NextRequest, { params }: RouteParams) {
  const session = await requireAuth();
  if (!session) return apiError('Unauthorized', 401);

  try {
    const { systemId } = await params;
    const body = await request.json();

    const {
      status,
      refundMethod,
      refundAmount,
      reason,
      notes,
      approvalNotes,
      updatedBy,
      ..._otherFields
    } = body;

    // Fetch existing return to validate state transitions
    const existingReturn = await prisma.salesReturn.findUnique({
      where: { systemId },
      include: { items: true },
    });

    if (!existingReturn) {
      return apiNotFound('SalesReturn');
    }

    // Build update data - using inferred type
    const updateData: any = {
      updatedAt: new Date(),
      updatedBy: updatedBy || session.user?.id || null,
    };

    if (status !== undefined) {
      // Validate status transitions
      if (status === 'APPROVED' && existingReturn.status !== 'PENDING') {
        return apiError('Can only approve pending returns', 400);
      }
      if (status === 'REJECTED' && existingReturn.status !== 'PENDING') {
        return apiError('Can only reject pending returns', 400);
      }
      updateData.status = status as SalesReturnStatus;
    }

    if (refundMethod !== undefined) {
      updateData.refundMethod = refundMethod;
    }

    if (refundAmount !== undefined) {
      // Validate refund amount doesn't exceed return total
      if (refundAmount > Number(existingReturn.total)) {
        return apiError('Refund amount exceeds return total', 400);
      }
      updateData.refundAmount = refundAmount;
      updateData.refunded = refundAmount;
    }

    if (reason !== undefined) {
      updateData.reason = reason;
      updateData.note = reason;
    }

    if (notes !== undefined) {
      updateData.notes = notes;
    }

    if (approvalNotes !== undefined) {
      updateData.notes = approvalNotes;
    }

    const salesReturn = await prisma.salesReturn.update({
      where: { systemId },
      data: updateData,
      include: {
        items: true,
      },
    });

    return apiSuccess(salesReturn);
  } catch (error) {
    console.error('[Sales Returns API] PATCH error:', error);
    if (error instanceof Error) {
      return apiError(error.message, 500);
    }
    return apiError('Failed to update sales return', 500);
  }
}

// DELETE - Soft or hard delete sales return
export async function DELETE(request: NextRequest, { params }: RouteParams) {
  const session = await requireAuth();
  if (!session) return apiError('Unauthorized', 401);

  try {
    const { systemId } = await params;
    const body = await request.json().catch(() => ({}));
    const hard = body.hard === true;

    if (hard) {
      // First delete items
      await prisma.salesReturnItem.deleteMany({
        where: { returnId: systemId },
      });
      
      // Then delete return
      await prisma.salesReturn.delete({
        where: { systemId },
      });
    } else {
      // SalesReturn has no soft delete fields, use hard delete
      await prisma.salesReturnItem.deleteMany({
        where: { returnId: systemId },
      });
      
      await prisma.salesReturn.delete({
        where: { systemId },
      });
    }

    return apiSuccess({ success: true });
  } catch (error) {
    console.error('[Sales Returns API] DELETE error:', error);
    return apiError('Failed to delete sales return', 500);
  }
}

import { NextRequest } from 'next/server';
import { prisma } from '@/lib/prisma';
import { Prisma } from '@/generated/prisma/client';
import { requireAuth, validateBody, apiSuccess, apiError } from '@/lib/api-utils';
import { z } from 'zod';

const TYPE = 'pricing-policy';

const updatePricingPolicySchema = z.object({
  id: z.string().optional(),
  name: z.string().optional(),
  description: z.string().optional(),
  type: z.enum(['Nhập hàng', 'Bán hàng']).optional(),
  isDefault: z.boolean().optional(),
  isActive: z.boolean().optional(),
});

// GET - Get single pricing policy
export async function GET(
  _request: NextRequest,
  { params }: { params: Promise<{ systemid: string }> }
) {
  const session = await requireAuth();
  if (!session) return apiError('Unauthorized', 401);

  try {
    const { systemid } = await params;
    const setting = await prisma.settingsData.findFirst({
      where: { systemId: systemid, type: TYPE, isDeleted: false },
    });

    if (!setting) {
      return apiError('Pricing policy not found', 404);
    }

    return apiSuccess({
      systemId: setting.systemId,
      id: setting.id,
      name: setting.name,
      type: setting.type,
      description: setting.description,
      isDefault: setting.isDefault,
      isActive: setting.isActive,
      createdAt: setting.createdAt.toISOString(),
      updatedAt: setting.updatedAt.toISOString(),
      ...(setting.metadata as Record<string, unknown> || {}),
    });
  } catch (error) {
    console.error('[Pricing Policy API] GET error:', error);
    return apiError('Failed to fetch pricing policy', 500);
  }
}

// PATCH - Update pricing policy
export async function PATCH(
  request: NextRequest,
  { params }: { params: Promise<{ systemid: string }> }
) {
  const session = await requireAuth();
  if (!session) return apiError('Unauthorized', 401);

  const validation = await validateBody(request, updatePricingPolicySchema);
  if (!validation.success) {
    return apiError(validation.error, 400);
  }

  try {
    const { systemid } = await params;
    const existing = await prisma.settingsData.findFirst({
      where: { systemId: systemid, type: TYPE, isDeleted: false },
    });

    if (!existing) {
      return apiError('Pricing policy not found', 404);
    }

    const { id, name, description, type, isDefault, isActive } = validation.data;

    // If setting as default, unset other defaults of same type
    if (isDefault) {
      const policyType = type ?? (existing.metadata as any)?.type;
      await prisma.settingsData.updateMany({
        where: {
          systemId: { not: systemid },
          type: TYPE,
          isDeleted: false,
          metadata: {
            path: ['type'],
            equals: policyType,
          },
        },
        data: { isDefault: false },
      });
    }

    // Build update data
    const updateData: Prisma.SettingsDataUpdateInput = {
      updatedBy: session.user.id,
    };

    if (id !== undefined) updateData.id = id;
    if (name !== undefined) updateData.name = name;
    if (description !== undefined) updateData.description = description;
    if (isDefault !== undefined) updateData.isDefault = isDefault;
    if (isActive !== undefined) updateData.isActive = isActive;

    // Update metadata if type changed
    if (type !== undefined) {
      updateData.metadata = {
        ...(existing.metadata as Record<string, unknown> || {}),
        type,
      } as Prisma.InputJsonValue;
    }

    const updated = await prisma.settingsData.update({
      where: { systemId: systemid },
      data: updateData,
    });

    return apiSuccess({
      systemId: updated.systemId,
      id: updated.id,
      name: updated.name,
      type: updated.type,
      description: updated.description,
      isDefault: updated.isDefault,
      isActive: updated.isActive,
      createdAt: updated.createdAt.toISOString(),
      updatedAt: updated.updatedAt.toISOString(),
      ...(updated.metadata as Record<string, unknown> || {}),
    });
  } catch (error) {
    console.error('[Pricing Policy API] PATCH error:', error);
    return apiError('Failed to update pricing policy', 500);
  }
}

// DELETE - Delete pricing policy
export async function DELETE(
  _request: NextRequest,
  { params }: { params: Promise<{ systemid: string }> }
) {
  const session = await requireAuth();
  if (!session) return apiError('Unauthorized', 401);

  try {
    const { systemid } = await params;
    const existing = await prisma.settingsData.findFirst({
      where: { systemId: systemid, type: TYPE, isDeleted: false },
    });

    if (!existing) {
      return apiError('Pricing policy not found', 404);
    }

    // Soft delete
    await prisma.settingsData.update({
      where: { systemId: systemid },
      data: {
        isDeleted: true,
        deletedAt: new Date(),
        updatedBy: session.user.id,
      },
    });

    return apiSuccess({ message: 'Pricing policy deleted successfully' });
  } catch (error) {
    console.error('[Pricing Policy API] DELETE error:', error);
    return apiError('Failed to delete pricing policy', 500);
  }
}

import { NextRequest } from 'next/server';
import { prisma } from '@/lib/prisma';
import { requireAuth, apiSuccess, apiError } from '@/lib/api-utils';

const TYPE = 'pricing-policy';

// POST - Set as default pricing policy
export async function POST(
  _request: NextRequest,
  { params }: { params: Promise<{ systemid: string }> }
) {
  const session = await requireAuth();
  if (!session) return apiError('Unauthorized', 401);

  try {
    const { systemid } = await params;
    const setting = await prisma.settingsData.findFirst({
      where: { systemId: systemid, type: TYPE, isDeleted: false },
    });

    if (!setting) {
      return apiError('Pricing policy not found', 404);
    }

    const policyType = (setting.metadata as any)?.type;

    // Unset all other defaults of same type
    await prisma.settingsData.updateMany({
      where: {
        systemId: { not: systemid },
        type: TYPE,
        isDeleted: false,
        metadata: {
          path: ['type'],
          equals: policyType,
        },
      },
      data: { isDefault: false },
    });

    // Set this as default
    const updated = await prisma.settingsData.update({
      where: { systemId: systemid },
      data: {
        isDefault: true,
        updatedBy: session.user.id,
      },
    });

    return apiSuccess({
      systemId: updated.systemId,
      id: updated.id,
      name: updated.name,
      isDefault: updated.isDefault,
    });
  } catch (error) {
    console.error('[Pricing Policy API] Set default error:', error);
    return apiError('Failed to set default pricing policy', 500);
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { auth } from '@/auth';
import { prisma } from '@/lib/prisma';
import { z } from 'zod';

// Validation schema
const salesChannelSchema = z.object({
  id: z.string().optional(),
  name: z.string().min(1, 'Tên nguồn bán hàng không được để trống'),
  isApplied: z.boolean().optional().default(false),
  isDefault: z.boolean().optional().default(false),
});

// GET /api/settings/sales-channels
export async function GET(request: NextRequest) {
  try {
    const session = await auth();
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const { searchParams } = new URL(request.url);
    const page = parseInt(searchParams.get('page') || '1');
    const limit = parseInt(searchParams.get('limit') || '1000');
    const isAppliedParam = searchParams.get('isApplied');

    const where: any = {};
    if (isAppliedParam !== null) {
      where.isApplied = isAppliedParam === 'true';
    }

    const [data, total] = await Promise.all([
      prisma.salesChannel.findMany({
        where,
        skip: (page - 1) * limit,
        take: limit,
        orderBy: { name: 'asc' },
      }),
      prisma.salesChannel.count({ where }),
    ]);

    return NextResponse.json({
      data,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil(total / limit),
      },
    });
  } catch (error) {
    console.error('Error fetching sales channels:', error);
    return NextResponse.json(
      { error: 'Failed to fetch sales channels' },
      { status: 500 }
    );
  }
}

// POST /api/settings/sales-channels
export async function POST(request: NextRequest) {
  try {
    const session = await auth();
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const body = await request.json();
    const validatedData = salesChannelSchema.parse(body);

    // If setting as default, unset other defaults
    if (validatedData.isDefault) {
      await prisma.salesChannel.updateMany({
        where: { isDefault: true },
        data: { isDefault: false },
      });
    }

    const salesChannel = await prisma.salesChannel.create({
      data: {
        systemId: body.systemId || `SC_${Date.now()}`,
        id: validatedData.id || `SC${Date.now()}`,
        name: validatedData.name,
        isApplied: validatedData.isApplied,
        isDefault: validatedData.isDefault,
        createdAt: new Date(),
        updatedAt: new Date(),
      },
    });

    return NextResponse.json(salesChannel, { status: 201 });
  } catch (error) {
    if (error instanceof z.ZodError) {
      return NextResponse.json(
        { error: error.issues[0].message },
        { status: 400 }
      );
    }
    console.error('Error creating sales channel:', error);
    return NextResponse.json(
      { error: 'Failed to create sales channel' },
      { status: 500 }
    );
  }
}

