/**
 * GenericExportDialog V2
 * 
 * Enhanced export dialog with:
 * - Column selection with groups
 * - Scope options (all/filtered/current-page/selected)
 * - Export history logging
 * - File size estimation
 */

import * as React from "react"
import { Download, FileSpreadsheet, Loader2 } from "lucide-react"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "../ui/dialog"
import { Button } from "../ui/button"
import { Label } from "../ui/label"
import { RadioGroup, RadioGroupItem } from "../ui/radio-group"
import { Checkbox } from "../ui/checkbox"
import { ScrollArea } from "../ui/scroll-area"
import { Separator } from "../ui/separator"
import { Badge } from "../ui/badge"
// XLSX is lazy loaded in handleExport to reduce bundle size (~500KB)
import { toast } from "sonner"
import {
  type ImportExportConfig,
  type FieldConfig,
  transformExportRow,
  generateExportFileName,
} from '../../lib/import-export/index'
import type { SystemId } from "../../lib/id-types"
import { useActivePricingPolicies } from "../../features/settings/pricing/hooks/use-pricing"
import { useImportExportLogsMutations } from "../../lib/import-export/hooks/use-import-export-logs"

// ============================================
// TYPES
// ============================================

type ExportScope = 'all' | 'filtered' | 'current-page' | 'selected';

interface GenericExportDialogV2Props<T> {
  open: boolean
  onOpenChange: (open: boolean) => void
  
  // Configuration from ImportExportConfig
  config: ImportExportConfig<T>
  
  // Data sources
  allData: T[]
  filteredData: T[]       // After applying filters
  currentPageData: T[]    // Current page only
  selectedData: T[]       // Selected rows
  
  // Filters applied (for logging)
  appliedFilters?: Record<string, unknown>
  
  // Current user for logging
  currentUser: {
    name: string
    systemId: SystemId
  }
}

// ============================================
// COMPONENT
// ============================================

export function GenericExportDialogV2<T>({
  open,
  onOpenChange,
  config,
  allData,
  filteredData,
  currentPageData,
  selectedData,
  appliedFilters,
  currentUser,
}: GenericExportDialogV2Props<T>) {
  // React Query hooks
  const { data: pricingPoliciesData } = useActivePricingPolicies()
  const activePricingPolicies = React.useMemo(
    () => pricingPoliciesData?.filter(p => p.isActive) ?? [],
    [pricingPoliciesData]
  )
  const { addExport } = useImportExportLogsMutations()
  
  // State
  const [exportScope, setExportScope] = React.useState<ExportScope>('filtered')
  const [selectedColumns, setSelectedColumns] = React.useState<string[]>([])
  const [isExporting, setIsExporting] = React.useState(false)

  // Initialize selected columns from config (all non-hidden fields)
  React.useEffect(() => {
    if (open && selectedColumns.length === 0) {
      const defaultColumns = config.fields
        .filter(f => !f.hidden && f.exportable !== false)
        .map(f => f.key as string)
      setSelectedColumns(defaultColumns)
    }
  }, [open, config.fields, selectedColumns.length])

  // Reset scope when dialog opens
  React.useEffect(() => {
    if (open) {
      // Default to filtered if has filters, else all
      if (filteredData.length < allData.length) {
        setExportScope('filtered')
      } else if (selectedData.length > 0) {
        setExportScope('selected')
      } else {
        setExportScope('all')
      }
    }
  }, [open, allData.length, filteredData.length, selectedData.length])

  // Group fields by category
  const groupedFields = React.useMemo(() => {
    const groups: Record<string, FieldConfig<T>[]> = {}
    
    config.fields.forEach(field => {
      if (field.hidden || field.exportable === false) return
      
      const group = field.group || field.exportGroup || 'Khác'
      if (!groups[group]) {
        groups[group] = []
      }
      groups[group].push(field)
    })
    
    // ===== DYNAMIC PRICING COLUMNS (chỉ cho products) =====
    if (config.entityType === 'products') {
      if (activePricingPolicies.length > 0) {
        const pricingFields: FieldConfig<T>[] = activePricingPolicies.map(policy => ({
          key: `_price_${policy.systemId}` as keyof T & string,
          label: `Giá: ${policy.name}`,
          type: 'number' as const,
          exportGroup: 'Bảng giá',
          group: 'Bảng giá',
          // Custom transform to extract price from prices object
          exportTransform: (value: unknown, row?: T) => {
            const product = row as { prices?: Record<string, number> }
            return product?.prices?.[policy.systemId] ?? ''
          },
        }))
        groups['Bảng giá'] = pricingFields
      }
    }
    
    return groups
  }, [config.fields, config.entityType])

  // Exportable fields (non-hidden) - including dynamic pricing fields
  const exportableFields = React.useMemo(() => {
    const staticFields = config.fields.filter(f => !f.hidden && f.exportable !== false)
    
    // Add dynamic pricing fields for products
    if (config.entityType === 'products') {
      const pricingFields: FieldConfig<T>[] = activePricingPolicies.map(policy => ({
        key: `_price_${policy.systemId}` as keyof T & string,
        label: `Giá: ${policy.name}`,
        type: 'number' as const,
        exportGroup: 'Bảng giá',
        group: 'Bảng giá',
      }))
      return [...staticFields, ...pricingFields]
    }
    
    return staticFields
  }, [config.fields, config.entityType])

  // Data count by scope
  const getDataByScope = React.useCallback((scope: ExportScope): T[] => {
    switch (scope) {
      case 'all':
        return allData
      case 'filtered':
        return filteredData
      case 'current-page':
        return currentPageData
      case 'selected':
        return selectedData
    }
  }, [allData, filteredData, currentPageData, selectedData])

  const dataToExport = getDataByScope(exportScope)

  // ============================================
  // HANDLERS
  // ============================================

  const handleToggleColumn = (columnKey: string) => {
    setSelectedColumns(prev => 
      prev.includes(columnKey)
        ? prev.filter(k => k !== columnKey)
        : [...prev, columnKey]
    )
  }

  const handleToggleGroup = (groupFields: FieldConfig<T>[]) => {
    const groupKeys = groupFields.map(f => f.key as string)
    const allSelected = groupKeys.every(k => selectedColumns.includes(k))
    
    if (allSelected) {
      setSelectedColumns(prev => prev.filter(k => !groupKeys.includes(k)))
    } else {
      setSelectedColumns(prev => [...new Set([...prev, ...groupKeys])])
    }
  }

  const handleToggleAll = () => {
    if (selectedColumns.length === exportableFields.length) {
      setSelectedColumns([])
    } else {
      setSelectedColumns(exportableFields.map(f => f.key as string))
    }
  }

  const handleExport = async () => {
    if (selectedColumns.length === 0) {
      toast.error('Vui lòng chọn ít nhất 1 cột để xuất')
      return
    }

    if (dataToExport.length === 0) {
      toast.error('Không có dữ liệu để xuất')
      return
    }

    setIsExporting(true)

    try {
      // Get selected fields config (including dynamic pricing fields)
      const staticSelectedFields = config.fields.filter(f => 
        selectedColumns.includes(f.key as string)
      )
      
      // Add dynamic pricing fields for products (prepared but handled inline in transform)
      let _allSelectedFieldsFinal = [...staticSelectedFields]
      const selectedPriceColumns = selectedColumns.filter(k => k.startsWith('_price_'))
      
      if (config.entityType === 'products' && selectedPriceColumns.length > 0) {
        const pricingFields: FieldConfig<T>[] = selectedPriceColumns.map(colKey => {
          const systemId = colKey.replace('_price_', '')
          const policy = activePricingPolicies.find(p => p.systemId === systemId)
          return {
            key: colKey as keyof T & string,
            label: `Giá: ${policy?.name || systemId}`,
            type: 'number' as const,
            exportGroup: 'Bảng giá',
          }
        })
        _allSelectedFieldsFinal = [..._allSelectedFieldsFinal, ...pricingFields]
      }

      // Transform data (with special handling for pricing columns)
      const transformedData = dataToExport.map(item => {
        const row = transformExportRow(item, staticSelectedFields)
        
        // Add pricing columns for products
        if (config.entityType === 'products' && selectedPriceColumns.length > 0) {
          const product = item as { prices?: Record<string, number> }
          
          selectedPriceColumns.forEach(colKey => {
            const systemId = colKey.replace('_price_', '')
            const policy = activePricingPolicies.find(p => p.systemId === systemId)
            const label = `Giá: ${policy?.name || systemId}`
            row[label] = product?.prices?.[systemId] ?? ''
          })
        }
        
        return row
      })

      // Lazy load XLSX to reduce bundle size (~500KB)
      const XLSX = await import('xlsx')

      // Create workbook
      const ws = XLSX.utils.json_to_sheet(transformedData)
      const wb = XLSX.utils.book_new()
      XLSX.utils.book_append_sheet(wb, ws, 'Data')

      // Auto-size columns
      const maxWidth = 50
      const colWidths = Object.keys(transformedData[0] || {}).map(key => ({
        wch: Math.min(
          maxWidth,
          Math.max(
            key.length + 2,
            ...transformedData.slice(0, 100).map(row => String(row[key] || '').length)
          )
        )
      }))
      ws['!cols'] = colWidths

      // Generate filename
      const fileName = generateExportFileName(config.entityType, exportScope)

      // Write file and get blob for size
      const wbout = XLSX.write(wb, { bookType: 'xlsx', type: 'array' })
      const blob = new Blob([wbout], { type: 'application/octet-stream' })
      
      // Download
      const url = URL.createObjectURL(blob)
      const link = document.createElement('a')
      link.href = url
      link.download = fileName
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      URL.revokeObjectURL(url)

      // Log export
      await addExport.mutateAsync({
        entityType: config.entityType,
        entityDisplayName: config.entityDisplayName,
        fileName,
        fileSize: blob.size,
        totalRows: dataToExport.length,
        scope: exportScope,
        columnsExported: selectedColumns,
        filters: appliedFilters,
        performedBy: currentUser.name,
        performedById: currentUser.systemId,
        performedAt: new Date().toISOString(),
        status: 'success',
      })

      toast.success('Xuất file thành công', {
        description: `Đã xuất ${dataToExport.length} ${config.entityDisplayName}`
      })
      
      onOpenChange(false)
    } catch (error) {
      console.error('Export error:', error)
      toast.error('Có lỗi khi xuất file')
    } finally {
      setIsExporting(false)
    }
  }

  // ============================================
  // RENDER
  // ============================================

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-hidden flex flex-col">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <FileSpreadsheet className="h-5 w-5" />
            Xuất {config.entityDisplayName} ra Excel
          </DialogTitle>
          <DialogDescription>
            Chọn phạm vi và các cột cần xuất
          </DialogDescription>
        </DialogHeader>

        <div className="flex-1 overflow-auto space-y-6 p-1">
          {/* Export Scope */}
          <div className="space-y-3">
            <Label className="text-base font-semibold">Giới hạn kết quả xuất</Label>
            <RadioGroup 
              value={exportScope} 
              onValueChange={(v) => setExportScope(v as ExportScope)}
              className="space-y-2"
            >
              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-2">
                  <RadioGroupItem value="all" id="scope-all" />
                  <Label htmlFor="scope-all" className="font-normal cursor-pointer">
                    Tất cả dữ liệu
                  </Label>
                </div>
                <Badge variant="secondary">{allData.length}</Badge>
              </div>
              
              {filteredData.length < allData.length && (
                <div className="flex items-center justify-between">
                  <div className="flex items-center space-x-2">
                    <RadioGroupItem value="filtered" id="scope-filtered" />
                    <Label htmlFor="scope-filtered" className="font-normal cursor-pointer">
                      Kết quả đã lọc
                    </Label>
                  </div>
                  <Badge variant="secondary">{filteredData.length}</Badge>
                </div>
              )}
              
              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-2">
                  <RadioGroupItem value="current-page" id="scope-page" />
                  <Label htmlFor="scope-page" className="font-normal cursor-pointer">
                    Trang hiện tại
                  </Label>
                </div>
                <Badge variant="secondary">{currentPageData.length}</Badge>
              </div>
              
              {selectedData.length > 0 && (
                <div className="flex items-center justify-between">
                  <div className="flex items-center space-x-2">
                    <RadioGroupItem value="selected" id="scope-selected" />
                    <Label htmlFor="scope-selected" className="font-normal cursor-pointer">
                      Các dòng đã chọn
                    </Label>
                  </div>
                  <Badge variant="default">{selectedData.length}</Badge>
                </div>
              )}
            </RadioGroup>
          </div>

          <Separator />

          {/* Column Selection */}
          <div className="space-y-3">
            <div className="flex items-center justify-between">
              <Label className="text-base font-semibold">
                Chọn cột xuất ({selectedColumns.length}/{exportableFields.length})
              </Label>
              <Button
                variant="outline"
                size="sm"
                onClick={handleToggleAll}
              >
                {selectedColumns.length === exportableFields.length ? 'Bỏ chọn tất cả' : 'Chọn tất cả'}
              </Button>
            </div>

            <ScrollArea className="h-[280px] rounded-md border p-4">
              <div className="space-y-4">
                {Object.entries(groupedFields).map(([group, fields]) => {
                  const groupKeys = fields.map(f => f.key as string)
                  const selectedCount = groupKeys.filter(k => selectedColumns.includes(k)).length
                  const allSelected = selectedCount === fields.length
                  const someSelected = selectedCount > 0 && selectedCount < fields.length
                  
                  return (
                    <div key={group} className="space-y-2">
                      <div className="flex items-center space-x-2">
                        <Checkbox
                          id={`group-${group}`}
                          checked={allSelected}
                          // @ts-expect-error - indeterminate is valid HTML attribute
                          ref={(el) => el && (el.indeterminate = someSelected)}
                          onCheckedChange={() => handleToggleGroup(fields)}
                        />
                        <Label 
                          htmlFor={`group-${group}`}
                          className="text-sm font-semibold text-muted-foreground cursor-pointer"
                        >
                          {group} ({selectedCount}/{fields.length})
                        </Label>
                      </div>
                      <div className="grid grid-cols-2 gap-2 ml-6">
                        {fields.map(field => (
                          <div key={field.key as string} className="flex items-center space-x-2">
                            <Checkbox
                              id={field.key as string}
                              checked={selectedColumns.includes(field.key as string)}
                              onCheckedChange={() => handleToggleColumn(field.key as string)}
                            />
                            <Label
                              htmlFor={field.key as string}
                              className="text-sm font-normal cursor-pointer"
                            >
                              {field.label}
                              {field.required && <span className="text-destructive">*</span>}
                            </Label>
                          </div>
                        ))}
                      </div>
                    </div>
                  )
                })}
              </div>
            </ScrollArea>
          </div>

          {/* Preview */}
          <div className="rounded-lg bg-muted p-3 text-sm space-y-1">
            <p className="text-muted-foreground">
              <strong>Sẽ xuất:</strong> {dataToExport.length} {config.entityDisplayName} với {selectedColumns.length} cột
            </p>
            {selectedColumns.length > 0 && (
              <p className="text-xs text-muted-foreground">
                Cột: {selectedColumns.slice(0, 5).map(k => {
                  const field = config.fields.find(f => f.key === k)
                  return field?.label || k
                }).join(', ')}
                {selectedColumns.length > 5 && ` và ${selectedColumns.length - 5} cột khác`}
              </p>
            )}
          </div>
        </div>

        <DialogFooter>
          <Button variant="outline" onClick={() => onOpenChange(false)} disabled={isExporting}>
            Hủy
          </Button>
          <Button 
            onClick={handleExport} 
            disabled={selectedColumns.length === 0 || dataToExport.length === 0 || isExporting}
          >
            {isExporting ? (
              <>
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                Đang xuất...
              </>
            ) : (
              <>
                <Download className="mr-2 h-4 w-4" />
                Xuất Excel ({dataToExport.length})
              </>
            )}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

/**
 * Attendance API Layer
 * Handles all attendance-related API calls
 */

import type { AttendanceDataRow } from '@/lib/types/prisma-extended';

export interface AttendanceFilters {
  page?: number;
  limit?: number;
  employeeId?: string;
  date?: string;
  fromDate?: string;
  toDate?: string;
  status?: string;
}

export interface AttendanceResponse {
  data: AttendanceDataRow[];
  pagination: {
    page: number;
    limit: number;
    total: number;
    totalPages: number;
  };
}

export interface AttendanceCreateInput {
  employeeId: string;
  date: string;
  checkIn?: string;
  checkOut?: string;
  status?: string;
  notes?: string;
}

export interface AttendanceUpdateInput extends Partial<AttendanceCreateInput> {
  action?: 'save' | 'lock' | 'unlock';
  monthKey?: string;
  employeeSystemId?: string;
  dayKey?: string;
  record?: any;
}

const BASE_URL = '/api/attendance';

/**
 * Fetch attendance records with filters
 */
export async function fetchAttendance(
  filters: AttendanceFilters = {}
): Promise<AttendanceResponse> {
  const params = new URLSearchParams();
  
  if (filters.page) params.set('page', String(filters.page));
  if (filters.limit) params.set('limit', String(filters.limit));
  if (filters.employeeId) params.set('employeeId', filters.employeeId);
  if (filters.date) params.set('date', filters.date);
  if (filters.fromDate) params.set('fromDate', filters.fromDate);
  if (filters.toDate) params.set('toDate', filters.toDate);
  if (filters.status) params.set('status', filters.status);

  const url = params.toString() ? `${BASE_URL}?${params}` : BASE_URL;
  const response = await fetch(url);
  
  if (!response.ok) {
    throw new Error('Failed to fetch attendance records');
  }
  
  return response.json();
}

/**
 * Fetch attendance for a specific month
 * Transforms individual records into row format (one row per employee)
 */
export async function fetchAttendanceByMonth(
  monthKey: string
): Promise<AttendanceDataRow[]> {
  const [year, month] = monthKey.split('-');
  const fromDate = `${year}-${month}-01`;
  const lastDay = new Date(parseInt(year), parseInt(month), 0).getDate();
  const toDate = `${year}-${month}-${String(lastDay).padStart(2, '0')}`;
  
  const response = await fetchAttendance({
    fromDate,
    toDate,
    limit: 500,
  });
  
  // Transform individual records into row format
  const recordsByEmployee = new Map<string, AttendanceDataRow>();
  
  type AttendanceRecord = {
    date: string;
    employeeId: string;
    employee?: { systemId?: string; fullName?: string; department?: string };
    status: string;
    checkIn?: string;
    checkOut?: string;
    notes?: string;
    createdAt?: string;
    updatedAt?: string;
    createdBy?: string;
    updatedBy?: string;
  };
  
  (response.data as any as AttendanceRecord[]).forEach((record) => {
    const employeeId = record.employeeId;
    
    if (!recordsByEmployee.has(employeeId)) {
      recordsByEmployee.set(employeeId, {
        systemId: record.employee?.systemId || employeeId,
        employeeSystemId: record.employee?.systemId || employeeId,
        employeeId: employeeId,
        fullName: record.employee?.fullName || '',
        department: record.employee?.department,
        workDays: 0,
        leaveDays: 0,
        absentDays: 0,
        lateArrivals: 0,
        earlyDepartures: 0,
        otHours: 0,
        createdAt: record.createdAt,
        updatedAt: record.updatedAt,
        createdBy: record.createdBy,
        updatedBy: record.updatedBy,
      } as any);
    }
    
    const row = recordsByEmployee.get(employeeId)!;
    const recordDate = new Date(record.date);
    const day = recordDate.getDate();
    
    // Map database status to frontend status
    const statusMap: Record<string, string> = {
      'PRESENT': 'present',
      'ABSENT': 'absent',
      'LEAVE': 'leave',
      'HALF_DAY': 'half-day',
      'HOLIDAY': 'holiday',
    };
    
    const status = statusMap[record.status] || 'present';
    
    (row as Record<string, unknown>)[`day_${day}`] = {
      status,
      checkIn: record.checkIn ? new Date(record.checkIn).toTimeString().slice(0, 5) : undefined,
      checkOut: record.checkOut ? new Date(record.checkOut).toTimeString().slice(0, 5) : undefined,
      notes: record.notes,
    };
  });
  
  return Array.from(recordsByEmployee.values());
}

/**
 * Fetch single attendance record by ID
 */
export async function fetchAttendanceById(
  systemId: string
): Promise<AttendanceDataRow> {
  const response = await fetch(`${BASE_URL}/${systemId}`);
  
  if (!response.ok) {
    throw new Error('Failed to fetch attendance record');
  }
  
  return response.json();
}

/**
 * Create attendance record (check-in)
 */
export async function createAttendance(
  data: AttendanceCreateInput
): Promise<AttendanceDataRow> {
  const response = await fetch(BASE_URL, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(data),
  });
  
  if (!response.ok) {
    const error = await response.json().catch(() => ({}));
    throw new Error(error.error || 'Failed to create attendance record');
  }
  
  return response.json();
}

/**
 * Update attendance record
 */
export async function updateAttendance(
  systemId: string,
  data: AttendanceUpdateInput
): Promise<AttendanceDataRow> {
  const response = await fetch(`${BASE_URL}/${systemId}`, {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(data),
  });
  
  if (!response.ok) {
    const error = await response.json().catch(() => ({}));
    throw new Error(error.error || 'Failed to update attendance record');
  }
  
  return response.json();
}

/**
 * Lock/Unlock attendance month
 */
export async function lockAttendanceMonth(
  monthKey: string,
  lock: boolean
): Promise<boolean> {
  const response = await fetch(BASE_URL, {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      action: lock ? 'lock' : 'unlock',
      monthKey,
    }),
  });
  
  return response.ok;
}

/**
 * Delete attendance record
 */
export async function deleteAttendance(systemId: string): Promise<void> {
  const response = await fetch(`${BASE_URL}/${systemId}`, {
    method: 'DELETE',
  });
  
  if (!response.ok) {
    throw new Error('Failed to delete attendance record');
  }
}

/**
 * Bulk update attendance records
 */
export async function bulkUpdateAttendance(
  records: Array<{ systemId: string; data: AttendanceUpdateInput }>
): Promise<{ success: number; failed: number }> {
  const response = await fetch(`${BASE_URL}/bulk`, {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ records }),
  });
  
  if (!response.ok) {
    throw new Error('Failed to bulk update attendance records');
  }
  
  return response.json();
}

'use client';

import * as React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
