export function AttendancePage() {
  const { data: employees } = useAllEmployees();
  const { data: departments } = useAllDepartments();
  const { data: rawSettings } = useEmployeeSettings();
  const settings = rawSettings ?? DEFAULT_EMPLOYEE_SETTINGS;
  const { data: leaveRequests } = useAllLeaves();
  const { info: storeInfo } = useStoreInfoData();
  const { print } = usePrint();

  // Core state
  const [currentDate, setCurrentDate] = React.useState(() => new Date());
  const currentMonthKey = formatDateCustom(currentDate, 'yyyy-MM');
  
  // Fetch attendance data from database
  const { data: dbAttendanceData } = useAttendanceByMonth(currentMonthKey);
  
  // Local state for UI
  const [attendanceData, setAttendanceData] = React.useState<AttendanceDataRow[]>([]);
  const [lockedMonths, setLockedMonths] = React.useState<Record<string, boolean>>({});
  const isLocked = !!lockedMonths[currentMonthKey];
  
  // Mutations
  const { update: updateAttendance, bulkUpdate: bulkUpdateAttendance } = useAttendanceMutations({
    onSuccess: () => {
      toast.success('Đã lưu chấm công');
    },
    onError: (error) => {
      toast.error('Lỗi khi lưu chấm công', { description: error.message });
    },
  });

  // Filter state
  const [departmentFilter, setDepartmentFilter] = React.useState('all');
  const [globalFilter, setGlobalFilter] = React.useState('');
  const debouncedGlobalFilter = useDebounce(globalFilter, 300);
  const [rowSelection, setRowSelection] = React.useState<Record<string, boolean>>({});
  const [sorting, setSorting] = React.useState<{ id: string; desc: boolean }>({ id: 'createdAt', desc: true });
  const [pagination, setPagination] = React.useState({ pageIndex: 0, pageSize: 20 });
  const [columnVisibility, setColumnVisibility] = React.useState({});
  const [columnOrder, setColumnOrder] = React.useState<string[]>([]);
  const [pinnedColumns, setPinnedColumns] = React.useState<string[]>([]);

  // Edit dialog state
  const [isEditModalOpen, setIsEditModalOpen] = React.useState(false);
  const [editingRecordInfo, setEditingRecordInfo] = React.useState<{ employeeSystemId: SystemId; day: number; record: DailyRecord } | null>(null);

  // Import/Export state
  const [isImportDialogOpen, setIsImportDialogOpen] = React.useState(false);

  // Bulk edit state
  const [isBulkEditDialogOpen, setIsBulkEditDialogOpen] = React.useState(false);
  const [cellSelection, setCellSelection] = React.useState<Record<string, boolean>>({});
  const [isSelectionMode, setIsSelectionMode] = React.useState(false);

  // Penalty state
  const [isPenaltyConfirmOpen, setIsPenaltyConfirmOpen] = React.useState(false);
  const [pendingPenalties, setPendingPenalties] = React.useState<PenaltyPreviewItem[]>([]);

  // Use ref for leaveRequests to avoid effect re-runs
  const leaveRequestsRef = React.useRef(leaveRequests);
  leaveRequestsRef.current = leaveRequests;

  // Replay approved leaves - use ref to avoid dependency on leaveRequests
  const replayApprovedLeavesForMonth = React.useCallback((monthKey: string) => {
    const currentLeaves = leaveRequestsRef.current;
    if (!currentLeaves?.length) return;
    const [yearStr, monthStr] = monthKey.split('-');
    const year = Number(yearStr), month = Number(monthStr);
    if (!year || !month) return;
    const monthStart = new Date(year, month - 1, 1);
    const monthEnd = new Date(year, month, 0);
    currentLeaves.forEach((leave) => {
      if (leave.status !== 'Đã duyệt') return;
      const start = new Date(leave.startDate), end = new Date(leave.endDate);
      if (!isNaN(start.getTime()) && !isNaN(end.getTime()) && start <= monthEnd && end >= monthStart) {
        leaveAttendanceSync.apply(leave);
      }
    });
  }, []);

  // Track if data has been loaded for current month to prevent re-runs
  const loadedMonthRef = React.useRef<string | null>(null);

  // Load attendance data - stabilized effect
  React.useEffect(() => {
    // Skip if we already loaded this month's data
    if (loadedMonthRef.current === currentMonthKey) return;
    // Skip if employees not loaded yet
    if (!employees?.length) return;
    
    // If no data from DB, generate empty structure
    if (!dbAttendanceData || dbAttendanceData.length === 0) {
      const seededData = generateEmptyAttendance(employees, currentDate.getFullYear(), currentDate.getMonth() + 1, settings);
      setAttendanceData(seededData);
      replayApprovedLeavesForMonth(currentMonthKey);
      loadedMonthRef.current = currentMonthKey;
    } else {
      setAttendanceData(dbAttendanceData);
      loadedMonthRef.current = currentMonthKey;
    }
  }, [employees, currentDate, settings, currentMonthKey, dbAttendanceData, replayApprovedLeavesForMonth]);

  // Toggle lock handler
  const _handleToggleLock = React.useCallback(() => {
    const monthLabel = formatDateCustom(currentDate, 'MM/yyyy');
    setLockedMonths(prev => {
      const newLocked = { ...prev };
      if (newLocked[currentMonthKey]) {
        delete newLocked[currentMonthKey];
      } else {
        newLocked[currentMonthKey] = true;
      }
      return newLocked;
    });
    toast.success(isLocked ? 'Đã mở khóa chấm công' : 'Đã khóa chấm công', { description: `Tháng ${monthLabel}` });
  }, [currentDate, currentMonthKey, isLocked]);

  // Cell selection toggle
  const toggleCellSelection = React.useCallback((employeeSystemId: SystemId, day: number) => {
    if (!isSelectionMode || isLocked) return;
    const key = `${employeeSystemId}-${day}`;
    setCellSelection(prev => { const n = { ...prev }; if (n[key]) delete n[key]; else n[key] = true; return n; });
  }, [isSelectionMode, isLocked]);

  // Quick fill handler
  const handleQuickFill = React.useCallback((employeeSystemId: SystemId, day: number) => {
    if (isLocked) return;
    const defaultRecord: DailyRecord = { status: 'present', checkIn: settings.workStartTime, checkOut: settings.workEndTime };
    const updatedData = attendanceData.map(row => {
      if (row.employeeSystemId === employeeSystemId) {
        const newRow = { ...row } as AnyAttendanceDataRow;
        newRow[`day_${day}`] = defaultRecord;
        return { ...newRow, ...recalculateSummary(newRow, currentDate.getFullYear(), currentDate.getMonth() + 1, settings) } as AttendanceDataRow;
      }
      return row;
    });
    setAttendanceData(updatedData);
    
    // Save single record to database
    updateAttendance.mutate({
      systemId: employeeSystemId,
      data: {
        action: 'save',
        monthKey: currentMonthKey,
        employeeSystemId,
        dayKey: `day_${day}`,
        record: defaultRecord,
      },
    });
    
    toast('Điền nhanh', { description: 'Đã áp dụng giờ làm việc mặc định' });
  }, [attendanceData, currentDate, settings, isLocked, currentMonthKey, updateAttendance]);

  // Edit record handler
  const handleEditRecord = React.useCallback((employeeSystemId: SystemId, day: number) => {
    if (isLocked) return;
    if (isSelectionMode) { toggleCellSelection(employeeSystemId, day); return; }
    const emp = attendanceData.find(e => e.employeeSystemId === employeeSystemId);
    if (emp) { setEditingRecordInfo({ employeeSystemId, day, record: emp[`day_${day}`] as DailyRecord }); setIsEditModalOpen(true); }
  }, [attendanceData, isLocked, isSelectionMode, toggleCellSelection]);

  // Save record handler
  const handleSaveRecord = React.useCallback((updatedRecord: DailyRecord) => {
    if (!editingRecordInfo) return;
    const updatedData = attendanceData.map(row => {
      if (row.employeeSystemId === editingRecordInfo.employeeSystemId) {
        const newRow = { ...row } as AnyAttendanceDataRow;
        newRow[`day_${editingRecordInfo.day}`] = updatedRecord;
        return { ...newRow, ...recalculateSummary(newRow, currentDate.getFullYear(), currentDate.getMonth() + 1, settings) } as AttendanceDataRow;
      }
      return row;
    });
    setAttendanceData(updatedData);
    
    // Save to database
    updateAttendance.mutate({
      systemId: editingRecordInfo.employeeSystemId,
      data: {
        action: 'save',
        monthKey: currentMonthKey,
        employeeSystemId: editingRecordInfo.employeeSystemId,
        dayKey: `day_${editingRecordInfo.day}`,
        record: updatedRecord,
      },
    });
    
    setIsEditModalOpen(false);
    setEditingRecordInfo(null);
    toast.success('Cập nhật thành công', { description: `Đã lưu chấm công ngày ${editingRecordInfo.day}` });
  }, [editingRecordInfo, attendanceData, currentDate, settings, currentMonthKey, updateAttendance]);

  // Bulk save handler
  const handleBulkSave = React.useCallback((updates: Array<{ employeeSystemId: SystemId; day: number; record: DailyRecord }>) => {
    const updatedData = attendanceData.map(row => {
      const empUpdates = updates.filter(u => u.employeeSystemId === row.employeeSystemId);
      if (empUpdates.length > 0) {
        const newRow = { ...row } as AnyAttendanceDataRow;
        empUpdates.forEach(u => { newRow[`day_${u.day}`] = u.record; });
        return { ...newRow, ...recalculateSummary(newRow, currentDate.getFullYear(), currentDate.getMonth() + 1, settings) } as AttendanceDataRow;
      }
      return row;
    });
    setAttendanceData(updatedData);
    
    // Save to database
    const records = updates.map(u => ({
      systemId: u.employeeSystemId,
      data: {
        action: 'save',
        monthKey: currentMonthKey,
        employeeSystemId: u.employeeSystemId,
        dayKey: `day_${u.day}`,
        record: u.record,
      } as any,
    }));
    bulkUpdateAttendance.mutate(records);
    
    setCellSelection({});
    setIsSelectionMode(false);
    toast.success('Cập nhật thành công', { description: `Đã chỉnh sửa ${updates.length} ô` });
  }, [attendanceData, currentDate, settings, currentMonthKey, bulkUpdateAttendance]);

  // Import confirm handler
  const handleConfirmImport = React.useCallback((importedData: Record<SystemId, { day: number; checkIn?: string; morningCheckOut?: string; afternoonCheckIn?: string; checkOut?: string; overtimeCheckIn?: string; overtimeCheckOut?: string }[]>, date: Date) => {
    const year = date.getFullYear(), month = date.getMonth() + 1;
    const baseData = generateEmptyAttendance(employees, year, month, settings);
    const updatedData = baseData.map(empRow => {
      const empUpdates = importedData[empRow.employeeSystemId];
      if (empUpdates) {
        const mutableRow = { ...empRow } as AnyAttendanceDataRow;
        const daysInMonth = new Date(year, month, 0).getDate();
        for (let d = 1; d <= daysInMonth; d++) {
          const workDate = new Date(year, month - 1, d);
          const dayOfWeek = getDayOfWeek(workDate);
          mutableRow[`day_${d}`] = { status: dayOfWeek !== null && settings.workingDays.includes(dayOfWeek) ? 'absent' : 'weekend' };
        }
        empUpdates.forEach(u => { mutableRow[`day_${u.day}`] = { status: u.checkIn && u.checkOut ? 'present' : 'absent', checkIn: u.checkIn, morningCheckOut: u.morningCheckOut, afternoonCheckIn: u.afternoonCheckIn, checkOut: u.checkOut, overtimeCheckIn: u.overtimeCheckIn, overtimeCheckOut: u.overtimeCheckOut }; });
        return { ...mutableRow, ...recalculateSummary(mutableRow, year, month, settings) } as AttendanceDataRow;
      }
      return empRow;
    });
    setAttendanceData(updatedData);
    
    // Save entire month to database
    const monthKey = formatDateCustom(date, 'yyyy-MM');
    const records = updatedData.flatMap(empRow => {
      const updates: Array<{ systemId: SystemId; data: Record<string, unknown> }> = [];
      const daysInMonth = new Date(year, month, 0).getDate();
      for (let d = 1; d <= daysInMonth; d++) {
        const dayRecord = empRow[`day_${d}`] as DailyRecord;
        if (dayRecord && dayRecord.status !== 'weekend' && dayRecord.status !== 'future' && dayRecord.status !== 'empty') {
          updates.push({
            systemId: empRow.employeeSystemId,
            data: {
              action: 'save',
              monthKey,
              employeeSystemId: empRow.employeeSystemId,
              dayKey: `day_${d}`,
              record: dayRecord,
            },
          });
        }
      }
      return updates;
    });
    
    if (records.length > 0) {
      bulkUpdateAttendance.mutate(records);
    }
    
    setCurrentDate(date);
    const penalties = previewAttendancePenalties(updatedData, year, month);
    if (penalties.length > 0) { setPendingPenalties(penalties); setIsPenaltyConfirmOpen(true); }
    toast.success('Nhập thành công', { description: `Đã cập nhật chấm công cho tháng ${formatDateCustom(date, 'MM/yyyy')}` });
  }, [employees, settings, bulkUpdateAttendance]);

  const handleConfirmPenalties = React.useCallback((selectedPenalties: Parameters<typeof confirmCreatePenalties>[0]) => {
    const created = confirmCreatePenalties(selectedPenalties);
    toast.success('Tạo phiếu phạt thành công', { description: `Đã tạo ${created} phiếu phạt` });
    setPendingPenalties([]);
  }, []);

  const handleSkipPenalties = React.useCallback(() => { toast.info('Đã bỏ qua tạo phiếu phạt'); setPendingPenalties([]); }, []);

  // Selected cells array
  const selectedCellsArray = React.useMemo(() => Object.keys(cellSelection).map(key => { const [sId, dayStr] = key.split('-'); const emp = attendanceData.find(e => e.employeeSystemId === sId); return { employeeSystemId: sId as SystemId, employeeCode: emp?.employeeId ?? '', employeeName: emp?.fullName ?? '', day: parseInt(dayStr, 10) }; }), [cellSelection, attendanceData]);

  // Filtering
  const fuseOptions = React.useMemo(() => ({ keys: ['employeeId', 'fullName', 'department'] }), []);
  const searchedData = useFuseFilter(attendanceData, debouncedGlobalFilter, fuseOptions);
  const filteredData = React.useMemo(() => { let data = searchedData; if (departmentFilter !== 'all') data = data.filter(r => r.department === departmentFilter); return data; }, [searchedData, departmentFilter]);
  const sortedData = React.useMemo(() => { const s = [...filteredData]; if (sorting.id) s.sort((a, b) => { const aV = (a as Record<string, unknown>)[sorting.id] as string | number | null | undefined, bV = (b as Record<string, unknown>)[sorting.id] as string | number | null | undefined; if (aV == null && bV == null) return 0; if (aV == null) return 1; if (bV == null) return -1; if (aV < bV) return sorting.desc ? 1 : -1; if (aV > bV) return sorting.desc ? -1 : 1; return 0; }); return s; }, [filteredData, sorting]);

  // Print & Export handlers (must be after sortedData)
  const _handlePrint = React.useCallback(() => {
    if (!sortedData?.length) return;
    const storeSettings = createStoreSettings(storeInfo);
    const sheetForPrint = convertAttendanceSheetForPrint(currentMonthKey, sortedData as Parameters<typeof convertAttendanceSheetForPrint>[1], { isLocked, departmentName: departmentFilter !== 'all' ? departments.find(d => d.name === departmentFilter)?.name : undefined });
    print('attendance', { data: mapAttendanceSheetToPrintData(sheetForPrint, storeSettings), lineItems: mapAttendanceSheetLineItems(sheetForPrint.employees, currentMonthKey) });
  }, [sortedData, currentMonthKey, departmentFilter, departments, isLocked, storeInfo, print]);

  const _handleExport = React.useCallback(async () => {
    const XLSX = await import('xlsx');
    const year = currentDate.getFullYear(), month = currentDate.getMonth() + 1, daysInMonth = new Date(year, month, 0).getDate();
    const headers = ['Mã NV', 'Họ tên', 'Phòng ban'];
    for (let d = 1; d <= daysInMonth; d++) headers.push(`${d}`);
    headers.push('Ngày công', 'Nghỉ phép', 'Vắng');
    const rows = sortedData.map(row => {
      const r: (string | number)[] = [row.employeeId, row.fullName, row.department ?? ''];
      for (let d = 1; d <= daysInMonth; d++) { const rec = row[`day_${d}` as keyof AttendanceDataRow] as DailyRecord | undefined; r.push(!rec ? '' : rec.status === 'present' ? 'X' : rec.status === 'leave' ? 'P' : rec.status === 'absent' ? 'V' : rec.status === 'weekend' ? '-' : rec.status === 'holiday' ? 'L' : ''); }
      r.push(row.workDays ?? 0, row.leaveDays ?? 0, row.absentDays ?? 0);
      return r;
    });
    const ws = XLSX.utils.aoa_to_sheet([headers, ...rows]);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, `Chấm công T${month}`);
    XLSX.writeFile(wb, `cham-cong-${formatDateCustom(currentDate, 'yyyy-MM')}.xlsx`);
    toast.success('Xuất Excel thành công', { description: `Đã xuất ${sortedData.length} nhân viên` });
  }, [sortedData, currentDate]);

  // Page actions (after handlers)
  usePageHeader(React.useMemo(() => ({
    title: 'Chấm công',
    breadcrumb: [
      { label: 'Nhân sự', href: ROUTES.HRM.EMPLOYEES, isCurrent: false },
      { label: 'Chấm công', href: ROUTES.HRM.ATTENDANCE, isCurrent: true }
    ],
    // ⚠️ Tạm bỏ actions khỏi header để tránh vòng lặp setState khi actions thay đổi liên tục
  }), []));

  // Columns - separate stable config from selection state
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth() + 1;
  const columns = React.useMemo(() => getColumns(year, month, handleEditRecord, settings, isLocked, isSelectionMode, cellSelection, handleQuickFill), [year, month, handleEditRecord, settings, isLocked, isSelectionMode, cellSelection, handleQuickFill]);

  // Init column visibility - only run once when columns are first available
  const initRef = React.useRef(false);
  React.useEffect(() => { 
    if (initRef.current) return; 
    // Only initialize when we have valid columns based on year/month
    const daysInMonth = new Date(year, month, 0).getDate();
    if (daysInMonth <= 0) return;
    
    const v: Record<string, boolean> = {}; 
    columns.forEach(c => { if (c.id) v[c.id] = true; }); 
    setColumnVisibility(v); 
    setColumnOrder(columns.map(c => c.id).filter(Boolean) as string[]); 
    setPinnedColumns(['select', 'fullName']); 
    initRef.current = true; 
  // eslint-disable-next-line react-hooks/exhaustive-deps -- intentionally only run once on initial mount
  }, [year, month]);


  const pageCount = Math.ceil(sortedData.length / pagination.pageSize);
  const paginatedData = sortedData.slice(pagination.pageIndex * pagination.pageSize, (pagination.pageIndex + 1) * pagination.pageSize);
  const allSelectedRows = React.useMemo(() => attendanceData.filter(a => rowSelection[a.systemId]), [attendanceData, rowSelection]);

  return (
    <div className="flex flex-col h-full space-y-4">
      <StatisticsDashboard data={filteredData} currentDate={currentDate} />
      <Card className="flex-shrink-0"><CardContent className="p-4"><div className="flex flex-wrap items-center justify-between gap-2"><div className="flex flex-wrap items-center gap-2"><MonthYearPicker value={currentDate} onChange={setCurrentDate} /><Select value={departmentFilter} onValueChange={setDepartmentFilter}><SelectTrigger className="h-9 w-full sm:w-[180px]"><SelectValue placeholder="Tất cả phòng ban" /></SelectTrigger><SelectContent><SelectItem value="all">Tất cả phòng ban</SelectItem>{departments.map(d => <SelectItem key={d.id} value={d.name}>{d.name}</SelectItem>)}</SelectContent></Select><div className="relative"><Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" /><Input placeholder="Tìm nhân viên..." value={globalFilter} onChange={e => setGlobalFilter(e.target.value)} className="h-9 w-[200px] pl-8" /></div></div><div className="flex items-center justify-end gap-2"><DataTableColumnCustomizer columns={columns} columnVisibility={columnVisibility} setColumnVisibility={setColumnVisibility} columnOrder={columnOrder} setColumnOrder={setColumnOrder} pinnedColumns={pinnedColumns} setPinnedColumns={setPinnedColumns} /></div></div></CardContent></Card>
      <ResponsiveDataTable columns={columns} data={paginatedData} rowCount={filteredData.length} pageCount={pageCount} pagination={pagination} setPagination={setPagination} rowSelection={rowSelection} setRowSelection={setRowSelection} sorting={sorting} setSorting={setSorting} columnVisibility={columnVisibility} setColumnVisibility={setColumnVisibility} columnOrder={columnOrder} setColumnOrder={setColumnOrder} pinnedColumns={pinnedColumns} setPinnedColumns={setPinnedColumns} className="flex-grow" allSelectedRows={allSelectedRows} expanded={{}} setExpanded={() => {}} />
      <AttendanceEditDialog isOpen={isEditModalOpen} onOpenChange={setIsEditModalOpen} recordData={editingRecordInfo} onSave={handleSaveRecord} monthDate={currentDate} />
      <AttendanceImportDialog isOpen={isImportDialogOpen} onOpenChange={setIsImportDialogOpen} onConfirmImport={handleConfirmImport} employees={employees} />
      <BulkEditDialog isOpen={isBulkEditDialogOpen} onOpenChange={setIsBulkEditDialogOpen} selectedCells={selectedCellsArray} onSave={handleBulkSave} />
      <PenaltyConfirmDialog isOpen={isPenaltyConfirmOpen} onOpenChange={setIsPenaltyConfirmOpen} penalties={pendingPenalties} onConfirm={handleConfirmPenalties} onSkip={handleSkipPenalties} />
    </div>
  );
}

'use client'

import * as React from 'react';
import { useRouter, useParams, usePathname } from 'next/navigation';
import { 
  Save, 
  X, 
  Trash2,
  Globe,
  Image as ImageIcon,
  Pencil,
  BarChart3,
  RefreshCw,
  ExternalLink,
} from 'lucide-react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Switch } from '@/components/ui/switch';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { OptimizedImage } from '@/components/ui/optimized-image';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import { useBrands, useBrandMutations } from './hooks/use-brands';
import type { Brand as _Brand } from '../settings/inventory/types';
import { asSystemId, asBusinessId, type SystemId as _SystemId } from '@/lib/id-types';
import { toast } from 'sonner';
import { NewDocumentsUpload } from '@/components/ui/new-documents-upload';
import { FileUploadAPI, type StagingFile } from '@/lib/file-upload-api';
import { SeoAnalysisPanel } from '@/components/shared/seo-preview';
import { TipTapEditor } from '@/components/ui/tiptap-editor';
import { usePageHeader } from '@/contexts/page-header-context';
import { usePkgxBrandSync } from './hooks/use-pkgx-brand-sync';

// Schema
const websiteSeoSchema = z.object({
  seoTitle: z.string().optional(),
  metaDescription: z.string().optional(),
  seoKeywords: z.string().optional(),
  shortDescription: z.string().optional(),
  longDescription: z.string().optional(),
  slug: z.string().optional(),
}).optional();

const brandFormSchema = z.object({
  id: z.string().min(1, 'Mã thương hiệu là bắt buộc'),
  name: z.string().min(1, 'Tên thương hiệu là bắt buộc'),
  description: z.string().optional(),
  website: z.string().optional(),
  logo: z.string().optional(),
  isActive: z.boolean().optional(),
  // SEO mặc định
  seoTitle: z.string().optional(),
  metaDescription: z.string().optional(),
  seoKeywords: z.string().optional(),
  shortDescription: z.string().optional(),
  longDescription: z.string().optional(),
  // SEO riêng cho từng website
  websiteSeo: z.object({
    pkgx: websiteSeoSchema,
    trendtech: websiteSeoSchema,
  }).optional(),
});

type BrandFormValues = z.infer<typeof brandFormSchema>;

export function BrandDetailPage() {
  const { systemId } = useParams<{ systemId: string }>();
  const router = useRouter();
  const pathname = usePathname();
  
  const isEditMode = pathname?.endsWith('/edit') ?? false;
  
  const { data: brandsData } = useBrands({ limit: 1000 });
  const brands = React.useMemo(() => brandsData?.data ?? [], [brandsData?.data]);
  const { update, remove } = useBrandMutations({
    onUpdateSuccess: () => {
      toast.success('Đã cập nhật thương hiệu');
      router.push(`/brands/${systemId}`);
    },
    onDeleteSuccess: () => {
      toast.success('Đã xóa thương hiệu');
      router.push('/brands');
    },
    onError: (err) => toast.error(err.message)
  });
  
  // PKGX sync hook
  const { handleSyncSeo, handleSyncDescription, handleSyncAll, hasPkgxMapping } = usePkgxBrandSync();
  
  const brand = React.useMemo(() => 
    brands.find(b => b.systemId === systemId), 
    [brands, systemId]
  );
  
  const [isDeleteAlertOpen, setIsDeleteAlertOpen] = React.useState(false);
  const [activeTab, setActiveTab] = React.useState<'general' | 'seo-default' | 'seo-pkgx' | 'seo-trendtech'>('general');
  
  // Logo upload state
  const [logoFiles, setLogoFiles] = React.useState<StagingFile[]>([]);
  const [logoSessionId, setLogoSessionId] = React.useState<string | undefined>();

  const form = useForm<BrandFormValues>({
    resolver: zodResolver(brandFormSchema),
    defaultValues: {
      id: '',
      name: '',
      description: '',
      website: '',
      logo: '',
      isActive: true,
      // SEO mặc định
      seoTitle: '',
      metaDescription: '',
      seoKeywords: '',
      shortDescription: '',
      longDescription: '',
      // SEO riêng cho từng website
      websiteSeo: {
        pkgx: {},
        trendtech: {},
      },
    },
  });

  // Reset form when brand data changes
  React.useEffect(() => {
    if (brand) {
      form.reset({
        id: brand.id || '',
        name: brand.name || '',
        description: brand.description || '',
        website: brand.website || '',
        logo: brand.logo || '',
        isActive: brand.isActive ?? true,
        // SEO mặc định
        seoTitle: brand.seoTitle || '',
        metaDescription: brand.metaDescription || '',
        seoKeywords: brand.seoKeywords || '',
        shortDescription: brand.shortDescription || '',
        longDescription: brand.longDescription || '',
        // SEO riêng cho từng website
        websiteSeo: {
          pkgx: (brand.websiteSeo as any)?.pkgx || {},
          trendtech: (brand.websiteSeo as any)?.trendtech || {},
        },
      });
    }
  }, [brand, form]);

  const watchedName = form.watch('name');
  const watchedPkgxSeoTitle = form.watch('websiteSeo.pkgx.seoTitle');
  const watchedPkgxMetaDesc = form.watch('websiteSeo.pkgx.metaDescription');
  const watchedPkgxKeywords = form.watch('websiteSeo.pkgx.seoKeywords');
  const watchedPkgxSlug = form.watch('websiteSeo.pkgx.slug');
  const watchedTrendtechSeoTitle = form.watch('websiteSeo.trendtech.seoTitle');
  const watchedTrendtechMetaDesc = form.watch('websiteSeo.trendtech.metaDescription');
  const watchedTrendtechKeywords = form.watch('websiteSeo.trendtech.seoKeywords');
  const watchedTrendtechSlug = form.watch('websiteSeo.trendtech.slug');

  const handleSubmit = React.useCallback(async (data: BrandFormValues) => {
    if (!systemId) return;
    
    // Confirm logo staging files
    let logoUrl = data.logo;
    if (logoFiles.length > 0 && logoSessionId) {
      try {
        await FileUploadAPI.confirmStagingFiles(
          logoSessionId,
          systemId,
          'brands',
          'logo',
          { name: data.name }
        );
        logoUrl = logoFiles[0]?.url || logoUrl;
      } catch (error) {
        console.error('Error confirming logo:', error);
      }
    }
    
    update.mutate({
      systemId: asSystemId(systemId),
      data: {
        ...data,
        id: asBusinessId(data.id),
        logo: logoUrl,
      }
    });
  }, [systemId, logoFiles, logoSessionId, update]);

  const handleDelete = () => {
    if (!systemId) return;
    remove.mutate(asSystemId(systemId));
  };

  const handleSwitchToEdit = React.useCallback(() => {
    router.push(`/brands/${systemId}/edit`);
  }, [router, systemId]);

  // Header actions
  const headerActions = React.useMemo(() => {
    if (isEditMode) {
      return [
        <Button key="cancel" variant="outline" size="sm" className="h-9" onClick={() => router.push(`/brands/${systemId}`)}>
          <X className="mr-2 h-4 w-4" />
          Hủy
        </Button>,
        <Button key="save" size="sm" className="h-9" onClick={form.handleSubmit(handleSubmit)}>
          <Save className="mr-2 h-4 w-4" />
          Lưu
        </Button>
      ];
    }
    return [
      <Button key="delete" variant="outline" size="sm" className="h-9 text-destructive hover:text-destructive" onClick={() => setIsDeleteAlertOpen(true)}>
        <Trash2 className="mr-2 h-4 w-4" />
        Xóa
      </Button>,
      <Button key="edit" size="sm" className="h-9" onClick={handleSwitchToEdit}>
        <Pencil className="mr-2 h-4 w-4" />
        Chỉnh sửa
      </Button>
    ];
  }, [isEditMode, systemId, router, form, handleSubmit, handleSwitchToEdit]);

  usePageHeader({
    actions: headerActions,
    showBackButton: true,
  });

  if (!brand) {
    return (
      <div className="flex items-center justify-center h-[50vh]">
        <div className="text-center">
          <p className="text-muted-foreground">Không tìm thấy thương hiệu</p>
          <Button variant="link" onClick={() => router.push('/brands')}>
            Quay lại danh sách
          </Button>
        </div>
      </div>
    );
  }

  // View mode
  if (!isEditMode) {
    return (
      <div className="space-y-6 pb-8">
        <Tabs value={activeTab} onValueChange={(v) => setActiveTab(v as typeof activeTab)}>
          <TabsList className="grid w-full grid-cols-4 max-w-2xl">
            <TabsTrigger value="general">Thông tin</TabsTrigger>
            <TabsTrigger value="seo-default" className="gap-1">
              <Globe className="h-3 w-3" />
              SEO Chung
            </TabsTrigger>
            <TabsTrigger value="seo-pkgx" className="gap-1">
              <Globe className="h-3 w-3 text-red-500" />
              SEO PKGX
            </TabsTrigger>
            <TabsTrigger value="seo-trendtech" className="gap-1">
              <Globe className="h-3 w-3 text-blue-500" />
              SEO Trendtech
            </TabsTrigger>
          </TabsList>

          {/* General Tab */}
          <TabsContent value="general" className="space-y-4 mt-4">
            {/* Brand Header Card */}
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-base">Thông tin cơ bản</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="flex items-start gap-6">
                  <Avatar className="h-24 w-24 rounded-lg border">
                    {brand.logo ? (
                      <AvatarImage src={brand.logo} alt={brand.name} className="object-cover" />
                    ) : null}
                    <AvatarFallback className="rounded-lg bg-muted">
                      <ImageIcon className="h-10 w-10 text-muted-foreground" />
                    </AvatarFallback>
                  </Avatar>
                  
                  <div className="flex-1 space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                      <div className="space-y-1">
                        <p className="text-sm text-muted-foreground">Mã thương hiệu</p>
                        <p className="font-mono font-medium">{brand.id}</p>
                      </div>
                      <div className="space-y-1">
                        <p className="text-sm text-muted-foreground">Trạng thái</p>
                        {brand.isActive !== false ? (
                          <Badge variant="default" className="bg-green-100 text-green-800 hover:bg-green-100">
                            Hoạt động
                          </Badge>
                        ) : (
                          <Badge variant="secondary">Tạm tắt</Badge>
                        )}
                      </div>
                    </div>
                    
                    <div className="space-y-1">
                      <p className="text-sm text-muted-foreground">Tên thương hiệu</p>
                      <p className="text-lg font-semibold">{brand.name}</p>
                    </div>
                    
                    {brand.website && (
                      <div className="space-y-1">
                        <p className="text-sm text-muted-foreground">Website</p>
                        <a 
                          href={brand.website} 
                          target="_blank" 
                          rel="noopener noreferrer"
                          className="inline-flex items-center gap-1.5 text-sm text-primary hover:underline"
                        >
                          <Globe className="h-4 w-4" />
                          {brand.website}
                          <ExternalLink className="h-3 w-3" />
                        </a>
                      </div>
                    )}
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Description Card */}
            {brand.description && (
              <Card>
                <CardHeader className="pb-3">
                  <CardTitle className="text-base">Mô tả</CardTitle>
                </CardHeader>
                <CardContent>
                  <p className="text-sm text-muted-foreground whitespace-pre-wrap">{brand.description}</p>
                </CardContent>
              </Card>
            )}
          </TabsContent>

          {/* SEO Default Tab */}
          <TabsContent value="seo-default" className="space-y-4 mt-4">
            <Card>
              <CardHeader>
                <div className="flex items-center gap-2">
                  <Globe className="h-4 w-4" />
                  <CardTitle className="text-base">SEO Mặc định</CardTitle>
                </div>
                <CardDescription>Thông tin SEO chung - sẽ được dùng nếu không có SEO riêng cho từng website</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">Tiêu đề SEO</p>
                  <p className="text-sm font-medium">{brand.seoTitle || '-'}</p>
                </div>
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">Meta Description</p>
                  <p className="text-sm">{brand.metaDescription || '-'}</p>
                </div>
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">Từ khóa SEO</p>
                  <p className="text-sm">{brand.seoKeywords || '-'}</p>
                </div>
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">Mô tả ngắn</p>
                  {brand.shortDescription ? (
                    <div className="prose prose-sm max-w-none text-sm border rounded-md p-3 bg-muted/30" dangerouslySetInnerHTML={{ __html: brand.shortDescription }} />
                  ) : <p className="text-sm text-muted-foreground">-</p>}
                </div>
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">Mô tả chi tiết</p>
                  {brand.longDescription ? (
                    <div className="prose prose-sm max-w-none text-sm border rounded-md p-3 bg-muted/30" dangerouslySetInnerHTML={{ __html: brand.longDescription }} />
                  ) : <p className="text-sm text-muted-foreground">-</p>}
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          {/* SEO PKGX Tab */}
          <TabsContent value="seo-pkgx" className="space-y-4 mt-4">
            <Card>
              <CardHeader>
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <Globe className="h-4 w-4 text-red-500" />
                    <CardTitle className="text-base">SEO PKGX</CardTitle>
                  </div>
                  {brand && hasPkgxMapping(brand as any) && (
                    <div className="flex items-center gap-2">
                      <Button 
                        variant="outline" 
                        size="sm" 
                        className="h-8 text-xs"
                        onClick={() => handleSyncSeo(brand as any)}
                      >
                        <RefreshCw className="mr-1.5 h-3 w-3" />
                        Đồng bộ SEO
                      </Button>
                      <Button 
                        variant="outline" 
                        size="sm" 
                        className="h-8 text-xs"
                        onClick={() => handleSyncDescription(brand as any)}
                      >
                        <RefreshCw className="mr-1.5 h-3 w-3" />
                        Đồng bộ mô tả
                      </Button>
                      <Button 
                        size="sm" 
                        className="h-8 text-xs"
                        onClick={() => handleSyncAll(brand as any)}
                      >
                        <RefreshCw className="mr-1.5 h-3 w-3" />
                        Đồng bộ tất cả
                      </Button>
                    </div>
                  )}
                </div>
                <CardDescription>
                  phukiengiaxuong.com.vn - Override SEO chung
                  {brand && !hasPkgxMapping(brand as any) && (
                    <span className="text-orange-600 ml-2">(Chưa mapping với PKGX - vào Cài đặt &gt; PKGX để mapping)</span>
                  )}
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">Tiêu đề SEO</p>
                  <p className="text-sm font-medium">{(brand.websiteSeo as any)?.pkgx?.seoTitle || '-'}</p>
                </div>
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">Meta Description</p>
                  <p className="text-sm">{(brand.websiteSeo as any)?.pkgx?.metaDescription || '-'}</p>
                </div>
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">Từ khóa SEO</p>
                  <p className="text-sm">{(brand.websiteSeo as any)?.pkgx?.seoKeywords || '-'}</p>
                </div>
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">URL Slug</p>
                  <p className="text-sm font-mono">{(brand.websiteSeo as any)?.pkgx?.slug || '-'}</p>
                </div>
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">Mô tả ngắn</p>
                  {(brand.websiteSeo as any)?.pkgx?.shortDescription ? (
                    <div className="prose prose-sm max-w-none text-sm border rounded-md p-3 bg-muted/30" dangerouslySetInnerHTML={{ __html: (brand.websiteSeo as any).pkgx.shortDescription }} />
                  ) : <p className="text-sm text-muted-foreground">-</p>}
                </div>
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">Mô tả chi tiết</p>
                  {(brand.websiteSeo as any)?.pkgx?.longDescription ? (
                    <div className="prose prose-sm max-w-none text-sm border rounded-md p-3 bg-muted/30" dangerouslySetInnerHTML={{ __html: (brand.websiteSeo as any).pkgx.longDescription }} />
                  ) : <p className="text-sm text-muted-foreground">-</p>}
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          {/* SEO Trendtech Tab */}
          <TabsContent value="seo-trendtech" className="space-y-4 mt-4">
            <Card>
              <CardHeader>
                <div className="flex items-center gap-2">
                  <Globe className="h-4 w-4 text-blue-500" />
                  <CardTitle className="text-base">SEO Trendtech</CardTitle>
                </div>
                <CardDescription>trendtech.vn - Override SEO chung</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">Tiêu đề SEO</p>
                  <p className="text-sm font-medium">{(brand.websiteSeo as any)?.trendtech?.seoTitle || '-'}</p>
                </div>
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">Meta Description</p>
                  <p className="text-sm">{(brand.websiteSeo as any)?.trendtech?.metaDescription || '-'}</p>
                </div>
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">Từ khóa SEO</p>
                  <p className="text-sm">{(brand.websiteSeo as any)?.trendtech?.seoKeywords || '-'}</p>
                </div>
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">URL Slug</p>
                  <p className="text-sm font-mono">{(brand.websiteSeo as any)?.trendtech?.slug || '-'}</p>
                </div>
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">Mô tả ngắn</p>
                  {(brand.websiteSeo as any)?.trendtech?.shortDescription ? (
                    <div className="prose prose-sm max-w-none text-sm border rounded-md p-3 bg-muted/30" dangerouslySetInnerHTML={{ __html: (brand.websiteSeo as any).trendtech.shortDescription }} />
                  ) : <p className="text-sm text-muted-foreground">-</p>}
                </div>
                <div className="space-y-1">
                  <p className="text-sm text-muted-foreground">Mô tả chi tiết</p>
                  {(brand.websiteSeo as any)?.trendtech?.longDescription ? (
                    <div className="prose prose-sm max-w-none text-sm border rounded-md p-3 bg-muted/30" dangerouslySetInnerHTML={{ __html: (brand.websiteSeo as any).trendtech.longDescription }} />
                  ) : <p className="text-sm text-muted-foreground">-</p>}
                </div>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>

        {/* Delete Alert */}
        <AlertDialog open={isDeleteAlertOpen} onOpenChange={setIsDeleteAlertOpen}>
          <AlertDialogContent>
            <AlertDialogHeader>
              <AlertDialogTitle>Xóa thương hiệu?</AlertDialogTitle>
              <AlertDialogDescription>
                Thương hiệu "{brand.name}" sẽ bị xóa khỏi hệ thống. Hành động này không thể hoàn tác.
              </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
              <AlertDialogCancel>Đóng</AlertDialogCancel>
              <AlertDialogAction onClick={handleDelete}>Xóa</AlertDialogAction>
            </AlertDialogFooter>
          </AlertDialogContent>
        </AlertDialog>
      </div>
    );
  }

  // Edit mode
  return (
    <div className="space-y-4 pb-8">
      <Form {...form}>
        <form className="space-y-6">
          <Tabs value={activeTab} onValueChange={(v) => setActiveTab(v as typeof activeTab)}>
            <TabsList className="grid w-full grid-cols-4 max-w-2xl">
              <TabsTrigger value="general">Thông tin</TabsTrigger>
              <TabsTrigger value="seo-default" className="gap-1">
                <Globe className="h-3 w-3" />
                SEO Chung
              </TabsTrigger>
              <TabsTrigger value="seo-pkgx" className="gap-1">
                <Globe className="h-3 w-3 text-red-500" />
                SEO PKGX
              </TabsTrigger>
              <TabsTrigger value="seo-trendtech" className="gap-1">
                <Globe className="h-3 w-3 text-blue-500" />
                SEO Trendtech
              </TabsTrigger>
            </TabsList>

            {/* General Tab */}
            <TabsContent value="general" className="space-y-4 mt-4">
              <Card>
                <CardHeader className="pb-3">
                  <CardTitle className="text-base">Thông tin cơ bản</CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                  <div className="grid grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="id"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Mã thương hiệu <span className="text-destructive">*</span></FormLabel>
                          <FormControl>
                            <Input 
                              placeholder="VD: APPLE" 
                              {...field} 
                              disabled
                              className="bg-muted"
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="name"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Tên thương hiệu <span className="text-destructive">*</span></FormLabel>
                          <FormControl>
                            <Input placeholder="VD: Apple Inc." {...field} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <FormField
                    control={form.control}
                    name="website"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Website</FormLabel>
                        <FormControl>
                          <div className="flex gap-2">
                            <Input placeholder="https://apple.com" {...field} />
                            {field.value && (
                              <Button
                                type="button"
                                variant="outline"
                                size="icon"
                                className="flex-shrink-0"
                                onClick={() => window.open(field.value, '_blank')}
                              >
                                <ExternalLink className="h-4 w-4" />
                              </Button>
                            )}
                          </div>
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="description"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Mô tả</FormLabel>
                        <FormControl>
                          <Textarea 
                            placeholder="Mô tả về thương hiệu..." 
                            {...field} 
                            rows={3}
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="isActive"
                    render={({ field }) => (
                      <FormItem className="flex flex-row items-center justify-between rounded-lg border p-3">
                        <div className="space-y-0.5">
                          <FormLabel>Kích hoạt</FormLabel>
                          <FormDescription>
                            Thương hiệu sẽ hiển thị trong danh sách lựa chọn
                          </FormDescription>
                        </div>
                        <FormControl>
                          <Switch
                            checked={field.value}
                            onCheckedChange={field.onChange}
                          />
                        </FormControl>
                      </FormItem>
                    )}
                  />
                </CardContent>
              </Card>

              {/* Logo Upload Card */}
              <Card>
                <CardHeader className="pb-3">
                  <CardTitle className="text-base flex items-center gap-2">
                    <ImageIcon className="h-4 w-4" />
                    Logo thương hiệu
                  </CardTitle>
                  <CardDescription>Tải lên logo thương hiệu (PNG, JPG, WebP - tối đa 2MB)</CardDescription>
                </CardHeader>
                <CardContent className="space-y-4">
                  {brand?.logo && logoFiles.length === 0 && (
                    <div className="flex items-center gap-4">
                      <div className="w-24 h-24 rounded-lg border overflow-hidden bg-muted flex items-center justify-center">
                        <OptimizedImage 
                          src={brand.logo} 
                          alt="Logo hiện tại" 
                          width={96}
                          height={96}
                          className="max-w-full max-h-full object-contain"
                        />
                      </div>
                      <div className="text-sm text-muted-foreground">
                        Logo hiện tại. Upload logo mới để thay thế.
                      </div>
                    </div>
                  )}
                  
                  <NewDocumentsUpload
                    accept={{ 'image/*': ['.png', '.jpg', '.jpeg', '.webp'] }}
                    maxFiles={1}
                    maxSize={2 * 1024 * 1024}
                    value={logoFiles}
                    onChange={setLogoFiles}
                    sessionId={logoSessionId}
                    onSessionChange={setLogoSessionId}
                    className="min-h-[120px]"
                  />
                </CardContent>
              </Card>
            </TabsContent>

            {/* SEO Default Tab */}
            <TabsContent value="seo-default" className="space-y-4 mt-4">
              <Card>
                <CardHeader className="pb-3">
                  <div className="flex items-center gap-2">
                    <Globe className="h-4 w-4" />
                    <CardTitle className="text-base">SEO Mặc định</CardTitle>
                  </div>
                  <CardDescription>Thông tin SEO chung - sẽ được dùng nếu không có SEO riêng</CardDescription>
                </CardHeader>
                <CardContent className="space-y-4">
                  <FormField
                    control={form.control}
                    name="seoTitle"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Tiêu đề SEO</FormLabel>
                        <FormControl>
                          <Input placeholder="Tiêu đề mặc định" {...field} value={field.value || ''} />
                        </FormControl>
                        <FormDescription>Title tag mặc định. Nên 50-60 ký tự.</FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="metaDescription"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Meta Description</FormLabel>
                        <FormControl>
                          <Textarea placeholder="Mô tả SEO mặc định" {...field} value={field.value || ''} rows={2} />
                        </FormControl>
                        <FormDescription>Nên 150-160 ký tự.</FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="seoKeywords"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Từ khóa SEO</FormLabel>
                        <FormControl>
                          <Input placeholder="từ khóa 1, từ khóa 2" {...field} value={field.value || ''} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="shortDescription"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Mô tả ngắn</FormLabel>
                        <FormControl>
                          <TipTapEditor
                            content={field.value || ''}
                            onChange={field.onChange}
                            placeholder="Mô tả ngắn gọn 1-2 câu..."
                            minHeight="100px"
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="longDescription"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Mô tả chi tiết</FormLabel>
                        <FormControl>
                          <TipTapEditor
                            content={field.value || ''}
                            onChange={field.onChange}
                            placeholder="Mô tả đầy đủ về thương hiệu..."
                            minHeight="200px"
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </CardContent>
              </Card>
            </TabsContent>

            {/* SEO PKGX Tab */}
            <TabsContent value="seo-pkgx" className="space-y-4 mt-4">
              <Card>
                <CardHeader className="pb-3">
                  <div className="flex items-center gap-2">
                    <Globe className="h-4 w-4 text-red-500" />
                    <CardTitle className="text-base">SEO cho PKGX</CardTitle>
                  </div>
                  <CardDescription>phukiengiaxuong.com.vn</CardDescription>
                </CardHeader>
                <CardContent className="space-y-4">
                  <FormField
                    control={form.control}
                    name="websiteSeo.pkgx.seoTitle"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Tiêu đề SEO</FormLabel>
                        <FormControl>
                          <Input placeholder="Tiêu đề cho PKGX" {...field} value={field.value || ''} />
                        </FormControl>
                        <FormDescription>Title tag. Nên 50-60 ký tự.</FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="websiteSeo.pkgx.metaDescription"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Meta Description</FormLabel>
                        <FormControl>
                          <Textarea placeholder="Mô tả SEO cho PKGX" {...field} value={field.value || ''} rows={2} />
                        </FormControl>
                        <FormDescription>Nên 150-160 ký tự.</FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="websiteSeo.pkgx.seoKeywords"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Từ khóa SEO</FormLabel>
                        <FormControl>
                          <Input placeholder="từ khóa 1, từ khóa 2" {...field} value={field.value || ''} />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="websiteSeo.pkgx.shortDescription"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Mô tả ngắn</FormLabel>
                        <FormControl>
                          <TipTapEditor
                            content={field.value || ''}
                            onChange={field.onChange}
                            placeholder="Mô tả ngắn gọn 1-2 câu..."
                            minHeight="100px"
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="websiteSeo.pkgx.longDescription"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Mô tả chi tiết</FormLabel>
                        <FormControl>
                          <TipTapEditor
                            content={field.value || ''}
                            onChange={field.onChange}
                            placeholder="Mô tả đầy đủ về thương hiệu..."
                            minHeight="200px"
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />

                  <FormField
                    control={form.control}
                    name="websiteSeo.pkgx.slug"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>URL Slug</FormLabel>
                        <FormControl>
                          <Input placeholder="thuong-hieu-abc" {...field} value={field.value || ''} />
                        </FormControl>
                        <FormDescription>Đường dẫn URL thân thiện</FormDescription>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </CardContent>
              </Card>

              <Card>
                <CardHeader className="pb-3">
                  <CardTitle className="text-base flex items-center gap-2"><BarChart3 className="h-4 w-4" /> Phân tích SEO</CardTitle>
                </CardHeader>
                <CardContent>
