  const sortedData = React.useMemo(() => {
    const sorted = [...filteredData];
    if (sorting.id) sorted.sort((a, b) => {
      const aV = (a as Record<string, unknown>)[sorting.id], bV = (b as Record<string, unknown>)[sorting.id];
      if (sorting.id === 'createdAt') { const aT = aV ? new Date(aV as string).getTime() : 0, bT = bV ? new Date(bV as string).getTime() : 0; return sorting.desc ? bT - aT : aT - bT; }
      const aS = String(aV ?? ''), bS = String(bV ?? '');
      return aS < bS ? (sorting.desc ? 1 : -1) : aS > bS ? (sorting.desc ? -1 : 1) : 0;
    });
    return sorted;
  }, [filteredData, sorting]);

  const allSelectedRows = React.useMemo(() => activeBrands.filter(b => rowSelection[b.systemId]), [activeBrands, rowSelection]);

  React.useEffect(() => { if (!isMobile) return; const h = () => { if ((window.pageYOffset + window.innerHeight) / document.documentElement.scrollHeight > 0.8 && mobileLoadedCount < sortedData.length) setMobileLoadedCount(p => Math.min(p + 20, sortedData.length)); }; window.addEventListener('scroll', h); return () => window.removeEventListener('scroll', h); }, [isMobile, mobileLoadedCount, sortedData.length]);
  React.useEffect(() => { setMobileLoadedCount(20); }, [debouncedGlobalFilter, statusFilter]);

  const pageCount = Math.ceil(sortedData.length / pagination.pageSize);
  const paginatedData = React.useMemo(() => sortedData.slice(pagination.pageIndex * pagination.pageSize, (pagination.pageIndex + 1) * pagination.pageSize), [sortedData, pagination]);

  const headerActions = React.useMemo(() => [<Button key="add" size="sm" className="h-9" onClick={() => router.push('/brands/new')}><Plus className="mr-2 h-4 w-4" />Thêm thương hiệu</Button>], [router]);
  usePageHeader({ actions: headerActions, showBackButton: false });

  return (
    <div className="space-y-4 h-full flex flex-col">
      {!isMobile && <PageToolbar leftActions={<><Button variant="outline" size="sm" onClick={() => setIsImportOpen(true)}><FileUp className="mr-2 h-4 w-4" />Nhập file</Button><Button variant="outline" size="sm" onClick={() => setIsExportOpen(true)}><Download className="mr-2 h-4 w-4" />Xuất Excel</Button></>} rightActions={[<DataTableColumnCustomizer key="c" columns={columns} columnVisibility={columnVisibility} setColumnVisibility={setColumnVisibility} columnOrder={columnOrder} setColumnOrder={setColumnOrder} pinnedColumns={pinnedColumns} setPinnedColumns={setPinnedColumns} />]} />}
      <PageFilters searchValue={globalFilter} onSearchChange={setGlobalFilter} searchPlaceholder="Tìm theo mã, tên..." rightFilters={<DataTableFacetedFilter title="Trạng thái" options={statusOptions} selectedValues={statusFilter} onSelectedValuesChange={setStatusFilter} />} />
      {isMobile ? (
        <div className="space-y-2 flex-1 overflow-y-auto">
          {sortedData.length === 0 ? <Card><CardContent className="p-8 text-center text-muted-foreground">Không tìm thấy thương hiệu</CardContent></Card> : <>
            {sortedData.slice(0, mobileLoadedCount).map(b => <MobileBrandCard key={b.systemId} brand={b as any} onDelete={handleDelete} onToggleActive={handleToggleActive} navigate={router.push} handleRowClick={handleRowClick} />)}
            {mobileLoadedCount < sortedData.length && <Card><CardContent className="p-4 text-center text-muted-foreground"><div className="flex items-center justify-center gap-2"><div className="animate-spin rounded-full h-4 w-4 border-b-2 border-primary" /><span>Đang tải...</span></div></CardContent></Card>}
            {mobileLoadedCount >= sortedData.length && sortedData.length > 20 && <Card><CardContent className="p-4 text-center text-muted-foreground text-sm">Đã hiển thị {sortedData.length} thương hiệu</CardContent></Card>}
          </>}
        </div>
      ) : (
        <div className="w-full py-4"><ResponsiveDataTable columns={columns} data={paginatedData as any} pageCount={pageCount} pagination={pagination} setPagination={setPagination} rowCount={sortedData.length} rowSelection={rowSelection} setRowSelection={setRowSelection} onBulkDelete={() => setIsBulkDeleteAlertOpen(true)} sorting={sorting} setSorting={setSorting as React.Dispatch<React.SetStateAction<{ id: string; desc: boolean }>>} allSelectedRows={allSelectedRows as any} bulkActions={bulkActions} pkgxBulkActions={pkgxBulkActions} expanded={{}} setExpanded={() => {}} columnVisibility={columnVisibility} setColumnVisibility={setColumnVisibility} columnOrder={columnOrder} setColumnOrder={setColumnOrder} pinnedColumns={pinnedColumns} setPinnedColumns={setPinnedColumns} onRowClick={handleRowClick} renderMobileCard={b => <MobileBrandCard brand={b as any} onDelete={handleDelete} onToggleActive={handleToggleActive} navigate={router.push} handleRowClick={handleRowClick} />} /></div>
      )}
      <AlertDialog open={isAlertOpen} onOpenChange={setIsAlertOpen}><AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Xóa thương hiệu?</AlertDialogTitle><AlertDialogDescription>Hành động này không thể hoàn tác.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Đóng</AlertDialogCancel><AlertDialogAction onClick={confirmDelete}>Xóa</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
      <AlertDialog open={isBulkDeleteAlertOpen} onOpenChange={setIsBulkDeleteAlertOpen}><AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Xóa {Object.keys(rowSelection).length} thương hiệu?</AlertDialogTitle><AlertDialogDescription>Hành động không thể hoàn tác.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Đóng</AlertDialogCancel><AlertDialogAction onClick={confirmBulkDelete}>Xóa tất cả</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
      <PkgxBrandLinkDialog open={pkgxLinkDialogOpen} onOpenChange={setPkgxLinkDialogOpen} brand={brandToLink} onSuccess={() => {}} />
      <PkgxBrandDetailDialog open={pkgxDetailDialogOpen} onOpenChange={setPkgxDetailDialogOpen} brand={brandToViewDetail} pkgxBrandId={pkgxBrandIdToView} />
      <PkgxBulkSyncConfirmDialog confirmAction={bulkConfirmAction} progress={bulkProgress} onConfirm={executeBulkAction} onCancel={cancelBulkConfirm} />
      <BrandImportDialog open={isImportOpen} onOpenChange={setIsImportOpen} existingData={activeBrands as any} onImport={handleImport} currentUser={authEmployee ? { systemId: authEmployee.systemId, name: authEmployee.fullName || authEmployee.id } : undefined} />
      <BrandExportDialog open={isExportOpen} onOpenChange={setIsExportOpen} allData={activeBrands as any} filteredData={sortedData as any} currentPageData={paginatedData as any} selectedData={allSelectedRows as any} currentUser={authEmployee ? { systemId: authEmployee.systemId, name: authEmployee.fullName || authEmployee.id } : { systemId: asSystemId('SYSTEM'), name: 'System' }} />
    </div>
  );
}

/**
 * Hook chứa tất cả các handlers để đồng bộ danh mục (Category) với PKGX
 * Tương tự như use-pkgx-sync.ts của products
 */
import React from 'react';
import { toast } from 'sonner';
import type { ProductCategory } from '@/features/settings/inventory/types';
import { updateCategory, updateCategoryBasic, getCategoryById } from '@/lib/pkgx/api-service';
import { usePkgxSettings, usePkgxCategoryMutations, usePkgxCategoryMappings } from '@/features/settings/pkgx/hooks/use-pkgx-settings';

// Types
type PkgxLogEntry = {
  action: 
    | 'sync_category_seo'
    | 'sync_category_description'
    | 'sync_category_all'
    | 'sync_category_basic';
  status: 'success' | 'error' | 'partial' | 'info';
  message: string;
  details?: Record<string, unknown>;
};

type UsePkgxCategorySyncOptions = {
  addPkgxLog?: (entry: PkgxLogEntry) => void;
};

/**
 * Lấy pkgxCatId từ category mapping
 */
function getPkgxCatId(category: ProductCategory, categoryMappings?: Array<{ hrmCategorySystemId: string; pkgxCatId: number }>) {
  
  if (!categoryMappings) {
    return undefined;
  }
  const mapping = categoryMappings.find(m => m.hrmCategorySystemId === category.systemId);
  return mapping?.pkgxCatId;
}

/**
 * Hook cung cấp các handlers để đồng bộ Category với PKGX
 */
export function usePkgxCategorySync({ addPkgxLog }: UsePkgxCategorySyncOptions = {}) {
  const { data: pkgxSettings } = usePkgxSettings();
  const categoryMappings = usePkgxCategoryMappings();
  const { updateCategory: updateCategoryMutation } = usePkgxCategoryMutations();

  // Default log function if not provided
  const logAction = React.useCallback((entry: PkgxLogEntry) => {
    if (addPkgxLog) {
      addPkgxLog(entry);
    }
  }, [addPkgxLog]);

  // ═══════════════════════════════════════════════════════════════
  // HELPER: Refresh category data từ PKGX sau khi sync thành công
  // ═══════════════════════════════════════════════════════════════
  const refreshCategoryFromPkgx = React.useCallback(async (pkgxCatId: number) => {
    try {
      const response = await getCategoryById(pkgxCatId);
      if (response.success && response.data?.data?.[0]) {
        const data = response.data.data[0];
        // Cập nhật vào store
        updateCategoryMutation.mutate({
          id: pkgxCatId,
          updates: {
            id: data.cat_id,
            name: data.cat_name,
            parentId: data.parent_id || 0,
            cat_desc: data.cat_desc || '',
            keywords: data.keywords || '',
            cat_alias: data.cat_alias || '',
            grade: data.grade || 0,
          },
        });
      }
    } catch (_error) {
      // Silently ignore sync errors
    }
  }, [updateCategoryMutation]);

  // ═══════════════════════════════════════════════════════════════
  // 1. SYNC SEO (keywords, meta_title, meta_desc)
  // ═══════════════════════════════════════════════════════════════
  const handleSyncSeo = React.useCallback(async (category: ProductCategory) => {
    const pkgxCatId = getPkgxCatId(category, categoryMappings);
    
    if (!pkgxCatId) {
      toast.error('Danh mục chưa được liên kết với PKGX. Vui lòng mapping trong Cài đặt > PKGX.');
      return;
    }
    
    toast.loading(`Đang đồng bộ SEO danh mục...`, { id: 'pkgx-category-sync-seo' });
    
    try {
      const pkgxSeo = category.websiteSeo?.pkgx;
      // Fallback chain: SEO PKGX → SEO Chung → name
      // Category DB columns: keywords, meta_title, meta_desc (NO cat_alias, NO short_desc!)
      const seoPayload = {
        keywords: pkgxSeo?.seoKeywords || category.seoKeywords || category.name,
        meta_title: pkgxSeo?.seoTitle || category.seoTitle || category.name,
        meta_desc: pkgxSeo?.metaDescription || category.metaDescription || '',
      };
      
      // DEBUG
      
      const response = await updateCategory(pkgxCatId, seoPayload);
      
      
      if (response.success) {
        // Auto-refresh để cập nhật store
        await refreshCategoryFromPkgx(pkgxCatId);
        
        toast.success(`Đã đồng bộ SEO cho danh mục: ${category.name}`, { id: 'pkgx-category-sync-seo' });
        logAction({
          action: 'sync_category_seo',
          status: 'success',
          message: `Đã đồng bộ SEO: ${category.name}`,
          details: { categoryId: category.systemId, pkgxCatId, payload: seoPayload },
        });
      } else {
        throw new Error(response.error);
      }
    } catch (error) {
      toast.error(`Lỗi đồng bộ SEO danh mục: ${error instanceof Error ? error.message : 'Unknown error'}`, { id: 'pkgx-category-sync-seo' });
      logAction({
        action: 'sync_category_seo',
        status: 'error',
        message: `Lỗi đồng bộ SEO: ${category.name}`,
        details: { categoryId: category.systemId, error: error instanceof Error ? error.message : String(error) },
      });
    }
  }, [pkgxSettings?.categoryMappings, categoryMappings, logAction, refreshCategoryFromPkgx]);

  // ═══════════════════════════════════════════════════════════════
  // 2. SYNC MÔ TẢ (cat_desc = longDescription)
  // ═══════════════════════════════════════════════════════════════
  const handleSyncDescription = React.useCallback(async (category: ProductCategory) => {
    const pkgxCatId = getPkgxCatId(category, pkgxSettings?.categoryMappings);
    
    if (!pkgxCatId) {
      toast.error('Danh mục chưa được liên kết với PKGX. Vui lòng mapping trong Cài đặt > PKGX.');
      return;
    }
    
    toast.loading(`Đang đồng bộ mô tả danh mục...`, { id: 'pkgx-category-sync-desc' });
    
    try {
      const pkgxSeo = category.websiteSeo?.pkgx;
      // Category DB: cat_desc = mô tả ngắn, long_desc = mô tả dài (NO short_desc column!)
      const descPayload = {
        cat_desc: pkgxSeo?.shortDescription || category.shortDescription || '',
        long_desc: pkgxSeo?.longDescription || category.longDescription || '',
      };
      
      
      const response = await updateCategory(pkgxCatId, descPayload);
      
      if (response.success) {
        // Auto-refresh để cập nhật store
        await refreshCategoryFromPkgx(pkgxCatId);
        
        toast.success(`Đã đồng bộ mô tả cho danh mục: ${category.name}`, { id: 'pkgx-category-sync-desc' });
        logAction({
          action: 'sync_category_description',
          status: 'success',
          message: `Đã đồng bộ mô tả: ${category.name}`,
          details: { categoryId: category.systemId, pkgxCatId },
        });
      } else {
        throw new Error(response.error);
      }
    } catch (error) {
      toast.error(`Lỗi đồng bộ mô tả danh mục: ${error instanceof Error ? error.message : 'Unknown error'}`, { id: 'pkgx-category-sync-desc' });
      logAction({
        action: 'sync_category_description',
        status: 'error',
        message: `Lỗi đồng bộ mô tả: ${category.name}`,
        details: { categoryId: category.systemId, error: error instanceof Error ? error.message : String(error) },
      });
    }
  }, [pkgxSettings?.categoryMappings, logAction, refreshCategoryFromPkgx]);

  // ═══════════════════════════════════════════════════════════════
  // 3. SYNC TẤT CẢ (SEO + Mô tả + Slug)
  // ═══════════════════════════════════════════════════════════════
  const handleSyncAll = React.useCallback(async (category: ProductCategory) => {
    const pkgxCatId = getPkgxCatId(category, pkgxSettings?.categoryMappings);
    
    if (!pkgxCatId) {
      toast.error('Danh mục chưa được liên kết với PKGX. Vui lòng mapping trong Cài đặt > PKGX.');
      return;
    }
    
    toast.loading(`Đang đồng bộ tất cả thông tin danh mục...`, { id: 'pkgx-category-sync-all' });
    
    try {
      const pkgxSeo = category.websiteSeo?.pkgx;
      
      // Build full payload
      // Category DB: cat_desc = mô tả ngắn, long_desc = mô tả dài (NO short_desc column!)
      const fullPayload = {
        // Basic info
        cat_name: category.name,
        cat_alias: pkgxSeo?.slug || category.slug || '',
        // SEO fields - Fallback chain: SEO PKGX → SEO Chung → name
        keywords: pkgxSeo?.seoKeywords || category.seoKeywords || category.name,
        meta_title: pkgxSeo?.seoTitle || category.seoTitle || category.name,
        meta_desc: pkgxSeo?.metaDescription || category.metaDescription || '',
        // Descriptions
        cat_desc: pkgxSeo?.shortDescription || category.shortDescription || '',
        long_desc: pkgxSeo?.longDescription || category.longDescription || '',
      };
      
      
      const response = await updateCategory(pkgxCatId, fullPayload);
      
      if (response.success) {
        // Auto-refresh để cập nhật store
        await refreshCategoryFromPkgx(pkgxCatId);
        
        toast.success(`Đã đồng bộ tất cả thông tin danh mục: ${category.name}`, { id: 'pkgx-category-sync-all' });
        logAction({
          action: 'sync_category_all',
          status: 'success',
          message: `Đã đồng bộ tất cả: ${category.name}`,
          details: { categoryId: category.systemId, pkgxCatId },
        });
      } else {
        throw new Error(response.error);
      }
    } catch (error) {
      toast.error(`Lỗi đồng bộ danh mục: ${error instanceof Error ? error.message : 'Unknown error'}`, { id: 'pkgx-category-sync-all' });
      logAction({
        action: 'sync_category_all',
        status: 'error',
        message: `Lỗi đồng bộ: ${category.name}`,
        details: { categoryId: category.systemId, error: error instanceof Error ? error.message : String(error) },
      });
    }
  }, [pkgxSettings?.categoryMappings, logAction, refreshCategoryFromPkgx]);

  // ═══════════════════════════════════════════════════════════════
  // 4. SYNC BASIC (cat_name, is_show)
  // ═══════════════════════════════════════════════════════════════
  const handleSyncBasic = React.useCallback(async (category: ProductCategory) => {
    const pkgxCatId = getPkgxCatId(category, pkgxSettings?.categoryMappings);
    
    if (!pkgxCatId) {
      toast.error('Danh mục chưa được liên kết với PKGX. Vui lòng mapping trong Cài đặt > PKGX.');
      return;
    }
    
    toast.loading(`Đang đồng bộ thông tin cơ bản danh mục...`, { id: 'pkgx-category-sync-basic' });
    
    try {
      // Build payload - chỉ tên và trạng thái hiển thị
      const basicPayload = {
        cat_name: category.name,
        is_show: category.isActive ? 1 : 0,
      };
      
      
      const response = await updateCategoryBasic(pkgxCatId, basicPayload);
      
      if (response.success) {
        // Auto-refresh để cập nhật store
        await refreshCategoryFromPkgx(pkgxCatId);
        
        toast.success(`Đã đồng bộ thông tin cơ bản danh mục: ${category.name}`, { id: 'pkgx-category-sync-basic' });
        logAction({
          action: 'sync_category_basic',
          status: 'success',
          message: `Đã đồng bộ thông tin cơ bản: ${category.name}`,
          details: { categoryId: category.systemId, pkgxCatId, payload: basicPayload },
        });
      } else {
        throw new Error(response.error);
      }
    } catch (error) {
      toast.error(`Lỗi đồng bộ thông tin cơ bản: ${error instanceof Error ? error.message : 'Unknown error'}`, { id: 'pkgx-category-sync-basic' });
      logAction({
        action: 'sync_category_basic',
        status: 'error',
        message: `Lỗi đồng bộ thông tin cơ bản: ${category.name}`,
        details: { categoryId: category.systemId, error: error instanceof Error ? error.message : String(error) },
      });
    }
  }, [pkgxSettings?.categoryMappings, logAction, refreshCategoryFromPkgx]);

  // ═══════════════════════════════════════════════════════════════
  // HELPER: Kiểm tra category có mapping với PKGX không
  // ═══════════════════════════════════════════════════════════════
  const hasPkgxMapping = React.useCallback((category: ProductCategory) => {
    return !!getPkgxCatId(category, pkgxSettings?.categoryMappings);
  }, [pkgxSettings?.categoryMappings]);

  return {
    handleSyncSeo,
    handleSyncDescription,
    handleSyncAll,
    handleSyncBasic,
    hasPkgxMapping,
    getPkgxCatId: (category: ProductCategory) => getPkgxCatId(category, pkgxSettings?.categoryMappings),
  };
}

