    </div>
  );
}

'use client'

import * as React from 'react';
import { useRouter } from 'next/navigation';
import { useForm, useFieldArray } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { useCostAdjustmentMutations } from './hooks/use-cost-adjustments';
import { useProductFinder } from '../products/hooks/use-all-products';
import { ProductImage } from '../products/components/product-image';
import { useEmployeeFinder } from '../employees/hooks/use-all-employees';
import { useAuth } from '../../contexts/auth-context';
import { usePageHeader } from '../../contexts/page-header-context';
import { ROUTES } from '../../lib/router';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card';
import { Button } from '../../components/ui/button';
import { Input } from '../../components/ui/input';
import { CurrencyInput } from '../../components/ui/currency-input';
import { Label } from '../../components/ui/label';
import { Textarea } from '../../components/ui/textarea';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '../../components/ui/table';
import { ProductSelectionDialog } from '../shared/product-selection-dialog';
import { Plus, X, Save, Trash2, Package, TrendingUp, TrendingDown } from 'lucide-react';
import { toast } from 'sonner';
import { asSystemId } from '../../lib/id-types';
import type { Product } from '@/lib/types/prisma-extended';
import { formatDateTimeForDisplay } from '@/lib/date-utils';

const formatCurrency = (value: number) => value.toLocaleString('vi-VN') + ' đ';

const formSchema = z.object({
  customId: z.string().optional(),
  reason: z.string().optional(),
  note: z.string().optional(),
  referenceCode: z.string().optional(),
  items: z.array(z.object({
    productSystemId: z.string(),
    productId: z.string(),
    productName: z.string(),
    productImage: z.string().optional(),
    oldCostPrice: z.number(),
    newCostPrice: z.number().min(0, 'Giá vốn mới phải >= 0'),
  })).min(1, 'Vui lòng thêm ít nhất 1 sản phẩm'),
});

type FormData = z.infer<typeof formSchema>;

export function CostAdjustmentFormPage() {
  const router = useRouter();
  const { setPageHeader, clearPageHeader } = usePageHeader();
  const { user } = useAuth();
  const { findById: findEmployeeById } = useEmployeeFinder();
  const { findById: findProductById } = useProductFinder();
  const { create } = useCostAdjustmentMutations({
    onSuccess: () => {
      toast.success('Đã tạo phiếu điều chỉnh giá vốn');
    },
    onError: (error) => {
      toast.error(error.message || 'Có lỗi xảy ra khi tạo phiếu');
    },
  });
  
  const [isProductDialogOpen, setIsProductDialogOpen] = React.useState(false);
  const [isSubmitting, setIsSubmitting] = React.useState(false);
  
  const currentEmployee = user?.employeeId ? findEmployeeById(asSystemId(user.employeeId)) : null;
  // TODO: Implement generateNextId via API if needed
  const nextId = 'AUTO';
  const customIdError = null;
  
  const form = useForm<FormData>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      customId: '',
      reason: '',
      note: '',
      referenceCode: '',
      items: [],
    },
  });
  
  const { fields, append, remove, update: _update } = useFieldArray({
    control: form.control,
    name: 'items',
  });
  
  const watchItems = form.watch('items');
  const watchCustomId = form.watch('customId');
  
  // TODO: Implement ID validation via API if needed
  
  // Calculate totals
  const totalOldValue = watchItems.reduce((sum, item) => sum + item.oldCostPrice, 0);
  const totalNewValue = watchItems.reduce((sum, item) => sum + item.newCostPrice, 0);
  const totalDifference = totalNewValue - totalOldValue;

  const handleAddProducts = (selectedProducts: Product[]) => {
    selectedProducts.forEach(product => {
      // Check if already added
      const existingIndex = fields.findIndex(f => f.productSystemId === product.systemId);
      if (existingIndex >= 0) {
        toast.warning(`${product.name} đã có trong danh sách`);
        return;
      }
      
      append({
        productSystemId: product.systemId,
        productId: product.id,
        productName: product.name,
        productImage: product.thumbnailImage || product.galleryImages?.[0] || product.images?.[0] || '',
        oldCostPrice: product.costPrice || 0,
        newCostPrice: product.costPrice || 0, // Default to same as old
      });
    });
    setIsProductDialogOpen(false);
  };
  
  const onSubmit = async (data: FormData) => {
    if (!currentEmployee) {
      toast.error('Không tìm thấy thông tin nhân viên');
      return;
    }
    
    // Check if any price changed
    const hasChanges = data.items.some(item => item.newCostPrice !== item.oldCostPrice);
    if (!hasChanges) {
      toast.error('Vui lòng thay đổi giá vốn ít nhất 1 sản phẩm');
      return;
    }
    
    setIsSubmitting(true);
    
    try {
      const result = await create.mutateAsync({
        items: data.items.map(item => ({
          productSystemId: asSystemId(item.productSystemId),
          productId: item.productId,
          productName: item.productName,
          productImage: item.productImage,
          oldCostPrice: item.oldCostPrice,
          newCostPrice: item.newCostPrice,
          adjustmentAmount: item.newCostPrice - item.oldCostPrice,
          adjustmentPercent: item.oldCostPrice > 0 ? ((item.newCostPrice - item.oldCostPrice) / item.oldCostPrice * 100) : 0,
        })),
        type: 'manual',
        reason: data.reason,
        note: data.note,
        referenceCode: data.referenceCode,
        businessId: data.customId,
      } as any);
      
      router.push(`/cost-adjustments/${result.systemId}`);
    } catch (_error) {
      // Error handled by mutation callbacks
    } finally {
      setIsSubmitting(false);
    }
  };
  
  const headerActions = React.useMemo(() => (
    <div className="flex items-center gap-2">
      <Button 
        variant="outline" 
        className="h-9"
        onClick={() => router.push('/cost-adjustments')}
        disabled={isSubmitting}
      >
        <X className="mr-2 h-4 w-4" />
        Hủy
      </Button>
      <Button 
        type="submit" 
        form="adjustment-form"
        className="h-9"
        disabled={isSubmitting || fields.length === 0}
      >
        <Save className="mr-2 h-4 w-4" />
        {isSubmitting ? 'Đang lưu...' : 'Tạo phiếu'}
      </Button>
    </div>
  ), [router, isSubmitting, fields.length]);
  
  const breadcrumb = React.useMemo(() => [
    { label: 'Trang chủ', href: ROUTES.ROOT },
    { label: 'Điều chỉnh giá vốn', href: '/cost-adjustments' },
    { label: 'Tạo phiếu', href: '' },
  ], []);
  
  React.useEffect(() => {
    setPageHeader({
      title: 'Tạo phiếu điều chỉnh giá vốn',
      subtitle: `Mã phiếu: ${watchCustomId || nextId} • Điều chỉnh giá vốn sản phẩm`,
      breadcrumb,
      showBackButton: true,
      backPath: '/cost-adjustments',
      actions: headerActions,
    });
    return () => clearPageHeader();
  }, [setPageHeader, clearPageHeader, breadcrumb, headerActions, watchCustomId, nextId]);
  
  return (
    <div className="space-y-6">
      <form id="adjustment-form" onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
        {/* Basic Info */}
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Thông tin phiếu điều chỉnh</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="space-y-2">
                <Label>Mã phiếu</Label>
                <Input 
                  {...form.register('customId')}
                  placeholder={nextId}
                  className="h-9"
                />
                {customIdError ? (
                  <p className="text-sm text-destructive">{customIdError}</p>
                ) : (
                  <p className="text-xs text-muted-foreground">
                    Để trống để tự động tạo mã: {nextId}
                  </p>
                )}
              </div>

              <div className="space-y-2">
                <Label>Mã tham chiếu</Label>
                <Input 
                  {...form.register('referenceCode')}
                  placeholder="Nhập mã tham chiếu (nếu có)..."
                  className="h-9"
                />
                <p className="text-xs text-muted-foreground">
                  Mã từ hệ thống khác hoặc mã nội bộ
                </p>
              </div>
              
              <div className="space-y-2">
                <Label>Người tạo</Label>
                <Input 
                  value={currentEmployee?.fullName || user?.name || 'Không xác định'}
                  disabled
                  className="h-9 bg-muted"
                />
                <p className="text-xs text-muted-foreground">
                  {formatDateTimeForDisplay(new Date())}
                </p>
              </div>
            </div>

            <div className="space-y-2">
              <Label>Lý do điều chỉnh</Label>
              <Input 
                {...form.register('reason')}
                placeholder="Ví dụ: Cập nhật giá theo đơn nhập mới, Điều chỉnh giá theo thị trường..."
                className="h-9"
              />
            </div>

            <div className="space-y-2">
              <Label>Ghi chú</Label>
              <Textarea
                {...form.register('note')}
                placeholder="Ghi chú thêm..."
                rows={2}
              />
            </div>
          </CardContent>
        </Card>

        {/* Product List */}
        <Card>
          <CardHeader className="flex flex-row items-center justify-between">
            <CardTitle className="text-base">Danh sách sản phẩm</CardTitle>
            <Button
              type="button"
              variant="outline"
              size="sm"
              onClick={() => setIsProductDialogOpen(true)}
            >
              <Plus className="mr-2 h-4 w-4" />
              Thêm sản phẩm
            </Button>
          </CardHeader>
          <CardContent>
            {fields.length === 0 ? (
              <div className="text-center py-8 text-muted-foreground">
                <Package className="mx-auto h-12 w-12 mb-2 opacity-50" />
                <p>Chưa có sản phẩm nào</p>
                <Button
                  type="button"
                  variant="link"
                  onClick={() => setIsProductDialogOpen(true)}
                >
                  Thêm sản phẩm
                </Button>
              </div>
            ) : (
              <div className="overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead className="w-[50px]">#</TableHead>
                      <TableHead className="w-[60px]">Ảnh</TableHead>
                      <TableHead>Sản phẩm</TableHead>
                      <TableHead className="w-[150px] text-right">Giá vốn cũ</TableHead>
                      <TableHead className="w-[150px] text-right">Giá vốn mới</TableHead>
                      <TableHead className="w-[150px] text-right">Chênh lệch</TableHead>
                      <TableHead className="w-[50px]"></TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {fields.map((field, index) => {
                      const linkedProduct = findProductById(asSystemId(field.productSystemId));
                      const newPrice = watchItems[index]?.newCostPrice || 0;
                      const oldPrice = field.oldCostPrice;
                      const difference = newPrice - oldPrice;
                      const percentChange = oldPrice > 0 ? (difference / oldPrice) * 100 : 0;
                      
                      return (
                        <TableRow key={field.id}>
                          <TableCell className="text-muted-foreground">{index + 1}</TableCell>
                          <TableCell>
                            <ProductImage
                              productSystemId={field.productSystemId}
                              productData={linkedProduct}
                              alt={field.productName}
                              size="md"
                            />
                          </TableCell>
                          <TableCell>
                            <div>
                              <p className="font-medium">{field.productName}</p>
                              <p className="text-sm text-muted-foreground">{field.productId}</p>
                            </div>
                          </TableCell>
                          <TableCell className="text-right text-muted-foreground">
                            {formatCurrency(oldPrice)}
                          </TableCell>
                          <TableCell>
                            <CurrencyInput
                              value={watchItems[index]?.newCostPrice || 0}
                              onChange={(value) => form.setValue(`items.${index}.newCostPrice`, value)}
                              className="h-9 w-[150px]"
                            />
                          </TableCell>
                          <TableCell className="text-right">
                            <div className="flex items-center justify-end gap-1">
                              {difference !== 0 && (
                                difference > 0 ? (
                                  <TrendingUp className="h-4 w-4 text-green-600" />
                                ) : (
                                  <TrendingDown className="h-4 w-4 text-red-600" />
                                )
                              )}
                              <span className={`font-medium ${
                                difference > 0 ? 'text-green-600' : 
                                difference < 0 ? 'text-red-600' : 
                                'text-muted-foreground'
                              }`}>
                                {difference >= 0 ? '+' : ''}{formatCurrency(difference)}
                              </span>
                            </div>
                            {difference !== 0 && (
                              <p className={`text-xs ${
                                difference > 0 ? 'text-green-600' : 'text-red-600'
                              }`}>
                                {difference >= 0 ? '+' : ''}{percentChange.toFixed(1)}%
                              </p>
                            )}
                          </TableCell>
                          <TableCell>
                            <Button
                              type="button"
                              variant="ghost"
                              size="icon"
                              onClick={() => remove(index)}
                            >
                              <Trash2 className="h-4 w-4 text-destructive" />
                            </Button>
                          </TableCell>
                        </TableRow>
                      );
                    })}
                  </TableBody>
                </Table>
                
                <div className="mt-4 flex justify-end">
                  <div className="text-right space-y-1">
                    <p className="text-sm text-muted-foreground">
                      Tổng số sản phẩm: {fields.length}
                    </p>
                    <p className="text-sm text-muted-foreground">
                      Tổng giá vốn cũ: {formatCurrency(totalOldValue)}
                    </p>
                    <p className="text-sm text-muted-foreground">
                      Tổng giá vốn mới: {formatCurrency(totalNewValue)}
                    </p>
                    <p className={`font-semibold ${
                      totalDifference > 0 ? 'text-green-600' : 
                      totalDifference < 0 ? 'text-red-600' : ''
                    }`}>
                      Chênh lệch: {totalDifference >= 0 ? '+' : ''}{formatCurrency(totalDifference)}
                    </p>
                  </div>
                </div>
              </div>
            )}
            
            {form.formState.errors.items && (
              <p className="text-sm text-destructive mt-2">{form.formState.errors.items.message}</p>
            )}
          </CardContent>
        </Card>
      </form>

      {/* Product Selection Dialog */}
      <ProductSelectionDialog
        isOpen={isProductDialogOpen}
        onOpenChange={setIsProductDialogOpen}
        onSelect={handleAddProducts}
      />
    </div>
  );
}

import * as React from 'react';
import type { Customer } from '../types';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../../../components/ui/card';
import { Badge } from '../../../components/ui/badge';
import { Button } from '../../../components/ui/button';
import { Check, Clock, MoreHorizontal, HelpCircle, AlertTriangle, AlertCircle, Info } from 'lucide-react';
import { format } from 'date-fns';
import { vi } from 'date-fns/locale';
import { useCustomerSlaEngineStore } from '../sla/store';
import { useCustomerMutations } from '../hooks/use-customers';
import { formatDaysRemaining } from '../../reports/customer-sla-report/sla-utils';
import { SLA_TYPE_BADGES } from '../sla/constants';
import type { CustomerSlaAlert } from '../sla/types';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '../../../components/ui/dropdown-menu';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '../../../components/ui/tooltip';
import { Progress } from '../../../components/ui/progress';
import { toast } from 'sonner';

type Props = {
  customer: Customer;
};

export function CustomerSlaStatusCard({ customer }: Props) {
  const entry = useCustomerSlaEngineStore((state) => state.index?.entries[customer.systemId]);
  const acknowledge = useCustomerSlaEngineStore((state) => state.acknowledge);
  const snooze = useCustomerSlaEngineStore((state) => state.snooze);
  const getAck = useCustomerSlaEngineStore((state) => state.getAck);
  const isSnoozed = useCustomerSlaEngineStore((state) => state.isSnoozed);
  const getSnoozeRemaining = useCustomerSlaEngineStore((state) => state.getSnoozeRemaining);
  const { update } = useCustomerMutations();
  const triggerReevaluation = useCustomerSlaEngineStore((state) => state.triggerReevaluation);

  // Handle acknowledge: update SLA store AND customer's lastContactDate (only for follow-up SLA)
  const handleAcknowledge = React.useCallback((alert: CustomerSlaAlert) => {
    const now = new Date().toISOString();
    
    // 1. Update SLA acknowledgement
    acknowledge(customer.systemId, alert, { actionType: 'acknowledged' });
    
    // 2. Only update customer's lastContactDate for follow-up SLA to reset that cycle
    // For other SLA types (re-engagement, debt-payment), just acknowledge without resetting baseline
    if (alert.slaType === 'follow-up') {
      update.mutate({
        systemId: customer.systemId,
        lastContactDate: now,
      } as any, {
        onSuccess: () => {
          toast.success('Đã xác nhận xử lý SLA', {
            description: 'Ngày liên hệ cuối đã được cập nhật',
          });
          
          // 3. Trigger re-evaluation after a short delay
          setTimeout(() => triggerReevaluation(), 500);
        },
      });
    } else {
      toast.success('Đã xác nhận xử lý SLA', {
        description: `SLA "${alert.slaName}" đã được đánh dấu xử lý`,
      });
    }
  }, [customer.systemId, acknowledge, update, triggerReevaluation]);

  // Handle snooze
  const handleSnooze = React.useCallback((alert: CustomerSlaAlert, days: number) => {
    snooze(customer.systemId, alert, days);
    toast.success(`Đã tạm ẩn ${days} ngày`, {
      description: `SLA sẽ hiển thị lại sau ${days} ngày`,
    });
  }, [customer.systemId, snooze]);

  if (!entry) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>Trạng thái SLA</CardTitle>
          <CardDescription>Không có cảnh báo nào</CardDescription>
        </CardHeader>
        <CardContent>
          <p className="text-body-sm text-muted-foreground">
            Khách hàng này hiện không có SLA nào cần theo dõi.
          </p>
        </CardContent>
      </Card>
    );
  }

  const alerts = entry.alerts;
  const debtAlert = entry.debtAlert;
  const healthAlert = entry.healthAlert;

  // Calculate summary stats
  const totalAlerts = alerts.length + (debtAlert ? 1 : 0) + (healthAlert ? 1 : 0);
  const overdueCount = alerts.filter(a => a.alertLevel === 'overdue').length;
  const criticalCount = alerts.filter(a => a.alertLevel === 'critical').length;
  const warningCount = alerts.filter(a => a.alertLevel === 'warning').length;
  const acknowledgedCount = alerts.filter(a => {
    const ack = getAck(customer.systemId, a.slaType);
    return ack?.targetDate === a.targetDate;
  }).length;
  const snoozedCount = alerts.filter(a => isSnoozed(customer.systemId, a.slaType)).length;
  const processedCount = acknowledgedCount + snoozedCount;
  const progressPercent = totalAlerts > 0 ? Math.round((processedCount / totalAlerts) * 100) : 0;

  if (!alerts.length && !debtAlert && !healthAlert) {
    return (
      <Card>
        <CardHeader>
          <CardTitle>Trạng thái SLA</CardTitle>
          <CardDescription>Không có cảnh báo nào</CardDescription>
        </CardHeader>
        <CardContent>
          <p className="text-body-sm text-muted-foreground">
            Khách hàng này hiện không có SLA nào cần theo dõi.
          </p>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>Trạng thái SLA</CardTitle>
        <CardDescription>Danh sách cảnh báo cần xử lý</CardDescription>
      </CardHeader>
      <CardContent className="space-y-4">
        {/* Summary Bar */}
        <div className="bg-muted/50 rounded-lg p-3 space-y-3">
          {/* Progress */}
          <div className="space-y-1.5">
            <div className="flex justify-between text-body-sm">
              <span className="text-muted-foreground">Tiến độ xử lý</span>
              <span className="font-medium">{processedCount}/{totalAlerts} ({progressPercent}%)</span>
            </div>
            <Progress value={progressPercent} className="h-2" />
          </div>
          
          {/* Alert counts by level */}
          <div className="flex flex-wrap gap-2">
            {overdueCount > 0 && (
              <TooltipProvider delayDuration={0}>
                <Tooltip>
                  <TooltipTrigger asChild>
                    <Badge variant="destructive" className="cursor-help">
                      <AlertTriangle className="h-3 w-3 mr-1" />
                      {overdueCount} quá hạn
                    </Badge>
                  </TooltipTrigger>
                  <TooltipContent>
                    <p>SLA đã quá hạn mục tiêu, cần xử lý ngay</p>
                  </TooltipContent>
                </Tooltip>
              </TooltipProvider>
            )}
            {criticalCount > 0 && (
              <TooltipProvider delayDuration={0}>
                <Tooltip>
                  <TooltipTrigger asChild>
                    <Badge variant="warning" className="cursor-help">
                      <AlertCircle className="h-3 w-3 mr-1" />
                      {criticalCount} nghiêm trọng
                    </Badge>
                  </TooltipTrigger>
                  <TooltipContent>
                    <p>SLA sắp đến hạn (còn 1-2 ngày), ưu tiên xử lý</p>
                  </TooltipContent>
                </Tooltip>
              </TooltipProvider>
            )}
            {warningCount > 0 && (
              <TooltipProvider delayDuration={0}>
                <Tooltip>
                  <TooltipTrigger asChild>
                    <Badge variant="secondary" className="cursor-help">
                      <Info className="h-3 w-3 mr-1" />
                      {warningCount} cảnh báo
                    </Badge>
                  </TooltipTrigger>
                  <TooltipContent>
                    <p>SLA cần theo dõi, còn vài ngày để xử lý</p>
                  </TooltipContent>
                </Tooltip>
              </TooltipProvider>
            )}
            {acknowledgedCount > 0 && (
              <Badge variant="outline" className="text-green-600 border-green-200 bg-green-50">
                <Check className="h-3 w-3 mr-1" />
                {acknowledgedCount} đã xử lý
              </Badge>
            )}
            {snoozedCount > 0 && (
              <Badge variant="outline" className="text-amber-600 border-amber-200 bg-amber-50">
                <Clock className="h-3 w-3 mr-1" />
                {snoozedCount} tạm ẩn
              </Badge>
            )}
          </div>
        </div>

        {alerts.map(alert => {
          const ack = getAck(customer.systemId, alert.slaType);
          const isAcknowledged = ack?.targetDate === alert.targetDate;
          const alertIsSnoozed = isSnoozed(customer.systemId, alert.slaType);
          const snoozeRemaining = getSnoozeRemaining(customer.systemId, alert.slaType);
          const badgeMeta = SLA_TYPE_BADGES[alert.slaType];
          const colorClass = badgeMeta?.color || 'text-slate-600 bg-slate-100';
          
          return (
            <div key={`${alert.slaType}-${alert.targetDate}`} className="border border-border rounded-lg p-3 space-y-2">
              <div className="flex justify-between items-center">
                <div>
                  <div className="flex items-center gap-2">
                    <Badge variant="outline" className={colorClass}>{badgeMeta?.label || alert.slaName}</Badge>
                    <span className="text-body-sm font-medium">{formatDaysRemaining(alert.daysRemaining)}</span>
                  </div>
                  <p className="text-body-sm text-muted-foreground">
                    Ngày mục tiêu: {format(new Date(alert.targetDate), 'dd/MM/yyyy', { locale: vi })}
                  </p>
                </div>
                <Badge variant={alert.alertLevel === 'overdue' ? 'destructive' : 'secondary'}>
                  {alert.alertLevel === 'overdue' ? 'Quá hạn' : alert.alertLevel === 'critical' ? 'Nghiêm trọng' : alert.alertLevel === 'warning' ? 'Cảnh báo' : 'Bình thường'}
                </Badge>
              </div>
              <div className="flex items-center justify-between text-body-sm text-muted-foreground">
                <span>Phụ trách: {alert.assignee || '—'}</span>
                <span>Hoạt động cuối: {alert.lastActivityDate ? format(new Date(alert.lastActivityDate), 'dd/MM/yyyy', { locale: vi }) : '—'}</span>
              </div>
              <div className="flex justify-end gap-2">
                {alertIsSnoozed ? (
                  <Badge variant="outline" className="text-amber-600">
                    <Clock className="h-3 w-3 mr-1" /> Tạm ẩn còn {snoozeRemaining} ngày
                  </Badge>
                ) : isAcknowledged ? (
                  <Badge variant="outline" className="text-green-600">
                    <Check className="h-3 w-3 mr-1" /> Đã xác nhận {format(new Date(ack!.acknowledgedAt), 'dd/MM HH:mm', { locale: vi })}
                  </Badge>
                ) : (
                  <div className="flex gap-2">
                    <TooltipProvider delayDuration={0}>
                      <Tooltip>
                        <TooltipTrigger asChild>
                          <Button variant="outline" size="sm" onClick={() => handleAcknowledge(alert)}>
                            <Check className="h-4 w-4 mr-1" /> Đã xử lý
                          </Button>
                        </TooltipTrigger>
                        <TooltipContent side="top" className="max-w-xs">
                          {alert.slaType === 'follow-up' ? (
                            <p>Xác nhận đã liên hệ khách hàng. Ngày liên hệ cuối sẽ được cập nhật và chu kỳ SLA được làm mới.</p>
                          ) : alert.slaType === 're-engagement' ? (
                            <p>Xác nhận đã tiếp cận lại khách hàng. Cảnh báo sẽ được đánh dấu đã xử lý.</p>
                          ) : (
                            <p>Xác nhận đã xử lý SLA này. Cảnh báo sẽ được đánh dấu hoàn thành.</p>
                          )}
                        </TooltipContent>
                      </Tooltip>
                    </TooltipProvider>
                    <TooltipProvider delayDuration={0}>
                      <Tooltip>
                        <TooltipTrigger asChild>
                          <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                              <Button variant="ghost" size="sm" className="h-8 w-8 p-0">
                                <MoreHorizontal className="h-4 w-4" />
                              </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end">
                              <DropdownMenuItem onClick={() => handleSnooze(alert, 1)}>
                                <Clock className="h-4 w-4 mr-2" /> Tạm ẩn 1 ngày
                              </DropdownMenuItem>
                              <DropdownMenuItem onClick={() => handleSnooze(alert, 3)}>
                                <Clock className="h-4 w-4 mr-2" /> Tạm ẩn 3 ngày
                              </DropdownMenuItem>
                              <DropdownMenuItem onClick={() => handleSnooze(alert, 7)}>
                                <Clock className="h-4 w-4 mr-2" /> Tạm ẩn 7 ngày
                              </DropdownMenuItem>
                              <DropdownMenuSeparator />
                              <DropdownMenuItem onClick={() => handleSnooze(alert, 30)}>
                                <Clock className="h-4 w-4 mr-2" /> Tạm ẩn 30 ngày
                              </DropdownMenuItem>
                            </DropdownMenuContent>
                          </DropdownMenu>
                        </TooltipTrigger>
                        <TooltipContent side="top">
                          <p>Tạm ẩn cảnh báo này trong một khoảng thời gian</p>
                        </TooltipContent>
                      </Tooltip>
                    </TooltipProvider>
                  </div>
                )}
              </div>
            </div>
          );
        })}

        {debtAlert && (
            <div className="border border-border rounded-lg p-3 space-y-2 bg-rose-50">
            <div className="flex items-center gap-2">
              <Badge variant="destructive">Công nợ</Badge>
              <span className="text-body-sm font-medium">{debtAlert.debtStatus}</span>
            </div>
            <p className="text-body-sm text-rose-700">
              Nợ quá hạn: {new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND', maximumFractionDigits: 0 }).format(debtAlert.overdueAmount)}
            </p>
            {debtAlert.oldestDueDate && (
              <p className="text-body-xs text-muted-foreground">
                Hạn sớm nhất: {format(new Date(debtAlert.oldestDueDate), 'dd/MM/yyyy', { locale: vi })}
              </p>
            )}
          </div>
        )}

        {healthAlert && (
          <div className="border border-border rounded-lg p-3 space-y-2 bg-purple-50">
            <div className="flex items-center gap-2">
              <Badge className="bg-purple-600 hover:bg-purple-700">Rủi ro churn</Badge>
              <TooltipProvider delayDuration={0}>
                <Tooltip>
                  <TooltipTrigger asChild>
                    <HelpCircle className="h-3.5 w-3.5 text-purple-600 cursor-help" />
                  </TooltipTrigger>
                  <TooltipContent side="top" className="max-w-sm p-4">
                    <div className="text-body-xs space-y-3">
                      <p className="font-semibold text-base">Cách tính điểm sức khỏe (Health Score):</p>
                      
                      <div className="space-y-1">
                        <p className="font-medium">1. Recency (Thời gian mua gần nhất) - Tối đa 30đ:</p>
                        <ul className="list-disc list-inside pl-1 text-muted-foreground">
                          <li>Mua trong 7 ngày: +30đ</li>
                          <li>Mua trong 30 ngày: +25đ</li>
                          <li>...giảm dần...</li>
                          <li>Trên 1 năm: +5đ</li>
                        </ul>
                      </div>

                      <div className="space-y-1">
                        <p className="font-medium">2. Frequency (Tần suất mua) - Tối đa 25đ:</p>
                        <ul className="list-disc list-inside pl-1 text-muted-foreground">
                          <li>Trên 20 đơn: +25đ</li>
                          <li>Trên 10 đơn: +20đ</li>
                          <li>...giảm dần...</li>
                        </ul>
                      </div>

                      <div className="space-y-1">
                        <p className="font-medium">3. Monetary (Tổng chi tiêu) - Tối đa 30đ:</p>
                        <ul className="list-disc list-inside pl-1 text-muted-foreground">
                          <li>Trên 500 triệu: +30đ</li>
                          <li>Trên 200 triệu: +25đ</li>
                          <li>...giảm dần...</li>
                        </ul>
                      </div>

                      <div className="space-y-1">
                        <p className="font-medium">4. Payment Behavior (Hành vi thanh toán) - Tối đa 15đ:</p>
                        <p className="text-muted-foreground mb-1">Dựa trên tỷ lệ nợ hiện tại / hạn mức tín dụng.</p>
                        <ul className="list-disc list-inside pl-1 text-muted-foreground">
                          <li>Dùng &lt; 20% hạn mức: +15đ (Tốt)</li>
                          <li>Dùng &gt; 80% hạn mức: 0đ (Rủi ro)</li>
                          <li>Nếu không có hạn mức nợ: Mặc định +15đ</li>
                        </ul>
                      </div>
                    </div>
                  </TooltipContent>
                </Tooltip>
              </TooltipProvider>
              <span className="text-body-sm font-medium">{healthAlert.churnRisk === 'high' ? 'Rủi ro cao' : healthAlert.churnRisk === 'medium' ? 'Rủi ro trung bình' : 'Rủi ro thấp'}</span>
            </div>
            <p className="text-body-sm text-purple-700">
              Health score: {healthAlert.healthScore}/100 • Không mua: {healthAlert.daysSinceLastPurchase} ngày
            </p>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

