  const { createWithPayslips } = usePayrollBatchMutations({
    onSuccess: () => {},
    onError: (err) => toast.error('Đã xảy ra lỗi', { description: err.message }),
  });
  const { data: penaltiesData } = usePenalties({});
  const penalties = penaltiesData?.data ?? [];
  const { update: updatePenalty } = usePenaltyMutations({
    onSuccess: () => {},
  });
  const { data: employeeSettings } = useEmployeeSettings();
  const defaultPayday = employeeSettings?.payday ?? 5;

  React.useEffect(() => {
    ensureDefault.mutate();
  }, []);

  const latestLockedMonth = React.useMemo(() => {
    const lockedKeys = Object.keys(lockedMonths).filter((key) => lockedMonths[key]);
    return lockedKeys.sort().reverse()[0];
  }, [lockedMonths]);

  const [currentStep, setCurrentStep] = React.useState(0);
  const [searchKeyword, setSearchKeyword] = React.useState('');
  const [preview, setPreview] = React.useState<PayrollCalculationResult | null>(null);
  const [isPreviewLoading, setIsPreviewLoading] = React.useState(false);

  // Employee selection table state
  const [empPagination, setEmpPagination] = React.useState({ pageIndex: 0, pageSize: 20 });
  const [empSorting, setEmpSorting] = React.useState<{ id: string; desc: boolean }>({ id: '', desc: false });

  // Preview table state
  const [previewPagination, setPreviewPagination] = React.useState({ pageIndex: 0, pageSize: 10 });
  const [previewSorting, setPreviewSorting] = React.useState<{ id: string; desc: boolean }>({ id: '', desc: false });
  const [previewSearchKeyword, setPreviewSearchKeyword] = React.useState('');

  const defaultMonthKey = latestLockedMonth ?? getCurrentMonthKey();
  const defaultPayrollDate = React.useMemo(
    () => buildPayrollDate(defaultMonthKey, defaultPayday),
    [defaultMonthKey, defaultPayday]
  );

  const defaultTemplateSystemId = React.useMemo(
    () => getDefault()?.systemId,
    [getDefault]
  );

  const [formState, setFormState] = React.useState({
    title: '',
    monthKey: defaultMonthKey,
    payrollDate: defaultPayrollDate,
    templateSystemId: defaultTemplateSystemId,
    selectedEmployeeSystemIds: [] as SystemId[],
  });

  React.useEffect(() => {
    setFormState((prev) => {
      const hasValidSelection = prev.templateSystemId
        ? templates.some((template) => template.systemId === prev.templateSystemId)
        : false;
      // Only update if current is invalid AND default exists AND they differ
      if (hasValidSelection || !defaultTemplateSystemId || prev.templateSystemId === defaultTemplateSystemId) {
        return prev;
      }
      return {
        ...prev,
        templateSystemId: defaultTemplateSystemId,
      };
    });
  }, [templates, defaultTemplateSystemId]);

  // Use activeEmployees from hook
  const employees = activeEmployees;
  const employeeLookup = React.useMemo(() => {
    return employees.reduce<Record<SystemId, (typeof employees)[number]>>(
      (acc, employee) => {
        acc[employee.systemId] = employee;
        return acc;
      },
      {} as Record<SystemId, (typeof employees)[number]>
    );
  }, [employees]);

  const filteredEmployees = React.useMemo(() => {
    if (!searchKeyword.trim()) {
      return employees;
    }
    const keyword = searchKeyword.trim().toLowerCase();
    return employees.filter((employee) =>
      employee.fullName.toLowerCase().includes(keyword) || employee.id.toLowerCase().includes(keyword)
    );
  }, [employees, searchKeyword]);

  const selectedMonthLabel = React.useMemo(
    () => formatMonthLabel(formState.monthKey) || formState.monthKey || 'Chưa chọn',
    [formState.monthKey]
  );

  const selectedMonthBounds = React.useMemo(() => {
    if (!formState.monthKey) return null;
    const [year, month] = formState.monthKey.split('-').map(Number);
    if (!year || !month) return null;
    return {
      start: new Date(year, month - 1, 1),
      end: new Date(year, month, 0),
    };
  }, [formState.monthKey]);

  const isSelectedMonthLocked = React.useMemo(
    () => Boolean(formState.monthKey && lockedMonths[formState.monthKey]),
    [formState.monthKey, lockedMonths]
  );

  const pendingLeavesInMonth = React.useMemo(() => {
    if (!selectedMonthBounds) return [] as typeof leaveRequests;
    return leaveRequests.filter((leave) => {
      if (leave.status !== 'Chờ duyệt') return false;
      const start = new Date(leave.startDate);
      const end = new Date(leave.endDate);
      if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) {
        return false;
      }
      return start <= selectedMonthBounds.end && end >= selectedMonthBounds.start;
    });
  }, [leaveRequests, selectedMonthBounds]);

  const snapshotBlockingEmployees = React.useMemo(() => {
    if (!isSelectedMonthLocked || !formState.monthKey || !formState.selectedEmployeeSystemIds.length) {
      return [] as string[];
    }
    const blocked = new Set<string>();
    formState.selectedEmployeeSystemIds.forEach((employeeSystemId) => {
      const snapshot = attendanceSnapshotService.getSnapshot({
        monthKey: formState.monthKey,
        employeeSystemId,
      });
      // Cast snapshot as any since it's not actually async
      if (!(snapshot as any)?.locked) {
        const employee = employeeLookup[employeeSystemId];
        blocked.add(employee?.fullName ?? employee?.id ?? employeeSystemId);
      }
    });
    return Array.from(blocked);
  }, [employeeLookup, formState.monthKey, formState.selectedEmployeeSystemIds, isSelectedMonthLocked]);

  const payrollBlockingReasons = React.useMemo(() => {
    const reasons: string[] = [];
    if (!isSelectedMonthLocked) {
      reasons.push(`Tháng ${selectedMonthLabel} chưa được khóa trong Chấm công.`);
    }
    if (pendingLeavesInMonth.length > 0) {
      reasons.push(`${pendingLeavesInMonth.length} đơn nghỉ đang chờ duyệt trong tháng này.`);
    }
    if (snapshotBlockingEmployees.length > 0) {
      const names = snapshotBlockingEmployees.slice(0, 4).join(', ');
      const remaining = snapshotBlockingEmployees.length > 4
        ? ` và ${snapshotBlockingEmployees.length - 4} người khác`
        : '';
      reasons.push(`Chưa có snapshot chấm công đã khóa cho: ${names}${remaining}.`);
    }
    return reasons;
  }, [selectedMonthLabel, isSelectedMonthLocked, pendingLeavesInMonth.length, snapshotBlockingEmployees]);

  const canProceedStep1 = Boolean(formState.monthKey && formState.payrollDate && formState.templateSystemId);
  const canProceedStep2 = formState.selectedEmployeeSystemIds.length > 0;

  const goNext = () => {
    if (currentStep === 0 && !canProceedStep1) return;
    if (currentStep === 1 && !canProceedStep2) return;
    setCurrentStep((prev) => Math.min(prev + 1, STEPS.length - 1));
  };
  const goPrev = () => setCurrentStep((prev) => Math.max(prev - 1, 0));

  // Get salary components from React Query
  const salaryComponents = React.useMemo(
    () => employeeSettings?.salaryComponents ?? [],
    [employeeSettings?.salaryComponents]
  );
  
  // Convert SalaryComponent to PayrollComponent format
  const payrollComponents = React.useMemo(() => {
    // Get template's component IDs if template selected
    const template = formState.templateSystemId 
      ? templates.find(t => t.systemId === formState.templateSystemId)
      : undefined;
    const templateComponentIds = template?.componentSystemIds ?? [];
    
    // Filter by template if exists, otherwise use all
    // Also filter by isActive
    const filteredComponents = (templateComponentIds.length > 0
      ? salaryComponents.filter(c => templateComponentIds.includes(c.systemId))
      : salaryComponents
    ).filter(c => c.isActive !== false); // Only include active components
    
    return filteredComponents.map((c, idx) => ({
      systemId: c.systemId,
      id: c.id,
      name: c.name,
      code: c.id,
      category: c.category ?? 'earning', // Use category from SalaryComponent
      calculationType: c.type,
      amount: c.amount,
      formula: c.formula,
      taxable: c.taxable,
      partOfSocialInsurance: c.partOfSocialInsurance,
      applicableDepartmentSystemIds: c.applicableDepartmentSystemIds,
      isDefault: true,
      sortOrder: c.sortOrder ?? idx,
      createdAt: c.createdAt ?? new Date().toISOString(),
      updatedAt: c.updatedAt ?? new Date().toISOString(),
    }));
  }, [salaryComponents, formState.templateSystemId, templates]);

  React.useEffect(() => {
    if (currentStep !== 2) {
      setPreview(null);
      setIsPreviewLoading(false);
      return;
    }
    if (!formState.selectedEmployeeSystemIds.length) {
      setPreview(null);
      return;
    }
    
    // Build employee inputs for the new engine
    const employeeInputs = formState.selectedEmployeeSystemIds.map((systemId) => {
      const emp = employeeData.find(e => e.systemId === systemId);
      return {
        employeeSystemId: systemId,
        employeeId: emp?.id ?? ('' as typeof emp extends { id: infer T } ? T : never),
        employeeName: emp?.fullName ?? 'Unknown',
        departmentSystemId: emp?.departmentId,
        baseSalary: emp?.baseSalary ?? 0,
      };
    }).filter(e => e.employeeId);
    
    setIsPreviewLoading(true);
    const result = payrollEngine.calculate({
      periodMonthKey: formState.monthKey,
      employees: employeeInputs,
      components: payrollComponents,
      penaltyMode: 'all-unpaid', // Auto-deduct all unpaid penalties
    });
    setPreview(result);
    setIsPreviewLoading(false);
  }, [currentStep, formState.selectedEmployeeSystemIds, formState.monthKey, payrollComponents, employeeData]);

  const handleSelectEmployee = React.useCallback((systemId: SystemId, checked: boolean) => {
    setFormState((prev) => ({
      ...prev,
      selectedEmployeeSystemIds: checked
        ? (prev.selectedEmployeeSystemIds.includes(systemId)
            ? prev.selectedEmployeeSystemIds
            : [...prev.selectedEmployeeSystemIds, systemId])
        : prev.selectedEmployeeSystemIds.filter((id) => id !== systemId),
    }));
  }, []);

  const handleSelectAll = React.useCallback((checked: boolean) => {
    setFormState((prev) => ({
      ...prev,
      selectedEmployeeSystemIds: checked ? filteredEmployees.map((employee) => employee.systemId) : [],
    }));
  }, [filteredEmployees]);

  // Employee selection columns with handlers
  const employeeSelectionColumns = React.useMemo(
    () => getEmployeeSelectionColumns(
      formState.selectedEmployeeSystemIds,
      handleSelectEmployee,
      handleSelectAll,
      filteredEmployees
    ),
    [formState.selectedEmployeeSystemIds, filteredEmployees, handleSelectEmployee, handleSelectAll]
  );

  // Paginated employee data
  const empPageCount = Math.ceil(filteredEmployees.length / empPagination.pageSize);
  const paginatedEmployees = React.useMemo(() => {
    const start = empPagination.pageIndex * empPagination.pageSize;
    const end = start + empPagination.pageSize;
    return filteredEmployees.slice(start, end);
  }, [filteredEmployees, empPagination.pageIndex, empPagination.pageSize]);

  // Row selection state for ResponsiveDataTable
  const empRowSelection = React.useMemo(() => {
    const selection: Record<string, boolean> = {};
    formState.selectedEmployeeSystemIds.forEach((id) => {
      selection[id] = true;
    });
    return selection;
  }, [formState.selectedEmployeeSystemIds]);

  const setEmpRowSelection = React.useCallback(
    (updater: Record<string, boolean> | ((old: Record<string, boolean>) => Record<string, boolean>)) => {
      const newSelection = typeof updater === 'function' ? updater(empRowSelection) : updater;
      const newSelectedIds = Object.keys(newSelection).filter((key) => newSelection[key]) as SystemId[];
      setFormState((prev) => ({ ...prev, selectedEmployeeSystemIds: newSelectedIds }));
    },
    [empRowSelection]
  );

  const handleCreateBatch = () => {
    if (!preview || !preview.payslips.length) {
      toast('Chưa có dữ liệu preview', {
        description: 'Vui lòng chọn nhân viên và chạy lại bước xem trước.',
      });
      return;
    }

    if (payrollBlockingReasons.length) {
      toast.error('Không thể tạo bảng lương', {
        description: payrollBlockingReasons[0],
      });
      if (!isSelectedMonthLocked || snapshotBlockingEmployees.length) {
        router.push(ROUTES.HRM.ATTENDANCE);
      } else if (pendingLeavesInMonth.length) {
        router.push(ROUTES.HRM.LEAVES);
      }
      return;
    }

    const title = formState.title?.trim() || `Bảng lương ${formatMonthLabel(formState.monthKey)}`;
    const [year, month] = formState.monthKey.split('-').map(Number);
    
    // Use penaltiesDeducted from engine result
    const penaltiesDeducted = preview.penaltiesDeducted ?? [];
    
    createWithPayslips.mutate(
      {
        title,
        month,
        year,
        payrollDate: formState.payrollDate,
        templateSystemId: formState.templateSystemId,
        referenceAttendanceMonthKeys: [formState.monthKey],
        generatedPayslips: preview.payslips.map((payslip) => ({
          employeeSystemId: payslip.employeeSystemId,
          employeeId: payslip.employeeId,
          departmentSystemId: payslip.departmentSystemId,
          periodMonthKey: formState.monthKey,
          components: payslip.components,
          totals: payslip.totals,
          attendanceSnapshotSystemId: undefined,
          deductedPenaltySystemIds: payslip.deductedPenaltySystemIds,
        })),
      },
      {
        onSuccess: (response) => {
          // Update penalties status to "Đã thanh toán" and link to this batch
          const now = new Date().toISOString();
          penaltiesDeducted.forEach((info) => {
            const penalty = penalties.find(p => p.systemId === info.penaltySystemId);
            if (penalty) {
              updatePenalty.mutate({
                systemId: penalty.systemId,
                data: {
                  status: 'Đã thanh toán',
                  deductedInPayrollId: response.batch.systemId,
                  deductedAt: now,
                  updatedAt: now,
                },
              });
            }
          });

          const penaltyMessage = penaltiesDeducted.length > 0 
            ? ` Đã trừ ${penaltiesDeducted.length} phiếu phạt vào lương.`
            : '';
          
          toast.success('Đã tạo bảng lương', { 
            description: `Bạn có thể xem chi tiết để duyệt hoặc khóa batch.${penaltyMessage}` 
          });
          router.push(ROUTES.PAYROLL.DETAIL.replace(':systemId', response.batch.systemId));
        },
      }
    );
  };

  const headerActions = React.useMemo(
    () => [
      <Button
        key="templates"
        variant="outline"
        size="sm"
        className="h-9"
        onClick={() => router.push(ROUTES.PAYROLL.TEMPLATES)}
      >
        Quản lý mẫu
      </Button>,
      <Button
        key="cancel"
        variant="ghost"
        size="sm"
        className="h-9"
        onClick={() => router.push(ROUTES.PAYROLL.LIST)}
      >
        Thoát
      </Button>,
    ],
    [router]
  );

  usePageHeader({
    title: 'Chạy bảng lương',
    subtitle: 'Wizard 3 bước để chọn kỳ, nhân sự và tạo batch lương mới',
    breadcrumb: [
      { label: 'Trang chủ', href: ROUTES.DASHBOARD, isCurrent: false },
      { label: 'Bảng lương', href: ROUTES.PAYROLL.LIST, isCurrent: false },
      { label: 'Chạy mới', href: ROUTES.PAYROLL.RUN, isCurrent: true },
    ],
    showBackButton: true,
    backPath: ROUTES.PAYROLL.LIST,
    actions: headerActions,
  });

  const previewWarnings = React.useMemo(() => {
    if (!preview?.payslips.length) return [] as string[];
    return preview.warnings.map((w) => 
      w.employeeName ? `${w.employeeName} · ${w.message}` : w.message
    );
  }, [preview]);

  const canCreateBatch = Boolean(preview?.payslips.length && payrollBlockingReasons.length === 0);

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <CardTitle className="text-h4 font-semibold">Tiến trình</CardTitle>
        </CardHeader>
        <CardContent className="p-0">
          <PayrollStepper currentStep={currentStep} />
        </CardContent>
      </Card>

      {currentStep === 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="text-h4">Cấu hình kỳ lương</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="grid gap-4 md:grid-cols-2">
              <div className="space-y-2">
                <Label htmlFor="payroll-title">Tiêu đề</Label>
                <Input
                  id="payroll-title"
                  placeholder="VD: Lương Tháng 11/2025"
                  value={formState.title}
                  onChange={(event) => setFormState((prev) => ({ ...prev, title: event.target.value }))}
                  className="h-9"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="payroll-month">Tháng tham chiếu</Label>
                <MonthPicker
                  id="payroll-month"
                  value={formState.monthKey}
                  onChange={(monthKey) =>
                    setFormState((prev) => {
                      const currentDay = Number(prev.payrollDate.split('-')[2]) || defaultPayday;
                      return {
                        ...prev,
                        monthKey: monthKey,
                        payrollDate: buildPayrollDate(monthKey, currentDay),
                      };
                    })
                  }
                  minYear={2024}
                  maxYear={2030}
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="payroll-date">Ngày chi trả</Label>
                <DatePicker
                  id="payroll-date"
                  value={formState.payrollDate ? new Date(formState.payrollDate + 'T00:00:00') : null}
                  onChange={(date) => setFormState((prev) => ({ 
                    ...prev, 
                    payrollDate: date 
                      ? `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`
                      : prev.payrollDate 
                  }))}
                />
              </div>
              <div className="space-y-2">
                <Label>Template</Label>
                <Select
                  value={formState.templateSystemId ?? ''}
                  onValueChange={(value) =>
                    setFormState((prev) => ({
                      ...prev,
                      templateSystemId: value ? asSystemId(value) : undefined,
                    }))
                  }
                >
                  <SelectTrigger className="h-9">
                    <SelectValue placeholder="Chọn template" />
                  </SelectTrigger>
                  <SelectContent>
                    {templates.map((template) => (
                      <SelectItem key={template.systemId} value={template.systemId}>
                        {template.name}
                        {template.isDefault ? ' · Mặc định' : ''}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            {!isSelectedMonthLocked && (
              <Alert variant="destructive">
                <AlertTitle>Tháng {selectedMonthLabel} chưa được khóa</AlertTitle>
                <AlertDescription>
                  Khóa chấm công trước khi chạy lương để cố định dữ liệu attendance và tránh chỉnh sửa sau khi trả lương.
                </AlertDescription>
                <div className="mt-3">
                  <Button size="sm" className="h-8" onClick={() => router.push(ROUTES.HRM.ATTENDANCE)}>
                    Mở trang Chấm công
                  </Button>
                </div>
              </Alert>
            )}

            {!latestLockedMonth && (
              <Alert className="border-amber-200 bg-amber-50 text-amber-900 dark:border-amber-400/40 dark:bg-amber-950/40">
                <AlertTitle>Chưa có tháng chấm công nào được khóa</AlertTitle>
                <AlertDescription>
                  Bạn vẫn có thể chạy bảng lương với dữ liệu hiện tại nhưng hãy khóa tháng trong Chấm công để tránh sai lệch.
                </AlertDescription>
              </Alert>
            )}
          </CardContent>
        </Card>
      )}

      {currentStep === 1 && (
        <Card>
          <CardHeader>
            <CardTitle className="text-h4">Chọn nhân viên ({formState.selectedEmployeeSystemIds.length})</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <div className="flex flex-col gap-2 md:flex-row md:items-center md:justify-between">
              <Input
                placeholder="Tìm theo tên hoặc mã"
                value={searchKeyword}
                onChange={(event) => setSearchKeyword(event.target.value)}
                className="h-9 md:w-64"
              />
            </div>

            <ResponsiveDataTable<Employee>
              data={paginatedEmployees}
              columns={employeeSelectionColumns}
              isLoading={false}
              emptyTitle="Không có nhân viên"
              emptyDescription="Không tìm thấy nhân viên phù hợp."
              rowSelection={empRowSelection}
              setRowSelection={setEmpRowSelection}
              pageCount={empPageCount}
              pagination={empPagination}
              setPagination={setEmpPagination}
              rowCount={filteredEmployees.length}
              sorting={empSorting}
              setSorting={setEmpSorting}
            />
          </CardContent>
        </Card>
      )}

      {currentStep === 2 && (
        <Card>
          <CardHeader>
            <CardTitle className="text-h4">Xem trước kết quả</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            {isPreviewLoading ? (
              <Skeleton className="h-32 w-full" />
            ) : preview ? (
              <>
                <PayrollSummaryCards
                  items={[
                    {
                      id: 'selected',
                      title: 'Nhân viên',
                      value: preview.payslips.length,
                      description: 'Đang chạy bảng lương',
                      icon: Users,
                    },
                    {
                      id: 'gross',
                      title: 'Tổng thu nhập',
                      value: preview.summary.totalGross.toLocaleString('vi-VN', { style: 'currency', currency: 'VND', maximumFractionDigits: 0 }),
                      icon: Wallet,
                    },
                    {
                      id: 'net',
                      title: 'Tổng thực lĩnh',
                      value: preview.summary.totalNet.toLocaleString('vi-VN', { style: 'currency', currency: 'VND', maximumFractionDigits: 0 }),
                      icon: CalendarIcon,
                    },
                    {
                      id: 'month',
                      title: 'Tháng tham chiếu',
                      value: selectedMonthLabel,
                    },
                  ]}
                />

                {previewWarnings.length > 0 && (
                  <Alert className="border-amber-200 bg-amber-50 text-amber-900 dark:border-amber-400/40 dark:bg-amber-950/40">
                    <AlertTitle>Cảnh báo</AlertTitle>
                    <AlertDescription>
                      <ul className="list-disc pl-4">
                        {previewWarnings.map((warning) => (
                          <li key={warning}>{warning}</li>
                        ))}
                      </ul>
                    </AlertDescription>
                  </Alert>
                )}

                {(() => {
                  const allPreviewData = preview.payslips.map((payslip) => ({
                    systemId: payslip.employeeSystemId,
                    employeeId: payslip.employeeId,
                    employeeName: payslip.employeeName,
                    departmentName: employeeLookup[payslip.employeeSystemId]?.department,
                    positionName: employeeLookup[payslip.employeeSystemId]?.jobTitle,
                    totals: payslip.totals,
                  }));
                  
                  // Filter by search keyword
                  const filteredPreviewData = previewSearchKeyword.trim()
                    ? allPreviewData.filter((row) => {
                        const query = previewSearchKeyword.toLowerCase().trim();
                        return (
                          row.employeeId?.toLowerCase().includes(query) ||
                          row.employeeName?.toLowerCase().includes(query) ||
                          row.departmentName?.toLowerCase().includes(query) ||
                          row.positionName?.toLowerCase().includes(query)
                        );
                      })
                    : allPreviewData;
                    
                  const previewPageCount = Math.ceil(filteredPreviewData.length / previewPagination.pageSize);
                  const paginatedPreview = filteredPreviewData.slice(
                    previewPagination.pageIndex * previewPagination.pageSize,
                    (previewPagination.pageIndex + 1) * previewPagination.pageSize
                  );

                  return (
                    <>
                      <Input
                        placeholder="Tìm theo mã, tên, phòng ban..."
                        value={previewSearchKeyword}
                        onChange={(e) => {
                          setPreviewSearchKeyword(e.target.value);
                          setPreviewPagination((prev) => ({ ...prev, pageIndex: 0 }));
                        }}
                        className="h-9 md:w-64"
                      />
                      <ResponsiveDataTable<PreviewTableRow>
                        data={paginatedPreview}
                        columns={previewTableColumns}
                        isLoading={false}
                        emptyTitle="Không có dữ liệu"
                        emptyDescription="Không có dữ liệu để hiển thị."
                        pageCount={previewPageCount}
                        pagination={previewPagination}
                        setPagination={setPreviewPagination}
                        rowCount={filteredPreviewData.length}
                        sorting={previewSorting}
                        setSorting={setPreviewSorting}
                      />
                    </>
                  );
                })()}

                {payrollBlockingReasons.length > 0 && (
                  <Alert variant="destructive">
                    <AlertTitle>Không thể tạo bảng lương</AlertTitle>
                    <AlertDescription>
                      <ul className="list-disc space-y-1 pl-4">
                        {payrollBlockingReasons.map((reason) => (
                          <li key={reason}>{reason}</li>
                        ))}
                      </ul>
                      <div className="mt-4 flex flex-wrap gap-2">
                        {!isSelectedMonthLocked && (
                          <Button size="sm" className="h-8" onClick={() => router.push(ROUTES.HRM.ATTENDANCE)}>
                            Khóa chấm công
                          </Button>
                        )}
                        {pendingLeavesInMonth.length > 0 && (
                          <Button
                            variant="outline"
                            size="sm"
                            className="h-8"
                            onClick={() => router.push(ROUTES.HRM.LEAVES)}
                          >
                            Xem đơn nghỉ chờ duyệt
                          </Button>
                        )}
                      </div>
                    </AlertDescription>
                  </Alert>
                )}
              </>
            ) : (
              <Alert>
                <AlertTitle>Chưa có dữ liệu preview</AlertTitle>
                <AlertDescription>
                  Vui lòng quay lại bước trước để chọn nhân viên, sau đó quay lại đây để xem kết quả.
                </AlertDescription>
              </Alert>
            )}
          </CardContent>
        </Card>
      )}

      <div className="flex items-center justify-between">
        <Button variant="outline" className="h-9" disabled={currentStep === 0} onClick={goPrev}>
          Quay lại
        </Button>
        {currentStep < 2 ? (
          <Button className="h-9" onClick={goNext} disabled={(currentStep === 0 && !canProceedStep1) || (currentStep === 1 && !canProceedStep2)}>
            Tiếp tục
          </Button>
        ) : (
          <Button className="h-9" disabled={!canCreateBatch} onClick={handleCreateBatch}>
            Tạo bảng lương
          </Button>
        )}
      </div>
    </div>
  );
}

import * as React from 'react';
import { useFuseFilter } from '../../hooks/use-fuse-search';
import { Plus, CheckCircle2, RotateCcw, Trash2, Search, X } from 'lucide-react';
import { Button } from '../../components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '../../components/ui/dialog';
import { Input } from '../../components/ui/input';
import { Textarea } from '../../components/ui/textarea';
import { Checkbox } from '../../components/ui/checkbox';
import { Label } from '../../components/ui/label';
import { Badge } from '../../components/ui/badge';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '../../components/ui/alert-dialog';
import { ResponsiveDataTable } from '../../components/data-table/responsive-data-table';
import { DataTableFacetedFilter } from '../../components/data-table/data-table-faceted-filter';
import { usePageHeader } from '../../contexts/page-header-context';
import { useBreakpoint } from '../../contexts/breakpoint-context';
import { useAllPayrollTemplates, usePayrollTemplateMutations, usePayrollTemplateExtended, usePayrollTemplateFinder } from './hooks/use-payroll';
import { useEmployeeSettings } from '../settings/employees/hooks/use-employee-settings';
import { getTemplateColumns } from './template-columns';
import { TemplateCard } from './template-card';
import { toast } from 'sonner';
import { asSystemId, type SystemId } from '../../lib/id-types';
import type { PayrollTemplate } from '../../lib/payroll-types';

export function PayrollTemplatePage() {
  const templates = useAllPayrollTemplates();
  const { findById } = usePayrollTemplateFinder();
  const { create, update, remove } = usePayrollTemplateMutations({
    onSuccess: () => {},
    onError: (err) => toast.error('Lỗi', { description: err.message }),
  });
  const { setDefault } = usePayrollTemplateExtended({
    onSuccess: () => {},
    onError: (err) => toast.error('Lỗi', { description: err.message }),
  });
  const { data: employeeSettings } = useEmployeeSettings();
  const salaryComponents = React.useMemo(
    () => employeeSettings?.salaryComponents ?? [],
    [employeeSettings?.salaryComponents]
  );
  const { isMobile } = useBreakpoint();

  // Search & Filter states
  const [searchQuery, setSearchQuery] = React.useState('');
  const [isDefaultFilter, setIsDefaultFilter] = React.useState<Set<string>>(new Set());

  // Dialog states
  const [isDialogOpen, setIsDialogOpen] = React.useState(false);
  const [isResetDialogOpen, setIsResetDialogOpen] = React.useState(false);
  const [editingTemplateId, setEditingTemplateId] = React.useState<SystemId | null>(null);
  const [deleteConfirmId, setDeleteConfirmId] = React.useState<SystemId | null>(null);

  // Form state
  const [formState, setFormState] = React.useState({
    name: '',
    description: '',
    componentSystemIds: salaryComponents.map((component) => asSystemId(component.systemId)),
    isDefault: false,
  });

  // Table states
  const [rowSelection, setRowSelection] = React.useState<Record<string, boolean>>({});
  const [columnVisibility, setColumnVisibility] = React.useState<Record<string, boolean>>({});
  const [columnOrder, setColumnOrder] = React.useState<string[]>([]);
  const [pinnedColumns, setPinnedColumns] = React.useState<string[]>(['select', 'id']);
  const [pagination, setPagination] = React.useState({ pageIndex: 0, pageSize: 20 });
  const [sorting, setSorting] = React.useState<{ id: string; desc: boolean }>({ id: 'createdAt', desc: true });

  // Mobile infinite scroll
  const [mobileLoadedCount, setMobileLoadedCount] = React.useState(20);

  // Fuse.js for search (lazy-loaded)
  const fuseOptions = React.useMemo(
    () => ({
      keys: ['id', 'name', 'description'],
      threshold: 0.3,
      includeScore: true,
    }),
    []
  );
  const searchedData = useFuseFilter(templates, searchQuery.trim(), fuseOptions);

  // Filtered data
  const filteredData = React.useMemo(() => {
    let result = searchQuery.trim() ? searchedData : templates;

    // Default filter
    if (isDefaultFilter.size > 0) {
      result = result.filter((t) => {
        if (isDefaultFilter.has('default') && t.isDefault) return true;
        if (isDefaultFilter.has('normal') && !t.isDefault) return true;
        return false;
      });
    }

    return result;
  }, [templates, searchQuery, isDefaultFilter, searchedData]);

  // Reset mobile count when filters change
  React.useEffect(() => {
    setMobileLoadedCount(20);
    setPagination((prev) => ({ ...prev, pageIndex: 0 }));
  }, [searchQuery, isDefaultFilter.size]);

  // Handlers
  const handleOpenCreateDialog = React.useCallback(() => {
    setEditingTemplateId(null);
    setFormState({
      name: '',
      description: '',
      componentSystemIds: salaryComponents.map((component) => asSystemId(component.systemId)),
      isDefault: false,
    });
    setIsDialogOpen(true);
  }, [salaryComponents]);

  const handleEdit = React.useCallback((systemId: SystemId) => {
    const template = findById(systemId);
    if (!template) return;
    setEditingTemplateId(systemId);
    setFormState({
      name: template.name,
      description: template.description ?? '',
      componentSystemIds: template.componentSystemIds as any,
      isDefault: template.isDefault,
    });
    setIsDialogOpen(true);
  }, [findById]);

  const handleDelete = React.useCallback((systemId: SystemId) => {
    setDeleteConfirmId(systemId);
  }, []);

  const handleConfirmDelete = React.useCallback(() => {
    if (deleteConfirmId) {
      remove.mutate(deleteConfirmId, {
        onSuccess: () => {
          toast.success('Đã xóa mẫu', { description: 'Mẫu bảng lương đã được gỡ bỏ.' });
          setDeleteConfirmId(null);
        },
      });
    }
  }, [remove, deleteConfirmId]);

  const handleSetDefault = React.useCallback((systemId: SystemId) => {
    setDefault.mutate(systemId, {
      onSuccess: () => {
        toast.success('Đã đặt mặc định', { description: 'Mẫu này sẽ được chọn sẵn khi chạy lương.' });
      },
    });
  }, [setDefault]);

  const handleToggleDefault = React.useCallback((template: PayrollTemplate, isDefault: boolean) => {
    if (isDefault) {
      // Đặt làm mặc định
      setDefault.mutate(template.systemId, {
        onSuccess: () => {
          toast.success('Đã đặt mặc định', { description: `"${template.name}" sẽ được chọn sẵn khi chạy lương.` });
        },
      });
    } else {
      // Bỏ mặc định - server will auto-assign new default
      update.mutate(
        { systemId: template.systemId, data: { isDefault: false } },
        {
          onSuccess: () => {
            toast.success('Đã bỏ mặc định', { description: 'Hệ thống đã chọn mẫu mặc định mới.' });
          },
        }
      );
    }
  }, [setDefault, update]);

  const handleResetToDefault = React.useCallback(() => {
    toast.info('Chức năng này đã được gỡ bỏ', { description: 'Vui lòng tạo mẫu mới từ đầu.' });
    setIsResetDialogOpen(false);
  }, []);

  const resetDialog = () => {
    setIsDialogOpen(false);
    setEditingTemplateId(null);
    setFormState({
      name: '',
      description: '',
      componentSystemIds: salaryComponents.map((component) => asSystemId(component.systemId)),
      isDefault: false,
    });
  };

  const handleSubmit = (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    if (!formState.name.trim()) {
      toast.error('Vui lòng nhập tên mẫu', { description: 'Tên mẫu bảng lương là bắt buộc.' });
      return;
    }

    if (editingTemplateId) {
      update.mutate(
        {
          systemId: editingTemplateId,
          data: {
            name: formState.name.trim(),
            description: formState.description.trim(),
            componentSystemIds: formState.componentSystemIds,
            isDefault: formState.isDefault,
          },
        },
        {
          onSuccess: () => {
            toast.success('Đã cập nhật mẫu', { description: 'Thông tin mẫu bảng lương đã được lưu.' });
            resetDialog();
          },
        }
      );
    } else {
      create.mutate(
        {
          name: formState.name.trim(),
          description: formState.description.trim(),
          componentSystemIds: formState.componentSystemIds,
          isDefault: formState.isDefault,
          id: '', // Will be generated by server
          isActive: true,
        },
        {
          onSuccess: () => {
            toast.success('Đã tạo mẫu mới', { description: 'Bạn có thể dùng mẫu này trong wizard chạy lương.' });
            resetDialog();
          },
        }
      );
    }
  };

  const toggleComponentSelection = (componentId: SystemId) => {
    setFormState((prev) => {
      const exists = prev.componentSystemIds.includes(componentId);
      return {
        ...prev,
        componentSystemIds: exists
          ? prev.componentSystemIds.filter((id) => id !== componentId)
          : [...prev.componentSystemIds, componentId],
      };
    });
  };

  // Columns
  const columns = React.useMemo(
    () => getTemplateColumns(handleEdit, handleDelete, handleToggleDefault),
    [handleEdit, handleDelete, handleToggleDefault]
  );

  // Set default column visibility
  React.useEffect(() => {
    const defaultVisibleColumns = ['select', 'id', 'name', 'componentCount', 'isDefault', 'createdAt', 'actions'];
    setColumnVisibility(
      Object.fromEntries(columns.map((col) => [col.id, defaultVisibleColumns.includes(col.id!)]))
    );
    setColumnOrder(columns.map((c) => c.id).filter(Boolean) as string[]);
  }, [columns]);

  // Mobile scroll listener
  React.useEffect(() => {
    if (!isMobile) return;

    const handleScroll = () => {
      const scrollPosition = window.innerHeight + window.scrollY;
      const threshold = document.body.offsetHeight * 0.8;
      if (scrollPosition >= threshold && mobileLoadedCount < filteredData.length) {
        setMobileLoadedCount((prev) => Math.min(prev + 20, filteredData.length));
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [isMobile, mobileLoadedCount, filteredData.length]);

  // Pagination
  const pageCount = Math.ceil(filteredData.length / pagination.pageSize);
  const paginatedData = React.useMemo(() => {
    const start = pagination.pageIndex * pagination.pageSize;
    const end = start + pagination.pageSize;
    return filteredData.slice(start, end);
  }, [filteredData, pagination.pageIndex, pagination.pageSize]);

  const displayData = isMobile ? filteredData.slice(0, mobileLoadedCount) : paginatedData;

  // Selected rows count
  const selectedCount = Object.values(rowSelection).filter(Boolean).length;

  // Header actions
  const headerActions = React.useMemo(
    () => [
      <Button
        key="reset"
        variant="outline"
        className="h-9"
        size="sm"
        onClick={() => setIsResetDialogOpen(true)}
      >
        <RotateCcw className="mr-2 h-4 w-4" />
        Khôi phục mặc định
      </Button>,
      <Button
        key="new"
        className="h-9"
        size="sm"
        onClick={handleOpenCreateDialog}
      >
        <Plus className="mr-2 h-4 w-4" />
        Thêm mẫu
      </Button>,
    ],
    [handleOpenCreateDialog]
  );

  usePageHeader({
    actions: headerActions,
  });

  // Render mobile card
  const renderMobileCard = React.useCallback(
    (template: PayrollTemplate) => (
      <TemplateCard
        key={template.systemId}
        template={template}
        isSelected={rowSelection[template.systemId] ?? false}
        onSelect={(selected) =>
          setRowSelection((prev) => ({ ...prev, [template.systemId]: selected }))
        }
        onEdit={handleEdit}
        onDelete={handleDelete}
        onSetDefault={handleSetDefault}
      />
    ),
    [rowSelection, handleEdit, handleDelete, handleSetDefault]
  );

  // Bulk actions
  const bulkActions = React.useMemo(
    () => [
      {
        label: 'Xóa đã chọn',
        icon: Trash2,
        onSelect: (selectedRows: PayrollTemplate[]) => {
          selectedRows.forEach((row) => remove.mutate(row.systemId));
          toast.success(`Đã xóa ${selectedRows.length} mẫu`);
          setRowSelection({});
        },
      },
    ],
    [remove]
  );

  return (
    <div className="space-y-6">
      {/* Search & Filter Bar */}
      <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div className="relative flex-1 max-w-md">
          <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <Input
            placeholder="Tìm theo tên, mã mẫu..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="h-9 pl-9 pr-9"
          />
          {searchQuery && (
            <Button
              variant="ghost"
              size="icon"
              className="absolute right-1 top-1/2 h-7 w-7 -translate-y-1/2"
              onClick={() => setSearchQuery('')}
            >
              <X className="h-4 w-4" />
            </Button>
          )}
        </div>
        <div className="flex items-center gap-2">
          <DataTableFacetedFilter
            title="Loại mẫu"
            selectedValues={isDefaultFilter}
            onSelectedValuesChange={setIsDefaultFilter}
            options={[
              { label: 'Mẫu mặc định', value: 'default' },
              { label: 'Mẫu thường', value: 'normal' },
            ]}
          />
          {(searchQuery || isDefaultFilter.size > 0) && (
            <Button
              variant="ghost"
              size="sm"
              className="h-9 px-2"
              onClick={() => {
                setSearchQuery('');
                setIsDefaultFilter(new Set());
              }}
            >
              <X className="mr-1 h-4 w-4" />
              Xóa bộ lọc
            </Button>
          )}
        </div>
      </div>

      {/* Results summary */}
      {(searchQuery || isDefaultFilter.size > 0) && (
        <p className="text-body-sm text-muted-foreground">
          Tìm thấy {filteredData.length} / {templates.length} mẫu
        </p>
      )}

      <ResponsiveDataTable<PayrollTemplate>
        columns={columns}
        data={displayData as any}
        renderMobileCard={renderMobileCard}
        rowSelection={rowSelection}
        setRowSelection={setRowSelection}
        columnVisibility={columnVisibility}
        setColumnVisibility={setColumnVisibility}
        columnOrder={columnOrder}
        setColumnOrder={setColumnOrder}
        pinnedColumns={pinnedColumns}
        setPinnedColumns={setPinnedColumns}
        sorting={sorting}
        setSorting={setSorting}
        pagination={pagination}
        setPagination={setPagination}
        pageCount={pageCount}
        rowCount={filteredData.length}
        bulkActions={bulkActions}
        showBulkDeleteButton={selectedCount > 0}
        emptyTitle={searchQuery || isDefaultFilter.size > 0 ? 'Không tìm thấy mẫu' : 'Chưa có mẫu bảng lương'}
        emptyDescription={searchQuery || isDefaultFilter.size > 0 ? 'Thử thay đổi từ khóa hoặc bộ lọc.' : "Nhấn 'Thêm mẫu' để tạo cấu hình đầu tiên."}
      />

      {/* Mobile loading indicator */}
      {isMobile && (
        <div className="py-6 text-center">
          {mobileLoadedCount < filteredData.length ? (
            <p className="text-body-sm text-muted-foreground">Đang tải thêm...</p>
          ) : filteredData.length > 0 ? (
            <p className="text-body-sm text-muted-foreground">
              Đã hiển thị tất cả {filteredData.length} mẫu
            </p>
          ) : null}
        </div>
      )}

      {/* Create/Edit Dialog */}
      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{editingTemplateId ? 'Chỉnh sửa mẫu' : 'Tạo mẫu bảng lương'}</DialogTitle>
            <DialogDescription>
              Lựa chọn thành phần lương mặc định để tái sử dụng khi chạy bảng lương.
            </DialogDescription>
          </DialogHeader>
          <form className="space-y-4" onSubmit={handleSubmit}>
            <div className="grid gap-3">
              <Label htmlFor="template-name">Tên mẫu</Label>
              <Input
                id="template-name"
                className="h-9"
                required
                value={formState.name}
                onChange={(event) => setFormState((prev) => ({ ...prev, name: event.target.value }))}
              />
            </div>
            <div className="grid gap-3">
              <Label htmlFor="template-description">Mô tả</Label>
              <Textarea
                id="template-description"
                placeholder="Mục đích sử dụng, phòng ban áp dụng..."
                value={formState.description}
                onChange={(event) => setFormState((prev) => ({ ...prev, description: event.target.value }))}
              />
            </div>

            <div className="grid gap-2">
              <Label>Thành phần lương</Label>
              <div className="max-h-60 space-y-2 overflow-y-auto rounded-lg border p-3">
                {salaryComponents
                  .filter((c) => c.isActive !== false)
                  .sort((a, b) => (a.sortOrder ?? 0) - (b.sortOrder ?? 0))
                  .map((component) => {
                    const componentSystemId = asSystemId(component.systemId);
                    const checked = formState.componentSystemIds.includes(componentSystemId);
                    return (
                      <label
                        key={component.systemId}
                        className="flex cursor-pointer items-center gap-3 text-body-sm"
                      >
                        <Checkbox
                          checked={checked}
                          onCheckedChange={() => toggleComponentSelection(componentSystemId)}
                          className="h-4 w-4"
                        />
                        <div className="flex-1">
                          <div className="flex items-center gap-2">
                            <p className="font-medium">{component.name}</p>
                            <Badge
                              variant="outline"
                              className={`text-xs ${
                                component.category === 'earning'
                                  ? 'border-green-200 bg-green-50 text-green-700'
                                  : component.category === 'deduction'
                                    ? 'border-red-200 bg-red-50 text-red-700'
                                    : 'border-blue-200 bg-blue-50 text-blue-700'
                              }`}
                            >
                              {component.category === 'earning'
                                ? 'Thu nhập'
                                : component.category === 'deduction'
                                  ? 'Khấu trừ'
                                  : 'Đóng góp'}
                            </Badge>
                          </div>
                          <p className="text-body-xs text-muted-foreground">
                            {component.type === 'fixed' ? 'Cố định' : component.formula ?? 'Theo công thức'}
                          </p>
                        </div>
                      </label>
                    );
                  })}
                {salaryComponents.filter((c) => c.isActive !== false).length === 0 && (
                  <p className="text-body-sm text-muted-foreground">
                    Chưa có thành phần lương trong Cài đặt &gt; Nhân viên.
                  </p>
                )}
              </div>
            </div>

            <label className="flex cursor-pointer items-center gap-3 text-body-sm font-medium">
              <Checkbox
                checked={formState.isDefault}
                onCheckedChange={(checked) =>
                  setFormState((prev) => ({ ...prev, isDefault: Boolean(checked) }))
                }
                className="h-4 w-4"
              />
              Đặt làm mẫu mặc định
            </label>

            <DialogFooter className="flex flex-row items-center justify-between gap-2">
              <Button type="button" variant="outline" className="h-9" onClick={resetDialog}>
                Hủy
              </Button>
              <Button type="submit" className="h-9">
                {editingTemplateId ? 'Lưu thay đổi' : 'Tạo mẫu'}
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>

      {/* Reset Confirmation Dialog */}
      <AlertDialog open={isResetDialogOpen} onOpenChange={setIsResetDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Khôi phục mẫu mặc định?</AlertDialogTitle>
            <AlertDialogDescription>
              Thao tác này sẽ xóa tất cả các mẫu hiện tại và thay thế bằng 5 mẫu mặc định theo chuẩn
              Việt Nam:
              <ul className="mt-2 list-inside list-disc space-y-1">
                <li>Mẫu lương cơ bản</li>
                <li>Mẫu lương nhân viên văn phòng</li>
                <li>Mẫu lương quản lý</li>
                <li>Mẫu lương kinh doanh</li>
                <li>Mẫu lương toàn bộ</li>
              </ul>
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Hủy</AlertDialogCancel>
            <AlertDialogAction onClick={handleResetToDefault}>Khôi phục</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Delete Confirmation Dialog */}
      <AlertDialog open={!!deleteConfirmId} onOpenChange={(open) => !open && setDeleteConfirmId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Xác nhận xóa mẫu?</AlertDialogTitle>
            <AlertDialogDescription>
              Bạn có chắc chắn muốn xóa mẫu bảng lương này không? Hành động này không thể hoàn tác.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Hủy</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleConfirmDelete}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              Xóa mẫu
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Implementation Notes */}
      <Card>
        <CardHeader>
          <CardTitle className="text-h4">Ghi chú triển khai</CardTitle>
        </CardHeader>
        <CardContent className="space-y-3 text-body-sm text-muted-foreground">
          <div className="flex items-center gap-2">
            <CheckCircle2 className="h-4 w-4 text-emerald-500" />
            Mỗi mẫu sẽ đồng bộ với wizard chạy lương trong các bước tiếp theo.
          </div>
          <div className="flex items-center gap-2">
            <CheckCircle2 className="h-4 w-4 text-emerald-500" />
            Thuế TNCN và bảo hiểm (BHXH, BHYT, BHTN) được tính tự động theo cài đặt trong{' '}
            <strong>Cài đặt → Nhân viên</strong>.
          </div>
          <div className="flex items-center gap-2">
            <CheckCircle2 className="h-4 w-4 text-emerald-500" />
            Khi backend sẵn sàng, các mẫu này sẽ được map sang API `/payroll/templates` mà không cần
            thay đổi UI.
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import * as React from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../../../components/ui/card';
import { Button } from '../../../components/ui/button';
import { Badge } from '../../../components/ui/badge';
import { Separator } from '../../../components/ui/separator';
import { Alert, AlertDescription, AlertTitle } from '../../../components/ui/alert';
import { 
  Globe, 
  Unlink, 
  Upload, 
  ExternalLink, 
  CheckCircle2, 
  AlertCircle, 
  Loader2,
  DollarSign,
  Package,
  FileText,
  Search,
  Star
} from 'lucide-react';
import { toast } from 'sonner';
import type { Product } from '../types';
import { usePkgxSettingsStore } from '../../settings/pkgx/store';
import { useProductMutations } from '../hooks/use-products';
import * as pkgxApi from '../../../lib/pkgx/api-service';
import { 
  mapHrmToPkgxPayload, 
  createPriceUpdatePayload, 
  createSeoUpdatePayload,
  createDescriptionUpdatePayload,
  createFlagsUpdatePayload,
  getTotalInventory 
} from '../../../lib/pkgx/mapping-service';

interface EcommerceTabProps {
  product: Product;
}

export function EcommerceTab({ product }: EcommerceTabProps) {
  const [isPushingPkgx, setIsPushingPkgx] = React.useState(false);
  const [isSyncingPrice, setIsSyncingPrice] = React.useState(false);
  const [isSyncingStock, setIsSyncingStock] = React.useState(false);
  const [isSyncingSeo, setIsSyncingSeo] = React.useState(false);
  const [isSyncingDesc, setIsSyncingDesc] = React.useState(false);
  const [isSyncingFlags, setIsSyncingFlags] = React.useState(false);
  const [isUnlinking, setIsUnlinking] = React.useState(false);
  
  const queryClient = useQueryClient();
  const pkgxSettings = usePkgxSettingsStore();
  const { update: updateMutation } = useProductMutations();
  const updateProduct = (systemId: string, data: Partial<Product>) => 
    updateMutation.mutate({ systemId, ...data });
  
  const isPkgxLinked = !!product.pkgxId;
  const isTrendtechLinked = !!product.trendtechId;
  
  // Get category mapping for this product
  const pkgxCategoryMapping = React.useMemo(() => {
    if (!product.categorySystemId) return null;
    return null; // getCategoryMappingByHrmId not available
  }, [product.categorySystemId]);
  
  // Get brand mapping for this product
  const pkgxBrandMapping = React.useMemo(() => {
    if (!product.brandSystemId) return null;
    return null; // getBrandMappingByHrmId not available
  }, [product.brandSystemId]);
  
  // Check if product can be pushed to PKGX
  const canPushToPkgx = React.useMemo(() => {
    if (!(pkgxSettings as any)?.apiUrl || !(pkgxSettings as any)?.apiKey) return false;
    if (!(pkgxSettings as any)?.enabled) return false;
    // Must have category mapping
    if (!pkgxCategoryMapping) return false;
    return true;
  }, [pkgxSettings, pkgxCategoryMapping]);
  
  // Push product to PKGX
  const handlePushToPkgx = async () => {
    if (!canPushToPkgx) {
      toast.error('Chưa cấu hình đủ thông tin để đẩy lên PKGX');
      return;
    }
    
    setIsPushingPkgx(true);
    try {
      const payload = mapHrmToPkgxPayload(product);
      
      let response;
      if (isPkgxLinked) {
        // Update existing
        response = await pkgxApi.updateProduct(product.pkgxId!, payload, pkgxSettings as any);
      } else {
        // Create new
        response = await pkgxApi.createProduct(payload, pkgxSettings as any);
      }
      
      if (response.success && response.data) {
        // Update product with PKGX ID if newly created
        if (!isPkgxLinked && response.data.goods_id) {
          updateProduct(product.systemId, { 
            pkgxId: response.data.goods_id,
            updatedAt: new Date().toISOString(),
          });
          
          // Invalidate React Query cache so list page refreshes immediately
          queryClient.invalidateQueries({ queryKey: ['products'] });
        }
        
        pkgxSettings.addLog({
          action: isPkgxLinked ? 'update_product' : 'create_product',
          status: 'success',
          message: `${isPkgxLinked ? 'Cập nhật' : 'Tạo mới'} sản phẩm trên PKGX: ${product.name}`,
          details: { productId: product.systemId, pkgxId: response.data.goods_id || product.pkgxId },
        });
        
        toast.success(isPkgxLinked ? 'Đã cập nhật sản phẩm trên PKGX' : 'Đã đẩy sản phẩm lên PKGX');
      } else {
        throw new Error(response.error || 'Lỗi không xác định');
      }
    } catch (error) {
      pkgxSettings.addLog({
        action: isPkgxLinked ? 'update_product' : 'create_product',
        status: 'error',
        message: `Lỗi ${isPkgxLinked ? 'cập nhật' : 'tạo'} sản phẩm: ${product.name}`,
        details: { error: error instanceof Error ? error.message : String(error) },
      });
      toast.error(error instanceof Error ? error.message : 'Lỗi khi đẩy sản phẩm lên PKGX');
    } finally {
      setIsPushingPkgx(false);
    }
  };
  
  // Sync price to PKGX
  const handleSyncPrice = async () => {
    if (!isPkgxLinked) {
      toast.error('Sản phẩm chưa liên kết với PKGX');
      return;
    }
    
    setIsSyncingPrice(true);
    try {
      const pricePayload = createPriceUpdatePayload(product);
      
      const response = await pkgxApi.updateProduct(product.pkgxId!, pricePayload, pkgxSettings as any);
      
      if (response.success) {
        pkgxSettings.addLog({
          action: 'sync_price',
          status: 'success',
          message: `Đồng bộ giá thành công: ${product.name}`,
          details: { productId: product.systemId, pkgxId: product.pkgxId },
        });
        toast.success('Đã đồng bộ giá lên PKGX');
      } else {
        throw new Error(response.error || 'Lỗi không xác định');
      }
    } catch (error) {
      pkgxSettings.addLog({
        action: 'sync_price',
        status: 'error',
        message: `Lỗi đồng bộ giá: ${product.name}`,
        details: { error: error instanceof Error ? error.message : String(error) },
      });
      toast.error(error instanceof Error ? error.message : 'Lỗi khi đồng bộ giá');
    } finally {
      setIsSyncingPrice(false);
    }
  };
  
  // Sync stock to PKGX
  const handleSyncStock = async () => {
    if (!isPkgxLinked) {
      toast.error('Sản phẩm chưa liên kết với PKGX');
      return;
    }
    
    setIsSyncingStock(true);
    try {
      const totalStock = getTotalInventory(product);
      
      const response = await pkgxApi.updateProductStock(product.pkgxId!, totalStock);
      
      if (response.success) {
        pkgxSettings.addLog({
          action: 'sync_inventory',
          status: 'success',
          message: `Đồng bộ tồn kho thành công: ${product.name} (${totalStock})`,
          details: { productId: product.systemId, pkgxId: product.pkgxId, inventory: totalStock },
        });
        toast.success(`Đã đồng bộ tồn kho: ${totalStock} ${product.unit}`);
      } else {
        throw new Error(response.error || 'Lỗi không xác định');
      }
    } catch (error) {
      pkgxSettings.addLog({
        action: 'sync_inventory',
        status: 'error',
        message: `Lỗi đồng bộ tồn kho: ${product.name}`,
        details: { error: error instanceof Error ? error.message : String(error) },
      });
      toast.error(error instanceof Error ? error.message : 'Lỗi khi đồng bộ tồn kho');
    } finally {
      setIsSyncingStock(false);
    }
  };
  
  // Sync SEO to PKGX
  const handleSyncSeo = async () => {
    if (!isPkgxLinked) {
      toast.error('Sản phẩm chưa liên kết với PKGX');
      return;
    }
    
    setIsSyncingSeo(true);
    try {
      const seoPayload = createSeoUpdatePayload(product);
      const response = await pkgxApi.updateProduct(product.pkgxId!, seoPayload);
      
      if (response.success) {
        pkgxSettings.addLog({
          action: 'sync_seo',
          status: 'success',
          message: `Đồng bộ SEO thành công: ${product.name}`,
          details: { productId: product.systemId, pkgxId: product.pkgxId },
        });
        toast.success('Đã đồng bộ SEO lên PKGX');
      } else {
        throw new Error(response.error || 'Lỗi không xác định');
      }
    } catch (error) {
      pkgxSettings.addLog({
        action: 'sync_seo',
        status: 'error',
        message: `Lỗi đồng bộ SEO: ${product.name}`,
        details: { error: error instanceof Error ? error.message : String(error) },
      });
      toast.error(error instanceof Error ? error.message : 'Lỗi khi đồng bộ SEO');
    } finally {
      setIsSyncingSeo(false);
    }
  };
  
  // Sync Description to PKGX
  const handleSyncDescription = async () => {
    if (!isPkgxLinked) {
      toast.error('Sản phẩm chưa liên kết với PKGX');
      return;
    }
    
    setIsSyncingDesc(true);
    try {
      const descPayload = createDescriptionUpdatePayload(product);
      const response = await pkgxApi.updateProduct(product.pkgxId!, descPayload);
      
      if (response.success) {
        pkgxSettings.addLog({
          action: 'update_product',
          status: 'success',
          message: `Đồng bộ mô tả thành công: ${product.name}`,
          details: { productId: product.systemId, pkgxId: product.pkgxId },
        });
        toast.success('Đã đồng bộ mô tả lên PKGX');
      } else {
        throw new Error(response.error || 'Lỗi không xác định');
      }
    } catch (error) {
      pkgxSettings.addLog({
        action: 'update_product',
        status: 'error',
        message: `Lỗi đồng bộ mô tả: ${product.name}`,
        details: { error: error instanceof Error ? error.message : String(error) },
      });
      toast.error(error instanceof Error ? error.message : 'Lỗi khi đồng bộ mô tả');
    } finally {
      setIsSyncingDesc(false);
    }
  };
  
  // Sync Flags to PKGX
  const handleSyncFlags = async () => {
    if (!isPkgxLinked) {
      toast.error('Sản phẩm chưa liên kết với PKGX');
      return;
    }
    
    setIsSyncingFlags(true);
    try {
      const flagsPayload = createFlagsUpdatePayload(product);
      const response = await pkgxApi.updateProduct(product.pkgxId!, flagsPayload);
      
      if (response.success) {
        pkgxSettings.addLog({
          action: 'update_product',
          status: 'success',
          message: `Đồng bộ flags thành công: ${product.name}`,
          details: { productId: product.systemId, pkgxId: product.pkgxId },
        });
        toast.success('Đã đồng bộ flags lên PKGX');
      } else {
        throw new Error(response.error || 'Lỗi không xác định');
      }
    } catch (error) {
      pkgxSettings.addLog({
        action: 'update_product',
        status: 'error',
        message: `Lỗi đồng bộ flags: ${product.name}`,
        details: { error: error instanceof Error ? error.message : String(error) },
      });
      toast.error(error instanceof Error ? error.message : 'Lỗi khi đồng bộ flags');
    } finally {
      setIsSyncingFlags(false);
    }
  };
  
  // View on PKGX website
  const handleViewOnPkgx = () => {
    if (!isPkgxLinked) {
      toast.error('Sản phẩm chưa liên kết với PKGX');
      return;
    }
    
    const slug = product.pkgxSlug || `product-${product.pkgxId}`;
    const url = `https://phukiengiaxuong.com.vn/${slug}.html`;
    window.open(url, '_blank');
  };
  
  // Unlink from PKGX
  const handleUnlinkPkgx = async () => {
    if (!isPkgxLinked) return;
    
    setIsUnlinking(true);
    try {
      updateProduct(product.systemId, { 
        pkgxId: undefined,
        updatedAt: new Date().toISOString(),
      });
      
      pkgxSettings.addLog({
        action: 'unlink_product',
        status: 'success',
        message: `Hủy liên kết sản phẩm: ${product.name}`,
        details: { productId: product.systemId, pkgxId: product.pkgxId },
      });
      
      toast.success('Đã hủy liên kết với PKGX');
    } catch (_error) {
      toast.error('Lỗi khi hủy liên kết');
    } finally {
      setIsUnlinking(false);
    }
  };
  
  return (
    <div className="space-y-4">
      {/* PKGX Section */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Globe className="h-5 w-5 text-orange-500" />
              <CardTitle className="text-lg">PKGX (phukiengiaxuong.com.vn)</CardTitle>
            </div>
            {isPkgxLinked ? (
              <Badge variant="default" className="bg-green-500">
                <CheckCircle2 className="h-3 w-3 mr-1" />
                Đã liên kết
              </Badge>
            ) : (
              <Badge variant="secondary">Chưa liên kết</Badge>
            )}
          </div>
          <CardDescription>
            Quản lý sản phẩm trên website PKGX
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {/* Status Info */}
          {isPkgxLinked && (
            <div className="flex items-center gap-4 p-3 bg-muted/50 rounded-lg">
              <div className="flex-1 grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
                <div>
                  <span className="text-muted-foreground">ID PKGX:</span>
                  <span className="ml-2 font-mono font-medium">{product.pkgxId}</span>
                </div>
                <div>
                  <span className="text-muted-foreground">Slug:</span>
                  <span className="ml-2 font-mono text-xs">{product.pkgxSlug || '-'}</span>
                </div>
              </div>
              <Button
                variant="outline"
                size="sm"
                onClick={() => window.open(`https://phukiengiaxuong.com.vn/goods-${product.pkgxId}.html`, '_blank')}
              >
                <ExternalLink className="h-4 w-4 mr-1" />
                Xem
              </Button>
            </div>
          )}
          
          {/* Mapping Status */}
          <div className="space-y-2">
            <p className="text-sm font-medium text-muted-foreground">Trạng thái mapping:</p>
            <div className="flex flex-wrap gap-2">
              <Badge variant={pkgxCategoryMapping ? 'default' : 'destructive'} className="text-xs">
                {pkgxCategoryMapping ? (
                  <>✓ Danh mục: {(pkgxCategoryMapping as any).pkgxCatName}</>
                ) : (
                  <>✗ Chưa mapping danh mục</>
                )}
              </Badge>
              <Badge variant={pkgxBrandMapping ? 'default' : 'secondary'} className="text-xs">
                {pkgxBrandMapping ? (
                  <>✓ Thương hiệu: {(pkgxBrandMapping as any).pkgxBrandName}</>
                ) : (
                  <>- Không có thương hiệu</>
                )}
              </Badge>
            </div>
          </div>
          
          {/* Warnings */}
          {!canPushToPkgx && (
            <Alert variant="destructive">
              <AlertCircle className="h-4 w-4" />
              <AlertTitle>Không thể đẩy lên PKGX</AlertTitle>
              <AlertDescription>
                <ul className="list-disc list-inside text-sm mt-1">
                  {!pkgxSettings.settings.enabled && <li>PKGX chưa được bật</li>}
                  {!pkgxSettings.settings.apiUrl && <li>Chưa cấu hình API URL</li>}
                  {!pkgxSettings.settings.apiKey && <li>Chưa cấu hình API Key</li>}
                  {!pkgxCategoryMapping && <li>Danh mục sản phẩm chưa được mapping với PKGX</li>}
                </ul>
              </AlertDescription>
            </Alert>
          )}
          
          <Separator />
          
          {/* Actions */}
          <div className="flex flex-wrap gap-2">
            <Button
              onClick={handlePushToPkgx}
              disabled={!canPushToPkgx || isPushingPkgx}
            >
              {isPushingPkgx ? (
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
              ) : (
                <Upload className="h-4 w-4 mr-2" />
              )}
              {isPkgxLinked ? 'Cập nhật PKGX' : 'Đẩy lên PKGX'}
            </Button>
            
            {isPkgxLinked && (
              <>
                <Button
                  variant="outline"
                  onClick={handleSyncPrice}
                  disabled={isSyncingPrice}
                >
                  {isSyncingPrice ? (
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  ) : (
                    <DollarSign className="h-4 w-4 mr-2" />
                  )}
                  Sync giá
                </Button>
                
                <Button
                  variant="outline"
                  onClick={handleSyncStock}
                  disabled={isSyncingStock}
                >
                  {isSyncingStock ? (
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  ) : (
                    <Package className="h-4 w-4 mr-2" />
                  )}
                  Sync tồn kho
                </Button>
                
                <Button
                  variant="outline"
                  onClick={handleSyncSeo}
                  disabled={isSyncingSeo}
                >
                  {isSyncingSeo ? (
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  ) : (
                    <Search className="h-4 w-4 mr-2" />
                  )}
                  Sync SEO
                </Button>
                
                <Button
                  variant="outline"
                  onClick={handleSyncDescription}
                  disabled={isSyncingDesc}
                >
                  {isSyncingDesc ? (
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  ) : (
                    <FileText className="h-4 w-4 mr-2" />
                  )}
                  Sync mô tả
                </Button>
                
                <Button
                  variant="outline"
                  onClick={handleSyncFlags}
                  disabled={isSyncingFlags}
                >
                  {isSyncingFlags ? (
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  ) : (
                    <Star className="h-4 w-4 mr-2" />
                  )}
                  Sync flags
                </Button>
                
                <Button
                  variant="outline"
                  onClick={handleViewOnPkgx}
                >
                  <ExternalLink className="h-4 w-4 mr-2" />
                  Xem trên web
                </Button>
                
                <Button
                  variant="ghost"
                  onClick={handleUnlinkPkgx}
                  disabled={isUnlinking}
                  className="text-destructive hover:text-destructive"
                >
                  {isUnlinking ? (
                    <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                  ) : (
                    <Unlink className="h-4 w-4 mr-2" />
                  )}
                  Hủy liên kết
                </Button>
              </>
            )}
          </div>
        </CardContent>
      </Card>
      
      {/* Trendtech Section */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Globe className="h-5 w-5 text-blue-500" />
              <CardTitle className="text-lg">Trendtech</CardTitle>
            </div>
            {isTrendtechLinked ? (
              <Badge variant="default" className="bg-green-500">
                <CheckCircle2 className="h-3 w-3 mr-1" />
                Đã liên kết
              </Badge>
            ) : (
              <Badge variant="secondary">Chưa liên kết</Badge>
            )}
          </div>
          <CardDescription>
            Quản lý sản phẩm trên website Trendtech
          </CardDescription>
        </CardHeader>
        <CardContent>
          {isTrendtechLinked ? (
            <div className="space-y-4">
              <div className="flex items-center gap-4 p-3 bg-muted/50 rounded-lg">
                <div className="flex-1">
                  <span className="text-muted-foreground text-sm">ID Trendtech:</span>
                  <span className="ml-2 font-mono font-medium">{product.trendtechId}</span>
                </div>
              </div>
              <p className="text-sm text-muted-foreground">
                Chức năng sync Trendtech sẽ sớm được triển khai.
              </p>
            </div>
          ) : (
            <div className="text-center py-6 text-muted-foreground">
              <Globe className="h-12 w-12 mx-auto mb-3 opacity-30" />
              <p>Trendtech API chưa sẵn sàng</p>
              <p className="text-sm mt-1">Chức năng sẽ được kích hoạt khi API hoàn thiện</p>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

import * as React from 'react';
import { Link2 } from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { VirtualizedCombobox, type ComboboxOption } from '@/components/ui/virtualized-combobox';
import { useAllProducts } from '../hooks/use-all-products';
import { useProductMutations } from '../hooks/use-products';
import type { Product } from '../types';
import type { PkgxProduct } from '@/features/settings/pkgx/types';
import { usePkgxSettings, usePkgxProductsMutations } from '@/features/settings/pkgx/hooks/use-pkgx-settings';

interface PkgxLinkDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  product: Product | null;
  onSuccess?: (pkgxId: number) => void;
}

export function PkgxLinkDialog({
  open,
  onOpenChange,
  product,
  onSuccess,
}: PkgxLinkDialogProps) {
  const { update: updateMutation } = useProductMutations();
  const { data: pkgxSettings } = usePkgxSettings();
  const { setPkgxProducts: setProducts } = usePkgxProductsMutations();
  const cachedPkgxProducts = React.useMemo(() => pkgxSettings?.pkgxProducts ?? [], [pkgxSettings?.pkgxProducts]);
  
  const [selectedPkgxProduct, setSelectedPkgxProduct] = React.useState<ComboboxOption | null>(null);
  const [pkgxProducts, setPkgxProductsLocal] = React.useState<PkgxProduct[]>([]);
  const [isLoading, setIsLoading] = React.useState(false);
  const [isSyncing, setIsSyncing] = React.useState(false);
  const [hasFetched, setHasFetched] = React.useState(false);

  const loadPkgxProducts = React.useCallback(async () => {
    setIsLoading(true);
    try {
      // fetchPkgxProducts not available - use placeholder
      const response: any = { success: false, data: null };
      if (response.success && response.data && response.data.data) {
        // API trả về { data: PkgxProduct[], pagination: {...} }
        const productsArray = Array.isArray(response.data.data) ? response.data.data : [];
        setPkgxProductsLocal(productsArray);
        setProducts.mutate(productsArray); // Lưu vào store để dùng chung
        setHasFetched(true);
      }
    } catch (error) {
      console.error('Failed to load PKGX products:', error);
      toast.error('Không thể tải danh sách sản phẩm PKGX');
    } finally {
      setIsLoading(false);
    }
  }, [setProducts]);

  // Load PKGX products khi mở dialog - chỉ chạy 1 lần
  React.useEffect(() => {
    if (open && !hasFetched) {
      if (cachedPkgxProducts && cachedPkgxProducts.length > 0) {
        setPkgxProductsLocal(cachedPkgxProducts);
        setHasFetched(true);
      } else {
        loadPkgxProducts();
      }
    }
  }, [open, hasFetched, cachedPkgxProducts, loadPkgxProducts]);

  // Reset state khi đóng dialog
  React.useEffect(() => {
    if (!open) {
      setSelectedPkgxProduct(null);
    }
  }, [open]);

  // Filter out products that are already linked
  const { data: hrmProducts } = useAllProducts();
  const linkedPkgxIds = React.useMemo(() => {
    return new Set(hrmProducts.filter(p => p.pkgxId).map(p => p.pkgxId));
  }, [hrmProducts]);

  // Convert PKGX products to combobox options
  const pkgxOptions: ComboboxOption[] = React.useMemo(() => {
    return pkgxProducts
      .filter(p => !linkedPkgxIds.has(p.goods_id)) // Exclude already linked
      .map(p => ({
        value: String(p.goods_id),
        label: p.goods_name,
        subtitle: `ID: ${p.goods_id} | Mã: ${p.goods_sn || '-'}`,
        metadata: p,
      }));
  }, [pkgxProducts, linkedPkgxIds]);

  const handleConfirmLink = async () => {
    if (!product || !selectedPkgxProduct) {
      toast.error('Vui lòng chọn sản phẩm PKGX để liên kết');
      return;
    }

    setIsSyncing(true);
    try {
      const pkgxId = Number(selectedPkgxProduct.value);
      
      // Update HRM product with pkgxId
      updateMutation.mutate({ systemId: product.systemId, pkgxId });
      
      // Log to console

      toast.success(`Đã liên kết với sản phẩm PKGX: ${selectedPkgxProduct.label}`);
      onSuccess?.(pkgxId);
      onOpenChange(false);
    } catch (error) {
      console.error('[PKGX Link Error]', error);
      toast.error('Lỗi khi liên kết sản phẩm');
    } finally {
      setIsSyncing(false);
    }
  };

  if (!product) return null;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-[500px]">
        <DialogHeader>
          <DialogTitle>Liên kết với sản phẩm PKGX</DialogTitle>
          <DialogDescription>
            Chọn sản phẩm PKGX để liên kết với sản phẩm HRM này
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4 py-4">
          {/* HRM Product Info */}
          <div className="rounded-lg bg-muted p-3">
            <p className="text-sm font-medium">Sản phẩm HRM:</p>
            <p className="text-sm">{product.name}</p>
            <p className="text-xs text-muted-foreground">
              Mã: {product.id} | SystemID: {product.systemId}
            </p>
          </div>

          {/* PKGX Product Selector */}
          <div className="space-y-2">
            <label className="text-sm font-medium">Chọn sản phẩm PKGX</label>
            <VirtualizedCombobox
              value={selectedPkgxProduct}
              onChange={setSelectedPkgxProduct}
              options={pkgxOptions}
              placeholder="Tìm và chọn sản phẩm PKGX..."
              searchPlaceholder="Tìm theo tên hoặc mã..."
              emptyPlaceholder={isLoading ? 'Đang tải...' : 'Không tìm thấy sản phẩm PKGX'}
              isLoading={isLoading}
              disabled={isLoading}
            />
            {pkgxOptions.length === 0 && !isLoading && (
              <p className="text-xs text-muted-foreground">
                Tất cả sản phẩm PKGX đã được liên kết. Hãy đồng bộ danh sách mới từ PKGX.
              </p>
            )}
          </div>
        </div>

        <DialogFooter>
          <Button
            variant="outline"
            onClick={() => onOpenChange(false)}
            disabled={isSyncing}
          >
            Hủy
          </Button>
          <Button
            onClick={handleConfirmLink}
            disabled={!selectedPkgxProduct || isSyncing}
          >
            <Link2 className="h-4 w-4 mr-2" />
            {isSyncing ? 'Đang liên kết...' : 'Liên kết'}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import * as React from "react";
import { asBusinessId } from "@/lib/id-types";
import { useProductMutations } from "../hooks/use-products";
import { toast } from 'sonner';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "../../../components/ui/dialog";
import { Button } from "../../../components/ui/button";
import { Input } from "../../../components/ui/input";
import { Label } from "../../../components/ui/label";
import { CurrencyInput } from "../../../components/ui/currency-input";

interface QuickAddProductDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSuccess?: (productId: string) => void;
}

export function QuickAddProductDialog({
  open,
  onOpenChange,
  onSuccess,
}: QuickAddProductDialogProps) {
  const { create: createMutation } = useProductMutations({
    onCreateSuccess: (data) => {
      toast.success(`Đã thêm sản phẩm`);
      onOpenChange(false);
      if (onSuccess && data && typeof data === 'object' && 'systemId' in data) {
        onSuccess((data as { systemId: string }).systemId);
      }
    },
    onError: () => {
      toast.error('Không thể thêm sản phẩm. Vui lòng thử lại.');
    }
  });
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  // Form state
  const [formData, setFormData] = React.useState({
    name: "",
    sku: "",
    costPrice: "",
    basePrice: "",
    importQuantity: "",
    category: "",
    unit: "Cái",
    productType: "regular" as "regular" | "serial-imei",
  });

  // Validation errors
  const [errors, setErrors] = React.useState<Record<string, string>>({});

  // Auto-focus first input when dialog opens
  const nameInputRef = React.useRef<HTMLInputElement>(null);
  React.useEffect(() => {
    if (open) {
      setTimeout(() => nameInputRef.current?.focus(), 100);
    }
  }, [open]);

  // Reset form when dialog closes
  React.useEffect(() => {
    if (!open) {
      setFormData({
        name: "",
        sku: "",
        costPrice: "",
        basePrice: "",
        importQuantity: "",
        category: "",
        unit: "Cái",
        productType: "regular",
      });
      setErrors({});
      setIsSubmitting(false);
    }
  }, [open]);

  const validateForm = (): boolean => {
    const newErrors: Record<string, string> = {};

    if (!formData.name.trim()) {
      newErrors.name = "Tên sản phẩm là bắt buộc";
    }

    if (formData.costPrice && isNaN(Number(formData.costPrice))) {
      newErrors.costPrice = "Giá nhập phải là số";
    }

    if (formData.costPrice && Number(formData.costPrice) < 0) {
      newErrors.costPrice = "Giá nhập không thể âm";
    }

    if (formData.basePrice && isNaN(Number(formData.basePrice))) {
      newErrors.basePrice = "Giá bán lẻ phải là số";
    }

    if (formData.basePrice && Number(formData.basePrice) < 0) {
      newErrors.basePrice = "Giá bán lẻ không thể âm";
    }

    if (formData.importQuantity && isNaN(Number(formData.importQuantity))) {
      newErrors.importQuantity = "Số lượng nhập phải là số";
    }

    if (formData.importQuantity && Number(formData.importQuantity) < 0) {
      newErrors.importQuantity = "Số lượng nhập không thể âm";
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validateForm()) {
      return;
    }

    setIsSubmitting(true);

    try {
      const rawId = formData.sku.trim().toUpperCase();
      const newProduct = {
        id: asBusinessId(rawId),
        name: formData.name.trim(),
        unit: formData.unit,
        costPrice: formData.costPrice ? Number(formData.costPrice) : 0,
        prices: {}, // Will be populated with default pricing policy
        category: formData.category.trim() || undefined,
        type: "physical" as const,
        status: "active" as const,
        isStockTracked: formData.productType === "regular",
        inventoryByBranch: {},
        committedByBranch: {},
        inTransitByBranch: {},
      };

      (createMutation.mutate as any)(newProduct);
    } catch (_error) {
      toast.error('Không thể thêm sản phẩm. Vui lòng thử lại.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Thêm nhanh sản phẩm</DialogTitle>
          <DialogDescription>
            Nhập thông tin sản phẩm mới. Các trường có dấu * là bắt buộc.
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Tên sản phẩm */}
          <div className="space-y-2">
            <Label htmlFor="product-name">
              Tên sản phẩm <span className="text-destructive">*</span>
            </Label>
            <Input
              id="product-name"
              ref={nameInputRef}
              placeholder="Nhập tên sản phẩm"
              value={formData.name}
              onChange={(e) =>
                setFormData((prev) => ({ ...prev, name: e.target.value }))
              }
              className={errors.name ? "border-destructive" : ""}
            />
            {errors.name && (
              <p className="text-body-sm text-destructive">{errors.name}</p>
            )}
          </div>

          {/* Mã sản phẩm/SKU */}
          <div className="space-y-2">
            <Label htmlFor="product-sku">Mã sản phẩm/SKU</Label>
            <Input
              id="product-sku"
              placeholder="Nhập tay hoặc để trống để tự động"
              value={formData.sku}
              onChange={(e) =>
                setFormData((prev) => ({ ...prev, sku: e.target.value }))
              }
            />
          </div>

          {/* Row 1: Giá nhập + Giá bán lẻ */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="product-cost">Giá nhập</Label>
              <CurrencyInput
                id="product-cost"
                value={formData.costPrice ? Number(formData.costPrice) : 0}
                onChange={(value) =>
                  setFormData((prev) => ({ ...prev, costPrice: value.toString() }))
                }
                placeholder="0"
                className={errors.costPrice ? "border-destructive" : ""}
              />
              {errors.costPrice && (
                <p className="text-body-sm text-destructive">{errors.costPrice}</p>
              )}
            </div>

            <div className="space-y-2">
              <Label htmlFor="product-base-price">Giá bán lẻ</Label>
              <CurrencyInput
                id="product-base-price"
                value={formData.basePrice ? Number(formData.basePrice) : 0}
                onChange={(value) =>
                  setFormData((prev) => ({ ...prev, basePrice: value.toString() }))
                }
                placeholder="0"
                className={errors.basePrice ? "border-destructive" : ""}
              />
              {errors.basePrice && (
                <p className="text-body-sm text-destructive">{errors.basePrice}</p>
              )}
            </div>
          </div>

          {/* Row 2: Số lượng nhập + Loại sản phẩm */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="product-quantity">Số lượng nhập</Label>
              <Input
                id="product-quantity"
                type="number"
                min="0"
                step="1"
                placeholder="0"
                value={formData.importQuantity}
                onChange={(e) =>
                  setFormData((prev) => ({
                    ...prev,
                    importQuantity: e.target.value,
                  }))
                }
                className={errors.importQuantity ? "border-destructive" : ""}
              />
              {errors.importQuantity && (
                <p className="text-body-sm text-destructive">{errors.importQuantity}</p>
              )}
            </div>

            <div className="space-y-2">
              <Label htmlFor="product-category">Loại sản phẩm</Label>
              <Input
                id="product-category"
                placeholder="Nhập loại sản phẩm"
                value={formData.category}
                onChange={(e) =>
                  setFormData((prev) => ({ ...prev, category: e.target.value }))
                }
              />
            </div>
          </div>

          {/* Đơn vị tính */}
          <div className="space-y-2">
            <Label htmlFor="product-unit">Đơn vị tính</Label>
            <Input
              id="product-unit"
              placeholder="Cái, Hộp, Thùng..."
              value={formData.unit}
              onChange={(e) =>
                setFormData((prev) => ({ ...prev, unit: e.target.value }))
              }
            />
          </div>

          <DialogFooter className="gap-2">
            <Button
              type="button"
              variant="outline"
              onClick={() => onOpenChange(false)}
              disabled={isSubmitting}
            >
              Thoát
            </Button>
            <Button type="submit" disabled={isSubmitting}>
              {isSubmitting ? "Đang thêm..." : "Thêm"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

/**
 * Hook chứa tất cả các handlers để đồng bộ sản phẩm với PKGX
 */
import React from 'react';
import { toast } from 'sonner';
import type { Product } from '../types';
import { updateProduct, updateMemberPrice, uploadImageFromUrl, processHtmlImagesForPkgx } from '@/lib/pkgx/api-service';
import { usePkgxSettings } from '@/features/settings/pkgx/hooks/use-pkgx-settings';
import { useImageStore } from '../image-store';

// Types
type PkgxLogEntry = {
  action: 
    | 'ping'
    | 'test_connection'
    | 'sync_all'
    | 'sync_price'
    | 'sync_inventory'
    | 'sync_seo'
    | 'sync_description'
    | 'sync_flags'
    | 'sync_basic_info'
    | 'sync_images'
    | 'create_product'
    | 'update_product'
    | 'link_product'
    | 'unlink_product'
    | 'unlink_mapping'
    | 'sync_categories'
    | 'sync_brands'
    | 'get_products'
    | 'upload_image'
    | 'save_config'
    | 'save_mapping';
  status: 'success' | 'error' | 'partial' | 'info';
  message: string;
  details?: Record<string, unknown>;
};

type UsePkgxSyncOptions = {
  addPkgxLog: (entry: PkgxLogEntry) => void;
};

/**
 * Hook cung cấp các handlers để đồng bộ sản phẩm với PKGX
 */
export function usePkgxSync({ addPkgxLog }: UsePkgxSyncOptions) {
  const { data: pkgxSettings } = usePkgxSettings();

  // ═══════════════════════════════════════════════════════════════
  // HELPER: Get price by mapping
  // ═══════════════════════════════════════════════════════════════
  const getPriceByMapping = React.useCallback((product: Product, pkgxPriceField: string): number | undefined => {
    const priceMapping = pkgxSettings?.priceMapping;
    if (!priceMapping) return undefined;
    
    // priceMapping is PkgxPriceMapping { shopPrice, marketPrice, partnerPrice, acePrice, dealPrice }
    // Each field contains SystemId of HRM pricing policy
    let hrmPriceSystemId: string | null = null;
    
    switch (pkgxPriceField) {
      case 'shopPrice': hrmPriceSystemId = priceMapping.shopPrice; break;
      case 'marketPrice': hrmPriceSystemId = priceMapping.marketPrice; break;
      case 'partnerPrice': hrmPriceSystemId = priceMapping.partnerPrice; break;
      case 'acePrice': hrmPriceSystemId = priceMapping.acePrice; break;
      case 'dealPrice': hrmPriceSystemId = priceMapping.dealPrice; break;
    }
    
    if (!hrmPriceSystemId) return undefined;
    return product.prices?.[hrmPriceSystemId];
  }, [pkgxSettings]);

  // ═══════════════════════════════════════════════════════════════
  // HELPER: Check if has price mapping
  // ═══════════════════════════════════════════════════════════════
  const hasPriceMapping = React.useMemo(() => {
    const priceMapping = (pkgxSettings as any)?.priceMapping;
    return priceMapping && (
      priceMapping.shopPrice || 
      priceMapping.marketPrice || 
      priceMapping.partnerPrice || 
      priceMapping.acePrice || 
      priceMapping.dealPrice
    );
  }, [pkgxSettings]);

  // ═══════════════════════════════════════════════════════════════
  // HELPER: Get mapped category ID
  // ═══════════════════════════════════════════════════════════════
  const getMappedCategoryId = React.useCallback((product: Product): number | undefined => {
    if (!pkgxSettings?.categoryMappings || !product.categorySystemId) return undefined;
    const mapping = pkgxSettings.categoryMappings.find(m => m.hrmCategorySystemId === product.categorySystemId);
    return mapping?.pkgxCatId;
  }, [pkgxSettings?.categoryMappings]);

  // ═══════════════════════════════════════════════════════════════
  // HELPER: Get mapped brand ID
  // ═══════════════════════════════════════════════════════════════
  const getMappedBrandId = React.useCallback((product: Product): number | undefined => {
    if (!pkgxSettings?.brandMappings || !product.brandSystemId) return undefined;
    const mapping = pkgxSettings.brandMappings.find(m => m.hrmBrandSystemId === product.brandSystemId);
    return mapping?.pkgxBrandId;
  }, [pkgxSettings?.brandMappings]);

  // ═══════════════════════════════════════════════════════════════
  // 1. SYNC GIÁ (bao gồm cả giá thành viên ace)
  // ═══════════════════════════════════════════════════════════════
  const handlePkgxUpdatePrice = React.useCallback(async (product: Product) => {
    if (!product.pkgxId) {
      toast.error('Sản phẩm chưa được liên kết với PKGX');
      return;
    }

    if (!hasPriceMapping) {
      toast.error('Chưa cấu hình mapping giá. Vui lòng vào Cài đặt > PKGX > Mapping Giá để thiết lập.');
      return;
    }
    
    toast.loading(`Đang đồng bộ giá...`, { id: 'pkgx-sync-price' });
    
    try {
      const payload: Record<string, number> = {};
      
      const shopPrice = getPriceByMapping(product, 'shopPrice');
      if (shopPrice !== undefined) payload.shop_price = shopPrice;
      
      const marketPrice = getPriceByMapping(product, 'marketPrice');
      if (marketPrice !== undefined) payload.market_price = marketPrice;
      
      const partnerPrice = getPriceByMapping(product, 'partnerPrice');
      if (partnerPrice !== undefined) payload.partner_price = partnerPrice;
      
      const acePrice = getPriceByMapping(product, 'acePrice');
      if (acePrice !== undefined) payload.ace_price = acePrice;
      
      const dealPrice = getPriceByMapping(product, 'dealPrice');
      if (dealPrice !== undefined) payload.deal_price = dealPrice;

      if (Object.keys(payload).length === 0) {
        toast.error('Không có giá nào được mapping. Vui lòng kiểm tra cấu hình.', { id: 'pkgx-sync-price' });
        return;
      }
      
      // 1. Sync giá vào bảng goods
      const response = await updateProduct(product.pkgxId, payload);
      
      if (!response.success) {
        throw new Error(response.error);
      }

      // 2. Sync giá ace vào member_price table (ace = rank_id 8)
      let memberPriceSynced = false;
      if (acePrice !== undefined && acePrice > 0) {
        const memberPriceResponse = await updateMemberPrice(product.pkgxId, [
          { user_rank: 8, user_price: acePrice }
        ]);
        memberPriceSynced = memberPriceResponse.success;
      }
      
      const successMsg = memberPriceSynced 
        ? `Đã đồng bộ giá + giá ace thành viên: ${product.name}`
        : `Đã đồng bộ giá: ${product.name}`;
      
      toast.success(successMsg, { id: 'pkgx-sync-price' });
      addPkgxLog({
        action: 'sync_price',
        status: 'success',
        message: successMsg,
        details: { 
          productId: product.systemId, 
          pkgxId: product.pkgxId, 
          prices: payload,
          memberPriceSynced,
          acePrice: acePrice 
        },
      });
    } catch (error) {
      toast.error(`Lỗi đồng bộ giá: ${error instanceof Error ? error.message : 'Unknown error'}`, { id: 'pkgx-sync-price' });
      addPkgxLog({
        action: 'sync_price',
        status: 'error',
        message: `Lỗi đồng bộ giá: ${product.name}`,
        details: { productId: product.systemId, error: error instanceof Error ? error.message : String(error) },
      });
    }
  }, [hasPriceMapping, getPriceByMapping, addPkgxLog]);

  // ═══════════════════════════════════════════════════════════════
  // 2. SYNC TỒN KHO
  // ═══════════════════════════════════════════════════════════════
  const handlePkgxSyncInventory = React.useCallback(async (product: Product) => {
    if (!product.pkgxId) {
      toast.error('Sản phẩm chưa được liên kết với PKGX');
      return;
    }
    
    toast.loading(`Đang đồng bộ tồn kho...`, { id: 'pkgx-sync-inventory' });
    
    try {
      const totalInventory = product.inventoryByBranch
        ? Object.values(product.inventoryByBranch).reduce((sum, qty) => sum + (qty || 0), 0)
        : 0;
      
      const response = await updateProduct(product.pkgxId, {
        goods_number: totalInventory,
      });
      
      if (response.success) {
        toast.success(`Đã đồng bộ tồn kho: ${totalInventory} sản phẩm`, { id: 'pkgx-sync-inventory' });
        addPkgxLog({
          action: 'sync_inventory',
          status: 'success',
          message: `Đã đồng bộ tồn kho: ${product.name} (${totalInventory})`,
          details: { productId: product.systemId, pkgxId: product.pkgxId, inventory: totalInventory },
        });
      } else {
        throw new Error(response.error);
      }
    } catch (error) {
      toast.error(`Lỗi đồng bộ tồn kho: ${error instanceof Error ? error.message : 'Unknown error'}`, { id: 'pkgx-sync-inventory' });
      addPkgxLog({
        action: 'sync_inventory',
        status: 'error',
        message: `Lỗi đồng bộ tồn kho: ${product.name}`,
        details: { productId: product.systemId, error: error instanceof Error ? error.message : String(error) },
      });
    }
  }, [addPkgxLog]);

  // ═══════════════════════════════════════════════════════════════
  // 3. SYNC SEO
  // ═══════════════════════════════════════════════════════════════
  const handlePkgxUpdateSeo = React.useCallback(async (product: Product) => {
    if (!product.pkgxId) {
      toast.error('Sản phẩm chưa được liên kết với PKGX');
      return;
    }
    
    toast.loading(`Đang đồng bộ SEO...`, { id: 'pkgx-sync-seo' });
    
    try {
      const pkgxSeo = product.seoPkgx;
      // Fallback chain: SEO PKGX → SEO Chung → tags → name
      const seoPayload = {
        keywords: pkgxSeo?.seoKeywords || product.seoKeywords || product.tags?.join(', ') || product.name,
        meta_title: pkgxSeo?.seoTitle || product.ktitle || product.name,
        meta_desc: pkgxSeo?.metaDescription || product.seoDescription || '',
      };
      
      // DEBUG: Log payload để kiểm tra
      
      const response = await updateProduct(product.pkgxId, seoPayload);
      
      if (response.success) {
        toast.success(`Đã đồng bộ SEO cho sản phẩm: ${product.name}`, { id: 'pkgx-sync-seo' });
        addPkgxLog({
          action: 'sync_seo',
          status: 'success',
          message: `Đã đồng bộ SEO: ${product.name}`,
          details: { productId: product.systemId, pkgxId: product.pkgxId },
        });
      } else {
        throw new Error(response.error);
      }
    } catch (error) {
      toast.error(`Lỗi đồng bộ SEO: ${error instanceof Error ? error.message : 'Unknown error'}`, { id: 'pkgx-sync-seo' });
      addPkgxLog({
        action: 'sync_seo',
        status: 'error',
        message: `Lỗi đồng bộ SEO: ${product.name}`,
        details: { productId: product.systemId, error: error instanceof Error ? error.message : String(error) },
      });
    }
  }, [addPkgxLog]);

  // ═══════════════════════════════════════════════════════════════
  // 4. SYNC MÔ TẢ (với xử lý ảnh trong HTML)
  // ═══════════════════════════════════════════════════════════════
  const handlePkgxSyncDescription = React.useCallback(async (product: Product) => {
    if (!product.pkgxId) {
      toast.error('Sản phẩm chưa được liên kết với PKGX');
