        is_on_sale: product.isPublished ?? (product.status === 'active'),
      });
      
      if (response.success) {
        toast.success(`Đã đồng bộ flags`, { id: 'pkgx-sync-flags' });
        addPkgxLog({
          action: 'sync_flags',
          status: 'success',
          message: `Đã đồng bộ flags: ${product.name}`,
          details: { productId: product.systemId, pkgxId: product.pkgxId },
        });
      } else {
