export function PurchaseOrderDetailPage() {
  const { systemId } = useParams<{ systemId: string }>();
  const router = useRouter();
  const { data: purchaseOrder } = usePurchaseOrder(systemId);
  const { update: updatePO } = usePurchaseOrderMutations({});
  
  // Helper functions using mutations
  const cancelOrder = React.useCallback((poSystemId: string, userId: string, _userName: string) => {
    (updatePO as any).mutate({ systemId: poSystemId, status: 'cancelled', cancelledBy: userId, cancelledAt: new Date().toISOString() });
  }, [updatePO]);
  
  const finishOrder = React.useCallback((poSystemId: string, userId: string, _userName: string) => {
    (updatePO as any).mutate({ systemId: poSystemId, status: 'completed', completedBy: userId, completedAt: new Date().toISOString() });
  }, [updatePO]);
  
  const processInventoryReceipt = React.useCallback((poSystemId: string) => {
    (updatePO as any).mutate({ systemId: poSystemId, deliveryStatus: 'Đã nhập kho' });
  }, [updatePO]);
  
  // All hooks must be called before any early returns (React hooks rules)
  // Move all hook calls here before the conditional return
  const { data: suppliers } = useAllSuppliers();
  const { data: queryData } = usePurchaseOrders({ limit: 1000 });
  const allPurchaseOrders = React.useMemo(() => queryData?.data ?? [], [queryData?.data]);
  const { data: allPayments } = useAllPayments();
  const { data: allReceiptsFinancial } = useAllReceipts();
  const allTransactions = React.useMemo(() => [...allPayments, ...allReceiptsFinancial], [allPayments, allReceiptsFinancial]);
  const { data: allReceipts } = useAllInventoryReceipts();
  const { create: createInventoryReceipt } = useInventoryReceiptMutations({
    onCreateSuccess: () => {},
    onError: (err) => toast.error(err.message)
  });
  const { data: products } = useAllProducts();
  const { findById: findProductById } = useProductFinder();
  const { create: createStockHistory } = useStockHistoryMutations({
    onSuccess: () => {},
    onError: (err) => toast.error(err.message)
  });
  const { data: _paymentTypes } = useAllPaymentTypes();
  const { accounts: _accounts } = useAllCashAccounts();
  const { data: _branches } = useAllBranches();
  const { data: allPurchaseReturns } = useAllPurchaseReturns();
  const { data: purchaseReturnsForPO } = usePurchaseReturnsByPO(systemId);
  const { create: createPurchaseReturn } = usePurchaseReturnMutations({
    onCreateSuccess: () => {},
    onError: (err) => toast.error(err.message)
  });
  const { employee: authEmployee } = useAuth();
  const currentUserSystemId = asSystemId(authEmployee?.systemId ?? 'SYSTEM');
  const currentUserName = authEmployee?.fullName ?? 'Hệ thống';
  const { findById: findProductTypeById } = useProductTypeFinder();
  const { findById: findEmployeeById } = useEmployeeFinder();
  const { data: employees } = useAllEmployees();

  const getProductTypeName = React.useCallback((productTypeSystemId: string) => {
    const productType = findProductTypeById(asSystemId(productTypeSystemId));
    return productType?.name || 'Hàng hóa';
  }, [findProductTypeById]);

  const [isPaymentConfirmationOpen, setIsPaymentConfirmationOpen] = React.useState(false);
  const [isReceiveConfirmationOpen, setIsReceiveConfirmationOpen] = React.useState(false);
  const [previewImage, setPreviewImage] = React.useState<{ url: string; title: string } | null>(null);
  const [cancelDialogState, setCancelDialogState] = React.useState<{
    isOpen: boolean;
    po: PurchaseOrder | null;
    willCreateReturn?: boolean;
    totalPaid?: number;
  }>({ isOpen: false, po: null });

  // Comments from database
  const { 
    comments: dbComments, 
    addComment: dbAddComment, 
    deleteComment: dbDeleteComment 
  } = useComments('purchase_order', systemId || '');

  const comments = React.useMemo(() => 
    dbComments.map(c => ({
      id: c.systemId,
      content: c.content,
      author: {
        systemId: c.createdBy || 'system',
        name: c.createdByName || 'Hệ thống',
        avatar: undefined,
      },
      createdAt: c.createdAt,
      updatedAt: c.updatedAt,
      attachments: c.attachments,
    })), 
    [dbComments]
  );

  const handleAddComment = (content: string, attachments?: string[], _parentId?: string) => {
    dbAddComment(content, attachments || []);
  };

  const handleUpdateComment = (_commentId: string, _content: string) => {
  };

  const handleDeleteComment = (commentId: string) => {
    dbDeleteComment(commentId);
  };

  const commentCurrentUser = React.useMemo(() => ({
    systemId: currentUserSystemId,
    name: currentUserName,
    avatar: authEmployee?.avatar,
  }), [currentUserSystemId, currentUserName, authEmployee?.avatar]);

  const purchaseReturns = React.useMemo(() => {
    if (!purchaseOrder) return [];
    return purchaseReturnsForPO ?? [];
  }, [purchaseReturnsForPO]);
  const poReceipts = React.useMemo(
    () => (purchaseOrder ? allReceipts.filter(r => r.purchaseOrderSystemId === purchaseOrder.systemId) : []),
    [purchaseOrder, allReceipts]
  );
  
  const canReturn = React.useMemo(() => {
    if (!purchaseOrder) return false;

    const totalReceived = purchaseOrder.lineItems.reduce((acc, item) => {
      const receivedQty = poReceipts.reduce((sum, receipt) => {
        const receiptItem = receipt.items.find(i => i.productSystemId === item.productSystemId);
        return sum + (receiptItem ? Number(receiptItem.receivedQuantity) : 0);
      }, 0);
      return acc + receivedQty;
    }, 0);

    const totalReturned = allPurchaseReturns
      .filter(pr => pr.purchaseOrderSystemId === purchaseOrder.systemId) // ✅ Fixed: Use systemId
      .reduce((acc, pr) => acc + pr.items.reduce((sum, item) => sum + item.returnQuantity, 0), 0);

    return totalReceived > totalReturned;
  }, [purchaseOrder, poReceipts, allPurchaseReturns]);

  // Tính xem còn sản phẩm nào cần nhập thêm không (sau khi đã nhập và trả hàng)
  const hasRemainingItemsToReceive = React.useMemo(() => {
    if (!purchaseOrder) return false;
    
    // Tính số lượng đã nhập cho mỗi sản phẩm
    const getAlreadyReceivedQty = (productSystemId: string) => {
      return poReceipts.reduce((total, receipt) => {
        const item = receipt.items.find(i => i.productSystemId === productSystemId);
        return total + (item ? Number(item.receivedQuantity) : 0);
      }, 0);
    };
    
    // Kiểm tra xem còn sản phẩm nào cần nhập không
    return purchaseOrder.lineItems.some(item => {
      const alreadyReceived = getAlreadyReceivedQty(item.productSystemId);
      const remaining = item.quantity - alreadyReceived;
      return remaining > 0;
    });
  }, [purchaseOrder, poReceipts]);
  
  const canBeFinished = React.useMemo(() => {
    if (!purchaseOrder) return false;
    const isFinanciallySettled = purchaseOrder.paymentStatus === 'Đã thanh toán';
    const isLogisticallySettled = purchaseOrder.deliveryStatus === 'Đã nhập';
    const isFullyReturned = purchaseOrder.returnStatus === 'Hoàn hàng toàn bộ';
    const isTerminal = purchaseOrder.status === 'Kết thúc' || purchaseOrder.status === 'Đã hủy';
    
    return !isTerminal && ((isFinanciallySettled && isLogisticallySettled) || isFullyReturned);
  }, [purchaseOrder]);
  
  const handleCancelRequest = React.useCallback((po: PurchaseOrder) => {
    const totalPaid = sumPaymentsForPurchaseOrder(allPayments, po);

    const hasBeenDelivered = po.deliveryStatus !== 'Chưa nhập';

    setCancelDialogState({ 
        isOpen: true, 
        po: po, 
        totalPaid: totalPaid,
        willCreateReturn: hasBeenDelivered 
    });
  }, [allPayments]);

  const confirmCancel = () => {
    if (!cancelDialogState.po) return;
    const po = cancelDialogState.po;

    if (cancelDialogState.willCreateReturn) {
        const poSystemId = asSystemId(po.systemId);
        const receiptsForPO = allReceipts.filter(r => r.purchaseOrderSystemId === poSystemId);
        const returnsForPO = allPurchaseReturns.filter(pr => pr.purchaseOrderSystemId === poSystemId);

        const returnItems = po.lineItems
          .map<PurchaseReturnLineItem | null>(item => {
            const totalReceived = receiptsForPO.reduce((sum, receipt) => {
              const receiptItem = receipt.items.find(i => i.productSystemId === item.productSystemId);
              return sum + (receiptItem ? Number(receiptItem.receivedQuantity) : 0);
            }, 0);
            const totalReturned = returnsForPO.reduce((sum, pr) => {
              const returnItem = pr.items.find(i => i.productSystemId === item.productSystemId);
              return sum + (returnItem ? returnItem.returnQuantity : 0);
            }, 0);
            const returnableQuantity = totalReceived - totalReturned;

            if (returnableQuantity <= 0) {
              return null;
            }

            return {
              productSystemId: asSystemId(item.productSystemId),
              productId: asBusinessId(item.productId),
              productName: item.productName,
              orderedQuantity: item.quantity,
              returnQuantity: returnableQuantity,
              unitPrice: item.unitPrice,
            } satisfies PurchaseReturnLineItem;
          })
          .filter((item): item is PurchaseReturnLineItem => Boolean(item));

        if (returnItems.length > 0) {
            const totalReturnValue = returnItems.reduce((sum, item) => sum + (item.returnQuantity * item.unitPrice), 0);
            
            createPurchaseReturn.mutate({
              id: asBusinessId(''),
              purchaseOrderSystemId: asSystemId(po.systemId),
              purchaseOrderId: asBusinessId(po.id),
              supplierSystemId: asSystemId(po.supplierSystemId),
              supplierName: po.supplierName,
              branchSystemId: asSystemId(po.branchSystemId),
              branchName: po.branchName,
              returnDate: toISODate(getCurrentDate()),
              reason: `Tự động tạo khi hủy đơn nhập hàng ${po.id}`,
              items: returnItems,
              totalReturnValue,
              refundAmount: 0, 
              refundMethod: '',
              creatorName: currentUserName,
            });
        }
    }

    cancelOrder(po.systemId, currentUserSystemId, currentUserName);
    setCancelDialogState({ isOpen: false, po: null });
  };

  const { findById: findBranchById } = useBranchFinder();
  const { info: storeInfo } = useStoreInfoData();
  const { print } = usePrint(purchaseOrder?.branchSystemId);

  const handlePrint = React.useCallback(async () => {
    if (!purchaseOrder) return;

    // ✅ Lazy load print helper
    const { 
      convertPurchaseOrderForPrint,
      mapPurchaseOrderToPrintData, 
      mapPurchaseOrderLineItems,
      createStoreSettings,
    } = await import('../../lib/print/purchase-order-print-helper');

    const branch = findBranchById(purchaseOrder.branchSystemId);
    const supplier = suppliers.find(s => s.systemId === purchaseOrder.supplierSystemId);

    // Use helper to prepare print data
    const storeSettings = createStoreSettings(storeInfo);
    const poForPrint = convertPurchaseOrderForPrint(purchaseOrder, { 
      branch: branch || undefined, 
      supplier: supplier || undefined,
    });

    // Calculate payment totals
    const totalPaid = sumPaymentsForPurchaseOrder(allPayments, purchaseOrder);
    poForPrint.totalTransactionAmount = totalPaid;
    poForPrint.totalRemain = purchaseOrder.grandTotal - totalPaid;

    const printData = mapPurchaseOrderToPrintData(poForPrint, storeSettings);
    const lineItems = mapPurchaseOrderLineItems(poForPrint.items);

    // Inject extra fields
    printData['amount_text'] = numberToWords(purchaseOrder.grandTotal);

    print('purchase-order', {
      data: printData,
      lineItems: lineItems
    });
  }, [purchaseOrder, findBranchById, storeInfo, print, suppliers, allPayments]);

  // Handle print for inventory receipt (phiếu nhập kho)
  const handlePrintReceipt = React.useCallback(async (receipt: InventoryReceipt) => {
    if (!purchaseOrder) return;

    // ✅ Lazy load print helper
    const { 
      convertStockInForPrint,
      mapStockInToPrintData,
      mapStockInLineItems,
      createStoreSettings: createStockInStoreSettings,
    } = await import('../../lib/print/stock-in-print-helper');

    const branch = findBranchById(purchaseOrder.branchSystemId);
    const supplierData = suppliers.find(s => s.systemId === purchaseOrder.supplierSystemId);

    // Use stock-in print helper to prepare data
    const storeSettings = createStockInStoreSettings(storeInfo);
    const stockInForPrint = convertStockInForPrint(receipt, {
      branch: branch || undefined,
      supplier: supplierData ? { 
        id: supplierData.id, 
        name: supplierData.name, 
        phone: supplierData.phone,
        email: supplierData.email,
      } : undefined,
      purchaseOrder: purchaseOrder ? {
        id: purchaseOrder.id,
        code: purchaseOrder.id,
      } : undefined,
    });

    const printData = mapStockInToPrintData(stockInForPrint, storeSettings);
    const lineItems = mapStockInLineItems(stockInForPrint.items);

    // Inject extra fields
    const totalValue = receipt.items.reduce((sum, item) => sum + (Number(item.receivedQuantity) * Number(item.unitPrice)), 0);
    printData['amount_text'] = numberToWords(totalValue);

    print('stock-in', {
      data: printData,
      lineItems: lineItems
    });
  }, [purchaseOrder, findBranchById, storeInfo, print, suppliers]);

  // Handle print for purchase return (phiếu trả hàng NCC)
  const handlePrintPurchaseReturn = React.useCallback(async (purchaseReturn: PurchaseReturn) => {
    if (!purchaseOrder) return;

    // ✅ Lazy load print helper
    const { 
      convertSupplierReturnForPrint,
      mapSupplierReturnToPrintData, 
      mapSupplierReturnLineItems,
      createStoreSettings: createSupplierReturnStoreSettings,
    } = await import('../../lib/print/supplier-return-print-helper');

    const branch = findBranchById(purchaseOrder.branchSystemId);
    const supplierData = suppliers.find(s => s.systemId === purchaseOrder.supplierSystemId);

    // Use supplier-return print helper to prepare data
    const storeSettings = createSupplierReturnStoreSettings(storeInfo);
    const returnForPrint = convertSupplierReturnForPrint(purchaseReturn, {
      branch: branch || undefined,
      supplier: supplierData || undefined,
      purchaseOrder: purchaseOrder || undefined,
    });

    const printData = mapSupplierReturnToPrintData(returnForPrint, storeSettings);
    const lineItems = mapSupplierReturnLineItems(returnForPrint.items);

    // Inject extra fields
    printData['amount_text'] = numberToWords(purchaseReturn.totalReturnValue);

    print('supplier-return', {
      data: printData,
      lineItems: lineItems
    });
  }, [purchaseOrder, findBranchById, storeInfo, print, suppliers]);

  const _printButton = React.useMemo(() => (
    <Button variant="outline" size="sm" onClick={handlePrint}>
      <Printer className="mr-2 h-4 w-4" /> In
    </Button>
  ), [handlePrint]);

  const statusBadgeVariant = React.useMemo(() => {
    if (!purchaseOrder) return 'secondary' as const;
    switch (purchaseOrder.status) {
      case 'Hoàn thành':
      case 'Kết thúc':
        return 'success' as const;
      case 'Đã hủy':
      case 'Đã trả hàng':
        return 'destructive' as const;
      case 'Đang giao dịch':
        return 'warning' as const;
      default:
        return 'secondary' as const;
    }
  }, [purchaseOrder]);

  const actions = React.useMemo(() => {
    if (!purchaseOrder) return [];
    const isTerminalStatus = purchaseOrder.status === 'Kết thúc' || purchaseOrder.status === 'Đã hủy';
    const _isCompleted = purchaseOrder.status === 'Hoàn thành';
    
    // Theo chuẩn Sapo: Chỉ cho phép sửa/hủy đơn CHƯA nhập kho
    const canEdit = !isTerminalStatus && purchaseOrder.deliveryStatus === 'Chưa nhập';
    const canCancel = !isTerminalStatus && purchaseOrder.deliveryStatus === 'Chưa nhập';

    // Nhóm nút bên trái (Thoát, Sao chép, In đơn)
    const leftButtons = [
      <Button key="exit" variant="outline" size="sm" onClick={() => router.push(ROUTES.PROCUREMENT.PURCHASE_ORDERS)} className="h-9">
        Thoát
      </Button>
    ];

    if (!isTerminalStatus) {
      leftButtons.push(
        <Button key="copy" variant="outline" size="sm" onClick={() => {
          // Copy order logic - navigate to new order with pre-filled data
          router.push(`${ROUTES.PROCUREMENT.PURCHASE_ORDER_NEW}?copy=${purchaseOrder.systemId}`);
        }} className="h-9">
          Sao chép
        </Button>
      );
    }

    leftButtons.push(
      <Button key="print" variant="outline" size="sm" onClick={handlePrint} className="h-9">
        <Printer className="mr-2 h-4 w-4" />
        In đơn
      </Button>
    );

    // Nhóm nút bên phải (Sửa, Hoàn trả, Hoàn tất, Hủy)
    const actionButtons = [...leftButtons];

    if (!isTerminalStatus && canBeFinished) {
      actionButtons.push(
        <Button key="finish" size="sm" onClick={() => finishOrder(purchaseOrder.systemId, currentUserSystemId, currentUserName)} className="h-9">
          Hoàn tất
        </Button>
      );
    }

    if (canEdit) {
      actionButtons.push(
        <Button key="edit" variant="outline" size="sm" onClick={() => router.push(`${ROUTES.PROCUREMENT.PURCHASE_ORDERS}/${purchaseOrder.systemId}/edit`)} className="h-9">
          <Edit className="mr-2 h-4 w-4" />
          Sửa
        </Button>
      );
    }

    if (canReturn) {
      actionButtons.push(
        <Button key="return" variant="outline" size="sm" onClick={() => router.push(`${ROUTES.PROCUREMENT.PURCHASE_ORDERS}/${purchaseOrder.systemId}/return`)} className="h-9">
          <Undo2 className="mr-2 h-4 w-4" />
          Hoàn trả
        </Button>
      );
    }

    if (canCancel) {
      actionButtons.push(
        <Button key="cancel" variant="destructive" size="sm" onClick={() => handleCancelRequest(purchaseOrder)} className="h-9">
          <Trash2 className="mr-2 h-4 w-4" />
          Hủy đơn
        </Button>
      );
    }

    return actionButtons;
  }, [router, purchaseOrder, canBeFinished, canReturn, finishOrder, currentUserSystemId, currentUserName, handleCancelRequest, handlePrint]);

  usePageHeader({ 
    actions,
    title: purchaseOrder?.id ? `Đơn nhập hàng ${purchaseOrder.id}` : 'Chi tiết đơn nhập hàng',
    badge: purchaseOrder ? <Badge variant={statusBadgeVariant}>{purchaseOrder.status}</Badge> : undefined,
    breadcrumb: [
      { label: 'Trang chủ', href: '/', isCurrent: false },
      { label: 'Đơn nhập hàng', href: ROUTES.PROCUREMENT.PURCHASE_ORDERS, isCurrent: false },
      { label: purchaseOrder?.id || 'Chi tiết', href: `${ROUTES.PROCUREMENT.PURCHASE_ORDERS}/${purchaseOrder?.systemId || ''}`, isCurrent: true }
    ],
    showBackButton: true,
    backPath: ROUTES.PROCUREMENT.PURCHASE_ORDERS
  });
  
  const supplier = React.useMemo(() => {
    if (!purchaseOrder) return null;
    return suppliers.find(s => s.systemId === purchaseOrder.supplierSystemId);
  }, [purchaseOrder, suppliers]);

  const handlePrintPayment = React.useCallback(async (e: React.MouseEvent, item: { type: 'payment' | 'refund'; amount: number; id: string; date: string; method: string; creator: string; description: string }) => {
      if (!purchaseOrder) return;
      e.stopPropagation();
      
      // ✅ Lazy load print mappers
      const { mapPaymentToPrintData } = await import('../../lib/print-mappers/payment.mapper');
      const { mapReceiptToPrintData } = await import('../../lib/print-mappers/receipt.mapper');
      
      const isPayment = item.type === 'payment';
      const amount = Math.abs(item.amount);
      
      // Get branch info
      const branch = findBranchById(purchaseOrder.branchSystemId);

      // Prepare store settings
      const storeSettings: StoreSettings = {
          name: storeInfo?.brandName || storeInfo?.companyName || '',
          address: storeInfo?.headquartersAddress,
          phone: storeInfo?.hotline,
          email: storeInfo?.email,
          province: storeInfo?.province,
      };

      const creator = (() => {
          const bySystemId = findEmployeeById(item.creator);
          if (bySystemId) return bySystemId;
          return employees.find(e => e.id === (item.creator as unknown as string));
      })();

      let printData;

      if (isPayment) {
          const paymentData: PaymentForPrint = {
              code: item.id,
              createdAt: item.date,
              issuedAt: item.date,
              createdBy: creator?.fullName || item.creator,
              recipientName: supplier?.name || 'Nhà cung cấp',
              recipientPhone: supplier?.phone || '',
              recipientAddress: supplier?.address || '',
              recipientType: 'Nhà cung cấp',
              amount: amount,
              description: item.description,
              paymentMethod: item.method,
              documentRootCode: purchaseOrder.id,
              note: item.description,
              location: branch ? {
                  name: branch.name,
                  address: branch.address,
                  province: branch.province
              } : undefined
          };
          
          printData = mapPaymentToPrintData(paymentData, storeSettings);
      } else {
          // Refund (Receipt)
           const receiptData: ReceiptForPrint = {
              code: item.id,
              createdAt: item.date,
              issuedAt: item.date,
              createdBy: creator?.fullName || item.creator,
              payerName: supplier?.name || 'Nhà cung cấp',
              payerPhone: supplier?.phone || '',
              payerAddress: supplier?.address || '',
              payerType: 'Nhà cung cấp',
              amount: amount,
              description: item.description,
              paymentMethod: item.method,
              documentRootCode: purchaseOrder.id,
              note: item.description,
              location: branch ? {
                  name: branch.name,
                  address: branch.address,
                  province: branch.province
              } : undefined
          };
          
          printData = mapReceiptToPrintData(receiptData, storeSettings);
      }

      printData['amount_text'] = numberToWords(amount);
      printData['print_date'] = formatDateTime(new Date());
      printData['print_time'] = formatTime(new Date());
      
      print(isPayment ? 'payment' : 'receipt', { data: printData });
  }, [purchaseOrder, supplier, findBranchById, storeInfo, print, findEmployeeById, employees]);

  const supplierPurchaseOrders = React.useMemo(() => {
    if (!supplier) return [];
    return allPurchaseOrders.filter(po => po.supplierSystemId === supplier.systemId);
  }, [supplier, allPurchaseOrders]);

  const { calculatedDebt, totalReturnValueForSupplier } = React.useMemo(() => {
    if (!supplier) return { calculatedDebt: 0, totalReturnValueForSupplier: 0 };
    
    const supplierReturns = allPurchaseReturns.filter(pr => pr.supplierSystemId === supplier.systemId);
    const totalReturnValue = supplierReturns.reduce((sum, pr) => sum + pr.totalReturnValue, 0);

    const totalPurchases = supplierPurchaseOrders.reduce((sum, po) => sum + po.grandTotal, 0);
    const totalPayments = supplierPurchaseOrders.reduce(
      (sum, po) => sum + sumPaymentsForPurchaseOrder(allPayments, po),
      0
    );
    
    // Debt calculation should factor in returns
    const calculatedDebt = totalPurchases - totalPayments - totalReturnValue;
      
    return { calculatedDebt, totalReturnValueForSupplier: totalReturnValue };
  }, [supplier, supplierPurchaseOrders, allPayments, allPurchaseReturns]);
  
    const { totalPaidOnThisOrder, financialHistory } = React.useMemo(() => {
    if (!purchaseOrder) return { totalPaidOnThisOrder: 0, financialHistory: [] };

    const paymentsForOrder = getPaymentsForPurchaseOrder(allPayments, purchaseOrder);
    const paymentTransactions = paymentsForOrder.map(p => ({
      type: 'payment' as const,
      systemId: p.systemId,
      id: p.id,
      date: p.date,
      amount: p.amount,
      method: p.paymentMethodName || (p as unknown as { paymentMethod?: string }).paymentMethod || 'Không xác định',
      creator: p.createdBy,
      description: p.description,
    }));

    const receiptsForOrder = getReceiptsForPurchaseOrder(allReceiptsFinancial, purchaseOrder);
    const refundTransactions = receiptsForOrder.map(r => ({
      type: 'refund' as const,
      systemId: r.systemId,
      id: r.id,
      date: r.date,
      amount: r.amount,
      method: r.paymentMethodName || (r as unknown as { paymentMethod?: string }).paymentMethod || 'Không xác định',
      creator: r.createdBy,
      description: r.description,
    }));

    const combinedHistory = [...paymentTransactions, ...refundTransactions].sort((a, b) => getDaysDiff(parseDate(b.date), parseDate(a.date)));
    const totalPaid = sumPaymentsForPurchaseOrder(allPayments, purchaseOrder);
    
    return { totalPaidOnThisOrder: totalPaid, financialHistory: combinedHistory };
    }, [purchaseOrder, allPayments, allReceiptsFinancial]);
  
  const totalReturnedValue = React.useMemo(() => 
    (Array.isArray(purchaseReturns) ? purchaseReturns : (purchaseReturns as any)?.data || []).reduce((sum: number, pr: any) => sum + Number(pr.totalReturnValue || 0), 0),
  [purchaseReturns]);

  const actualDebt = (purchaseOrder?.grandTotal || 0) - totalReturnedValue;
  const amountRemainingOnThisOrder = actualDebt - totalPaidOnThisOrder;

  const localPaymentStatus: PaymentStatus = React.useMemo(() => {
    if (!purchaseOrder) return 'Chưa thanh toán';
    if (totalPaidOnThisOrder >= actualDebt) {
        return 'Đã thanh toán';
    } else if (totalPaidOnThisOrder > 0) {
        return 'Thanh toán một phần';
    } else {
        return 'Chưa thanh toán';
    }
  }, [purchaseOrder, totalPaidOnThisOrder, actualDebt]);

  const canPay = amountRemainingOnThisOrder > 0 && purchaseOrder?.status !== 'Đã hủy' && purchaseOrder?.status !== 'Kết thúc';

  // Early return if purchase order not found - after all hooks have been called
  if (!purchaseOrder) {
    return (
      <div className="p-8">
        <div className="max-w-2xl mx-auto text-center">
          <h2 className="text-h2 mb-4">Không tìm thấy đơn hàng</h2>
          <p className="text-body-sm text-muted-foreground mb-6">Đơn hàng với mã {systemId} không tồn tại hoặc đã bị xóa.</p>
          <Button onClick={() => router.push('/purchase-orders')}>
            Quay lại danh sách
          </Button>
        </div>
      </div>
    );
  }
  
  const handleSupplierClick = () => {
    if (supplier) {
      router.push(`${ROUTES.PROCUREMENT.SUPPLIERS}/${supplier.systemId}`);
    }
  };
  
   const handleReceiveAllItems = () => {
    if (!purchaseOrder) {
      toast.error('Không tìm thấy đơn nhập hàng để nhận.');
      return;
    }

    if (purchaseOrder.deliveryStatus === 'Đã nhập') {
      toast.info('Đơn hàng đã được nhập kho đầy đủ.');
      return;
    }

    if (!purchaseOrder.branchSystemId || !purchaseOrder.branchName) {
      toast.error('Đơn hàng này chưa được gán cho chi nhánh. Vui lòng cập nhật thông tin chi nhánh trước khi nhập.');
      return;
    }

    // Mở dialog xác nhận
    setIsReceiveConfirmationOpen(true);
  };

  const handleConfirmReceive = () => {
    if (!purchaseOrder) return;

    const getAlreadyReceivedQty = (productSystemId: string) => {
      const receiptsForPO = allReceipts.filter(r => r.purchaseOrderSystemId === purchaseOrder.systemId);
      return receiptsForPO.reduce((total, receipt) => {
        const item = receipt.items.find(i => i.productSystemId === productSystemId);
        return total + (item ? Number(item.receivedQuantity) : 0);
      }, 0);
    };

    const itemsToReceive = purchaseOrder.lineItems.map(item => {
      const alreadyReceived = getAlreadyReceivedQty(item.productSystemId);
      const remaining = item.quantity - alreadyReceived;
      return {
        productSystemId: asSystemId(item.productSystemId),
        productId: asBusinessId(item.productId),
        productName: item.productName,
        orderedQuantity: item.quantity,
        receivedQuantity: remaining > 0 ? remaining : 0,
        unitPrice: item.unitPrice,
      };
    }).filter(item => item.receivedQuantity > 0);

    if (itemsToReceive.length === 0) {
      toast.info('Không có sản phẩm nào cần nhập thêm.');
      setIsReceiveConfirmationOpen(false);
      return;
    }
    
    const receiptData: Omit<InventoryReceipt, 'systemId'> = {
      id: asBusinessId(''),
      purchaseOrderSystemId: asSystemId(purchaseOrder.systemId),
      purchaseOrderId: asBusinessId(purchaseOrder.id || purchaseOrder.systemId),
      supplierSystemId: asSystemId(purchaseOrder.supplierSystemId),
      supplierName: purchaseOrder.supplierName,
      receivedDate: formatDateCustom(getCurrentDate(), 'yyyy-MM-dd HH:mm'),
      receiverSystemId: currentUserSystemId,
      receiverName: currentUserName,
      branchSystemId: asSystemId(purchaseOrder.branchSystemId),
      branchName: purchaseOrder.branchName,
      warehouseName: purchaseOrder.branchName ? `Kho ${purchaseOrder.branchName}` : undefined,
      items: itemsToReceive,
      notes: 'Nhập kho tự động toàn bộ sản phẩm còn lại.',
    };

    createInventoryReceipt.mutate(receiptData);

    itemsToReceive.forEach(item => {
      const productData = products.find(p => p.systemId === item.productSystemId || p.id === item.productId);
      // Products now store on-hand inventory in `inventoryByBranch` (Record<branchId, number>)
      const branchSystemId = asSystemId(purchaseOrder.branchSystemId);
      const oldStock = productData?.inventoryByBranch?.[branchSystemId] || 0;
      
      // Note: Inventory updates now happen server-side
      
      // Ghi lịch sử kho
      createStockHistory.mutate({
        productId: asSystemId(item.productSystemId),
        action: 'Nhập hàng từ NCC',
        employeeName: currentUserName,
        date: formatDateCustom(getCurrentDate(), 'yyyy-MM-dd HH:mm'),
        quantityChange: item.receivedQuantity,
        newStockLevel: oldStock + item.receivedQuantity,
        documentId: asBusinessId(purchaseOrder.id || purchaseOrder.systemId),
        branch: purchaseOrder.branchName,
        branchSystemId,
      });
    });
    
    processInventoryReceipt(asSystemId(purchaseOrder.systemId)); // ✅ Fixed: Use systemId

    setIsReceiveConfirmationOpen(false);
    toast.success(`Đã nhập kho thành công ${itemsToReceive.length} sản phẩm còn lại.`);
  };

  const handlePaymentConfirmationSubmit = (values: PaymentConfirmationFormValues) => {
    if (!purchaseOrder || !supplier) return;

    // Create payment document using standard helper (same as order)
    const { document: createdPayment, error } = createPaymentDocument({
      amount: values.amount,
      description: `Thanh toán cho đơn nhập hàng ${purchaseOrder.id}${values.reference ? ` - ${values.reference}` : ''}`,
      recipientName: supplier.name,
      recipientSystemId: supplier.systemId,
      branchSystemId: asSystemId(purchaseOrder.branchSystemId),
      branchName: purchaseOrder.branchName,
      createdBy: currentUserSystemId,
      paymentMethodName: values.paymentMethod,
      accountSystemId: values.accountSystemId ? asSystemId(values.accountSystemId) : undefined,
      paymentTypeName: 'Thanh toán cho đơn nhập hàng',
      recipientTargetGroupName: 'Nhà cung cấp',
      originalDocumentId: purchaseOrder.id,
      affectsDebt: true,
      date: values.paymentDate,
    });

    if (!createdPayment) {
      toast.error(error || 'Không thể tạo phiếu chi. Vui lòng kiểm tra cấu hình chứng từ.');
      return;
    }
    
    // Sync payment status after payment
    // Note: syncAllPurchaseOrderStatuses removed - handled by React Query invalidation
    
    setIsPaymentConfirmationOpen(false);
    toast.success(`Đã tạo phiếu chi ${createdPayment.id} - ${formatCurrency(values.amount)} cho đơn nhập hàng ${purchaseOrder.id}.`);
  };
  
  const canReceiveItems = purchaseOrder.deliveryStatus !== 'Đã nhập' && purchaseOrder.status !== 'Đã hủy' && purchaseOrder.status !== 'Kết thúc' && hasRemainingItemsToReceive;
  
  let paymentSection;
  
  const paymentDetails = (
      <div className="grid grid-cols-1 gap-2 bg-muted/50 p-3 sm:p-4 rounded-md text-sm">
          {purchaseOrder.grandTotal === 0 ? (
            <div className="bg-amber-50 dark:bg-amber-950/20 border border-amber-200 dark:border-amber-800 rounded-lg p-4">
              <div className="flex items-center gap-2 text-amber-800 dark:text-amber-300">
                <AlertCircle className="h-5 w-5" />
                <p className="font-medium">Đơn hàng chưa có sản phẩm hoặc tổng tiền bằng 0</p>
              </div>
              <p className="mt-2 text-body-sm text-amber-700 dark:text-amber-400">
                Vui lòng kiểm tra lại danh sách sản phẩm trong đơn hàng.
              </p>
            </div>
          ) : (
            <>
              <div className="flex justify-between">
                  <span className="text-muted-foreground">Tổng tiền ĐH:</span>
                  <span className="font-medium">{formatCurrency(purchaseOrder.grandTotal)}</span>
              </div>
              
              {totalReturnedValue > 0 && (
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Giá trị hàng đã trả:</span>
                  <span className="font-medium text-amber-600">-{formatCurrency(totalReturnedValue)}</span>
                </div>
              )}
              
              {totalReturnedValue > 0 && (
                <div className="flex justify-between">
                  <span className="text-muted-foreground font-semibold">Công nợ thực tế:</span>
                  <span className="font-semibold">{formatCurrency(actualDebt)}</span>
                </div>
              )}
              
              <div className="flex justify-between">
                  <span className="text-muted-foreground">Đã trả:</span>
                  <span className="font-medium">{totalPaidOnThisOrder > 0 ? formatCurrency(totalPaidOnThisOrder) : '0'}</span>
              </div>
              
              <div className="border-t my-1" />
              
              <div className="flex justify-between">
                  <span className="text-muted-foreground font-bold">Còn phải trả:</span>
                  <span className={cn(
                      "font-bold text-lg",
                      amountRemainingOnThisOrder > 0 ? 'text-red-500' : amountRemainingOnThisOrder < 0 ? 'text-green-600' : 'text-foreground'
                  )}>{amountRemainingOnThisOrder >= 0 ? formatCurrency(amountRemainingOnThisOrder) : formatCurrency(0)}</span>
              </div>
              {amountRemainingOnThisOrder < 0 && (
                <div className="flex justify-between text-green-600">
                  <span className="font-medium">NCC cần hoàn lại:</span>
                  <span className="font-bold">{formatCurrency(Math.abs(amountRemainingOnThisOrder))}</span>
                </div>
              )}
            </>
          )}
      </div>
  );

  switch(localPaymentStatus) {
      case 'Chưa thanh toán':
      case 'Thanh toán một phần':
          paymentSection = (
              <Card>
                  <CardHeader>
                      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
                          <div className="flex items-center gap-2">
                              <FileWarning className="h-5 w-5 text-amber-500 flex-shrink-0" />
                              <CardTitle className="text-base font-semibold">
                                {localPaymentStatus === 'Chưa thanh toán' 
                                  ? 'Đơn hàng chờ thanh toán' 
                                  : `Đơn hàng thanh toán ${localPaymentStatus.toLowerCase()}`}
                              </CardTitle>
                          </div>
                          {canPay && amountRemainingOnThisOrder > 0 && (
                            <Button size="sm" onClick={() => setIsPaymentConfirmationOpen(true)}>
                              Thanh toán
                            </Button>
                          )}
                      </div>
                  </CardHeader>
                  <CardContent className="space-y-3">
                      {paymentDetails}
                      {financialHistory.length > 0 && (
                        <div className="space-y-2 pt-2">
                          {[...financialHistory].reverse().map((item, index) => (
                            <PurchaseOrderPaymentItem 
                                key={`${item.systemId}-${index}`} 
                                item={item} 
                                onPrint={handlePrintPayment} 
                            />
                          ))}
                        </div>
                      )}
                  </CardContent>
              </Card>
          );
          break;
      case 'Đã thanh toán':
          paymentSection = (
              <Card>
                  <CardHeader>
                      <div className="flex items-center gap-2">
                          <CheckCircle2 className="h-5 w-5 text-green-500 flex-shrink-0" />
                          <CardTitle className="text-base font-semibold">
                            Đơn hàng thanh toán thanh toán toàn bộ
                          </CardTitle>
                      </div>
                  </CardHeader>
                  <CardContent className="space-y-3">
                      {paymentDetails}
                      {financialHistory.length > 0 && (
                        <div className="space-y-2 pt-2">
                          {[...financialHistory].reverse().map((item, index) => (
                            <PurchaseOrderPaymentItem 
                                key={`${item.systemId}-${index}`} 
                                item={item} 
                                onPrint={handlePrintPayment} 
                            />
                          ))}
                        </div>
                      )}
                  </CardContent>
              </Card>
          );
          break;
  }
  
  let receivingSection;

  // Nếu đã nhập đủ (không còn sản phẩm cần nhập) thì coi như đã nhập kho
  const isEffectivelyReceived = purchaseOrder.deliveryStatus === 'Đã nhập' || !hasRemainingItemsToReceive;

  if (isEffectivelyReceived) {
      receivingSection = (
          <Card>
              <CardHeader>
                  <div className="flex items-center gap-2 text-green-600">
                      <CheckCircle2 className="h-5 w-5" />
                      <CardTitle className="text-h3">Nhập hàng: Đã nhập kho</CardTitle>
                  </div>
              </CardHeader>
          </Card>
      );
  } else { // 'Chưa nhập' or 'Đã nhập một phần'
      const title = purchaseOrder.deliveryStatus === 'Chưa nhập'
          ? 'Nhập hàng: Chưa nhập kho'
          : 'Nhập hàng: Đã nhập một phần';
      
      receivingSection = (
          <Card>
              <CardHeader>
                  <div className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                          <Package className="h-5 w-5 text-amber-500" />
                          <CardTitle className="text-h3">{title}</CardTitle>
                      </div>
                      {canReceiveItems && (
                        <Button size="sm" onClick={handleReceiveAllItems}>
                          <Truck className="mr-2 h-4 w-4" />
                          Nhập hàng
                        </Button>
                      )}
                  </div>
              </CardHeader>
          </Card>
      );
  }
  
  const _statusVariants = {
    "Đặt hàng": "secondary", "Đang giao dịch": "warning", "Hoàn thành": "success", "Đã hủy": "destructive", "Kết thúc": "default", "Đã trả hàng": "destructive"
  }
  const _paymentStatusVariants = {
    "Chưa thanh toán": "warning", "Thanh toán một phần": "warning", "Đã thanh toán": "success"
  }

  return (
      <div className="space-y-6">
          <StatusTimeline status={purchaseOrder.status} deliveryStatus={purchaseOrder.deliveryStatus} orderDate={purchaseOrder.orderDate} />

          {/* Thông tin NCC và Đơn hàng */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <div className="lg:col-span-2">
                  <Card className="h-[300px]">
                      <CardHeader>
                        <div className="flex items-center gap-2">
                          <Users className="h-5 w-5 text-muted-foreground" />
                          <CardTitle className="text-h3">Thông tin nhà cung cấp</CardTitle>
                        </div>
                      </CardHeader>
                      <CardContent className="overflow-y-auto" style={{maxHeight: 'calc(300px - 80px)'}}>
                        <div className="space-y-4">
                          <div className="flex items-start gap-3">
                            <div className="flex-1">
                              <p className="font-semibold text-h3 text-primary cursor-pointer hover:underline" onClick={handleSupplierClick}>
                                {purchaseOrder.supplierName}
                              </p>
                              <div className="mt-2 space-y-1 text-body-sm text-muted-foreground">
                                <p>Địa chỉ: {supplier?.address || '-'}</p>
                              </div>
                            </div>
                          </div>
                          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 p-3 bg-muted/30 rounded-lg">
                            <div className="space-y-1">
                              <p className="text-body-xs text-muted-foreground">Nợ hiện tại</p>
                              <p className="text-body-sm font-semibold text-destructive">
                                {formatCurrency(calculatedDebt)}
                              </p>
                            </div>
                            <div className="space-y-1">
                              <p className="text-body-xs text-muted-foreground">Tổng đơn nhập</p>
                              <p className="text-body-sm font-semibold">
                                {formatCurrency(supplierPurchaseOrders.reduce((sum, po) => sum + po.grandTotal, 0))}
                              </p>
                            </div>
                            <div className="space-y-1">
                              <p className="text-body-xs text-muted-foreground">Trả hàng</p>
                              <p className="text-body-sm font-semibold text-orange-600">
                                {formatCurrency(totalReturnValueForSupplier)}
                              </p>
                            </div>
                          </div>
                        </div>
                      </CardContent>
                  </Card>
              </div>

              <div className="lg:col-span-1">
                  <Card className="h-[300px] flex flex-col">
                      <CardHeader>
                        <CardTitle className="text-h3">Thông tin đơn nhập hàng</CardTitle>
                      </CardHeader>
                      <CardContent className="flex-1 overflow-y-auto text-body-sm space-y-3">
                          <DetailField label="Chi nhánh" value={purchaseOrder.branchName} />
                          <DetailField label="Chính sách giá" value="Giá nhập" />
                          <DetailField label="Nhân viên phụ trách" value={purchaseOrder.buyer} />
                          <DetailField label="Ngày đặt" value={formatDateCustom(parseDate(purchaseOrder.orderDate) || getCurrentDate(), 'dd/MM/yyyy')} />
                          <DetailField label="Ngày giao" value={formatDateCustom(parseDate(purchaseOrder.deliveryDate ?? '') || getCurrentDate(), 'dd/MM/yyyy')} />
                          <DetailField label="Tham chiếu" value={purchaseOrder.reference || '-'} />
                          <Button variant="link" className="p-0 h-auto text-body-sm" onClick={handleSupplierClick}>Xem lịch sử đơn nhập hàng</Button>
                      </CardContent>
                  </Card>
              </div>
          </div>

          {/* Trạng thái hàng và thanh toán - Full width mỗi hàng */}
          <div className="space-y-4">
              {receivingSection}
              {paymentSection}
          </div>

          <Card>
              <CardHeader>
                  <CardTitle className="text-h3">Thông tin sản phẩm</CardTitle>
              </CardHeader>
              <CardContent>
                  <div className="border rounded-md overflow-x-auto">
                      <Table>
                          <TableHeader>
                              <TableRow>
                                  <TableHead className="w-[50px] text-center">STT</TableHead>
                                  <TableHead className="w-[60px]">Ảnh</TableHead>
                                  <TableHead className="min-w-[200px]">Tên sản phẩm</TableHead>
                                  <TableHead className="w-[100px]">Loại SP</TableHead>
                                  <TableHead className="w-[80px]">Đơn vị</TableHead>
                                  <TableHead className="w-[80px] text-center">SL nhập</TableHead>
                                  <TableHead className="w-[130px] text-right">Đơn giá</TableHead>
                                  <TableHead className="w-[80px] text-right">Thuế</TableHead>
                                  <TableHead className="w-[100px] text-right">Chiết khấu</TableHead>
                                  <TableHead className="w-[130px] text-right">Thành tiền</TableHead>
                              </TableRow>
                          </TableHeader>
                          <TableBody>
                              {purchaseOrder.lineItems.map((item, index) => {
                                  const lineGross = item.quantity * item.unitPrice;
                                  const discountAmount = item.discountType === 'percentage'
                                    ? lineGross * (item.discount / 100)
                                    : item.discount;
                                  const lineTotal = lineGross - discountAmount;
                                  const product = findProductById(item.productSystemId);
                                  const productTypeName = product?.productTypeSystemId 
                                    ? getProductTypeName(product.productTypeSystemId)
                                    : 'Hàng hóa';
                                  return (
                                  <TableRow key={item.productSystemId}>
                                      <TableCell className="text-center">{index + 1}</TableCell>
                                      <TableCell>
                                        <ProductThumbnailCell
                                          productSystemId={item.productSystemId}
                                          product={product}
                                          productName={item.productName}
                                          onPreview={(url, title) => setPreviewImage({ url, title })}
                                        />
                                      </TableCell>
                                      <TableCell>
                                        <div className="flex flex-col gap-1">
                                          <Link href={`/products/${item.productSystemId}`} 
                                            className="text-body-sm font-medium text-primary hover:underline"
                                          >
                                            {item.productName}
                                          </Link>
                                          <div className="flex items-center gap-1 text-body-xs text-muted-foreground">
                                            <Link href={`/products/${item.productSystemId}`} 
                                              className="text-primary hover:underline"
                                            >
                                              {item.sku || item.productId}
                                            </Link>
                                          </div>
                                          {item.note && (
                                            <p className="text-body-xs text-muted-foreground italic">• {item.note}</p>
                                          )}
                                        </div>
                                      </TableCell>
                                      <TableCell className="text-body-sm text-muted-foreground">{productTypeName}</TableCell>
                                      <TableCell>{item.unit || '-'}</TableCell>
                                      <TableCell className="text-center">{item.quantity}</TableCell>
                                      <TableCell className="text-right">{formatCurrency(item.unitPrice)}</TableCell>
                                      <TableCell className="text-right">{item.taxRate}%</TableCell>
                                      <TableCell className="text-right">
                                        {item.discountType === 'percentage' ? `${item.discount || 0}%` : formatCurrency(item.discount || 0)}
                                      </TableCell>
                                      <TableCell className="text-body-sm font-semibold text-right">{formatCurrency(lineTotal)}</TableCell>
                                  </TableRow>
                              )})}
                          </TableBody>
                          <TableFooter>
                              <TableRow>
                                  <TableCell colSpan={5} className="text-right font-bold">Tổng cộng</TableCell>
                                  <TableCell className="text-center font-bold">
                                    {purchaseOrder.lineItems.reduce((sum, item) => sum + item.quantity, 0)}
                                  </TableCell>
                                  <TableCell colSpan={3} />
                                  <TableCell className="text-body-sm font-bold text-right">
                                    {formatCurrency(
                                      purchaseOrder.lineItems.reduce((sum, item) => {
                                        const lineGross = item.quantity * item.unitPrice;
                                        const discountAmount = item.discountType === 'percentage'
                                          ? lineGross * (item.discount / 100)
                                          : item.discount;
                                        return sum + (lineGross - discountAmount);
                                      }, 0)
                                    )}
                                  </TableCell>
                              </TableRow>
                              
                              <TableRow>
                                  <TableCell colSpan={9} className="text-right text-muted-foreground">Tổng tiền hàng</TableCell>
                                  <TableCell className="text-right">
                                    {formatCurrency(
                                      purchaseOrder.lineItems.reduce((sum, item) => {
                                        const lineGross = item.quantity * item.unitPrice;
                                        const discountAmount = item.discountType === 'percentage'
                                          ? lineGross * (item.discount / 100)
                                          : item.discount;
                                        return sum + (lineGross - discountAmount);
                                      }, 0)
                                    )}
                                  </TableCell>
                              </TableRow>

                              <TableRow>
                                  <TableCell colSpan={9} className="text-right text-muted-foreground">
                                    Chiết khấu {purchaseOrder.discountType === 'percentage' && (purchaseOrder.discount ?? 0) > 0 ? `(${purchaseOrder.discount}%)` : ''}
                                  </TableCell>
                                  <TableCell className="text-right text-red-600">
                                    -{formatCurrency(
                                      purchaseOrder.discountType === 'percentage'
                                        ? ((purchaseOrder.subtotal || 0) * (purchaseOrder.discount ?? 0) / 100)
                                        : (purchaseOrder.discount ?? 0)
                                    )}
                                  </TableCell>
                              </TableRow>

                              <TableRow>
                                  <TableCell colSpan={9} className="text-right text-muted-foreground">Thuế</TableCell>
                                  <TableCell className="text-right">{formatCurrency(purchaseOrder.tax)}</TableCell>
                              </TableRow>

                              <TableRow>
                                  <TableCell colSpan={9} className="text-right text-muted-foreground">Phí vận chuyển</TableCell>
                                  <TableCell className="text-right">{formatCurrency(purchaseOrder.shippingFee)}</TableCell>
                              </TableRow>

                              <TableRow>
                                  <TableCell colSpan={9} className="text-h3 font-bold text-right">Thành tiền</TableCell>
                                  <TableCell className="text-h3 font-bold text-right">
                                    {formatCurrency(purchaseOrder.grandTotal)}
                                  </TableCell>
                              </TableRow>
                          </TableFooter>
                      </Table>
                  </div>
              </CardContent>
          </Card>

          <Tabs defaultValue="stock_history">
              <TabsList>
                  <TabsTrigger value="stock_history">Lịch sử kho ({poReceipts.length + (Array.isArray(purchaseReturns) ? purchaseReturns.length : 0)})</TabsTrigger>
              </TabsList>
              <TabsContent value="stock_history" className="mt-4">
                 <StockHistoryTab 
                   poReceipts={poReceipts} 
                   purchaseReturns={(Array.isArray(purchaseReturns) ? purchaseReturns : []) as PurchaseReturn[]} 
                   allTransactions={allTransactions}
                   onPrintReceipt={handlePrintReceipt}
                   onPrintReturn={handlePrintPurchaseReturn}
                 />
              </TabsContent>
          </Tabs>

          {/* Comments */}
          <Comments
            entityType="purchase-order"
            entityId={purchaseOrder.systemId}
            comments={comments}
            onAddComment={handleAddComment}
            onUpdateComment={handleUpdateComment}
            onDeleteComment={handleDeleteComment}
            currentUser={commentCurrentUser}
            title="Bình luận"
            placeholder="Thêm bình luận về đơn nhập hàng..."
          />

          {/* Activity History */}
          <ActivityHistory 
            history={purchaseOrder.activityHistory || []}
            title="Lịch sử thao tác"
            emptyMessage="Chưa có lịch sử thay đổi"
            showMetadata
          />

           <PaymentConfirmationDialog
              isOpen={isPaymentConfirmationOpen}
              onOpenChange={setIsPaymentConfirmationOpen}
              amountRemaining={amountRemainingOnThisOrder}
              onSubmit={handlePaymentConfirmationSubmit}
          />
          
          <AlertDialog open={isReceiveConfirmationOpen} onOpenChange={setIsReceiveConfirmationOpen}>
            <AlertDialogContent>
              <AlertDialogHeader>
                <AlertDialogTitle>Xác nhận nhập hàng</AlertDialogTitle>
                <AlertDialogDescription>
                  Bạn có chắc chắn muốn nhập kho <strong>toàn bộ sản phẩm</strong> còn lại trong đơn hàng này không?
                  <br /><br />
                  Hệ thống sẽ tạo phiếu nhập kho (PNK) và cập nhật tồn kho tự động.
                </AlertDialogDescription>
              </AlertDialogHeader>
              <AlertDialogFooter>
                <AlertDialogCancel>Hủy</AlertDialogCancel>
                <AlertDialogAction onClick={handleConfirmReceive}>
                  Xác nhận nhập hàng
                </AlertDialogAction>
              </AlertDialogFooter>
            </AlertDialogContent>
          </AlertDialog>

          <AlertDialog open={cancelDialogState.isOpen} onOpenChange={(open) => setCancelDialogState(s => ({ ...s, isOpen: open }))}>
            <AlertDialogContent>
            <AlertDialogHeader>
                <AlertDialogTitle>Bạn có chắc chắn muốn hủy đơn hàng này?</AlertDialogTitle>
                <AlertDialogDescription>
                {cancelDialogState.willCreateReturn ? (
                    <>
                    Đơn hàng này đã có sản phẩm được nhập kho. Hủy đơn sẽ tự động tạo một <strong>Phiếu Xuất trả hàng</strong> cho các sản phẩm đã nhận.
                    {cancelDialogState.totalPaid && cancelDialogState.totalPaid > 0 ? (
                        ` Đồng thời, một Phiếu Thu hoàn tiền ${formatCurrency(cancelDialogState.totalPaid)} sẽ được tạo.`
                    ) : ''}
                    {' '}Hành động này không thể hoàn tác.
                    </>
                ) : cancelDialogState.totalPaid && cancelDialogState.totalPaid > 0 ? (
                    <>
                    Đơn hàng này đã được thanh toán <strong>{formatCurrency(cancelDialogState.totalPaid)}</strong>. 
                    Việc hủy đơn sẽ tự động tạo một <strong>Phiếu Thu</strong> ghi nhận khoản tiền này là "Nhà cung cấp cần hoàn lại". 
                    Hành động này không thể hoàn tác.
                    </>
                ) : (
                    'Hành động này sẽ chuyển trạng thái đơn hàng thành "Đã hủy" và không thể hoàn tác.'
                )}
                </AlertDialogDescription>
            </AlertDialogHeader>
            <AlertDialogFooter>
                <AlertDialogCancel onClick={() => setCancelDialogState({ isOpen: false, po: null })}>Thoát</AlertDialogCancel>
                <AlertDialogAction onClick={confirmCancel}>Xác nhận hủy</AlertDialogAction>
            </AlertDialogFooter>
            </AlertDialogContent>
        </AlertDialog>

        <ImagePreviewDialog
          images={previewImage ? [previewImage.url] : []}
          open={!!previewImage}
          onOpenChange={(open) => !open && setPreviewImage(null)}
          title={previewImage?.title}
        />
      </div>
  );
}

'use client'

import * as React from 'react';
import { useRouter, useParams } from 'next/navigation';
import { useSearchParamsWithSetter } from '@/lib/hooks/use-search-params-setter';
import { usePurchaseOrders, usePurchaseOrderMutations } from './hooks/use-purchase-orders';
import { usePurchaseOrder } from './hooks/use-purchase-orders';
import { ROUTES } from '../../lib/router';
import { useAllBranches } from '../settings/branches/hooks/use-all-branches';
import { useAllEmployees } from '../employees/hooks/use-all-employees';
import { useAuth } from '../../contexts/auth-context';
import { useAllProducts, useProductFinder } from '../products/hooks/use-all-products';
import { useAllSuppliers } from '../suppliers/hooks/use-all-suppliers';
import { useInventoryReceipts, useInventoryReceiptMutations } from '../inventory-receipts/hooks/use-inventory-receipts';
import { useStockHistoryMutations } from '../stock-history/hooks/use-stock-history';
// REMOVED: Voucher store no longer exists
// import { useVoucherStore } from '../vouchers/store';
import { useAllPaymentTypes } from '../settings/payments/types/hooks/use-all-payment-types';
import { useAllCashAccounts } from '../cashbook/hooks/use-all-cash-accounts';
import { usePaymentMutations } from '../payments/hooks/use-payments';
import type { Payment } from '../payments/types';
import { usePageHeader } from '../../contexts/page-header-context';
import { toast } from 'sonner';
import { getCurrentDate, toISODate, formatDateCustom } from '../../lib/date-utils';
import type { PurchaseOrder, PurchaseOrderPaymentStatus as PaymentStatus, PurchaseOrderStatus, PurchaseOrderDeliveryStatus as DeliveryStatus } from '@/lib/types/prisma-extended';
import { Button } from '../../components/ui/button';
import { SupplierSelectionCard } from './components/supplier-selection-card';
import { OrderInfoCard } from './components/order-info-card';
import {
  ProductSelectionCard,
  type ProductLineItem,
} from './components/product-selection-card';
import { OrderNotesCard } from './components/order-notes-card';
import {
  OrderSummaryCard,
  type DiscountType,
  type Fee,
  type PaymentRecord,
} from './components/order-summary-card';
import { asBusinessId, asSystemId } from '@/lib/id-types';
import type { SystemId } from '@/lib/id-types';

export function PurchaseOrderFormPage() {
  const { systemId: systemIdParam } = useParams<{ systemId: string }>();
  const [searchParams] = useSearchParamsWithSetter();
  const router = useRouter();
  
  const purchaseOrderSystemId = systemIdParam ? asSystemId(systemIdParam) : null;
  
  const { data: queryData } = usePurchaseOrders({ limit: 1000 });
  const _allOrders = queryData?.data ?? [];
  const { data: existingOrder } = usePurchaseOrder(purchaseOrderSystemId);
  
  const { create, update } = usePurchaseOrderMutations({
    onCreateSuccess: () => {
      toast.success('Tạo đơn nhập hàng thành công');
      router.push('/purchase-orders');
    },
    onUpdateSuccess: () => {
      toast.success('Cập nhật đơn nhập hàng thành công');
      router.push('/purchase-orders');
    },
    onError: (err) => toast.error(err.message)
  });
  
  // Helper function for processing inventory receipt
  const processInventoryReceipt = React.useCallback((poSystemId: string) => {
    (update as any).mutate({ systemId: poSystemId, deliveryStatus: 'Đã nhập kho' });
  }, [update]);
  
  const { data: branches } = useAllBranches();
  const { data: employees } = useAllEmployees();
  const { employee: authEmployee } = useAuth();
  const { data: products } = useAllProducts();
  const { findById: findProductById } = useProductFinder();
  const { data: suppliers } = useAllSuppliers();
  const { data: irQueryData } = useInventoryReceipts({ limit: 1000 });
  const _allReceipts = irQueryData?.data ?? [];
  const { create: createInventoryReceipt } = useInventoryReceiptMutations({
    onCreateSuccess: () => {},
    onError: (err) => toast.error(err.message)
  });
  const { create: createStockHistory } = useStockHistoryMutations({
    onSuccess: () => {},
    onError: (err) => toast.error(err.message)
  });
  const { create: createPayment } = usePaymentMutations({
    onCreateSuccess: () => {},
    onError: (err) => toast.error(err.message)
  });
  const { data: paymentTypes } = useAllPaymentTypes();
  const { accounts: _accounts } = useAllCashAccounts();

  const isEditMode = Boolean(purchaseOrderSystemId);
  
  // Copy mode: ?copy=systemId
  const copyFromId = searchParams.get('copy');
  const copyFromSystemId = copyFromId ? asSystemId(copyFromId) : null;
  const copyFromOrder = copyFromSystemId ? _allOrders.find(o => o.systemId === copyFromSystemId) : null;

  // Kiểm tra nếu đơn đã nhập kho thì không cho sửa (theo chuẩn Sapo)
  React.useEffect(() => {
    if (isEditMode && existingOrder && existingOrder.deliveryStatus !== 'Chưa nhập') {
      toast.error('Không thể sửa đơn', {
        description: 'Đơn đã nhập kho không thể sửa. Vui lòng sử dụng chức năng Hoàn trả để điều chỉnh.',
      });
      router.push(`/purchase-orders/${existingOrder.systemId}`);
    }
  }, [isEditMode, existingOrder, router]);

  // Form state
  const [supplierId, setSupplierId] = React.useState<SystemId | null>(
    existingOrder?.supplierSystemId ? asSystemId(existingOrder.supplierSystemId) : null
  );

  // Wrap setSupplierId to add logging
  const handleSetSupplierId = React.useCallback((id: SystemId | null) => {
    setSupplierId(id);
  }, []);


  // Use ref to keep latest supplierId value
  const supplierIdRef = React.useRef<SystemId | null>(supplierId);
  React.useEffect(() => {
    supplierIdRef.current = supplierId;
  }, [supplierId]);

  const defaultBranchId: SystemId | null = existingOrder?.branchSystemId
    ? asSystemId(existingOrder.branchSystemId)
    : branches[0]?.systemId
    ? asSystemId(branches[0].systemId)
    : null;
  const [branchId, setBranchId] = React.useState<SystemId | null>(defaultBranchId);
  const defaultEmployeeSystemId: SystemId | null = existingOrder?.buyerSystemId
    ? asSystemId(existingOrder.buyerSystemId)
    : authEmployee?.systemId
    ? asSystemId(authEmployee.systemId)
    : null;
  const [employeeId, setEmployeeId] = React.useState<SystemId | null>(defaultEmployeeSystemId);
  React.useEffect(() => {
    if (!isEditMode && !employeeId && authEmployee?.systemId) {
      setEmployeeId(asSystemId(authEmployee.systemId));
    }
  }, [isEditMode, employeeId, authEmployee]);
  const [reference, setReference] = React.useState<string>(
    existingOrder?.reference || ''
  );
  const [orderId, setOrderId] = React.useState<string>(existingOrder?.id || '');
  const [deliveryDate, setDeliveryDate] = React.useState<Date | undefined>(
    existingOrder?.deliveryDate ? new Date(existingOrder.deliveryDate) : undefined
  );
  const [items, setItems] = React.useState<ProductLineItem[]>([]);
  
  // Use ref to keep latest items value
  const itemsRef = React.useRef(items);
  React.useEffect(() => {
    itemsRef.current = items;
  }, [items]);
  const [notes, setNotes] = React.useState<string>(existingOrder?.notes || '');
  const [tags, setTags] = React.useState<string>('');
  const [discount, setDiscount] = React.useState<number>(0);
  const [discountType, setDiscountType] = React.useState<DiscountType>('fixed');
  const [shippingFees, setShippingFees] = React.useState<Fee[]>([]);
  const [otherFees, setOtherFees] = React.useState<Fee[]>([]);
  const [payments, setPayments] = React.useState<PaymentRecord[]>([]);
  const [isSaving, setIsSaving] = React.useState(false);
  
  // Track unsaved changes
  const [hasUnsavedChanges, setHasUnsavedChanges] = React.useState(false);

  // Use refs to keep latest values
  const shippingFeesRef = React.useRef(shippingFees);
  const otherFeesRef = React.useRef(otherFees);
  const paymentsRef = React.useRef(payments);
  const discountRef = React.useRef(discount);
  const discountTypeRef = React.useRef(discountType);

  React.useEffect(() => {
    shippingFeesRef.current = shippingFees;
    otherFeesRef.current = otherFees;
    paymentsRef.current = payments;
    discountRef.current = discount;
    discountTypeRef.current = discountType;
  }, [shippingFees, otherFees, payments, discount, discountType]);

  // Track changes để cảnh báo khi thoát
  React.useEffect(() => {
    if (!isEditMode && (
      supplierId || 
      items.length > 0 || 
      notes || 
      discount > 0 ||
      shippingFees.length > 0 ||
      otherFees.length > 0 ||
      payments.length > 0
    )) {
      setHasUnsavedChanges(true);
    }
  }, [supplierId, items, notes, discount, shippingFees, otherFees, payments, isEditMode]);

  // Ngăn chặn reload/close tab khi có thay đổi
  React.useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      if (hasUnsavedChanges && !isSaving) {
        e.preventDefault();
        e.returnValue = '';
      }
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [hasUnsavedChanges, isSaving]);

  // Logic copy từ đơn cũ
  React.useEffect(() => {
    if (copyFromOrder && !isEditMode) {
      
      // Copy supplier
      setSupplierId(asSystemId(copyFromOrder.supplierSystemId));
      
      // Copy branch và employee
      setBranchId(asSystemId(copyFromOrder.branchSystemId));
      setEmployeeId(asSystemId(copyFromOrder.buyerSystemId));
      
      // Copy delivery date nếu có
      if (copyFromOrder.deliveryDate) {
        setDeliveryDate(new Date(copyFromOrder.deliveryDate));
      }
      
      // Copy line items
      const copiedItems: ProductLineItem[] = copyFromOrder.lineItems
        .map(li => {
          const product = findProductById(asSystemId(li.productSystemId));
          if (!product) return null;
          
          return {
            product,
            quantity: li.quantity,
            unitPrice: li.unitPrice,
            discount: li.discount || 0,
            discountType: li.discountType === 'percentage' ? 'percent' as const : 'fixed' as const,
            tax: li.taxRate || 0,
            total: li.quantity * li.unitPrice,
            notes: li.note,
          } as ProductLineItem;
        })
        .filter((item): item is ProductLineItem => item !== null);
      
      setItems(copiedItems);
      
      // Copy discount
      if (copyFromOrder.discount) {
        setDiscount(copyFromOrder.discount);
        setDiscountType(copyFromOrder.discountType || 'fixed');
      }
      
      // Copy shipping fee
      if (copyFromOrder.shippingFee && copyFromOrder.shippingFee > 0) {
        setShippingFees([{
          id: 'shipping-1',
          name: 'Phí vận chuyển',
          amount: copyFromOrder.shippingFee
        }]);
      }
      
      // Copy tax/other fees
      if (copyFromOrder.tax && copyFromOrder.tax > 0) {
        setOtherFees([{
          id: 'tax-1',
          name: 'Thuế',
          amount: copyFromOrder.tax
        }]);
      }
      
      // Copy notes với prefix
      setNotes(`Sao chép từ đơn ${copyFromOrder.id}\n${copyFromOrder.notes || ''}`);
      
      // Hiện toast thông báo
      toast('Đã sao chép đơn hàng', {
        description: `Dữ liệu từ đơn ${copyFromOrder.id} đã được điền sẵn. Vui lòng kiểm tra lại trước khi lưu.`,
      });
    }
  }, [copyFromOrder, isEditMode, findProductById]);

  // Generate order ID for new orders
  React.useEffect(() => {
    if (!isEditMode && !orderId) {
      setOrderId('');
    }
  }, [isEditMode, orderId]);

  // Load existing order items
  React.useEffect(() => {
    if (existingOrder && existingOrder.lineItems) {
      const loadedItems: ProductLineItem[] = existingOrder.lineItems
        .map((item) => {
          const product = products.find(
            (p) => p.systemId === item.productSystemId
          );
          if (!product) return null;
          return {
            product,
            quantity: item.quantity,
            unitPrice: item.unitPrice,
            discount: item.discount,
            total: item.quantity * item.unitPrice - item.discount,
          };
        })
        .filter((item): item is ProductLineItem => item !== null);
      setItems(loadedItems);
    }
  }, [existingOrder, products]);

  // Calculate totals
  const subtotal = React.useMemo(
    () => items.reduce((sum, item) => sum + item.total, 0),
    [items]
  );

  const { preTaxSubtotal, totalTax } = React.useMemo(() => {
    return items.reduce((acc, item) => {
      const taxRate = item.tax || 0;
      const itemTotal = item.total;
      const preTax = itemTotal / (1 + taxRate / 100);
      const tax = itemTotal - preTax;
      return {
        preTaxSubtotal: acc.preTaxSubtotal + preTax,
        totalTax: acc.totalTax + tax
      };
    }, { preTaxSubtotal: 0, totalTax: 0 });
  }, [items]);

  const totalQuantity = React.useMemo(
    () => items.reduce((sum, item) => sum + item.quantity, 0),
    [items]
  );

  const discountAmount =
    discountType === 'percentage' ? (subtotal * discount) / 100 : discount;
  const _totalShippingFees = shippingFees.reduce((sum, fee) => sum + fee.amount, 0);
  const _totalOtherFees = otherFees.reduce((sum, fee) => sum + fee.amount, 0);
  const grandTotal = subtotal - discountAmount;

  const handleSave = async (receiveImmediately: boolean = false) => {
    // Use ref to get latest values
    const currentSupplierId = supplierIdRef.current;
    const currentItems = itemsRef.current;
    const currentShippingFees = shippingFeesRef.current;
    const currentOtherFees = otherFeesRef.current;
    const currentPayments = paymentsRef.current;
    const currentDiscount = discountRef.current;
    const currentDiscountType = discountTypeRef.current;
    
    
    // Validation
    if (!currentSupplierId) {
      toast.error('Lỗi', {
        description: 'Vui lòng chọn nhà cung cấp',
      });
      return;
    }

    if (!branchId) {
      toast.error('Lỗi', {
        description: 'Vui lòng chọn chi nhánh',
      });
      return;
    }

    if (!employeeId) {
      toast.error('Lỗi', {
        description: 'Vui lòng chọn nhân viên',
      });
      return;
    }

    const branchSystemId: SystemId = branchId;
    const employeeSystemId: SystemId = employeeId;

    if (currentItems.length === 0) {
      toast.error('Lỗi', {
        description: 'Vui lòng thêm ít nhất một sản phẩm',
      });
      return;
    }

    // Kiểm tra items có giá = 0
    const itemsWithZeroPrice = currentItems.filter(item => item.unitPrice === 0);
    if (itemsWithZeroPrice.length > 0) {
      const itemNames = itemsWithZeroPrice.map(item => item.product.name).join(', ');
      toast.error('Cảnh báo', {
        description: `Các sản phẩm sau chưa có giá: ${itemNames}. Vui lòng nhập giá trước khi lưu.`,
      });
      return;
    }

      setIsSaving(true);

      try {
        const supplier = suppliers.find((s) => s.systemId === currentSupplierId);
        const branch = branches.find((b) => b.systemId === branchSystemId);
        const employee = employees.find((e) => e.systemId === employeeSystemId);

        // Use order ID from state (will be auto-generated if empty)
        const finalOrderId = orderId || '';
        
        // Tính toán tất cả giá trị
        const calculatedSubtotal = currentItems.reduce((sum, item) => {
          const lineGross = item.quantity * item.unitPrice;
          const itemDiscount = item.discountType === 'percent' 
            ? lineGross * (item.discount / 100) 
            : item.discount;
          return sum + (lineGross - itemDiscount);
        }, 0);
        
        const calculatedDiscountAmount = currentDiscountType === 'percentage' 
          ? (calculatedSubtotal * currentDiscount) / 100 
          : currentDiscount;
        
        const calculatedShippingFee = currentShippingFees.reduce((sum, fee) => sum + fee.amount, 0);
        const calculatedTax = currentOtherFees.reduce((sum, fee) => sum + fee.amount, 0);
        const calculatedGrandTotal = calculatedSubtotal - calculatedDiscountAmount;

        

        // Tính payment status
        let initialPaymentStatus: PaymentStatus = 'Chưa thanh toán';
        const totalPayments = currentPayments.reduce((sum, p) => sum + p.amount, 0);
        if (totalPayments > 0) {
          if (totalPayments >= calculatedGrandTotal) {
            initialPaymentStatus = 'Đã thanh toán';
          } else {
            initialPaymentStatus = 'Thanh toán một phần';
          }
        }

        // Delivery status luôn là 'Chưa nhập' khi tạo mới (sẽ update sau khi tạo PNK)
        const deliveryStatus: DeliveryStatus = 'Chưa nhập';

        // Tính main status
        let initialStatus: PurchaseOrderStatus;
        // Khi tạo mới, delivery luôn là 'Chưa nhập'
        if (initialPaymentStatus === 'Chưa thanh toán') {
          initialStatus = 'Đặt hàng';
        } else {
          initialStatus = 'Đang giao dịch';
        }

        const orderData: Omit<PurchaseOrder, 'systemId'> = {
          id: finalOrderId,
          supplierSystemId: currentSupplierId,
          supplierName: supplier?.name || '',
          branchSystemId,
          branchName: branch?.name || '',
          buyerSystemId: employeeSystemId,
          buyer: employee?.fullName || '',
          reference: reference || undefined,
          orderDate: toISODate(getCurrentDate()),
          deliveryDate: deliveryDate ? toISODate(deliveryDate) : undefined,
          lineItems: currentItems.map((item) => ({
            productSystemId: item.product.systemId,
            productId: item.product.id || item.product.systemId,
            productName: item.product.name,
            sku: item.product.id,
            unit: item.product.unit,
            imageUrl: item.product.thumbnailImage ?? item.product.images?.[0],
            quantity: item.quantity,
            unitPrice: item.unitPrice,
            discount: item.discount,
            discountType: item.discountType === 'percent' ? 'percentage' : 'fixed',
            taxRate: item.tax || 0,
            note: item.notes,
          })),
          subtotal: calculatedSubtotal,
          discount: currentDiscount,
          discountType: currentDiscountType,
          shippingFee: calculatedShippingFee,
          tax: calculatedTax,
          grandTotal: calculatedGrandTotal,
          notes: notes || undefined,
          status: initialStatus,
          deliveryStatus: deliveryStatus,
          paymentStatus: initialPaymentStatus,
          payments: [],
          creatorSystemId: employeeSystemId,
          creatorName: employee?.fullName || '',
        };


        let createdOrder: PurchaseOrder;
        if (isEditMode && purchaseOrderSystemId) {
          (update as any).mutate({ ...orderData, systemId: purchaseOrderSystemId });
          createdOrder = { ...orderData, systemId: purchaseOrderSystemId } as PurchaseOrder;
          toast.success('Thành công', {
            description: 'Đã cập nhật đơn nhập hàng',
          });
        } else {
          (create as any).mutate(orderData);
          createdOrder = orderData as PurchaseOrder;
          toast.success('Thành công', {
            description: `Đã tạo đơn nhập hàng ${finalOrderId}`,
          });
        }

      // ========================================
      // XỬ LÝ KHI "TẠO & NHẬP HÀNG"
      // ========================================
      if (receiveImmediately && !isEditMode) {
        // 1. Tạo phiếu nhập kho
        const receiptData = {
          id: asBusinessId(''),
          purchaseOrderSystemId: asSystemId(createdOrder.systemId),
          purchaseOrderId: createdOrder.id ? asBusinessId(createdOrder.id) : asBusinessId(''),
          supplierSystemId: asSystemId(createdOrder.supplierSystemId),
          supplierName: createdOrder.supplierName,
          receivedDate: formatDateCustom(getCurrentDate(), 'yyyy-MM-dd HH:mm'),
          receiverSystemId: employeeSystemId,
          receiverName: employee?.fullName || '',
          branchSystemId,
          branchName: branch?.name,
          warehouseName: branch?.name ? `Kho ${branch.name}` : undefined,
          items: currentItems.map(item => ({
            productSystemId: item.product.systemId,
            productId: item.product.id,
            productName: item.product.name,
            orderedQuantity: item.quantity,
            receivedQuantity: item.quantity,
            unitPrice: item.unitPrice,
          })),
          notes: 'Nhập kho tự động khi tạo đơn',
        };

        createInventoryReceipt.mutate(receiptData);

        // 2. Cập nhật tồn kho + ghi lịch sử
        currentItems.forEach(item => {
          const productBeforeUpdate = findProductById(item.product.systemId);
          const oldStock = productBeforeUpdate?.inventoryByBranch?.[branchSystemId] || 0;
          
          // Note: Inventory updates now happen server-side

          // Ghi lịch sử kho
          createStockHistory.mutate({
            productId: item.product.systemId,
            date: formatDateCustom(getCurrentDate(), 'yyyy-MM-dd HH:mm'),
            employeeName: employee?.fullName || '',
            action: 'Nhập hàng từ NCC',
            quantityChange: item.quantity,
            newStockLevel: oldStock + item.quantity,
            documentId: receiptData.id,
            branch: branch?.name || '',
            branchSystemId,
          });
        });

        // 3. Cập nhật delivery status trong store
        processInventoryReceipt(createdOrder.systemId); // ✅ Fixed: Use systemId

        // 4. Xử lý thanh toán nếu có payment records
        if (currentPayments.length > 0) {
          const totalPayments = currentPayments.reduce((sum, p) => sum + p.amount, 0);
          
          currentPayments.forEach((payment, _index) => {
            const paymentCategory = paymentTypes.find(pt => pt.name === 'Thanh toán cho đơn nhập hàng');

            const timestamp = formatDateCustom(getCurrentDate(), 'yyyy-MM-dd HH:mm');
            const newPayment = {
              id: '' as Payment['id'], // Let Payment store auto-generate PC-XXXXXX
              date: timestamp,
              amount: payment.amount,
              recipientTypeSystemId: asSystemId('NHACUNGCAP'),
              recipientTypeName: 'Nhà cung cấp',
              recipientName: supplier?.name || '',
              recipientSystemId: supplier?.systemId,
              description: payment.note || `Thanh toán đơn nhập hàng ${finalOrderId}`,
              paymentMethodSystemId: asSystemId(payment.paymentMethodSystemId || 'BANK_TRANSFER'),
              paymentMethodName: payment.paymentMethodName || 'Chuyển khoản',
              accountSystemId: asSystemId(''), // TODO: Add accountSystemId to PaymentRecord
              paymentReceiptTypeSystemId: asSystemId(paymentCategory?.systemId || ''),
              paymentReceiptTypeName: paymentCategory?.name || 'Thanh toán cho đơn nhập hàng',
              branchSystemId: asSystemId(branchSystemId),
              branchName: branch?.name || '',
              createdBy: asSystemId(employee?.systemId || ''),
              createdAt: timestamp,
              status: 'completed' as const,
              category: 'supplier_payment' as const,
              affectsDebt: true,
              purchaseOrderSystemId: asSystemId(createdOrder.systemId),
              purchaseOrderId: asBusinessId(createdOrder.id),
              originalDocumentId: createdOrder.id,
            } satisfies Omit<Payment, 'systemId'>;

            createPayment.mutate(newPayment);
          });

          // Cập nhật payment status
          const updatedPaymentStatus = totalPayments >= grandTotal ? 'Đã thanh toán' : 'Thanh toán một phần';
          (update as any).mutate({
            systemId: createdOrder.systemId,
            paymentStatus: updatedPaymentStatus,
            payments: currentPayments.map((p, idx) => ({
              systemId: `PAY${finalOrderId}${String(idx + 1).padStart(3, '0')}`,
              id: `PAY_${finalOrderId}_${idx + 1}`,
              method: p.paymentMethodName,
              amount: p.amount,
              paymentDate: formatDateCustom(getCurrentDate(), 'yyyy-MM-dd'),
              reference: p.note,
              payerName: employee?.fullName || '',
            })),
          });
        }

        // Tính tổng số phiếu chi đã tạo (bao gồm thanh toán NCC + phí vận chuyển + chi phí khác)
        const shippingFeeCount = currentShippingFees.filter(f => f.amount > 0).length;
        const otherFeeCount = currentOtherFees.filter(f => f.amount > 0).length;
        const totalVoucherCount = currentPayments.length + shippingFeeCount + otherFeeCount;

        if (totalVoucherCount > 0) {
          toast.success('Hoàn tất', {
            description: `Đã nhập kho và tạo ${totalVoucherCount} phiếu chi`,
          });
        } else {
          toast.success('Hoàn tất', {
            description: `Đã nhập kho ${currentItems.length} sản phẩm`,
          });
        }

        // 5. Tạo phiếu chi cho Phí vận chuyển và Chi phí khác (Trả bên thứ 3)
        if (currentShippingFees.length > 0 || currentOtherFees.length > 0) {
          const expenseCategory = paymentTypes.find(pt => pt.name === 'Chi phí nhập hàng') || paymentTypes[0];
          const timestamp = formatDateCustom(getCurrentDate(), 'yyyy-MM-dd HH:mm');

          // Tạo phiếu chi cho từng khoản phí vận chuyển
          currentShippingFees.forEach(fee => {
             if (fee.amount <= 0) return;
             const feePayment = {
              id: '' as Payment['id'],
              date: timestamp,
              amount: fee.amount,
              recipientTypeSystemId: asSystemId('KHAC'),
              recipientTypeName: 'Khác',
              recipientName: 'Đơn vị vận chuyển',
              recipientSystemId: asSystemId(''),
              description: `Chi phí vận chuyển cho đơn nhập hàng ${finalOrderId} - ${fee.name}`,
              paymentMethodSystemId: asSystemId('CASH'), // Mặc định tiền mặt
              paymentMethodName: 'Tiền mặt',
              accountSystemId: asSystemId(''),
              paymentReceiptTypeSystemId: asSystemId(expenseCategory?.systemId || ''),
              paymentReceiptTypeName: 'Chi phí nhập hàng',
              branchSystemId: asSystemId(branchSystemId),
              branchName: branch?.name || '',
              createdBy: asSystemId(employee?.systemId || ''),
              createdAt: timestamp,
              status: 'completed' as const,
              category: 'expense' as const,
              affectsDebt: false,
              purchaseOrderSystemId: asSystemId(createdOrder.systemId),
              purchaseOrderId: asBusinessId(createdOrder.id),
              originalDocumentId: createdOrder.id,
            } satisfies Omit<Payment, 'systemId'>;
            createPayment.mutate(feePayment);
          });

          // Tạo phiếu chi cho từng khoản phí khác
          currentOtherFees.forEach(fee => {
             if (fee.amount <= 0) return;
             const feePayment = {
              id: '' as Payment['id'],
              date: timestamp,
              amount: fee.amount,
              recipientTypeSystemId: asSystemId('KHAC'),
              recipientTypeName: 'Khác',
              recipientName: 'Bên thứ 3',
              recipientSystemId: asSystemId(''),
              description: `Chi phí khác cho đơn nhập hàng ${finalOrderId} - ${fee.name}`,
              paymentMethodSystemId: asSystemId('CASH'), // Mặc định tiền mặt
              paymentMethodName: 'Tiền mặt',
              accountSystemId: asSystemId(''),
              paymentReceiptTypeSystemId: asSystemId(expenseCategory?.systemId || ''),
              paymentReceiptTypeName: 'Chi phí nhập hàng',
              branchSystemId: asSystemId(branchSystemId),
              branchName: branch?.name || '',
              createdBy: asSystemId(employee?.systemId || ''),
              createdAt: timestamp,
              status: 'completed' as const,
              category: 'expense' as const,
              affectsDebt: false,
              purchaseOrderSystemId: asSystemId(createdOrder.systemId),
              purchaseOrderId: asBusinessId(createdOrder.id),
              originalDocumentId: createdOrder.id,
            } satisfies Omit<Payment, 'systemId'>;
            createPayment.mutate(feePayment);
          });
        }
      }

      // Chuyển đến trang chi tiết đơn vừa tạo/cập nhật
      router.push(`/purchase-orders/${createdOrder.systemId}`);
    } catch (_error) {
      toast.error('Lỗi', {
        description: 'Không thể lưu đơn nhập hàng. Vui lòng thử lại.',
      });
    } finally {
      setIsSaving(false);
    }
  };

  // Page header with action buttons
  const handleExit = () => {
    
    if (hasUnsavedChanges && !isSaving) {
      if (window.confirm('Bạn có thay đổi chưa lưu. Bạn có chắc muốn thoát?')) {
        router.push('/purchase-orders');
      }
    } else {
      router.push('/purchase-orders');
    }
  };

  const handleSaveWithoutReceive = () => {
    setHasUnsavedChanges(false); // Reset flag khi save
    handleSave(false);
  };

  const handleSaveWithReceive = () => {
    setHasUnsavedChanges(false); // Reset flag khi save
    handleSave(true);
  };

  const headerActions = [
    <Button 
      key="exit" 
      type="button" 
      variant="outline" 
      onClick={handleExit} 
      size="sm" 
      className="h-9"
      disabled={isSaving}
    >
      Thoát
    </Button>,
    <Button 
      key="save" 
      type="button" 
      variant="outline" 
      onClick={handleSaveWithoutReceive} 
      size="sm" 
      className="h-9"
      disabled={isSaving}
    >
      {isSaving ? "Đang lưu..." : "Tạo & chưa nhập"}
    </Button>,
    <Button 
      key="save-receive" 
      type="button" 
      onClick={handleSaveWithReceive} 
      size="sm" 
      className="h-9"
      disabled={isSaving}
    >
      {isSaving ? "Đang lưu..." : "Tạo & nhập hàng"}
    </Button>,
  ];

  const headerTitle = isEditMode
    ? `Chỉnh sửa đơn nhập hàng ${existingOrder?.id ?? ''}`.trim()
    : 'Tạo đơn nhập hàng mới';

  usePageHeader({ 
    title: headerTitle,
    breadcrumb: [
      { label: 'Trang chủ', href: '/', isCurrent: false },
      { label: 'Đơn nhập hàng', href: ROUTES.PROCUREMENT.PURCHASE_ORDERS, isCurrent: false },
      { label: isEditMode ? 'Chỉnh sửa' : 'Tạo mới', href: isEditMode ? `${ROUTES.PROCUREMENT.PURCHASE_ORDERS}/${existingOrder?.systemId}/edit` : `${ROUTES.PROCUREMENT.PURCHASE_ORDER_NEW}`, isCurrent: true }
    ],
    actions: headerActions,
    showBackButton: true,
    backPath: ROUTES.PROCUREMENT.PURCHASE_ORDERS
  });

  return (
    <div className="w-full h-full space-y-4 pb-20 lg:pb-4">
      {/* Row 1: Supplier Info (70%) + Order Info (30%) - Mobile: Stack vertical */}
      <div className="grid grid-cols-1 lg:grid-cols-10 gap-4 h-auto lg:h-[340px]">
        <div className="lg:col-span-7 h-full overflow-hidden order-2 lg:order-1">
          <SupplierSelectionCard value={supplierId ?? undefined} onChange={handleSetSupplierId} />
        </div>
        <div className="lg:col-span-3 h-full overflow-hidden order-1 lg:order-2">
          <OrderInfoCard
            branchSystemId={branchId ?? ''}
            employeeSystemId={employeeId ?? ''}
            reference={reference}
            orderId={orderId}
            deliveryDate={deliveryDate}
            onBranchChange={(nextBranchId) =>
              setBranchId(nextBranchId ? asSystemId(nextBranchId) : null)
            }
            onEmployeeChange={(nextEmployeeId) =>
              setEmployeeId(nextEmployeeId ? asSystemId(nextEmployeeId) : null)
            }
            onReferenceChange={setReference}
            onOrderIdChange={setOrderId}
            onDeliveryDateChange={setDeliveryDate}
          />
        </div>
      </div>

        {/* Row 2: Product Selection (100%) */}
        <ProductSelectionCard
          items={items}
          onItemsChange={setItems}
          supplierId={supplierId ?? undefined}
        />

        {/* Row 3: Notes (60%) + Summary (40%) - Mobile: Stack vertical */}
        <div className="grid grid-cols-1 lg:grid-cols-10 gap-4">
          <div className="lg:col-span-6 order-2 lg:order-1">
            <OrderNotesCard
              notes={notes}
              tags={tags}
              onNotesChange={setNotes}
              onTagsChange={setTags}
            />
          </div>
          <div className="lg:col-span-4 order-1 lg:order-2">
            <OrderSummaryCard
              subtotal={preTaxSubtotal}
              tax={totalTax}
              discount={discount}
              discountType={discountType}
              shippingFees={shippingFees}
              otherFees={otherFees}
              totalQuantity={totalQuantity}
              payments={payments}
              onDiscountChange={setDiscount}
              onDiscountTypeChange={setDiscountType}
              onShippingFeesChange={setShippingFees}
              onOtherFeesChange={setOtherFees}
              onPaymentsChange={setPayments}
            />
          </div>
        </div>
        
        {/* Mobile Sticky Footer - Chỉ hiện trên mobile */}
        <div className="fixed bottom-0 left-0 right-0 lg:hidden bg-background border-t p-4 flex gap-2 z-50 shadow-lg">
          <Button 
            type="button" 
            variant="outline" 
            onClick={handleExit}
            className="flex-1"
            disabled={isSaving}
          >
            Thoát
          </Button>
          <Button 
            type="button" 
            variant="outline" 
            onClick={handleSaveWithoutReceive}
            className="flex-1"
            disabled={isSaving}
          >
            {isSaving ? "Đang lưu..." : "Lưu"}
          </Button>
          <Button 
            type="button" 
            onClick={handleSaveWithReceive}
            className="flex-1"
            disabled={isSaving}
          >
            {isSaving ? "Đang lưu..." : "Lưu & Nhập"}
          </Button>
        </div>
    </div>
  );
}

/**
 * Hook cho cancel workflow của PurchaseOrder
 * Tách từ page.tsx để giảm kích thước file
 */
import React from 'react';
import { toast } from 'sonner';
import { toISODate, getCurrentDate } from '@/lib/date-utils';
import { asBusinessId, asSystemId } from '@/lib/id-types';
import type { PurchaseOrder } from '@/lib/types/prisma-extended';
import { usePurchaseOrderStore } from '../store';
import { sumPaymentsForPurchaseOrder } from '../payment-utils';
import { useAllPayments } from '@/features/payments/hooks/use-all-payments';
import { useInventoryReceipts } from '@/features/inventory-receipts/hooks/use-inventory-receipts';
import { usePurchaseReturns, usePurchaseReturnMutations } from '@/features/purchase-returns/hooks/use-purchase-returns';
import type { PurchaseReturnLineItem } from '@/features/purchase-returns/types';
import { useAuth } from '@/contexts/auth-context';

export interface CancelPODialogState {
  isOpen: boolean;
  po: PurchaseOrder | null;
  willCreateReturn?: boolean;
  totalPaid?: number;
}

const initialCancelState: CancelPODialogState = {
  isOpen: false,
  po: null,
};

export function usePurchaseOrderCancelWorkflow() {
  const { cancelOrder, bulkCancel } = usePurchaseOrderStore();
  const { data: allPayments } = useAllPayments();
  const { data: irQueryData } = useInventoryReceipts({ limit: 1000 });
  const allReceipts = irQueryData?.data ?? [];
  const { data: prQueryData } = usePurchaseReturns({ limit: 1000 });
  const allPurchaseReturns = prQueryData?.data ?? [];
  const { create: createPurchaseReturn } = usePurchaseReturnMutations({
    onCreateSuccess: () => {},
    onError: (err) => toast.error(err.message)
  });
  const { employee: loggedInUser } = useAuth();
  
  const currentUserSystemId = loggedInUser?.systemId ?? 'SYSTEM';
  const currentUserName = loggedInUser?.fullName ?? 'Hệ thống';

  const [cancelDialogState, setCancelDialogState] = React.useState<CancelPODialogState>(initialCancelState);

  const handleCancelRequest = React.useCallback((po: PurchaseOrder) => {
    const totalPaid = sumPaymentsForPurchaseOrder(allPayments, po);
    const hasBeenDelivered = po.deliveryStatus !== 'Chưa nhập';

    setCancelDialogState({ 
      isOpen: true, 
      po: po, 
      totalPaid: totalPaid,
      willCreateReturn: hasBeenDelivered 
    });
  }, [allPayments]);

  const closeCancelDialog = React.useCallback(() => {
    setCancelDialogState(initialCancelState);
  }, []);

  const confirmCancel = React.useCallback(() => {
    if (!cancelDialogState.po) return;
    const po = cancelDialogState.po;

    if (cancelDialogState.willCreateReturn) {
      const poSystemId = asSystemId(po.systemId);
      const receiptsForPO = allReceipts.filter(r => r.purchaseOrderSystemId === poSystemId);
      const returnsForPO = allPurchaseReturns.filter(pr => pr.purchaseOrderSystemId === poSystemId);

      const returnItems = po.lineItems
        .map<PurchaseReturnLineItem | null>(item => {
          const totalReceived = receiptsForPO.reduce((sum, receipt) => {
            const receiptItem = receipt.items.find(i => i.productSystemId === item.productSystemId);
            return sum + (receiptItem ? Number(receiptItem.receivedQuantity) : 0);
          }, 0);
          const totalReturned = returnsForPO.reduce((sum, pr) => {
            const returnItem = pr.items.find(i => i.productSystemId === item.productSystemId);
            return sum + (returnItem ? returnItem.returnQuantity : 0);
          }, 0);
          const returnableQuantity = totalReceived - totalReturned;

          if (returnableQuantity <= 0) {
            return null;
          }

          return {
            productSystemId: asSystemId(item.productSystemId),
            productId: asBusinessId(item.productId),
            productName: item.productName,
            orderedQuantity: item.quantity,
            returnQuantity: returnableQuantity,
            unitPrice: item.unitPrice,
          } satisfies PurchaseReturnLineItem;
        })
        .filter((item): item is PurchaseReturnLineItem => Boolean(item));

      if (returnItems.length > 0) {
        const totalReturnValue = returnItems.reduce((sum, item) => sum + (item.returnQuantity * item.unitPrice), 0);

        createPurchaseReturn.mutate({
          id: asBusinessId(''),
          purchaseOrderSystemId: asSystemId(po.systemId),
          purchaseOrderId: asBusinessId(po.id),
          supplierSystemId: asSystemId(po.supplierSystemId),
          supplierName: po.supplierName,
          branchSystemId: asSystemId(po.branchSystemId),
          branchName: po.branchName,
          returnDate: toISODate(getCurrentDate()),
          reason: `Tự động tạo khi hủy đơn nhập hàng ${po.id}`,
          items: returnItems,
          totalReturnValue,
          refundAmount: 0,
          refundMethod: '',
          creatorName: currentUserName,
        });
      }
    }

    cancelOrder(po.systemId, currentUserSystemId, currentUserName);
    setCancelDialogState(initialCancelState);
    toast.success('Đã hủy đơn nhập hàng', {
      description: `Đơn ${po.id} đã được hủy`,
    });
  }, [cancelDialogState, allReceipts, allPurchaseReturns, createPurchaseReturn, cancelOrder, currentUserSystemId, currentUserName]);

  const handleBulkCancel = React.useCallback((selectedIds: string[]) => {
    if (selectedIds.length === 0) {
      toast.error('Chưa chọn đơn hàng', {
        description: 'Vui lòng chọn ít nhất một đơn hàng',
      });
      return;
    }
    bulkCancel(selectedIds, currentUserSystemId, currentUserName);
    toast.success('Đã hủy', {
      description: `Đã hủy ${selectedIds.length} đơn nhập hàng`,
    });
  }, [bulkCancel, currentUserSystemId, currentUserName]);

  return {
    cancelDialogState,
    handleCancelRequest,
    closeCancelDialog,
    confirmCancel,
    handleBulkCancel,
  };
}

/**
 * Hook tổng hợp handlers cho PurchaseOrders page
 * Kết hợp receive workflow, cancel workflow, và print handlers
 * Sử dụng để giảm kích thước page.tsx < 300 lines
 */
import * as React from 'react';
import { useRouter } from 'next/navigation';
import { toast } from 'sonner';
import { formatDateCustom, getCurrentDate } from '@/lib/date-utils';
import { asBusinessId, asSystemId } from '@/lib/id-types';
import type { PurchaseOrder } from '@/lib/types/prisma-extended';
import { usePurchaseOrders, usePurchaseOrderMutations } from '../hooks/use-purchase-orders';
import { useAllPayments } from '@/features/payments/hooks/use-all-payments';
import { usePaymentStore } from '@/features/payments/store';
import { useAllCashAccounts } from '@/features/cashbook/hooks/use-all-cash-accounts';
import { useAllPaymentTypes } from '@/features/settings/payments/types/hooks/use-all-payment-types';
import { usePurchaseReturns } from '@/features/purchase-returns/hooks/use-purchase-returns';
import { useAuth } from '@/contexts/auth-context';
import { sumPaymentsForPurchaseOrder } from '../payment-utils';
import type { Payment } from '@/features/payments/types';

// Import sub-workflows
import { usePurchaseOrderReceiveWorkflow, type ReceiveDialogState, type ReceiveLineItemForm } from './use-po-receive-workflow';
import { usePurchaseOrderCancelWorkflow, type CancelPODialogState } from './use-po-cancel-workflow';
import { usePurchaseOrderPrintHandlers } from './use-po-print-handlers';

export type { ReceiveDialogState, ReceiveLineItemForm, CancelPODialogState };

/**
 * Main hook combining all PurchaseOrders page handlers
 */
export function usePurchaseOrdersPageHandlers() {
  const router = useRouter();
  const { data: queryData } = usePurchaseOrders({ limit: 1000 });
  const purchaseOrders = queryData?.data ?? [];
  const { update: updatePO } = usePurchaseOrderMutations({});
  const { data: allPayments } = useAllPayments();
  const { accounts } = useAllCashAccounts();
  const { data: paymentTypes } = useAllPaymentTypes();
  const { data: prQueryData } = usePurchaseReturns({ limit: 1000 });
  const allPurchaseReturns = prQueryData?.data ?? [];
  const { employee: loggedInUser } = useAuth();
  
  const currentUserSystemId = loggedInUser?.systemId ?? 'SYSTEM';
  const currentUserName = loggedInUser?.fullName ?? 'Hệ thống';
  
  // Helper functions
  const bulkCancel = React.useCallback((systemIds: string[], userId: string, _userName: string) => {
    systemIds.forEach(id => (updatePO as any).mutate({ systemId: id, status: 'cancelled', cancelledBy: userId, cancelledAt: new Date().toISOString() }));
  }, [updatePO]);
  
  const syncAllPurchaseOrderStatuses = React.useCallback(() => {
    // Note: This is handled by React Query invalidation
  }, []);

  // Sub-workflows
  const receiveWorkflow = usePurchaseOrderReceiveWorkflow();
  const cancelWorkflow = usePurchaseOrderCancelWorkflow();
  const printHandlers = usePurchaseOrderPrintHandlers();

  // Row selection state
  const [rowSelection, setRowSelection] = React.useState<Record<string, boolean>>({});
  const [isBulkPayAlertOpen, setIsBulkPayAlertOpen] = React.useState(false);

  // Computed values
  const selectedOrders = React.useMemo(() => {
    return purchaseOrders.filter(o => rowSelection[o.systemId]);
  }, [purchaseOrders, rowSelection]);

  const numSelected = Object.keys(rowSelection).filter(k => rowSelection[k]).length;

  // Handler: Start cancel request
  const handleCancelRequest = React.useCallback((po: PurchaseOrder) => {
    cancelWorkflow.handleCancelRequest(po);
  }, [cancelWorkflow]);

  // Handler: Start receive goods
  const handleReceiveGoods = React.useCallback((po: PurchaseOrder) => {
    receiveWorkflow.beginReceiveFlow([po]);
  }, [receiveWorkflow]);

  // Handler: View payment details
  const handlePayment = React.useCallback((po: PurchaseOrder) => {
    router.push(`/purchase-orders/${po.systemId}`);
    toast(`Mở trang thanh toán cho đơn ${po.id}`);
  }, [router]);

  // Handler: Print single
  const handlePrint = React.useCallback((po: PurchaseOrder) => {
    printHandlers.handlePrint(po);
  }, [printHandlers]);

  // Bulk actions
  const handleBulkPrint = React.useCallback(() => {
    if (numSelected === 0) {
      toast.error('Chưa chọn đơn hàng', {
        description: 'Vui lòng chọn ít nhất một đơn hàng',
      });
      return;
    }
    printHandlers.openBulkPrintDialog(selectedOrders);
  }, [numSelected, selectedOrders, printHandlers]);

  const handleBulkCancel = React.useCallback(() => {
    const selectedIds = Object.keys(rowSelection).filter(id => rowSelection[id]);
    if (selectedIds.length === 0) {
      toast.error('Chưa chọn đơn hàng', {
        description: 'Vui lòng chọn ít nhất một đơn hàng',
      });
      return;
    }
    bulkCancel(selectedIds, currentUserSystemId, currentUserName);
    toast.success('Đã hủy', {
      description: `Đã hủy ${selectedIds.length} đơn nhập hàng`,
    });
    setRowSelection({});
  }, [rowSelection, bulkCancel, currentUserSystemId, currentUserName]);

  const handleBulkReceive = React.useCallback(() => {
    if (numSelected === 0) {
      toast.error('Chưa chọn đơn hàng', {
        description: 'Vui lòng chọn ít nhất một đơn hàng',
      });
      return;
    }
    receiveWorkflow.beginReceiveFlow(selectedOrders);
  }, [numSelected, selectedOrders, receiveWorkflow]);

  const confirmBulkPay = React.useCallback(() => {
    const paymentCategory = paymentTypes.find(pt => pt.name === 'Thanh toán cho đơn nhập hàng');
    const { add: addPayment } = usePaymentStore.getState();
    const paymentMethodName = 'Chuyển khoản';
    const paymentMethodSystemId = 'BANK_TRANSFER';
    let totalPaymentsCreated = 0;
    
    selectedOrders.forEach(po => {
      const totalPaid = sumPaymentsForPurchaseOrder(allPayments, po);
      const totalReturnValue = allPurchaseReturns
        .filter(r => r.purchaseOrderSystemId === asSystemId(po.systemId))
        .reduce((sum, r) => sum + r.totalReturnValue, 0);
      const actualDebt = Math.max(po.grandTotal - totalReturnValue, 0);
      const amountRemaining = actualDebt - totalPaid;

      if (amountRemaining > 0) {
        const account = accounts.find(acc => acc.type === 'bank' && acc.branchSystemId === po.branchSystemId) 
          || accounts.find(acc => acc.type === 'bank');
        if (!account) {
          console.error(`Không tìm thấy tài khoản ngân hàng cho chi nhánh ${po.branchName}`);
          return;
        }

        const now = formatDateCustom(getCurrentDate(), 'yyyy-MM-dd HH:mm');
        const newPayment = {
          id: '' as Payment['id'],
          date: now,
          amount: amountRemaining,
          recipientTypeSystemId: asSystemId('NHACUNGCAP'),
          recipientTypeName: 'Nhà cung cấp',
          recipientName: po.supplierName,
          recipientSystemId: asSystemId(po.supplierSystemId),
          description: `Thanh toán toàn bộ cho đơn nhập hàng ${po.id}`,
          paymentMethodSystemId: asSystemId(paymentMethodSystemId),
          paymentMethodName,
          accountSystemId: asSystemId(account.systemId),
          paymentReceiptTypeSystemId: asSystemId(paymentCategory?.systemId || ''),
          paymentReceiptTypeName: paymentCategory?.name || 'Thanh toán cho đơn nhập hàng',
          branchSystemId: asSystemId(po.branchSystemId),
          branchName: po.branchName,
          createdBy: asSystemId(currentUserSystemId),
          createdAt: now,
          status: 'completed' as const,
          category: 'supplier_payment' as const,
          affectsDebt: true,
          purchaseOrderSystemId: asSystemId(po.systemId),
          purchaseOrderId: asBusinessId(po.id),
          originalDocumentId: po.id,
        } satisfies Omit<Payment, 'systemId'>;
        addPayment(newPayment);
        totalPaymentsCreated += 1;
      }
    });

    if (totalPaymentsCreated > 0) {
      syncAllPurchaseOrderStatuses();
      toast.success('Đã tạo phiếu chi', {
        description: `Hoàn tất ${totalPaymentsCreated} phiếu chi cho đơn nhập hàng đã chọn.`,
      });
    }

    setRowSelection({});
    setIsBulkPayAlertOpen(false);
  }, [selectedOrders, allPayments, allPurchaseReturns, accounts, paymentTypes, currentUserSystemId, syncAllPurchaseOrderStatuses]);

  // Print dialog handlers
  const handlePrintConfirm = React.useCallback((options: Parameters<typeof printHandlers.handlePrintConfirm>[0]) => {
    printHandlers.handlePrintConfirm(options);
    setRowSelection({});
  }, [printHandlers]);

  // Cancel dialog handlers
  const handleConfirmCancel = React.useCallback(() => {
    cancelWorkflow.confirmCancel();
    setRowSelection({});
  }, [cancelWorkflow]);

  return {
    // State
    rowSelection,
    setRowSelection,
    isBulkPayAlertOpen,
    setIsBulkPayAlertOpen,
    numSelected,
    selectedOrders,
    
    // Individual actions
    handleCancelRequest,
    handleReceiveGoods,
    handlePayment,
    handlePrint,
    
    // Bulk actions  
    handleBulkPrint,
    handleBulkCancel,
    handleBulkReceive,
    confirmBulkPay,
    
    // Receive workflow state & handlers
    receiveDialogState: receiveWorkflow.receiveDialogState,
    isSubmittingReceive: receiveWorkflow.isSubmittingReceive,
    handleReceiveQuantityChange: receiveWorkflow.handleReceiveQuantityChange,
    handleReceiveFieldChange: receiveWorkflow.handleReceiveFieldChange,
    handleReceiveBranchChange: receiveWorkflow.handleReceiveBranchChange,
    handleSubmitReceiveDialog: receiveWorkflow.handleSubmitReceiveDialog,
    closeReceiveDialog: receiveWorkflow.closeReceiveDialog,
    
    // Cancel workflow state & handlers
    cancelDialogState: cancelWorkflow.cancelDialogState,
    closeCancelDialog: cancelWorkflow.closeCancelDialog,
    handleConfirmCancel,
    
    // Print workflow state & handlers
    isPrintDialogOpen: printHandlers.isPrintDialogOpen,
    pendingPrintPOs: printHandlers.pendingPrintPOs,
    handlePrintConfirm,
    closePrintDialog: printHandlers.closePrintDialog,
  };
}

