    const pageHeaderConfig = React.useMemo(() => ({
        title: order ? `Tạo phiếu trả cho ${order.id}` : 'Tạo phiếu trả hàng',
        subtitle: order ? `${customer?.name || 'Khách lẻ'} | ${order.branchName}` : 'Chọn đơn hàng để bắt đầu khởi tạo phiếu trả',
        breadcrumb,
        showBackButton: true,
        backPath: backDestination,
        actions: headerActions,
    }), [order, customer?.name, backDestination, headerActions, breadcrumb]);

    usePageHeader(pageHeaderConfig);

  if (!order || !customer || !branches.length) {
    return <div>Đang tải hoặc không tìm thấy đơn hàng...</div>;
  }
  
  const handleSelectProducts = (selectedProducts: Product[]) => {
      const currentItems = getValues('exchangeItems') || [];
      
      selectedProducts.forEach(product => {
          const policyId = selectedPricingPolicy || defaultSellingPolicy?.systemId;
          const price = (policyId && product.prices?.[policyId]) 
              ? product.prices[policyId]
              : (product.sellingPrice || Object.values(product.prices || {})[0] || 0);
          
          // If split line is disabled, try to find existing item and increase quantity
          if (!enableSplitLine) {
              const existingIndex = currentItems.findIndex(item => item.productSystemId === product.systemId);
              
              if (existingIndex > -1) {
                  const currentItem = getValues(`exchangeItems.${existingIndex}`);
                  const updatedQuantity = (Number(currentItem.quantity) || 0) + 1;
                  const updatedTotal = price * updatedQuantity - (currentItem.discount || 0);
                  
                  setValue(`exchangeItems.${existingIndex}.quantity`, updatedQuantity);
                  setValue(`exchangeItems.${existingIndex}.total`, updatedTotal);
                  return; // Skip adding new line
              }
          }
          
          // Add as new line (either split line is enabled, or product doesn't exist yet)
          appendExchange({
              productSystemId: product.systemId,
              productId: product.id,
              productName: product.name,
              quantity: 1,
              unitPrice: price,
              discount: 0,
              discountType: 'fixed',
              total: price,
          });
      });
  };

  const _handleAddProduct = (_values: ExchangeLineItem) => {
      // Note: This function is deprecated. Use appendExchangeItem directly
      // addProduct expects Product, not LineItem
  };

  const onSubmit = async (values: FormValues) => {
    if (!order || !customer) return;
    
    // ✅ Prevent double submission
    if (isSubmitting) {
        return;
    }
    
    setIsSubmitting(true);

    const branch = branches.find(b => b.systemId === values.branchSystemId);
        if (!branch) {
            setError('branchSystemId', { message: 'Chi nhánh không hợp lệ' });
            setIsSubmitting(false);
            return;
        }

        const returnItems = values.items.filter(i => i.returnQuantity > 0);
        if (returnItems.length === 0 && values.exchangeItems.length === 0) {
          toast.error('Vui lòng chọn sản phẩm để trả hoặc đổi.');
          setIsSubmitting(false);
          return;
        }
        
        // Calculate financials
        const { finalAmount, maxRefundableAmount, totalReturnValue, totalExchangeValue, subtotalExchangeValue } = calculateFinancials(values);

        // ✅ Validate refunds when finalAmount < 0 AND customer has actually paid
        // Nếu khách chưa thanh toán (maxRefundableAmount = 0), không cần bắt buộc hoàn tiền
        const requiredRefundAmount = Math.min(Math.abs(finalAmount), maxRefundableAmount);
        
    if (finalAmount < 0 && requiredRefundAmount > 0.01) {
        const totalRefunded = (values.refunds || []).reduce((sum, r) => sum + (r.amount || 0), 0);
        const remainingRefund = requiredRefundAmount - totalRefunded;
        
        if (remainingRefund > 0.01) {
            toast.error(`Còn phải hoàn trả khách: ${formatCurrency(remainingRefund)}. Vui lòng thêm phương thức hoàn tiền.`);
            setIsSubmitting(false);
            return;
        }
        
        // Validate each refund has method and account
        for (let i = 0; i < values.refunds.length; i++) {
            const refund = values.refunds[i];
            if (!refund.method) {
                toast.error(`Vui lòng chọn phương thức hoàn tiền cho dòng ${i + 1}`);
                setIsSubmitting(false);
                return;
            }
            if (!refund.accountSystemId) {
                toast.error(`Vui lòng chọn tài khoản quỹ cho dòng ${i + 1}`);
                setIsSubmitting(false);
                return;
            }
            if (!refund.amount || refund.amount <= 0) {
                toast.error(`Vui lòng nhập số tiền hoàn cho dòng ${i + 1}`);
                setIsSubmitting(false);
                return;
            }
        }
    }
    
    // ✅ Validate payment total when finalAmount > 0
    if (finalAmount > 0 && values.payments && values.payments.length > 0) {
        const totalPaymentAmount = values.payments.reduce((sum, p) => sum + (p.amount || 0), 0);
        const difference = Math.abs(totalPaymentAmount - finalAmount);
        if (difference > 0.01) {
            toast.error(`Tổng thanh toán (${formatCurrency(totalPaymentAmount)}) không khớp với số tiền cần thu (${formatCurrency(finalAmount)}). Vui lòng kiểm tra lại.`);
            setIsSubmitting(false);
            return;
        }
    }

    const returnPayload = {
        orderSystemId: order.systemId,
        orderId: order.id,
        customerSystemId: customer.systemId,
        customerName: customer.name,
        branchSystemId: asSystemId(values.branchSystemId),  // ✅ Đúng tên field: branchSystemId
        branchName: branch.name,
        returnDate: toISODateTime(new Date()),
        reason: values.returnReason || values.notes,
        notes: values.notes,
        reference: values.reference,
        items: returnItems.map(({ total: _total, returnableQuantity: _returnableQuantity, orderedQuantity: _orderedQuantity, originalUnitPrice: _originalUnitPrice, ...rest }) => ({
            ...rest, 
            totalValue: rest.returnQuantity * rest.unitPrice,
            note: rest.note?.trim() || undefined,
        })),
        totalReturnValue,
        isReceived: values.isReceived, // ✅ Pass isReceived flag to control inventory update
        exchangeItems: values.exchangeItems.map(({ total: _total, ...rest }) => rest),
        subtotalNew: subtotalExchangeValue, // ✅ Use subtotal (before discount & shipping)
        shippingFeeNew: values.shippingFee || 0,
        grandTotalNew: totalExchangeValue, // ✅ Total after discount & shipping)
        finalAmount,
        payments: finalAmount > 0 ? values.payments?.map(p => ({ ...p, accountSystemId: asSystemId(p.accountSystemId) })) : undefined,
        refunds: finalAmount < 0 ? values.refunds?.map(r => ({ ...r, accountSystemId: asSystemId(r.accountSystemId) })) : undefined, // ✅ Use new refunds array
        creatorName,
        creatorId: creatorSystemId,
        creatorSystemId: asSystemId(creatorSystemId as string), // ✅ Also pass creatorSystemId for SalesReturn type
        // ✅ Pass shipping info for exchange order
        deliveryMethod: values.deliveryMethod,
        shippingPartnerId: values.shippingPartnerId,
        shippingServiceId: values.shippingServiceId,
        shippingAddress: values.shippingAddress ?? undefined,
        packageInfo: values.packageInfo as unknown as PackageInfo | undefined,
        configuration: values.configuration,
    };
    
    
    // ✅ Call GHTK API if using GHTK shipping partner
    
    const isUsingShippingPartner = values.deliveryMethod === 'deliver-later' || values.deliveryMethod === 'shipping-partner';
    
    if (isUsingShippingPartner && values.shippingPartnerId === 'GHTK' && values.exchangeItems.length > 0) {
        
        try {
            // Load shipping config
            const shippingConfig = loadShippingConfig();
            const ghtkData = shippingConfig.partners.GHTK;
            
            if (!ghtkData || !ghtkData.accounts || ghtkData.accounts.length === 0) {
                toast.error('Lỗi cấu hình', { description: 'Chưa cấu hình tài khoản GHTK' });
                setIsSubmitting(false);
                return;
            }
            
            const ghtkAccount = ghtkData.accounts.find(a => a.isDefault && a.active)
                || ghtkData.accounts.find(a => a.active)
                || ghtkData.accounts[0];
            
            if (!ghtkAccount || !ghtkAccount.active) {
                toast.error('Lỗi cấu hình', { description: 'Không tìm thấy tài khoản GHTK khả dụng' });
                setIsSubmitting(false);
                return;
            }
            
            const apiToken = ghtkAccount.credentials.apiToken as string;
            const partnerCode = ghtkAccount.credentials.partnerCode as string;
            
            if (!apiToken) {
                toast.error('Lỗi cấu hình', { description: 'Thiếu API Token GHTK' });
                setIsSubmitting(false);
                return;
            }

            // Build GHTK request body from form data
            const customer = customers.find(c => c.systemId === order?.customerSystemId);
            
            // ✅ Use shipping address from FORM, not from original order
            const shippingAddress = values.shippingAddress;
            
            
            if (!shippingAddress || !customer) {
                toast.error('Thiếu thông tin giao hàng', { 
                    description: 'Vui lòng cấu hình đầy đủ thông tin vận chuyển GHTK trước khi tạo đơn' 
                });
                setIsSubmitting(false);
                return;
            }

            // Build full address: Try all possible address fields
            // Address may be split across: street, address, fullAddress, houseNumber, etc.
            const shippingAddrAny = shippingAddress as Record<string, unknown>;
            const addressParts = [
                shippingAddrAny.houseNumber as string | undefined,
                shippingAddrAny.street as string | undefined,
                shippingAddrAny.address as string | undefined,
                shippingAddrAny.fullAddress as string | undefined,
            ].filter(Boolean) as string[];
            
            const customerAddress: string = addressParts.length > 0 
                ? addressParts.join(', ')
                : ((shippingAddrAny.address || shippingAddrAny.street || shippingAddrAny.fullAddress || '') as string);
            
            
            if (!customerAddress || !shippingAddress.province || !shippingAddress.district || !shippingAddress.ward) {
                toast.error('Thiếu thông tin địa chỉ', { 
                    description: 'Vui lòng nhập đầy đủ địa chỉ chi tiết, tỉnh/thành, quận/huyện, phường/xã' 
                });
                setIsSubmitting(false);
                return;
            }

            // Build products array from exchange items
            const products = values.exchangeItems.map(item => {
                const product = products.find(p => p.systemId === item.productSystemId);
                return {
                    name: product?.name || item.productName || 'Sản phẩm',
                    weight: product?.weight || 100, // Keep in grams (don't divide by 1000)
                    quantity: item.quantity,
                    price: item.unitPrice || 0,
                };
            });

            // Get pickup info from GHTK account settings
            const pickupAddress = (ghtkAccount.pickupAddresses as Array<{
                partnerWarehouseName?: string;
                partnerWarehouseAddress?: string;
                partnerWarehouseTel?: string;
                partnerWarehouseProvince?: string;
                partnerWarehouseDistrict?: string;
                partnerWarehouseWard?: string;
            }>)?.[0]; // Use first pickup address
            if (!pickupAddress) {
                toast.error('Lỗi cấu hình', { 
                    description: 'Chưa cấu hình địa chỉ lấy hàng GHTK' 
                });
                setIsSubmitting(false);
                return;
            }

            const ghtkParams: GHTKCreateOrderParams = {
                // ✅ Unique order ID: Include timestamp to avoid collision when multiple returns from same order
                orderId: `RETURN_${order?.id}_${Date.now()}`,
                
                // Pickup info from partner warehouse
                pickName: pickupAddress.partnerWarehouseName as string || 'Cửa hàng',
                pickAddress: pickupAddress.partnerWarehouseAddress as string || '',
                pickTel: pickupAddress.partnerWarehouseTel as string || '',
                pickProvince: pickupAddress.partnerWarehouseProvince as string || '',
                pickDistrict: pickupAddress.partnerWarehouseDistrict as string || '',
                pickWard: pickupAddress.partnerWarehouseWard as string || '',
                
                // Customer info from FORM (user may have edited)
                customerName: (shippingAddrAny.name as string) || (shippingAddrAny.contactName as string) || customer.name || '',
                customerTel: (shippingAddrAny.phone as string) || (shippingAddrAny.contactPhone as string) || customer.phone || '',
                // Use the fully built address with all parts
                customerAddress: customerAddress,
                customerProvince: (shippingAddress.province as string) || '',
                customerDistrict: (shippingAddress.district as string) || '',
                customerWard: (shippingAddress.ward as string) || '',
                customerHamlet: 'Khác',
                
                // Products
                products,
                
                // Payment
                pickMoney: (values.packageInfo?.codAmount as number) || 0,
                // ✅ value = "Giá trị hàng hoá" = finalAmount if > 0, else totalExchangeValue
                value: finalAmount > 0 ? finalAmount : totalExchangeValue,
                isFreeship: (values.packageInfo?.codAmount || 0) === 0 ? 1 : 0,
                
                // Additional info
                note: values.notes || '',
                transport: 'road',
                // Don't send tags unless user explicitly selects them
            };
            
            const ghtkService = new GHTKService(apiToken, partnerCode || '');
            
            toast.info('Đang tạo đơn trên GHTK...', { duration: 2000 });
            const result = await ghtkService.createOrder(ghtkParams);
            
            if (result.success && result.order) {
                toast.success('Đã tạo đơn GHTK thành công', { 
                    description: `Mã vận đơn: ${result.order.label}` 
                });
                // Update packageInfo with tracking code (stored in extended Record<string, unknown>)
                returnPayload.packageInfo = {
                    ...(returnPayload.packageInfo || { weight: 0, length: 0, width: 0, height: 0, codAmount: 0 }),
                    trackingCode: result.order.label,
                } as unknown as PackageInfo;
            } else {
                toast.error('Tạo đơn GHTK thất bại', { 
                    description: result.message || 'Vui lòng kiểm tra lại thông tin' 
                });
                setIsSubmitting(false);
                return; // Don't create return if GHTK failed
            }
        } catch (error: unknown) {
            console.error('❌ GHTK create order error:', error);
            toast.error('Lỗi tạo đơn GHTK', { 
                description: (error as Error)?.message || 'Vui lòng thử lại sau' 
            });
            setIsSubmitting(false);
            return; // Don't create return if GHTK failed
        }
    }
    // Note: addReturn needs to use mutations
    const newReturnSystemId = asSystemId(`SR${(returnPayload as any).systemId || Date.now()}`);
    const newReturn = { ...returnPayload, systemId: newReturnSystemId };
    const newOrderSystemId = newReturn.systemId;
    
    
    // ✅ Navigate to new exchange order if created, otherwise back to original order
    if (newOrderSystemId) {
        toast.success('Tạo phiếu trả hàng và đơn đổi hàng thành công!', {
            description: `Đang chuyển đến đơn đổi hàng mới...`,
            duration: 2000,
        });
        // Navigate to the new exchange order
        setTimeout(() => {
            router.push(`/orders/${newOrderSystemId}`);
        }, 500);
    } else if (newReturn) {
        toast.success('Tạo phiếu trả hàng thành công!');
        // Navigate back to original order if no exchange order
        router.push(`/orders/${order.systemId}`);
    }
    
    setIsSubmitting(false);
  };
  
  // Only disable if order is cancelled (not completed - completed orders can still be returned)
  const isFullyReadOnly = order.status === 'Đã hủy';
  
  return (
    <FormProvider {...form}>
      <form id="sales-return-form" onSubmit={handleSubmit(onSubmit)}>
        <div className="space-y-4">
            {/* Row 1: Thông tin phiếu + Thông tin bổ sung + Quy trình xử lý */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
                <Card>
                    <CardHeader><CardTitle className="text-h4">Thông tin phiếu</CardTitle></CardHeader>
                    <CardContent>
                        <div className="grid grid-cols-2 gap-4 text-body-sm">
                            <p>Khách hàng: <a className="font-semibold text-primary hover:underline">{customer.name}</a></p>
                            <p>Mã đơn hàng gốc: <Link href={`/orders/${order.systemId}`} className="font-semibold text-primary hover:underline">{order.id}</Link></p>
                            <FormField 
                                control={control} 
                                name="branchSystemId" 
                                render={({ field }) => (
                                    <FormItem className="flex items-center gap-2">
                                        <FormLabel>Chi nhánh trả hàng</FormLabel>
                                        <Select 
                                            onValueChange={field.onChange} 
                                            value={field.value}
                                        >
                                            <FormControl>
                                                <SelectTrigger className="w-[180px] h-8">
                                                    <SelectValue placeholder="Chọn chi nhánh" />
                                                </SelectTrigger>
                                            </FormControl>
                                            <SelectContent>
                                                {branches.map(b => (
                                                    <SelectItem key={b.systemId} value={b.systemId}>
                                                        {b.name}
                                                    </SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    </FormItem>
                                )} 
                            />
                            <FormField control={control} name="reference" render={({ field }) => (
                                <FormItem className="flex items-center gap-2"><FormLabel>Tham chiếu</FormLabel><FormControl><Input className="h-8" {...field} value={field.value || ''} /></FormControl></FormItem>
                            )} />
                        </div>
                    </CardContent>
                </Card>
                <Card>
                     <CardHeader><CardTitle className="text-h4">Thông tin bổ sung</CardTitle></CardHeader>
                     <CardContent className="space-y-4">
                        <FormField control={control} name="returnReason" render={({ field }) => (
                            <FormItem>
                                <FormLabel>Lý do trả hàng</FormLabel>
                                <Select onValueChange={field.onChange} value={field.value}>
                                    <FormControl>
                                        <SelectTrigger>
                                            <SelectValue placeholder="Chọn lý do" />
                                        </SelectTrigger>
                                    </FormControl>
                                    <SelectContent>
                                        <SelectItem value="Sản phẩm lỗi">Sản phẩm lỗi</SelectItem>
                                        <SelectItem value="Sai mô tả">Sai mô tả</SelectItem>
                                        <SelectItem value="Không vừa ý">Không vừa ý</SelectItem>
                                        <SelectItem value="Giao nhầm sản phẩm">Giao nhầm sản phẩm</SelectItem>
                                        <SelectItem value="Đổi size/màu">Đổi size/màu</SelectItem>
                                        <SelectItem value="Khác">Khác</SelectItem>
                                    </SelectContent>
                                </Select>
                            </FormItem>
                        )} />
                        <FormField control={control} name="notes" render={({ field }) => (
                            <FormItem>
                                <FormLabel>Ghi chú chi tiết</FormLabel>
                                <FormControl>
                                    <Textarea {...field} value={field.value || ''} rows={3} placeholder="Mô tả chi tiết lý do trả hàng..." />
                                </FormControl>
                            </FormItem>
                        )} />
                     </CardContent>
                </Card>
                <SalesReturnWorkflowCard
                    subtasks={getValues('subtasks') || []}
                    onSubtasksChange={(subtasks) => setValue('subtasks', subtasks)}
                    readonly={true}
                />
            </div>

            {/* Row 2: Products to Return */}
            <Card>
                 <CardHeader>
                    <div className="flex items-center justify-between">
                        <CardTitle className="text-h4">Sản phẩm trả</CardTitle>
                         <div className="flex items-center space-x-2">
                             <Label htmlFor="returnAll" className="font-normal">Trả toàn bộ</Label>
                            <Controller
                                name="returnAll"
                                control={control}
                                render={({ field }) => (
                                    <Checkbox
                                        id="returnAll"
                                        checked={field.value}
                                        onCheckedChange={(checked) => {
                                            const boolChecked = !!checked;
                                            field.onChange(boolChecked);
                                            const currentItems = getValues('items');
                                            currentItems.forEach((item, index) => {
                                                const newQty = boolChecked ? item.returnableQuantity : 0;
                                                setValue(`items.${index}.returnQuantity`, newQty, { shouldDirty: true });
                                            });
                                        }}
                                    />
                                )}
                            />
                         </div>
                    </div>
                </CardHeader>
                <CardContent>
                    <div className="border rounded-md">
                        <Table>
                            <TableHeader><TableRow><TableHead className="w-12 text-center">STT</TableHead><TableHead>Sản phẩm</TableHead><TableHead className="w-40">Số lượng trả</TableHead><TableHead className="w-[180px] text-right">Đơn giá gốc</TableHead><TableHead className="w-[180px] text-right">Đơn giá trả</TableHead><TableHead className="w-[180px] text-right">Thành tiền</TableHead></TableRow></TableHeader>
                            <TableBody>
                                {fields.map((field, index) => (
                                    <ReturnItemRow
                                        key={field.id}
                                        index={index}
                                        field={field}
                                        control={control}
                                        setValue={setValue}
                                        products={products}
                                        expandedCombos={expandedCombos}
                                        toggleComboRow={toggleComboRow}
                                        handlePreview={handlePreview}
                                        handleOpenReturnNoteDialog={handleOpenReturnNoteDialog}
                                        getProductTypeLabel={getProductTypeLabel}
                                    />
                                ))}
                            </TableBody>
                            <ReturnTableFooter />
                        </Table>
                    </div>
                </CardContent>
            </Card>

            {/* Row 3: Nhận hàng trả lại */}
            <Card>
                <CardHeader><CardTitle className="text-h4">Nhận hàng trả lại</CardTitle></CardHeader>
                <CardContent className="space-y-4">
                    <p className="text-body-sm text-muted-foreground">Hàng trả lại được nhập vào kho chi nhánh {branches.find(b => b.systemId === getValues('branchSystemId'))?.name || 'mặc định'}</p>
                    
                    <FormField control={control} name="isReceived" render={({ field }) => (
                        <RadioGroup onValueChange={(v) => field.onChange(v === 'true')} value={String(field.value)} className="flex gap-4">
                            <Button type="button" asChild variant={field.value ? 'default' : 'outline'}><label className="flex items-center gap-2 cursor-pointer"><RadioGroupItem value="true" className="sr-only" /> Đã nhận và nhập kho</label></Button>
                            <Button type="button" asChild variant={!field.value ? 'default' : 'outline'}><label className="flex items-center gap-2 cursor-pointer"><RadioGroupItem value="false" className="sr-only" /> Chưa nhận hàng</label></Button>
                        </RadioGroup>
                    )} />

                    {/* Warning về ảnh hưởng tồn kho */}
                    {watchIsReceived ? (
                        <Alert className="border-green-200 bg-green-50">
                            <CheckCircle2 className="h-4 w-4 text-green-600" />
                            <AlertDescription className="text-body-sm text-green-800">
                                <strong>Đã nhận và nhập kho:</strong> Tồn kho sẽ được cập nhật ngay lập tức khi tạo đơn trả hàng. Số lượng hàng trả sẽ được thêm vào kho chi nhánh đã chọn.
                            </AlertDescription>
                        </Alert>
                    ) : (
                        <Alert className="border-amber-200 bg-amber-50">
                            <AlertTriangle className="h-4 w-4 text-amber-600" />
                            <AlertDescription className="text-body-sm text-amber-800">
                                <strong>Chưa nhận hàng:</strong> Tồn kho sẽ KHÔNG thay đổi. Bạn cần xác nhận nhận hàng sau để cập nhật tồn kho.
                            </AlertDescription>
                        </Alert>
                    )}
                </CardContent>
            </Card>

            {/* Row 4: Đổi hàng */}
            <Card>
                <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-4">
                    <CardTitle className="text-h4">Đổi hàng</CardTitle>
                    <ProductTableToolbar
                        enableSplitLine={enableSplitLine}
                        onSplitLineChange={setEnableSplitLine}
                        disabled={isFullyReadOnly}
                    />
                </CardHeader>
                <CardContent>
                    <div className="mb-4">
                        <div className="flex items-center gap-2">
                            <OrderProductSearch
                                onSelectProduct={(p) => handleSelectProducts([p])}
                                disabled={isFullyReadOnly}
                                allowCreateNew={true}
                                placeholder="Thêm sản phẩm (F3)"
                                searchPlaceholder="Tìm kiếm theo tên, mã SKU, barcode..."
                            />
                            <Button 
                                type="button" 
                                variant="outline" 
                                className="h-9 flex-shrink-0"
                                onClick={() => setIsProductSelectionOpen(true)} 
                                disabled={isFullyReadOnly}
                            >
                                Chọn nhanh
                            </Button>
                            <Select 
                                value={selectedPricingPolicy} 
                                onValueChange={setSelectedPricingPolicy}
                                disabled={isFullyReadOnly}
                            >
                                <SelectTrigger className="w-[180px] h-9 flex-shrink-0">
                                    <SelectValue placeholder="Chọn bảng giá" />
                                </SelectTrigger>
                                <SelectContent>
                                    {pricingPolicies.filter(p => p.type === 'Bán hàng' && p.isActive).map(policy => (
                                        <SelectItem key={policy.systemId} value={policy.systemId}>
                                            {policy.name} {policy.isDefault && '(Mặc định)'}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                    </div>
                    
                    {exchangeFields.length === 0 ? (
                        <div className="text-center text-muted-foreground p-12 border border-dashed rounded-md">
                            <PackageOpen className="mx-auto h-12 w-12 text-gray-300" />
                            <p className="mt-4 text-body-sm">Chưa có sản phẩm nào trong đơn hàng</p>
                            <Button 
                                type="button" 
                                variant="link" 
                                className="mt-2" 
                                onClick={() => setIsProductSelectionOpen(true)} 
                                disabled={isFullyReadOnly}
                            >
                                Thêm sản phẩm
                            </Button>
                        </div>
                    ) : (
                        <LineItemsTable
                            disabled={isFullyReadOnly}
                            // eslint-disable-next-line @typescript-eslint/no-explicit-any
                            fields={exchangeFields.map(f => ({ ...f, systemId: f.id, tax: f.tax ?? 0 })) as any[]}
                            remove={removeExchange}
                            pricingPolicyId={selectedPricingPolicy}
                            fieldName="exchangeItems"
                        />
                    )}
                </CardContent>
            </Card>

            <SalesReturnSummary />

            {/* Row 7: Giao hàng (chỉ hiển thị khi có sản phẩm đổi) */}
            <ShippingCard hidden={exchangeFields.length === 0} customer={customer} />
        </div>
        <ProductSelectionDialog 
            isOpen={isProductSelectionOpen} 
            onOpenChange={setIsProductSelectionOpen} 
            onSelect={handleSelectProducts} 
        />
        <ImagePreviewDialog
            images={previewState.image ? [previewState.image] : []}
            title={previewState.title}
            open={previewState.open}
            onOpenChange={(open) => setPreviewState(prev => ({ ...prev, open }))}
        />
        
        {/* Return Note Dialog */}
        <Dialog 
            open={editingReturnNoteIndex !== null} 
            onOpenChange={(open) => { if (!open) { setEditingReturnNoteIndex(null); setTempReturnNote(''); } }}
        >
            <DialogContent className="sm:max-w-md">
                <DialogHeader>
                    <DialogTitle>Ghi chú sản phẩm trả</DialogTitle>
                </DialogHeader>
                <div className="py-4">
                    <Textarea
                        value={tempReturnNote}
                        onChange={(e) => setTempReturnNote(e.target.value)}
                        placeholder="Nhập ghi chú cho sản phẩm..."
                        rows={3}
                    />
                </div>
                <DialogFooter>
                    <Button 
                        type="button" 
                        variant="outline" 
                        onClick={() => { setEditingReturnNoteIndex(null); setTempReturnNote(''); }}
                    >
                        Hủy
                    </Button>
                    <Button type="button" onClick={handleSaveReturnNote}>
                        Lưu
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
        
        {/* Exchange Note Dialog */}
        <Dialog 
            open={editingExchangeNoteIndex !== null} 
            onOpenChange={(open) => { if (!open) { setEditingExchangeNoteIndex(null); setTempExchangeNote(''); } }}
        >
            <DialogContent className="sm:max-w-md">
                <DialogHeader>
                    <DialogTitle>Ghi chú sản phẩm đổi</DialogTitle>
                </DialogHeader>
                <div className="py-4">
                    <Textarea
                        value={tempExchangeNote}
                        onChange={(e) => setTempExchangeNote(e.target.value)}
                        placeholder="Nhập ghi chú cho sản phẩm..."
                        rows={3}
                    />
                </div>
                <DialogFooter>
                    <Button 
                        type="button" 
                        variant="outline" 
                        onClick={() => { setEditingExchangeNoteIndex(null); setTempExchangeNote(''); }}
                    >
                        Hủy
                    </Button>
                    <Button type="button" onClick={handleSaveExchangeNote}>
                        Lưu
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
      </form>
    </FormProvider>
  );
}

﻿'use client'

import * as React from 'react';
import { useRouter } from 'next/navigation';
import dynamic from 'next/dynamic';
import { toast } from 'sonner';
import { formatDate } from '../../lib/date-utils';
import { usePageHeader } from '../../contexts/page-header-context';
import { useSalesReturns } from './hooks/use-sales-returns';
import { useAllBranches } from '../settings/branches/hooks/use-all-branches';
import { useStoreInfoData } from '../settings/store-info/hooks/use-store-info';
import { usePrint } from '../../lib/use-print';
import { convertSalesReturnForPrint, mapSalesReturnToPrintData, mapSalesReturnLineItems, createStoreSettingsFromBranch } from '../../lib/print/sales-return-print-helper';
import { getColumns } from './columns';
import { ResponsiveDataTable } from '../../components/data-table/responsive-data-table';
import { asSystemId } from '../../lib/id-types';
import { DataTableFacetedFilter } from '../../components/data-table/data-table-faceted-filter';
import { DynamicDataTableColumnCustomizer as DataTableColumnCustomizer } from '../../components/data-table/dynamic-column-customizer';
import { PageToolbar } from '../../components/layout/page-toolbar';
import { PageFilters } from '../../components/layout/page-filters';
import { SimplePrintOptionsDialog, type SimplePrintOptionsResult } from '../../components/shared/simple-print-options-dialog';
import { Card, CardContent } from '../../components/ui/card';
import { Button } from '../../components/ui/button';
import { Badge } from '../../components/ui/badge';
import { Avatar, AvatarFallback } from '../../components/ui/avatar';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '../../components/ui/select';
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from '../../components/ui/dropdown-menu';
import { PlusCircle, Undo2, MoreHorizontal, Package, Calendar, User, Printer, Download } from 'lucide-react';
import { TouchButton } from '../../components/mobile/touch-button';
import { useMediaQuery } from '../../lib/use-media-query';
import { useAuth } from '../../contexts/auth-context';
import type { SalesReturn } from '@/lib/types/prisma-extended';
import { useFuseFilter } from '../../hooks/use-fuse-search';
import { ROUTES } from '../../lib/router';
import { useColumnVisibility } from '../../hooks/use-column-visibility';

const SalesReturnExportDialog = dynamic(() => import("./components/sales-returns-import-export-dialogs").then(mod => ({ default: mod.SalesReturnExportDialog })), { ssr: false });

const formatCurrency = (value?: number) => typeof value === 'number' ? new Intl.NumberFormat('vi-VN').format(value) : '0';

export function SalesReturnsPage() {
    const router = useRouter();
    const { data: queryData } = useSalesReturns({ limit: 1000 });
    const returns = React.useMemo(() => queryData?.data ?? [], [queryData?.data]);
    const { data: branches } = useAllBranches();
    const { info: storeInfo } = useStoreInfoData();
    const { employee: currentUser } = useAuth();
    const { print, printMultiple } = usePrint();
    const isMobile = !useMediaQuery('(min-width: 768px)');
    const mobileScrollRef = React.useRef<HTMLDivElement>(null);

     
    const activeReturns = React.useMemo(() => returns.filter(r => (r as any).status !== 'Đã hủy'), [returns]);

    const [exportDialogOpen, setExportDialogOpen] = React.useState(false), [printDialogOpen, setPrintDialogOpen] = React.useState(false);
    const [itemsToPrint, setItemsToPrint] = React.useState<SalesReturn[]>([]);
    const [sorting, setSorting] = React.useState({ id: 'createdAt', desc: true }), [globalFilter, setGlobalFilter] = React.useState('');
    const [debouncedGlobalFilter, setDebouncedGlobalFilter] = React.useState(''), [pagination, setPagination] = React.useState({ pageIndex: 0, pageSize: 40 });
    const [rowSelection, setRowSelection] = React.useState({}), [expanded, setExpanded] = React.useState<Record<string, boolean>>({});
    const [branchFilter, setBranchFilter] = React.useState('all'), [statusFilter, setStatusFilter] = React.useState<Set<string>>(new Set());
    const [columnOrder, setColumnOrder] = React.useState<string[]>([]), [pinnedColumns, setPinnedColumns] = React.useState<string[]>(['id']);
    const [mobileLoadedCount, setMobileLoadedCount] = React.useState(20);

    const defaultColumnVisibility = React.useMemo(() => {
        const initial: Record<string, boolean> = {};
        getColumns(() => {}).forEach(c => { if (c.id) initial[c.id] = true; });
        return initial;
    }, []);
    const [columnVisibility, setColumnVisibility] = useColumnVisibility('sales-returns', defaultColumnVisibility);

    const handleCreateReturn = React.useCallback(() => router.push(ROUTES.SALES.ORDERS), [router]);
    const headerActions = React.useMemo(() => [
        <Button key="create" size="sm" className="h-9 px-4" onClick={handleCreateReturn}><PlusCircle className="mr-2 h-4 w-4" />Tạo phiếu trả</Button>
    ], [handleCreateReturn]);

    usePageHeader(React.useMemo(() => ({
        title: 'Phiếu trả hàng',
        breadcrumb: [{ label: 'Trang chủ', href: ROUTES.ROOT }, { label: 'Trả hàng', href: ROUTES.SALES.RETURNS, isCurrent: true }],
        showBackButton: false, actions: headerActions,
    }), [headerActions]));

    React.useEffect(() => { const timer = setTimeout(() => setDebouncedGlobalFilter(globalFilter), 300); return () => clearTimeout(timer); }, [globalFilter]);

    const handleBulkPrint = React.useCallback((rows: SalesReturn[]) => { setItemsToPrint(rows); setPrintDialogOpen(true); }, []);

    const handlePrintConfirm = React.useCallback((options: SimplePrintOptionsResult) => {
        if (itemsToPrint.length === 0) return;
        const { branchSystemId, paperSize } = options;
        const selectedBranch = branches.find(b => b.systemId === branchSystemId);
        const storeSettings = createStoreSettingsFromBranch(selectedBranch, storeInfo);
        const printOptionsList = itemsToPrint.map(ret => {
            const returnData = convertSalesReturnForPrint(ret, { branch: selectedBranch });
            return { data: mapSalesReturnToPrintData(returnData, storeSettings), lineItems: mapSalesReturnLineItems(returnData.returnItems || []), paperSize };
        });
        printMultiple('sales-return', printOptionsList);
        setPrintDialogOpen(false); setItemsToPrint([]); setRowSelection({});
        toast.success(`Đang in ${itemsToPrint.length} phiếu trả hàng`);
    }, [itemsToPrint, branches, storeInfo, printMultiple]);

    const handlePrintReturn = React.useCallback((returnIds: string[]) => {
        returnIds.forEach(id => {
            const ret = activeReturns.find(r => r.systemId === id);
            if (!ret) return;
            const branch = branches.find(b => b.name === ret.branchName);
            const storeSettings = createStoreSettingsFromBranch(branch, storeInfo);
            const returnData = convertSalesReturnForPrint(ret, { branch });
            print('sales-return', { data: mapSalesReturnToPrintData(returnData, storeSettings), lineItems: mapSalesReturnLineItems(returnData.returnItems || []) });
        });
    }, [activeReturns, branches, storeInfo, print]);

    const handlePrintSingleReturn = React.useCallback((returnId: string) => handlePrintReturn([returnId]), [handlePrintReturn]);
    const columns = React.useMemo(() => getColumns(handlePrintSingleReturn), [handlePrintSingleReturn]);

    React.useEffect(() => { setColumnOrder(columns.map(c => c.id).filter(Boolean) as string[]); }, [columns]);

    const fuseOptions = React.useMemo(() => ({ keys: ['id', 'orderId', 'customerName', 'creatorName'], threshold: 0.3, ignoreLocation: true }), []);
    const searchedData = useFuseFilter(activeReturns, debouncedGlobalFilter, fuseOptions);

    const filteredData = React.useMemo(() => {
        let filtered = activeReturns;
        if (branchFilter !== 'all') {
            const selectedBranch = branches.find(b => b.systemId === branchFilter);
            if (selectedBranch) filtered = filtered.filter(r => r.branchName === selectedBranch.name);
        }
        if (statusFilter.size > 0) filtered = filtered.filter(r => statusFilter.has(r.isReceived ? 'Đã nhận' : 'Chưa nhận'));
        if (debouncedGlobalFilter?.trim()) {
            const searchedIds = new Set(searchedData.map(s => s.systemId));
            filtered = filtered.filter(r => searchedIds.has(r.systemId));
        }
        return filtered;
    }, [activeReturns, debouncedGlobalFilter, searchedData, branchFilter, statusFilter, branches]);

    React.useEffect(() => { setPagination(p => ({ ...p, pageIndex: 0 })); }, [debouncedGlobalFilter, branchFilter, statusFilter]);

    const sortedData = React.useMemo(() => {
        const sorted = [...filteredData];
        if (sorting.id) {
            sorted.sort((a, b) => {
                const aValue = (a as unknown as Record<string, unknown>)[sorting.id];
                const bValue = (b as unknown as Record<string, unknown>)[sorting.id];
                if (aValue == null) return 1;
                if (bValue == null) return -1;
                if (sorting.id === 'createdAt' || sorting.id === 'returnDate') {
                    const aTime = aValue ? new Date(aValue as string | number | Date).getTime() : 0, bTime = bValue ? new Date(bValue as string | number | Date).getTime() : 0;
                    return sorting.desc ? bTime - aTime : aTime - bTime;
                }
                return aValue < bValue ? (sorting.desc ? 1 : -1) : aValue > bValue ? (sorting.desc ? -1 : 1) : 0;
            });
        }
        return sorted;
    }, [filteredData, sorting]);

    const pageCount = Math.ceil(sortedData.length / pagination.pageSize);
    const paginatedData = React.useMemo(() => sortedData.slice(pagination.pageIndex * pagination.pageSize, (pagination.pageIndex + 1) * pagination.pageSize), [sortedData, pagination]);

    React.useEffect(() => {
        if (!isMobile) return;
        const handleScroll = () => {
            const { scrollTop, scrollHeight } = document.documentElement;
            if ((window.pageYOffset || scrollTop) + window.innerHeight >= scrollHeight * 0.8 && mobileLoadedCount < sortedData.length)
                setMobileLoadedCount(prev => Math.min(prev + 20, sortedData.length));
        };
        window.addEventListener('scroll', handleScroll, { passive: true });
        return () => window.removeEventListener('scroll', handleScroll);
    }, [isMobile, mobileLoadedCount, sortedData.length]);

    React.useEffect(() => { setMobileLoadedCount(20); }, [debouncedGlobalFilter, branchFilter, statusFilter]);

    const statusOptions = React.useMemo(() => [{ label: 'Đã nhận', value: 'Đã nhận' }, { label: 'Chưa nhận', value: 'Chưa nhận' }], []);
    const handleRowClick = (row: SalesReturn) => router.push('/returns/' + row.systemId);
    const allSelectedRows = React.useMemo(() => activeReturns.filter(r => rowSelection[r.systemId]), [activeReturns, rowSelection]);
    const bulkActions = React.useMemo(() => [{ label: 'In phiếu trả hàng', icon: Printer, onSelect: handleBulkPrint }], [handleBulkPrint]);

    const MobileSalesReturnCard = ({ salesReturn }: { salesReturn: SalesReturn }) => (
        <Card className='hover:shadow-md transition-shadow cursor-pointer' onClick={() => handleRowClick(salesReturn)}>
            <CardContent className='p-4'>
                <div className='flex items-center justify-between mb-2'>
                    <div className='flex items-center gap-2 flex-1 min-w-0'>
                        <Avatar className='h-8 w-8 shrink-0 bg-orange-100'><AvatarFallback className='text-body-xs text-orange-700'><Undo2 className='h-4 w-4' /></AvatarFallback></Avatar>
                        <div className='flex items-center gap-1.5 min-w-0 flex-1'>
                            <h3 className='font-medium text-body-sm truncate'>{salesReturn.id}</h3>
                            <span className='text-body-xs text-muted-foreground font-mono'>{salesReturn.orderId}</span>
                        </div>
                    </div>
                    <DropdownMenu>
                        <DropdownMenuTrigger asChild><TouchButton variant='ghost' size='sm' className='h-8 w-8 p-0 flex-shrink-0' onClick={(e) => e.stopPropagation()}><MoreHorizontal className='h-4 w-4' /></TouchButton></DropdownMenuTrigger>
                        <DropdownMenuContent align='end'><DropdownMenuItem onClick={(e) => { e.stopPropagation(); handlePrintSingleReturn(salesReturn.systemId); }}>In Phiếu Trả Hàng</DropdownMenuItem></DropdownMenuContent>
                    </DropdownMenu>
                </div>
                <div className='text-body-xs text-muted-foreground mb-3 flex items-center'><User className='h-3 w-3 mr-1.5 flex-shrink-0' /><span className='truncate'>{salesReturn.customerName}</span></div>
                <div className='border-t mb-3' />
                <div className='space-y-2'>
                    <div className='flex items-center text-body-xs text-muted-foreground'><Package className='h-3 w-3 mr-1.5 flex-shrink-0' /><span>{salesReturn.items.reduce((sum, item) => sum + item.returnQuantity, 0)} sản phẩm</span></div>
                    <div className='flex items-center text-body-xs text-muted-foreground'><Calendar className='h-3 w-3 mr-1.5 flex-shrink-0' /><span>{formatDate(salesReturn.returnDate)}</span></div>
                    <div className='flex items-center justify-between text-body-xs pt-1'>
                        <span className='text-h4'>{formatCurrency(salesReturn.totalReturnValue)}</span>
                        <Badge variant={salesReturn.isReceived ? 'default' : 'secondary'} className='text-body-xs'>{salesReturn.isReceived ? 'Đã nhận' : 'Chưa nhận'}</Badge>
                    </div>
                </div>
            </CardContent>
        </Card>
    );

    return (
        <div className='flex flex-col w-full h-full'>
            {!isMobile && (
                <PageToolbar
                    leftActions={<Button variant="outline" size="sm" onClick={() => setExportDialogOpen(true)}><Download className="h-4 w-4 mr-2" />Xuất Excel</Button>}
                    rightActions={<DataTableColumnCustomizer columns={columns} columnVisibility={columnVisibility} setColumnVisibility={setColumnVisibility} columnOrder={columnOrder} setColumnOrder={setColumnOrder} pinnedColumns={pinnedColumns} setPinnedColumns={setPinnedColumns} />}
                />
            )}
            <PageFilters searchValue={globalFilter} onSearchChange={setGlobalFilter} searchPlaceholder='Tìm kiếm phiếu trả hàng (mã phiếu, mã đơn, khách hàng)...'>
                <Select value={branchFilter} onValueChange={setBranchFilter}>
                    <SelectTrigger className='w-full sm:w-[180px]'><SelectValue placeholder='Tất cả chi nhánh' /></SelectTrigger>
                    <SelectContent><SelectItem value='all'>Tất cả chi nhánh</SelectItem>{branches.map(b => <SelectItem key={b.systemId} value={b.systemId}>{b.name}</SelectItem>)}</SelectContent>
                </Select>
                <DataTableFacetedFilter title='Trạng thái' options={statusOptions} selectedValues={statusFilter} onSelectedValuesChange={setStatusFilter} />
            </PageFilters>
            {isMobile ? (
                <div ref={mobileScrollRef} className='space-y-3 pb-4'>
                    {sortedData.length === 0 ? (
                        <Card><CardContent className='py-12 text-center'><p className='text-muted-foreground'>Không tìm thấy phiếu trả hàng</p></CardContent></Card>
                    ) : (<>
                        {sortedData.slice(0, mobileLoadedCount).map(salesReturn => <MobileSalesReturnCard key={salesReturn.systemId} salesReturn={salesReturn} />)}
                        {mobileLoadedCount < sortedData.length && <Card className='border-dashed'><CardContent className='py-6 text-center'><div className='flex items-center justify-center gap-2'><div className='h-4 w-4 animate-spin rounded-full border-2 border-primary border-t-transparent' /><span className='text-body-sm text-muted-foreground'>Đang tải thêm...</span></div></CardContent></Card>}
                        {mobileLoadedCount >= sortedData.length && sortedData.length > 20 && <Card className='border-dashed'><CardContent className='py-4 text-center'><span className='text-body-sm text-muted-foreground'>Đã hiển thị tất cả {sortedData.length} phiếu trả hàng</span></CardContent></Card>}
                    </>)}
                </div>
            ) : (
                <div className='w-full py-4'>
                    <ResponsiveDataTable columns={columns} data={paginatedData} renderMobileCard={(salesReturn) => <MobileSalesReturnCard salesReturn={salesReturn} />} pageCount={pageCount} pagination={pagination} setPagination={setPagination} rowCount={filteredData.length} rowSelection={rowSelection} setRowSelection={setRowSelection} allSelectedRows={allSelectedRows} bulkActions={bulkActions} expanded={expanded} setExpanded={setExpanded} sorting={sorting} setSorting={setSorting as React.Dispatch<React.SetStateAction<{ id: string; desc: boolean; }>>} columnVisibility={columnVisibility} setColumnVisibility={setColumnVisibility} columnOrder={columnOrder} setColumnOrder={setColumnOrder} pinnedColumns={pinnedColumns} setPinnedColumns={setPinnedColumns} onRowClick={handleRowClick} />
                </div>
            )}
            <SimplePrintOptionsDialog open={printDialogOpen} onOpenChange={setPrintDialogOpen} selectedCount={itemsToPrint.length} onConfirm={handlePrintConfirm} title="In phiếu trả hàng" />
            <SalesReturnExportDialog open={exportDialogOpen} onOpenChange={setExportDialogOpen} allData={activeReturns} filteredData={sortedData} currentPageData={paginatedData} selectedData={allSelectedRows} currentUser={{ name: currentUser?.fullName || 'Hệ thống', systemId: currentUser?.systemId || asSystemId('SYSTEM') }} />
        </div>
    );
}

'use client'

import * as React from 'react';
import { useDepartments, useDepartmentMutations } from '../hooks/use-departments';
import { DepartmentForm, type DepartmentFormValues } from '../department-form';
import { JobTitlesPageContent } from '../../job-titles/page-content';
import { Button } from '../../../../components/ui/button';
import { ScrollArea } from '../../../../components/ui/scroll-area';
import { 
  Dialog, 
  DialogContent, 
  DialogDescription, 
  DialogFooter, 
  DialogHeader, 
  DialogTitle 
} from '../../../../components/ui/dialog';
import type { Department } from '@/lib/types/prisma-extended';
import { toast } from 'sonner';

// ==========================================
// ManageDepartmentsDialog Component
// ==========================================
export const ManageDepartmentsDialog = React.memo(function ManageDepartmentsDialog({ 
  isOpen, 
  onOpenChange 
}: { 
  isOpen: boolean; 
  onOpenChange: (open: boolean) => void; 
}) {
  const { data: departmentsData } = useDepartments({ limit: 1000 });
  const data = departmentsData?.data ?? [];
  const { create, update, remove } = useDepartmentMutations({
    onCreateSuccess: () => toast.success('Thêm mới thành công'),
    onUpdateSuccess: () => toast.success('Cập nhật thành công'),
    onDeleteSuccess: () => toast.success('Xóa thành công'),
    onError: (err) => toast.error(err.message)
  });
  const [editingDepartment, setEditingDepartment] = React.useState<Department | null>(null);

  const handleFormSubmit = (values: DepartmentFormValues) => {
    if (editingDepartment) {
      update.mutate({ systemId: editingDepartment.systemId, data: values });
    } else {
      create.mutate(values as Omit<Department, 'systemId'>);
    }
    setEditingDepartment(null);
  };

  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-2xl">
        <DialogHeader>
          <DialogTitle>Quản lý Phòng ban</DialogTitle>
        </DialogHeader>
        <div className="grid grid-cols-2 gap-6 pt-4">
          <div>
            <h4 className="font-semibold mb-2">{editingDepartment ? 'Chỉnh sửa' : 'Thêm mới'}</h4>
            <React.Fragment key={editingDepartment?.systemId || 'new'}>
              <DepartmentForm
                initialData={editingDepartment ? { ...editingDepartment, jobTitleIds: [] } : null}
                onSubmit={handleFormSubmit}
              />
            </React.Fragment>
            <DialogFooter className="mt-4">
              {editingDepartment && <Button variant="outline" onClick={() => setEditingDepartment(null)}>Hủy sửa</Button>}
              <Button type="submit" form="department-form">Lưu</Button>
            </DialogFooter>
          </div>
          <div>
            <h4 className="font-semibold mb-2">Danh sách phòng ban</h4>
            <ScrollArea className="h-72 border rounded-md">
              {data.map(dep => (
                <div key={dep.systemId} className="flex items-center p-2 border-b">
                  <span className="flex-grow">{dep.name}</span>
                  <Button variant="ghost" size="sm" onClick={() => setEditingDepartment(dep)}>Sửa</Button>
                  <Button variant="ghost" size="sm" className="text-destructive" onClick={() => (remove as any).mutate(dep.systemId)}>Xóa</Button>
                </div>
              ))}
            </ScrollArea>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
});

// ==========================================
// ManageJobTitlesDialog Component
// ==========================================
export const ManageJobTitlesDialog = React.memo(function ManageJobTitlesDialog({ 
  isOpen, 
  onOpenChange 
}: { 
  isOpen: boolean; 
  onOpenChange: (open: boolean) => void; 
}) {
  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-4xl">
        <DialogHeader>
          <DialogTitle>Quản lý Chức vụ</DialogTitle>
          <DialogDescription>Thêm, sửa, xóa các chức vụ trong công ty.</DialogDescription>
        </DialogHeader>
        <JobTitlesPageContent />
      </DialogContent>
    </Dialog>
  );
});

'use client'

import * as React from 'react';
import { useRouter, useParams } from 'next/navigation';
import { DepartmentForm, DepartmentFormValues } from './department-form';
import { useDepartment, useDepartmentMutations } from './hooks/use-departments';
import { useSettingsPageHeader } from '../use-settings-page-header';
import { Card, CardContent, CardHeader, CardTitle } from '../../../components/ui/card';
import { SettingsActionButton } from '../../../components/settings/SettingsActionButton';
import { ROUTES, generatePath } from '../../../lib/router';
import { toast } from 'sonner';

export function DepartmentFormPage() {
  const router = useRouter();
  const { id } = useParams<{ id: string }>();
  const { data: department } = useDepartment(id);
  const { create, update } = useDepartmentMutations({
    onCreateSuccess: () => {
      toast.success('Tạo mới thành công');
      router.push(backPath);
    },
    onUpdateSuccess: () => {
      toast.success('Cập nhật thành công');
      router.push(backPath);
    },
    onError: (err) => toast.error(err.message)
  });
  
  const isEditMode = !!id;

  const backPath = ROUTES.HRM.DEPARTMENTS;
  const headerActions = React.useMemo(() => [
    <SettingsActionButton
      key="cancel"
      variant="outline"
      onClick={() => router.push(backPath)}
    >
      Hủy
    </SettingsActionButton>,
    <SettingsActionButton
      key="save"
      type="submit"
      form="department-form"
    >
      {isEditMode ? 'Cập nhật' : 'Tạo mới'}
    </SettingsActionButton>,
  ], [backPath, router, isEditMode]);

  useSettingsPageHeader({
    title: isEditMode ? `Chỉnh sửa phòng ban${department?.name ? ` • ${department.name}` : ''}` : 'Thêm phòng ban mới',
    breadcrumb: [
      { label: 'Phòng ban', href: ROUTES.HRM.DEPARTMENTS, isCurrent: false },
      {
        label: isEditMode ? 'Chỉnh sửa' : 'Thêm mới',
        href: isEditMode && id
          ? generatePath(ROUTES.HRM.DEPARTMENT_EDIT, { systemId: id })
          : ROUTES.HRM.DEPARTMENT_NEW,
        isCurrent: true,
      },
    ],
    showBackButton: true,
    backPath,
    actions: headerActions,
  });

  const handleSubmit = (values: DepartmentFormValues) => {
    if (isEditMode && department) {
      update.mutate({
        systemId: department.systemId,
        data: {
          id: values.id,
          name: values.name,
        }
      });
    } else {
      (create as any).mutate({
        id: values.id,
        name: values.name,
      });
    }
  };

  return (
    <div className="container mx-auto py-6 max-w-2xl">
      <Card>
        <CardHeader>
          <CardTitle>
            {isEditMode ? 'Chỉnh sửa phòng ban' : 'Thêm phòng ban mới'}
          </CardTitle>
        </CardHeader>
        <CardContent>
          <DepartmentForm
            initialData={department ?? null}
            onSubmit={handleSubmit}
          />
        </CardContent>
      </Card>
    </div>
  );
}

'use client'

import * as React from "react"
import { useAllDepartments } from "./hooks/use-all-departments"
import { useDepartmentMutations } from "./hooks/use-departments"
import { Card, CardContent } from "../../../components/ui/card"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "../../../components/ui/alert-dialog"
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "../../../components/ui/dialog"
import { DepartmentForm, type DepartmentFormValues } from "./department-form"
import type { Department } from '@/lib/types/prisma-extended'
import { Button } from "../../../components/ui/button"
import { PlusCircle, MoreHorizontal } from "lucide-react"
import { useFuseFilter } from "../../../hooks/use-fuse-search"
import { asBusinessId, type SystemId } from "@/lib/id-types"
import { Input } from "../../../components/ui/input"
import { SimpleSettingsTable } from "../../../components/settings/SimpleSettingsTable"
import type { ColumnDef } from "../../../components/data-table/types"
import { Skeleton } from "../../../components/ui/skeleton"
import { toast } from "sonner"
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "../../../components/ui/dropdown-menu"

export function DepartmentsSettingsContent() {
  // React Query hooks
  const { data: departments, isLoading } = useAllDepartments();
  const { create, update, remove } = useDepartmentMutations({
    onCreateSuccess: () => toast.success('Đã thêm phòng ban mới'),
    onUpdateSuccess: () => toast.success('Đã cập nhật phòng ban'),
    onDeleteSuccess: () => toast.success('Đã xóa phòng ban'),
    onError: (err) => toast.error(err.message || 'Có lỗi xảy ra'),
  });
  
  const [isAlertOpen, setIsAlertOpen] = React.useState(false)
  const [idToDelete, setIdToDelete] = React.useState<SystemId | null>(null)
  const [isFormOpen, setIsFormOpen] = React.useState(false)
  const [editingDepartment, setEditingDepartment] = React.useState<Department | null>(null)
  
  const [globalFilter, setGlobalFilter] = React.useState('');

  const handleDelete = React.useCallback((systemId: SystemId) => {
    setIdToDelete(systemId)
    setIsAlertOpen(true)
  }, [])

  const handleEdit = React.useCallback((department: Department) => {
    setEditingDepartment(department)
    setIsFormOpen(true)
  }, [])

  const columns: ColumnDef<Department>[] = React.useMemo(() => ([
    {
      id: "id",
      accessorKey: "id",
      header: "Mã",
      cell: ({ row }) => <span>{row.id}</span>,
      meta: { displayName: "Mã phòng ban" },
    },
    {
      id: "name",
      accessorKey: "name",
      header: "Tên phòng ban",
      cell: ({ row }) => <span>{row.name}</span>,
      meta: { displayName: "Tên phòng ban" },
    },
    {
      id: "description",
      accessorKey: "description",
      header: "Mô tả",
      cell: ({ row }) => <span className="text-muted-foreground">{(row as any).description || '-'}</span>,
      meta: { displayName: "Mô tả" },
    },
    {
      id: "actions",
      header: () => <div className="text-center">Sửa</div>,
      cell: ({ row }) => (
        <div className="flex items-center justify-center">
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="ghost" className="h-8 w-8 p-0">
                <span className="sr-only">Mở menu</span>
                <MoreHorizontal className="h-4 w-4" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
              <DropdownMenuItem onSelect={() => handleEdit(row)}>
                Sửa
              </DropdownMenuItem>
              <DropdownMenuItem
                className="text-destructive"
                onSelect={() => handleDelete(row.systemId)}
              >
                Xóa
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
      ),
      meta: {
        displayName: "Sửa",
        sticky: "right",
      },
      size: 90,
    },
  ] as any), [handleDelete, handleEdit]);
  
  const fuseOptions = React.useMemo(() => ({ keys: ["id", "name"] }), []);
  const searchedData = useFuseFilter(departments, globalFilter, fuseOptions);
  
  const confirmDelete = () => {
    if (idToDelete) {
      remove.mutate(idToDelete)
    }
    setIsAlertOpen(false)
    setIdToDelete(null)
  }

  const handleAddNew = () => {
    setEditingDepartment(null);
    setIsFormOpen(true);
  }

  const handleSubmit = (values: DepartmentFormValues) => {
    if (editingDepartment) {
      update.mutate({
        systemId: editingDepartment.systemId,
        data: {
          ...values,
          id: asBusinessId(values.id),
        }
      });
    } else {
      create.mutate({
        ...values,
        id: asBusinessId(values.id),
      } as Omit<Department, 'systemId'>);
    }
    setIsFormOpen(false);
    setEditingDepartment(null);
  };

  const handleCancel = () => {
    setIsFormOpen(false);
    setEditingDepartment(null);
  };
  
  const filteredData = React.useMemo(() => globalFilter ? searchedData : departments, [departments, globalFilter, searchedData]);
  
  const sortedData = React.useMemo(() => {
    return [...filteredData].sort((a, b) => a.name.localeCompare(b.name));
  }, [filteredData]);

  // Loading state
  if (isLoading) {
    return (
      <div className="space-y-4">
        <div className="flex justify-between">
          <Skeleton className="h-10 w-64" />
          <Skeleton className="h-10 w-32" />
        </div>
        <Card>
          <CardContent className="p-4 space-y-3">
            <Skeleton className="h-10 w-full" />
            <Skeleton className="h-10 w-full" />
            <Skeleton className="h-10 w-full" />
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <Input
          value={globalFilter}
          onChange={(event) => setGlobalFilter(event.target.value)}
          placeholder="Tìm kiếm phòng ban..."
          className="sm:max-w-sm"
        />
        <Button onClick={handleAddNew} size="sm">
          <PlusCircle className="mr-2 h-4 w-4" />
          Thêm phòng ban
        </Button>
      </div>

      <Card>
        <CardContent className="p-0">
          <SimpleSettingsTable
            data={sortedData}
            columns={columns}
            emptyTitle="Chưa có phòng ban"
            emptyDescription="Tạo phòng ban đầu tiên để quản lý nhân sự"
            emptyAction={
              <Button size="sm" onClick={handleAddNew}>
                Thêm phòng ban
              </Button>
            }
          />
        </CardContent>
      </Card>
      
      <AlertDialog open={isAlertOpen} onOpenChange={setIsAlertOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Bạn có chắc chắn muốn xóa?</AlertDialogTitle>
            <AlertDialogDescription>Hành động này không thể được hoàn tác. Dữ liệu phòng ban sẽ bị xóa vĩnh viễn.</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Hủy</AlertDialogCancel>
            <AlertDialogAction onClick={confirmDelete} disabled={remove.isPending}>
              {remove.isPending ? 'Đang xóa...' : 'Tiếp tục'}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
      
      <Dialog open={isFormOpen} onOpenChange={setIsFormOpen}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>{editingDepartment ? 'Chỉnh sửa phòng ban' : 'Thêm phòng ban mới'}</DialogTitle>
              <DialogDescription>{editingDepartment ? 'Cập nhật thông tin cho phòng ban.' : 'Điền thông tin để tạo mới.'}</DialogDescription>
            </DialogHeader>
            <DepartmentForm 
              initialData={editingDepartment} 
              onSubmit={handleSubmit} 
            />
            <DialogFooter>
              <Button variant="outline" onClick={handleCancel}>Hủy</Button>
              <Button type="submit" form="department-form">
                {editingDepartment ? 'Cập nhật' : 'Thêm mới'}
              </Button>
            </DialogFooter>
          </DialogContent>
      </Dialog>
    </div>
  )
}

'use client'

import * as React from 'react';
import { useSettingsPageHeader } from '../use-settings-page-header';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../../../components/ui/card';
import { Button } from '../../../components/ui/button';
import { Input } from '../../../components/ui/input';
import { Label } from '../../../components/ui/label';
import { Badge } from '../../../components/ui/badge';
import { Checkbox } from '../../../components/ui/checkbox';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from '../../../components/ui/dialog';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from '../../../components/ui/alert-dialog';
import { Separator } from '../../../components/ui/separator';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '../../../components/ui/select';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '../../../components/ui/table';
import { TabsContent } from '../../../components/ui/tabs';
import { SettingsVerticalTabs } from '../../../components/settings/SettingsVerticalTabs';
import { SettingsActionButton } from '../../../components/settings/SettingsActionButton';
import { toast } from 'sonner';
import { Shield, Plus, Edit, Trash2, Save, RotateCcw, Copy, Users, Search, UserCog, Key, RefreshCw, Eye, EyeOff, Clipboard, MoreHorizontal, Loader2 } from 'lucide-react';
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from '../../../components/ui/dropdown-menu';
import { PERMISSION_GROUPS, PERMISSION_LABELS, type Permission } from '../../employees/permissions';
import { useRoleSettings, useRoleMutations, type CustomRole } from './hooks/use-role-settings';
import { useAllEmployees } from '../../employees/hooks/use-all-employees';
import { useEmployeeMutations } from '../../employees/hooks/use-employees';
import type { Employee } from '@/lib/types/prisma-extended';

export function EmployeeRolesPage() {
  const { data: roles = [] } = useRoleSettings();
  const { addRole, updateRole, deleteRole, resetRole } = useRoleMutations();
  const { data: employees, isLoading: isLoadingEmployees } = useAllEmployees();
  const { update: updateEmployeeMutation } = useEmployeeMutations();
  
  const [activeTab, setActiveTab] = React.useState('roles');
  const [selectedRole, setSelectedRole] = React.useState<CustomRole | null>(null);
  const [editingPermissions, setEditingPermissions] = React.useState<Permission[]>([]);
  const [showPermissionsDialog, setShowPermissionsDialog] = React.useState(false);
  const [showAddDialog, setShowAddDialog] = React.useState(false);
  const [showEditDialog, setShowEditDialog] = React.useState(false);
  const [showDeleteDialog, setShowDeleteDialog] = React.useState(false);
  const [roleToDelete, setRoleToDelete] = React.useState<CustomRole | null>(null);
  const [roleForm, setRoleForm] = React.useState({ name: '', description: '' });
  
  // Tab 2: Gán vai trò
  const [searchTerm, setSearchTerm] = React.useState('');
  const [roleFilter, setRoleFilter] = React.useState<string>('all');
  
  // Password management
  const [showPasswordDialog, setShowPasswordDialog] = React.useState(false);
  const [showResetDialog, setShowResetDialog] = React.useState(false);
  const [selectedEmployee, setSelectedEmployee] = React.useState<Employee | null>(null);
  const [newPassword, setNewPassword] = React.useState('');
  const [confirmPassword, setConfirmPassword] = React.useState('');
  const [showPassword, setShowPassword] = React.useState(false);
  const [generatedPassword, setGeneratedPassword] = React.useState('');

  const tabs = React.useMemo(() => [
    { value: 'roles', label: 'Danh sách vai trò' },
    { value: 'assign', label: 'Gán vai trò' },
  ], []);

  // Page header actions
  const headerActions = React.useMemo(() => {
    if (activeTab === 'roles') {
      return [
        <SettingsActionButton
          key="add"
          onClick={() => {
            setRoleForm({ name: '', description: '' });
            setShowAddDialog(true);
          }}
        >
          <Plus className="mr-2 h-4 w-4" />
          Thêm vai trò
        </SettingsActionButton>
      ];
    }
    return [];
  }, [activeTab]);

  useSettingsPageHeader({
    title: 'Phân quyền & Tài khoản',
    subtitle: 'Quản lý vai trò và gán quyền cho nhân viên',
    actions: headerActions,
    breadcrumb: [
      { label: 'Trang chủ', href: '/', isCurrent: false },
      { label: 'Cài đặt', href: '/settings', isCurrent: false },
      { label: 'Phân quyền & Tài khoản', href: '', isCurrent: true }
    ]
  });

  // Filter employees for Tab 2
  const filteredEmployees = React.useMemo(() => {
    return employees.filter(emp => {
      const matchSearch = !searchTerm || 
        emp.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        emp.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
        emp.workEmail?.toLowerCase().includes(searchTerm.toLowerCase());
      
      const matchRole = roleFilter === 'all' || emp.role === roleFilter;
      
      return matchSearch && matchRole;
    });
  }, [employees, searchTerm, roleFilter]);

  // Count employees by role
  const employeeCountByRole = React.useMemo(() => {
    const counts: Record<string, number> = {};
    employees.forEach(emp => {
      counts[emp.role] = (counts[emp.role] || 0) + 1;
    });
    return counts;
  }, [employees]);

  const handleEditRole = (role: CustomRole) => {
    setSelectedRole(role);
    setEditingPermissions([...role.permissions]);
    setShowPermissionsDialog(true);
  };

  const handleEditRoleInfo = (role: CustomRole) => {
    setSelectedRole(role);
    setRoleForm({ name: role.name, description: role.description });
    setShowEditDialog(true);
  };

  const handleDuplicateRole = (role: CustomRole) => {
    addRole(`${role.name} (Copy)`, role.description);
    toast.success(`Đã sao chép vai trò "${role.name}"`);
  };

  const handleDeleteClick = (role: CustomRole) => {
    // Check if any employee is using this role
    const count = employeeCountByRole[role.id] || 0;
    if (count > 0) {
      toast.error(`Không thể xóa vai trò đang được sử dụng bởi ${count} nhân viên`);
      return;
    }
    setRoleToDelete(role);
    setShowDeleteDialog(true);
  };

  const handleConfirmDelete = () => {
    if (roleToDelete) {
      deleteRole(roleToDelete.id);
      setShowDeleteDialog(false);
      setRoleToDelete(null);
      toast.success('Đã xóa vai trò');
    }
  };

  const handleAddRole = () => {
    if (!roleForm.name.trim()) {
      toast.error('Vui lòng nhập tên vai trò');
      return;
    }
    addRole(roleForm.name.trim(), roleForm.description.trim());
    setShowAddDialog(false);
    setRoleForm({ name: '', description: '' });
    toast.success('Đã thêm vai trò mới');
  };

  const handleUpdateRoleInfo = () => {
    if (!selectedRole || !roleForm.name.trim()) {
      toast.error('Vui lòng nhập tên vai trò');
      return;
    }
    updateRole(selectedRole.id, {
      name: roleForm.name.trim(),
      description: roleForm.description.trim(),
    });
    setShowEditDialog(false);
    setSelectedRole(null);
    toast.success('Đã cập nhật thông tin vai trò');
  };

  const handleTogglePermission = (permission: Permission) => {
    setEditingPermissions(prev => {
      if (prev.includes(permission)) {
        return prev.filter(p => p !== permission);
      } else {
        return [...prev, permission];
      }
    });
  };

  const handleToggleGroup = (groupPermissions: Permission[]) => {
    const allSelected = groupPermissions.every(p => editingPermissions.includes(p));
    
    if (allSelected) {
      setEditingPermissions(prev => prev.filter(p => !groupPermissions.includes(p)));
    } else {
      setEditingPermissions(prev => {
        const newPerms = new Set([...prev, ...groupPermissions]);
        return Array.from(newPerms);
      });
    }
  };

  const handleSavePermissions = () => {
    if (!selectedRole) return;
    updateRole(selectedRole.id, { permissions: editingPermissions });
    setShowPermissionsDialog(false);
    setSelectedRole(null);
    toast.success('Đã lưu cấu hình phân quyền');
  };

  const handleResetRole = (roleId: string) => {
    resetRole(roleId);
    toast.success('Đã khôi phục quyền mặc định');
  };

  const handleChangeEmployeeRole = (employee: Employee, newRole: string) => {
    (updateEmployeeMutation as any).mutate(
      { systemId: employee.systemId, role: newRole },
      {
        onSuccess: () => toast.success(`Đã cập nhật vai trò cho ${employee.fullName}`),
        onError: () => toast.error(`Không thể cập nhật vai trò cho ${employee.fullName}`),
      }
    );
  };

  // Password management handlers
  const generatePassword = (length: number = 12): string => {
    const uppercase = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ';
    const lowercase = 'abcdefghijklmnopqrstuvwxyz';
    const numbers = '0123456789';
    const special = '!@#$%^&*';
    const all = uppercase + lowercase + numbers + special;
    
    let password = '';
    password += uppercase[Math.floor(Math.random() * uppercase.length)];
    password += lowercase[Math.floor(Math.random() * lowercase.length)];
    password += numbers[Math.floor(Math.random() * numbers.length)];
    password += special[Math.floor(Math.random() * special.length)];
    
    for (let i = 4; i < length; i++) {
      password += all[Math.floor(Math.random() * all.length)];
    }
    
    return password.split('').sort(() => Math.random() - 0.5).join('');
  };

  const handleOpenPasswordDialog = (employee: Employee) => {
    setSelectedEmployee(employee);
    setNewPassword('');
    setConfirmPassword('');
    setShowPassword(false);
    setShowPasswordDialog(true);
  };

  const handleOpenResetDialog = (employee: Employee) => {
    setSelectedEmployee(employee);
    const pwd = generatePassword(12);
    setGeneratedPassword(pwd);
    setShowResetDialog(true);
  };

  const handleSavePassword = () => {
    if (!selectedEmployee) return;
    
    if (!newPassword) {
      toast.error('Vui lòng nhập mật khẩu');
      return;
    }
    if (newPassword.length < 6) {
      toast.error('Mật khẩu phải có ít nhất 6 ký tự');
      return;
    }
    if (newPassword !== confirmPassword) {
      toast.error('Mật khẩu xác nhận không khớp');
      return;
    }
    
    // Note: Password updates should go through a separate secure endpoint
    // This is just a placeholder - actual implementation needs backend support
    toast.info('Chức năng đặt mật khẩu cần được cập nhật để sử dụng API bảo mật');
    setShowPasswordDialog(false);
    setSelectedEmployee(null);
  };

  const handleConfirmReset = () => {
    if (!selectedEmployee) return;
    
    // Note: Password reset should go through a separate secure endpoint
    toast.info('Chức năng reset mật khẩu cần được cập nhật để sử dụng API bảo mật');
    setShowResetDialog(false);
    setSelectedEmployee(null);
  };

  const handleCopyPassword = async (password: string) => {
    try {
      await navigator.clipboard.writeText(password);
      toast.success('Đã sao chép mật khẩu');
    } catch {
      toast.error('Không thể sao chép');
    }
  };

  const handleGeneratePassword = () => {
    const pwd = generatePassword(12);
    setNewPassword(pwd);
    setConfirmPassword(pwd);
    setShowPassword(true);
  };

  const getRoleBadgeVariant = (roleId: string) => {
    switch (roleId) {
      case 'Admin': return 'destructive' as const;
      case 'Manager': return 'default' as const;
      case 'Sales': return 'secondary' as const;
      case 'Warehouse': return 'outline' as const;
      default: return 'secondary' as const;
    }
  };

  return (
    <>
      <SettingsVerticalTabs value={activeTab} onValueChange={setActiveTab} tabs={tabs}>
        {/* Tab 1: Danh sách vai trò */}
        <TabsContent value="roles" className="mt-0">
          <Card>
            <CardHeader>
              <CardTitle>Danh sách vai trò</CardTitle>
              <CardDescription>Quản lý các vai trò và quyền hạn trong hệ thống</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="border rounded-md">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead className="w-[200px]">Tên vai trò</TableHead>
                      <TableHead className="w-[250px]">Mô tả</TableHead>
                      <TableHead className="w-[100px] text-center">Số quyền</TableHead>
                      <TableHead className="w-[120px] text-center">Nhân viên</TableHead>
                      <TableHead className="w-[100px] text-center">Loại</TableHead>
                      <TableHead className="w-[180px] text-right">Thao tác</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {roles.map((role) => (
                      <TableRow key={role.id}>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            <Shield className="h-4 w-4 text-muted-foreground" />
                            <span className="font-medium">{role.name}</span>
                          </div>
                        </TableCell>
                        <TableCell className="text-muted-foreground">
                          {role.description}
                        </TableCell>
                        <TableCell className="text-center">
                          <Badge variant="outline">{role.permissions.length}</Badge>
                        </TableCell>
                        <TableCell className="text-center">
                          <Badge variant="secondary">
                            <Users className="h-3 w-3 mr-1" />
                            {employeeCountByRole[role.id] || 0}
                          </Badge>
                        </TableCell>
                        <TableCell className="text-center">
                          {role.isDefault ? (
                            <Badge variant="outline" className="text-xs">Mặc định</Badge>
                          ) : (
                            <Badge variant="secondary" className="text-xs">Tùy chỉnh</Badge>
                          )}
                        </TableCell>
                        <TableCell className="text-right">
                          <div className="flex items-center justify-end gap-1">
                            <Button
                              variant="ghost"
                              size="icon"
                              className="h-8 w-8"
                              onClick={() => handleEditRoleInfo(role)}
                              title="Sửa thông tin"
                            >
                              <Edit className="h-4 w-4" />
                            </Button>
                            <Button
                              variant="ghost"
                              size="icon"
                              className="h-8 w-8"
                              onClick={() => handleDuplicateRole(role)}
                              title="Sao chép"
                            >
                              <Copy className="h-4 w-4" />
                            </Button>
                            <Button
                              variant="ghost"
                              size="icon"
                              className="h-8 w-8 text-primary"
                              onClick={() => handleEditRole(role)}
                              title="Phân quyền"
                            >
                              <Shield className="h-4 w-4" />
                            </Button>
                            {role.isDefault ? (
                              <Button
                                variant="ghost"
                                size="icon"
                                className="h-8 w-8 text-muted-foreground hover:text-foreground"
                                onClick={() => handleResetRole(role.id)}
                                title="Khôi phục mặc định"
                              >
                                <RotateCcw className="h-4 w-4" />
                              </Button>
                            ) : (
                              <Button
                                variant="ghost"
                                size="icon"
                                className="h-8 w-8 text-muted-foreground hover:text-destructive"
                                onClick={() => handleDeleteClick(role)}
                                title="Xóa vai trò"
                              >
                                <Trash2 className="h-4 w-4" />
                              </Button>
                            )}
                          </div>
                        </TableCell>
                      </TableRow>
                    ))}
                    {roles.length === 0 && (
                      <TableRow>
                        <TableCell colSpan={6} className="text-center text-muted-foreground py-8">
                          Chưa có vai trò nào. Thêm vai trò mới để bắt đầu.
                        </TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>
              </div>
            </CardContent>
          </Card>

          {/* Info Card */}
          <Card className="bg-muted/50 mt-6">
            <CardContent className="pt-6">
              <div className="space-y-2">
                <p className="text-sm font-medium">
                  Hướng dẫn phân quyền:
                </p>
                <ul className="text-sm text-muted-foreground space-y-1 list-disc list-inside">
                  <li><strong>Thêm vai trò mới:</strong> Click nút "Thêm vai trò" ở góc trên</li>
                  <li><strong>Chỉnh sửa thông tin:</strong> Click icon bút chì để sửa tên và mô tả</li>
                  <li><strong>Phân quyền:</strong> Click icon khiên để cấu hình quyền truy cập</li>
                  <li><strong>Khôi phục:</strong> Vai trò mặc định có thể reset về quyền ban đầu</li>
                  <li><strong>Xóa vai trò:</strong> Chỉ xóa được vai trò tùy chỉnh không có nhân viên nào</li>
                </ul>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        {/* Tab 2: Gán vai trò */}
        <TabsContent value="assign" className="mt-0">
          <Card>
            <CardHeader>
              <CardTitle>Gán vai trò cho nhân viên</CardTitle>
              <CardDescription>Quản lý vai trò của từng nhân viên trong hệ thống</CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              {/* Filters */}
              <div className="flex flex-col sm:flex-row gap-4">
                <div className="relative flex-1">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                  <Input
                    placeholder="Tìm kiếm theo tên, mã NV, email..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-9"
                  />
                </div>
                <Select value={roleFilter} onValueChange={setRoleFilter}>
                  <SelectTrigger className="w-full sm:w-[200px]">
                    <SelectValue placeholder="Lọc theo vai trò" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">Tất cả vai trò</SelectItem>
                    {roles.map((role) => (
                      <SelectItem key={role.id} value={role.id}>
                        {role.name} ({employeeCountByRole[role.id] || 0})
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              {/* Employee Table */}
              <div className="border rounded-md">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead className="w-[80px]">Mã NV</TableHead>
                      <TableHead>Họ và tên</TableHead>
                      <TableHead className="w-[200px]">Email</TableHead>
                      <TableHead className="w-[150px]">Phòng ban</TableHead>
                      <TableHead className="w-[180px]">Vai trò</TableHead>
                      <TableHead className="w-[100px] text-right">Thao tác</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {isLoadingEmployees && (
                      <TableRow>
                        <TableCell colSpan={6} className="text-center py-8">
                          <div className="flex items-center justify-center gap-2">
                            <Loader2 className="h-4 w-4 animate-spin" />
                            <span>Đang tải danh sách nhân viên...</span>
                          </div>
                        </TableCell>
                      </TableRow>
                    )}
                    {!isLoadingEmployees && filteredEmployees.map((employee) => (
                      <TableRow key={employee.systemId}>
                        <TableCell className="font-medium">{employee.id}</TableCell>
                        <TableCell>
                          <div className="flex items-center gap-2">
                            <UserCog className="h-4 w-4 text-muted-foreground" />
                            {employee.fullName}
                          </div>
                        </TableCell>
                        <TableCell className="text-muted-foreground">
                          {employee.workEmail || '—'}
                        </TableCell>
                        <TableCell className="text-muted-foreground">
                          {employee.departmentId || '—'}
                        </TableCell>
                        <TableCell>
                          <Select
                            value={employee.role || 'Sales'}
                            onValueChange={(value) => handleChangeEmployeeRole(employee, value)}
                          >
                            <SelectTrigger className="h-8">
                              <SelectValue>
                                <Badge variant={getRoleBadgeVariant(employee.role || 'Sales')}>
                                  {roles.find(r => r.id === employee.role)?.name || employee.role || 'Kinh doanh'}
                                </Badge>
                              </SelectValue>
                            </SelectTrigger>
                            <SelectContent>
                              {roles.map((role) => (
                                <SelectItem key={role.id} value={role.id}>
                                  <div className="flex items-center gap-2">
                                    <Badge variant={getRoleBadgeVariant(role.id)} className="text-xs">
                                      {role.name}
                                    </Badge>
                                    <span className="text-xs text-muted-foreground">
                                      {role.description}
                                    </span>
                                  </div>
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </TableCell>
                        <TableCell className="text-right">
                          <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                              <Button variant="ghost" size="icon" className="h-8 w-8">
                                <MoreHorizontal className="h-4 w-4" />
                              </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end">
                              <DropdownMenuItem onClick={() => handleOpenPasswordDialog(employee)}>
                                <Key className="h-4 w-4 mr-2" />
                                Đặt mật khẩu
                              </DropdownMenuItem>
                              <DropdownMenuItem onClick={() => handleOpenResetDialog(employee)}>
                                <RefreshCw className="h-4 w-4 mr-2" />
                                Reset mật khẩu
                              </DropdownMenuItem>
                            </DropdownMenuContent>
                          </DropdownMenu>
                        </TableCell>
                      </TableRow>
                    ))}
                    {!isLoadingEmployees && filteredEmployees.length === 0 && (
                      <TableRow>
                        <TableCell colSpan={6} className="text-center text-muted-foreground py-8">
                          {searchTerm || roleFilter !== 'all' 
                            ? 'Không tìm thấy nhân viên phù hợp'
                            : 'Chưa có nhân viên nào trong hệ thống'}
                        </TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>
              </div>

              {/* Summary */}
              <div className="flex flex-wrap gap-2 pt-2">
                {roles.map((role) => (
                  <Badge key={role.id} variant="outline" className="text-xs">
                    {role.name}: {employeeCountByRole[role.id] || 0} nhân viên
                  </Badge>
                ))}
              </div>
            </CardContent>
          </Card>
        </TabsContent>
      </SettingsVerticalTabs>

      {/* Add Role Dialog */}
      <Dialog open={showAddDialog} onOpenChange={setShowAddDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Plus className="h-5 w-5" />
              Thêm vai trò mới
            </DialogTitle>
            <DialogDescription>
              Tạo vai trò mới và cấu hình quyền truy cập
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="role-name">Tên vai trò</Label>
              <Input
                id="role-name"
                placeholder="Nhập tên vai trò..."
                value={roleForm.name}
                onChange={(e) => setRoleForm(prev => ({ ...prev, name: e.target.value }))}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="role-desc">Mô tả</Label>
              <Input
                id="role-desc"
                placeholder="Nhập mô tả vai trò..."
                value={roleForm.description}
                onChange={(e) => setRoleForm(prev => ({ ...prev, description: e.target.value }))}
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowAddDialog(false)}>
              Hủy
            </Button>
            <Button onClick={handleAddRole}>
              <Plus className="h-4 w-4 mr-2" />
              Thêm
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Edit Role Info Dialog */}
      <Dialog open={showEditDialog} onOpenChange={setShowEditDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Edit className="h-5 w-5" />
              Chỉnh sửa vai trò
            </DialogTitle>
            <DialogDescription>
              Cập nhật thông tin vai trò
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="edit-role-name">Tên vai trò</Label>
              <Input
                id="edit-role-name"
                placeholder="Nhập tên vai trò..."
                value={roleForm.name}
                onChange={(e) => setRoleForm(prev => ({ ...prev, name: e.target.value }))}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="edit-role-desc">Mô tả</Label>
              <Input
                id="edit-role-desc"
                placeholder="Nhập mô tả vai trò..."
                value={roleForm.description}
                onChange={(e) => setRoleForm(prev => ({ ...prev, description: e.target.value }))}
              />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowEditDialog(false)}>
              Hủy
            </Button>
            <Button onClick={handleUpdateRoleInfo}>
              <Save className="h-4 w-4 mr-2" />
              Lưu
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Confirmation Dialog */}
      <AlertDialog open={showDeleteDialog} onOpenChange={setShowDeleteDialog}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Xác nhận xóa vai trò</AlertDialogTitle>
            <AlertDialogDescription>
              Bạn có chắc muốn xóa vai trò "{roleToDelete?.name}"? Hành động này không thể hoàn tác.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Hủy</AlertDialogCancel>
            <AlertDialogAction onClick={handleConfirmDelete} className="bg-red-600 hover:bg-red-700">
              Xóa
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Permissions Dialog */}
      <Dialog open={showPermissionsDialog} onOpenChange={setShowPermissionsDialog}>
        <DialogContent className="max-w-3xl max-h-[80vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Shield className="h-5 w-5" />
              Phân quyền cho {selectedRole?.name}
            </DialogTitle>
            <DialogDescription>
              Chọn các quyền mà vai trò này được phép thực hiện
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-6 py-4">
            {Object.entries(PERMISSION_GROUPS).map(([groupKey, group]) => {
              const groupPerms = group.permissions;
              const selectedCount = groupPerms.filter(p => editingPermissions.includes(p)).length;
              const allSelected = selectedCount === groupPerms.length;

              return (
                <div key={groupKey} className="space-y-3">
                  <div className="flex items-center gap-2">
                    <Checkbox
                      checked={allSelected}
                      onCheckedChange={() => handleToggleGroup(groupPerms)}
                    />
                    <Label className="text-base font-semibold cursor-pointer" onClick={() => handleToggleGroup(groupPerms)}>
                      {group.label} ({selectedCount}/{groupPerms.length})
                    </Label>
                  </div>
                  <div className="ml-6 grid grid-cols-2 gap-3">
                    {groupPerms.map((permission) => (
                      <div key={permission} className="flex items-center gap-2">
                        <Checkbox
                          id={permission}
                          checked={editingPermissions.includes(permission)}
                          onCheckedChange={() => handleTogglePermission(permission)}
                        />
                        <Label
                          htmlFor={permission}
                          className="text-sm cursor-pointer"
                        >
                          {PERMISSION_LABELS[permission]}
                        </Label>
                      </div>
                    ))}
                  </div>
                  <Separator />
                </div>
              );
            })}
          </div>

          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => {
                setShowPermissionsDialog(false);
                setSelectedRole(null);
              }}
            >
              Hủy
            </Button>
            <Button onClick={handleSavePermissions}>
              <Save className="h-4 w-4 mr-2" />
              Lưu thay đổi
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Set Password Dialog */}
      <Dialog open={showPasswordDialog} onOpenChange={setShowPasswordDialog}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Key className="h-5 w-5" />
              Đặt mật khẩu
            </DialogTitle>
            <DialogDescription>
              Đặt mật khẩu đăng nhập cho {selectedEmployee?.fullName}
            </DialogDescription>
          </DialogHeader>
          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="new-password">Mật khẩu mới</Label>
              <div className="relative">
                <Input
                  id="new-password"
                  type={showPassword ? 'text' : 'password'}
                  placeholder="Nhập mật khẩu mới..."
                  value={newPassword}
                  onChange={(e) => setNewPassword(e.target.value)}
                  className="pr-20"
                />
                <div className="absolute right-1 top-1/2 -translate-y-1/2 flex gap-1">
                  <Button
                    type="button"
                    variant="ghost"
                    size="icon"
                    className="h-7 w-7"
                    onClick={() => handleCopyPassword(newPassword)}
                    disabled={!newPassword}
                    title="Sao chép"
                  >
                    <Clipboard className="h-4 w-4" />
                  </Button>
                  <Button
                    type="button"
                    variant="ghost"
                    size="icon"
                    className="h-7 w-7"
                    onClick={() => setShowPassword(!showPassword)}
                    title={showPassword ? 'Ẩn mật khẩu' : 'Hiện mật khẩu'}
                  >
                    {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                  </Button>
                </div>
              </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="confirm-password">Xác nhận mật khẩu</Label>
              <Input
                id="confirm-password"
                type={showPassword ? 'text' : 'password'}
                placeholder="Nhập lại mật khẩu..."
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
              />
            </div>
            <Button
              type="button"
              variant="outline"
              size="sm"
              onClick={handleGeneratePassword}
              className="w-full"
            >
              <RefreshCw className="h-4 w-4 mr-2" />
              Tạo mật khẩu ngẫu nhiên
            </Button>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowPasswordDialog(false)}>
              Hủy
            </Button>
            <Button onClick={handleSavePassword}>
              <Save className="h-4 w-4 mr-2" />
              Lưu
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Reset Password Dialog */}
      <AlertDialog open={showResetDialog} onOpenChange={setShowResetDialog}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle className="flex items-center gap-2">
              <RefreshCw className="h-5 w-5" />
              Reset mật khẩu
            </AlertDialogTitle>
            <AlertDialogDescription className="space-y-3">
              <span>Bạn có chắc muốn reset mật khẩu cho <strong>{selectedEmployee?.fullName}</strong>?</span>
              <div className="bg-muted p-3 rounded-md space-y-2">
                <p className="text-sm font-medium text-foreground">Mật khẩu mới:</p>
                <div className="flex items-center gap-2">
                  <code className="flex-1 bg-background px-3 py-2 rounded border text-sm font-mono">
                    {generatedPassword}
                  </code>
                  <Button
                    variant="outline"
                    size="icon"
                    className="h-8 w-8"
                    onClick={() => setGeneratedPassword(generatePassword(12))}
                    title="Tạo mật khẩu khác"
                  >
                    <RefreshCw className="h-4 w-4" />
                  </Button>
                  <Button
                    variant="outline"
                    size="icon"
                    className="h-8 w-8"
                    onClick={() => handleCopyPassword(generatedPassword)}
                    title="Sao chép"
                  >
                    <Clipboard className="h-4 w-4" />
                  </Button>
                </div>
                <p className="text-xs text-muted-foreground">
                  Hãy sao chép và gửi mật khẩu này cho nhân viên
                </p>
              </div>
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Hủy</AlertDialogCancel>
            <AlertDialogAction onClick={handleConfirmReset}>
              <RefreshCw className="h-4 w-4 mr-2" />
              Xác nhận reset
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  );
}

'use client'

import * as React from "react";
import { Plus } from "lucide-react";
import { asBusinessId, type SystemId } from "@/lib/id-types";
import { toast } from "sonner";

import { useImporters, useImporterMutations } from "../hooks/use-inventory-settings";
import { ImporterFormDialog, type ImporterFormValues } from "../importer-form-dialog";
import { getImporterColumns } from "../importer-columns";
import type { Importer } from "../types";
import type { RegisterTabActions } from "../../use-tab-action-registry";

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "@/components/ui/alert-dialog";
import { SimpleSettingsTable } from "@/components/settings/SimpleSettingsTable";
import { SettingsActionButton } from "@/components/settings/SettingsActionButton";

type TabContentProps = { isActive: boolean; onRegisterActions: RegisterTabActions };

export function ImportersTabContent({ isActive, onRegisterActions }: TabContentProps) {
  const { data: importersData } = useImporters();
  const data = React.useMemo(() => importersData ?? [], [importersData]);
  const { create, update, remove } = useImporterMutations();
  const [dialogOpen, setDialogOpen] = React.useState(false);
  const [editingItem, setEditingItem] = React.useState<Importer | null>(null);
  const [isAlertOpen, setIsAlertOpen] = React.useState(false);
  const [idToDelete, setIdToDelete] = React.useState<SystemId | null>(null);

  const activeImporters = React.useMemo(() => data.filter(b => !b.isDeleted), [data]);
  const existingIds = React.useMemo(() => activeImporters.map(b => b.id), [activeImporters]);

  const handleAdd = React.useCallback(() => { setEditingItem(null); setDialogOpen(true); }, []);
  const handleEdit = React.useCallback((item: Importer) => { setEditingItem(item); setDialogOpen(true); }, []);
  const handleDeleteRequest = React.useCallback((systemId: SystemId) => { setIdToDelete(systemId); setIsAlertOpen(true); }, []);
  const handleToggleActive = React.useCallback((item: Importer) => { const na = !item.isActive; update.mutate({ systemId: item.systemId, data: { isActive: na } }, { onSuccess: () => toast.success(na ? 'Đã kích hoạt' : 'Đã tắt'), onError: (err) => toast.error(err.message) }); }, [update]);
  const handleToggleDefault = React.useCallback((item: Importer) => { if (!item.isDefault) { update.mutate({ systemId: item.systemId, data: { isDefault: true } }, { onSuccess: () => toast.success('Đã đặt làm mặc định'), onError: (err) => toast.error(err.message) }); } }, [update]);
  const confirmDelete = () => { if (idToDelete) { remove.mutate(idToDelete, { onSuccess: () => toast.success('Đã xóa đơn vị nhập khẩu'), onError: (err) => toast.error(err.message) }); } setIsAlertOpen(false); setIdToDelete(null); };

  const handleSubmit = (values: ImporterFormValues) => {
    const payload = { ...values, id: asBusinessId(values.id) };
    if (editingItem) { update.mutate({ systemId: editingItem.systemId, data: payload }, { onSuccess: () => toast.success('Đã cập nhật đơn vị nhập khẩu'), onError: (err) => toast.error(err.message) }); }
    else { create.mutate(payload, { onSuccess: () => toast.success('Đã thêm đơn vị nhập khẩu mới'), onError: (err) => toast.error(err.message) }); }
    setDialogOpen(false);
  };

  const columns = React.useMemo(() => getImporterColumns({ onEdit: handleEdit, onDelete: handleDeleteRequest, onToggleActive: handleToggleActive, onToggleDefault: handleToggleDefault }), [handleDeleteRequest, handleEdit, handleToggleActive, handleToggleDefault]);

  React.useEffect(() => { if (!isActive) return; onRegisterActions([<SettingsActionButton key="add-importer" onClick={handleAdd}><Plus className="mr-2 h-4 w-4" /> Thêm đơn vị nhập khẩu</SettingsActionButton>]); }, [handleAdd, isActive, onRegisterActions]);

  return (
    <>
      <Card><CardHeader><div className="flex items-center justify-between"><div><CardTitle>Đơn vị nhập khẩu</CardTitle><CardDescription>Quản lý các đơn vị nhập khẩu để in tem phụ sản phẩm</CardDescription></div></div></CardHeader><CardContent><SimpleSettingsTable data={activeImporters as any} columns={columns as any} emptyTitle="Chưa có đơn vị nhập khẩu" emptyDescription="Thêm đơn vị nhập khẩu đầu tiên để in tem phụ sản phẩm" emptyAction={<Button size="sm" onClick={handleAdd}>Thêm đơn vị nhập khẩu</Button>} /></CardContent></Card>
      <ImporterFormDialog open={dialogOpen} onOpenChange={setDialogOpen} initialData={editingItem} onSubmit={handleSubmit} existingIds={existingIds} />
      <AlertDialog open={isAlertOpen} onOpenChange={setIsAlertOpen}><AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Bạn có chắc chắn muốn xóa?</AlertDialogTitle><AlertDialogDescription>Hành động này không thể được hoàn tác.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Hủy</AlertDialogCancel><AlertDialogAction onClick={confirmDelete}>Xóa</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
    </>
  );
}

'use client'

import * as React from "react";
import { Plus } from "lucide-react";
import { asBusinessId, type SystemId } from "@/lib/id-types";
import { toast } from "sonner";

import { useProductTypes, useProductTypeMutations } from "../hooks/use-product-types";
import { ProductTypeFormDialog, type ProductTypeFormValues } from "../setting-form-dialogs";
import { getProductTypeColumns } from "../product-type-columns";
import type { ProductType } from "../types";
import type { RegisterTabActions } from "../../use-tab-action-registry";

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "@/components/ui/alert-dialog";
import { SimpleSettingsTable } from "@/components/settings/SimpleSettingsTable";
import { SettingsActionButton } from "@/components/settings/SettingsActionButton";

type TabContentProps = { isActive: boolean; onRegisterActions: RegisterTabActions };

export function ProductTypesTabContent({ isActive, onRegisterActions }: TabContentProps) {
  const { data: queryData } = useProductTypes({ limit: 1000 });
  const data = React.useMemo(() => queryData?.data ?? [], [queryData?.data]);
  const { create, update, remove } = useProductTypeMutations();
  const [dialogOpen, setDialogOpen] = React.useState(false);
  const [editingItem, setEditingItem] = React.useState<ProductType | null>(null);
  const [isAlertOpen, setIsAlertOpen] = React.useState(false);
  const [idToDelete, setIdToDelete] = React.useState<SystemId | null>(null);

  const activeProductTypes = React.useMemo(() => data.filter(t => !t.isDeleted), [data]);
  const existingIds = React.useMemo(() => activeProductTypes.map(t => t.id), [activeProductTypes]);

  const handleAdd = React.useCallback(() => { setEditingItem(null); setDialogOpen(true); }, []);
  const handleEdit = React.useCallback((item: ProductType) => { setEditingItem(item); setDialogOpen(true); }, []);
  const handleDeleteRequest = React.useCallback((systemId: SystemId) => { setIdToDelete(systemId); setIsAlertOpen(true); }, []);

  const handleToggleDefault = React.useCallback((item: ProductType) => {
    data.forEach(t => { if ((t as any).isDefault && t.systemId !== item.systemId && !t.isDeleted) (update as any).mutate({ systemId: t.systemId, isDefault: false }); });
    (update as any).mutate({ systemId: item.systemId, isDefault: !(item as any).isDefault });
    toast.success(item.isDefault ? 'Đã bỏ mặc định' : 'Đã đặt làm mặc định');
  }, [data, update]);

  const handleToggleActive = React.useCallback((item: ProductType) => { const na = item.isActive === false ? true : false; update.mutate({ systemId: item.systemId, data: { isActive: na } }, { onSuccess: () => toast.success(na ? 'Đã kích hoạt' : 'Đã tắt'), onError: (err) => toast.error(err.message) }); }, [update]);
  const confirmDelete = () => { if (idToDelete) { remove.mutate(idToDelete, { onSuccess: () => toast.success('Đã xóa loại sản phẩm'), onError: (err) => toast.error(err.message) }); } setIsAlertOpen(false); setIdToDelete(null); };

  const handleSubmit = (values: ProductTypeFormValues) => {
    const payload = { ...values, id: asBusinessId(values.id) };
    if (editingItem) { update.mutate({ systemId: editingItem.systemId, data: payload }, { onSuccess: () => toast.success('Đã cập nhật loại sản phẩm'), onError: (err) => toast.error(err.message) }); }
    else { create.mutate(payload, { onSuccess: () => toast.success('Đã thêm loại sản phẩm mới'), onError: (err) => toast.error(err.message) }); }
    setDialogOpen(false);
  };

  const columns = React.useMemo(() => getProductTypeColumns({ onEdit: handleEdit, onDelete: handleDeleteRequest, onToggleDefault: handleToggleDefault, onToggleActive: handleToggleActive }), [handleDeleteRequest, handleEdit, handleToggleDefault, handleToggleActive]);

  React.useEffect(() => { if (!isActive) return; onRegisterActions([<SettingsActionButton key="add-product-type" onClick={handleAdd}><Plus className="mr-2 h-4 w-4" /> Thêm loại sản phẩm</SettingsActionButton>]); }, [handleAdd, isActive, onRegisterActions]);

  return (
    <>
      <Card><CardHeader><div className="flex items-center justify-between"><div><CardTitle>Loại sản phẩm</CardTitle><CardDescription>Quản lý các loại sản phẩm: Hàng hóa, Dịch vụ, Digital</CardDescription></div></div></CardHeader><CardContent><SimpleSettingsTable data={activeProductTypes} columns={columns} emptyTitle="Chưa có loại sản phẩm" emptyDescription="Thêm loại sản phẩm đầu tiên để cấu hình tồn kho" emptyAction={<Button size="sm" onClick={handleAdd}>Thêm loại sản phẩm</Button>} /></CardContent></Card>
      <ProductTypeFormDialog open={dialogOpen} onOpenChange={setDialogOpen} initialData={editingItem} onSubmit={handleSubmit} existingIds={existingIds} />
      <AlertDialog open={isAlertOpen} onOpenChange={setIsAlertOpen}><AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Bạn có chắc chắn muốn xóa?</AlertDialogTitle><AlertDialogDescription>Hành động này không thể được hoàn tác.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Hủy</AlertDialogCancel><AlertDialogAction onClick={confirmDelete}>Xóa</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
    </>
  );
}

'use client'

import * as React from "react";
import { Plus } from "lucide-react";
import { asBusinessId, type SystemId } from "@/lib/id-types";
import { toast } from "sonner";

import { useStorageLocations, useStorageLocationMutations } from "../hooks/use-storage-locations";
