import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "../../../components/ui/select"
import { TouchButton } from "../../../components/mobile/touch-button"
import { Badge } from "../../../components/ui/badge"
import { useMediaQuery } from "../../../lib/use-media-query"
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from "../../../components/ui/dropdown-menu"
import { PageToolbar } from "../../../components/layout/page-toolbar"
import { PageFilters } from "../../../components/layout/page-filters"
import { usePrint } from "../../../lib/use-print"
import { convertPenaltyForPrint, mapPenaltyToPrintData, createStoreSettings } from "../../../lib/print/penalty-print-helper"
import { SimplePrintOptionsDialog, type SimplePrintOptionsResult } from "../../../components/shared/simple-print-options-dialog"
import { useColumnLayout } from '../../../hooks/use-column-visibility'

const formatCurrency = (v?: number) => typeof v === 'number' ? new Intl.NumberFormat('vi-VN').format(v) : ''

export function PenaltiesPage() {
  const { data: penalties } = useAllPenalties();
  const { data: _penaltyTypes } = useAllPenaltyTypes();
  const { update } = usePenaltyMutations();
  const { data: employees } = useAllEmployees()
  const { data: branches } = useAllBranches()
  const { info: storeInfo } = useStoreInfoData()
  const router = useRouter()
  const { printMultiple } = usePrint()
  const defaultPageSize = useDefaultPageSize()
  const isMobile = !useMediaQuery("(min-width: 768px)")

  const [printDialogOpen, setPrintDialogOpen] = React.useState(false), [itemsToPrint, setItemsToPrint] = React.useState<Penalty[]>([])
  const [rowSelection, setRowSelection] = React.useState<Record<string, boolean>>({})
  const [sorting, setSorting] = React.useState<{ id: string; desc: boolean }>({ id: 'createdAt', desc: true })
  const [globalFilter, setGlobalFilter] = React.useState(''), [debouncedGlobalFilter, setDebouncedGlobalFilter] = React.useState('')
  const [statusFilter, setStatusFilter] = React.useState<Set<string>>(new Set())
  const [employeeFilter, setEmployeeFilter] = React.useState('all'), [categoryFilter, setCategoryFilter] = React.useState<Set<string>>(new Set())
  const [pagination, setPagination] = React.useState({ pageIndex: 0, pageSize: defaultPageSize })
  const [expanded, setExpanded] = React.useState<Record<string, boolean>>({})

  usePageHeader({ actions: React.useMemo(() => [<Button key="add" size="sm" className="h-9" onClick={() => router.push('/penalties/new')}><PlusCircle className="mr-2 h-4 w-4" />Tạo phiếu phạt</Button>], [router]) })
  React.useEffect(() => { const t = setTimeout(() => setDebouncedGlobalFilter(globalFilter), 300); return () => clearTimeout(t) }, [globalFilter])

  const [columnLayout, columnLayoutSetters] = useColumnLayout('penalties', React.useMemo(() => ({ visibility: {}, order: [] as string[], pinned: [] as string[] }), []))
  const { visibility: columnVisibility, order: columnOrder, pinned: pinnedColumns } = columnLayout
  const { setVisibility: setColumnVisibility, setOrder: setColumnOrder, setPinned: setPinnedColumns } = columnLayoutSetters

  const handleMarkPaid = React.useCallback((p: Penalty) => { update.mutate({ systemId: p.systemId, data: { status: "Đã thanh toán" as PenaltyStatus, updatedAt: new Date().toISOString() } }); toast.success("Đã cập nhật trạng thái", { description: `Phiếu phạt ${p.id} đã chuyển sang "Đã thanh toán"` }) }, [update])
  const handleCancel = React.useCallback((p: Penalty) => { update.mutate({ systemId: p.systemId, data: { status: "Đã hủy" as PenaltyStatus, updatedAt: new Date().toISOString() } }); toast.success("Đã hủy phiếu phạt", { description: `Phiếu phạt ${p.id} đã bị hủy` }) }, [update])
  const columns = React.useMemo(() => getColumns(handleMarkPaid, handleCancel, router), [handleMarkPaid, handleCancel, router])

  const defaultVisibleCols = React.useMemo(() => new Set(['select', 'id', 'employeeName', 'penaltyTypeName', 'reason', 'amount', 'issueDate', 'issuerName', 'status', 'category', 'linkedComplaintSystemId', 'linkedOrderSystemId', 'deductedInPayrollId', 'createdAt', 'actions']), [])
  const buildDefaultVisibility = React.useCallback(() => Object.fromEntries(columns.map(c => [c.id, c.id === 'select' || c.id === 'actions' || defaultVisibleCols.has(c.id!)])), [columns, defaultVisibleCols])
  const buildDefaultOrder = React.useCallback(() => columns.map(c => c.id).filter(Boolean) as string[], [columns])
  const defaultsInitialized = React.useRef(false)
  
  // eslint-disable-next-line react-hooks/exhaustive-deps
  React.useEffect(() => { if (columns.length === 0 || defaultsInitialized.current) return; defaultsInitialized.current = true; setColumnVisibility(buildDefaultVisibility()); setColumnOrder(buildDefaultOrder()) }, [])
  const resetColumnLayout = React.useCallback(() => { setColumnVisibility(buildDefaultVisibility()); setColumnOrder(buildDefaultOrder()); setPinnedColumns([]); toast.success('Đã khôi phục bố cục cột mặc định') }, [buildDefaultVisibility, buildDefaultOrder, setColumnVisibility, setColumnOrder, setPinnedColumns])

  const searchedPenalties = useFuseFilter(penalties, debouncedGlobalFilter, React.useMemo(() => ({ keys: ["id", "employeeName", "reason", "issuerName", "penaltyTypeName"], threshold: 0.3, ignoreLocation: true, useExtendedSearch: false }), []))
  const filteredData = React.useMemo(() => {
    let f = debouncedGlobalFilter ? searchedPenalties : penalties
    if (employeeFilter !== 'all') f = f.filter(p => p.employeeSystemId === employeeFilter)
    if (statusFilter.size > 0) f = f.filter(p => p.status && statusFilter.has(p.status))
    if (categoryFilter.size > 0) f = f.filter(p => p.category && categoryFilter.has(p.category))
    return f
  }, [penalties, debouncedGlobalFilter, searchedPenalties, employeeFilter, statusFilter, categoryFilter])
  React.useEffect(() => { setPagination(p => ({ ...p, pageIndex: 0 })) }, [debouncedGlobalFilter, employeeFilter, statusFilter, categoryFilter])

  const sortedData = React.useMemo(() => [...filteredData].sort((a, b) => {
    if (!sorting.id) return 0
    const aV = (a as Record<string, unknown>)[sorting.id], bV = (b as Record<string, unknown>)[sorting.id]
    if (aV == null) return 1; if (bV == null) return -1
    if (sorting.id === 'issueDate' || sorting.id === 'createdAt') { const aT = aV ? new Date(aV as string).getTime() : 0, bT = bV ? new Date(bV as string).getTime() : 0; return sorting.desc ? bT - aT : aT - bT }
    return aV < bV ? (sorting.desc ? 1 : -1) : aV > bV ? (sorting.desc ? -1 : 1) : 0
  }), [filteredData, sorting])

  const pageCount = Math.ceil(sortedData.length / pagination.pageSize)
  const paginatedData = React.useMemo(() => sortedData.slice(pagination.pageIndex * pagination.pageSize, (pagination.pageIndex + 1) * pagination.pageSize), [sortedData, pagination])
  const allSelectedRows = React.useMemo(() => penalties.filter(p => rowSelection[p.systemId]), [penalties, rowSelection])

  const { create } = usePenaltyMutations();
  const statusOptions = React.useMemo(() => [{ label: 'Chưa thanh toán', value: 'Chưa thanh toán' }, { label: 'Đã thanh toán', value: 'Đã thanh toán' }, { label: 'Đã hủy', value: 'Đã hủy' }], [])
  const categoryOptions = React.useMemo(() => [{ label: 'Khiếu nại', value: 'complaint' }, { label: 'Chấm công', value: 'attendance' }, { label: 'Hiệu suất', value: 'performance' }, { label: 'Khác', value: 'other' }], [])
  const employeeOptions = React.useMemo(() => { const ids = new Set(penalties.map(p => p.employeeSystemId)); return employees.filter(e => ids.has(e.systemId)).map(e => ({ value: e.systemId, label: e.fullName })) }, [penalties, employees])

  const exportConfig = { fileName: 'Danh_sach_Phieu_phat', columns }
  const importConfig: ImportConfig<Penalty> = { importer: items => { (create as any).mutate(items.map(({ systemId: _, ...rest }) => rest) as any); return Promise.resolve(); }, fileName: 'Mau_Nhap_Phieu_phat', existingData: penalties, getUniqueKey: (item: Penalty) => item.id }

  const handleBulkPrint = React.useCallback((rows: Penalty[]) => { setItemsToPrint(rows); setPrintDialogOpen(true) }, [])
  const handlePrintConfirm = React.useCallback((options: SimplePrintOptionsResult) => {
    if (itemsToPrint.length === 0) return
    printMultiple('penalty', itemsToPrint.map(penalty => {
      const employee = employees.find(e => e.systemId === penalty.employeeSystemId)
      const selectedBranch = options.branchSystemId ? branches.find(b => b.systemId === options.branchSystemId) : null
      const storeSettings = createStoreSettings(selectedBranch || storeInfo)
      return { data: mapPenaltyToPrintData(convertPenaltyForPrint(penalty, { employee }), storeSettings), lineItems: [], paperSize: options.paperSize }
    }))
    toast.success(`Đang in ${itemsToPrint.length} phiếu phạt`); setItemsToPrint([]); setPrintDialogOpen(false)
  }, [itemsToPrint, employees, branches, storeInfo, printMultiple])

  const bulkActions: BulkAction<Penalty>[] = [
    { label: "In phiếu", icon: Printer, onSelect: handleBulkPrint },
    { label: "Đánh dấu đã thanh toán", onSelect: rows => { rows.forEach(p => update.mutate({ systemId: p.systemId, data: { status: "Đã thanh toán" as PenaltyStatus } })); toast.success("Đã cập nhật trạng thái", { description: `${rows.length} phiếu phạt đã chuyển sang "Đã thanh toán"` }); setRowSelection({}) } },
    { label: "Hủy phiếu phạt", onSelect: rows => { rows.forEach(p => update.mutate({ systemId: p.systemId, data: { status: "Đã hủy" as PenaltyStatus } })); toast.success("Đã cập nhật trạng thái", { description: `${rows.length} phiếu phạt đã hủy` }); setRowSelection({}) } }
  ]
  const handleRowClick = (row: Penalty) => router.push(`/penalties/${row.systemId}`)

  const MobilePenaltyCard = ({ penalty }: { penalty: Penalty }) => {
    const statusVariant = { 'Chưa thanh toán': 'warning', 'Đã thanh toán': 'success', 'Đã hủy': 'secondary' }[penalty.status] as "warning" | "success" | "secondary" || 'secondary'
    return (
      <Card className="hover:shadow-md transition-shadow cursor-pointer" onClick={() => handleRowClick(penalty)}>
        <CardContent className="p-4">
          <div className="flex items-center justify-between mb-2">
            <div className="flex items-center gap-2 flex-1 min-w-0"><AlertTriangle className="h-4 w-4 text-destructive flex-shrink-0" /><span className="font-semibold text-sm font-mono">{penalty.id}</span><Badge variant={statusVariant} className="text-xs ml-auto">{penalty.status}</Badge></div>
            <DropdownMenu><DropdownMenuTrigger asChild><TouchButton variant="ghost" size="sm" className="h-9 w-10 p-0 flex-shrink-0 ml-2" onClick={e => e.stopPropagation()}><MoreHorizontal className="h-4 w-4" /></TouchButton></DropdownMenuTrigger><DropdownMenuContent align="end"><DropdownMenuItem onClick={e => { e.stopPropagation(); router.push(`/penalties/${penalty.systemId}/edit`) }}>Chỉnh sửa</DropdownMenuItem></DropdownMenuContent></DropdownMenu>
          </div>
          <div className="flex items-center text-sm mb-2"><User className="h-3.5 w-3.5 mr-1.5 text-muted-foreground flex-shrink-0" /><span className="font-medium truncate">{penalty.employeeName}</span></div>
          <div className="text-xs text-muted-foreground mb-3 line-clamp-2"><FileText className="h-3 w-3 mr-1.5 inline-flex flex-shrink-0" />{penalty.reason}</div>
          <div className="border-t mb-3" />
          <div className="flex items-center justify-between text-xs">
            <div className="flex items-center gap-3"><span className="font-bold text-destructive text-sm">{formatCurrency(penalty.amount)} đ</span>{penalty.category && <Badge variant="outline" className="text-xs">{penaltyCategoryLabels[penalty.category]}</Badge>}</div>
            <div className="flex items-center text-muted-foreground"><Calendar className="h-3 w-3 mr-1" />{formatDate(penalty.issueDate)}</div>
          </div>
          <div className="text-xs text-muted-foreground mt-2 pt-2 border-t">Người lập: {penalty.issuerName}</div>
        </CardContent>
      </Card>
    )
  }

  return (
    <div className="flex flex-col w-full h-full">
      {!isMobile && <PageToolbar leftActions={<><DataTableImportDialog config={importConfig} /><DataTableExportDialog allData={penalties} filteredData={sortedData} pageData={paginatedData} config={exportConfig} /></>} rightActions={<DataTableColumnCustomizer columns={columns} columnVisibility={columnVisibility} setColumnVisibility={setColumnVisibility} columnOrder={columnOrder} setColumnOrder={setColumnOrder} pinnedColumns={pinnedColumns} setPinnedColumns={setPinnedColumns} onResetToDefault={resetColumnLayout} />} />}
      <PageFilters searchValue={globalFilter} onSearchChange={setGlobalFilter} searchPlaceholder="Tìm kiếm phiếu phạt (mã, tên NV, lý do)...">
        <Select value={employeeFilter} onValueChange={setEmployeeFilter}><SelectTrigger className="w-full sm:w-[180px] h-9"><SelectValue placeholder="Tất cả nhân viên" /></SelectTrigger><SelectContent><SelectItem value="all">Tất cả nhân viên</SelectItem>{employeeOptions.map(e => <SelectItem key={e.value} value={e.value}>{e.label}</SelectItem>)}</SelectContent></Select>
        <DataTableFacetedFilter title="Trạng thái" options={statusOptions} selectedValues={statusFilter} onSelectedValuesChange={setStatusFilter} />
        <DataTableFacetedFilter title="Phân loại" options={categoryOptions} selectedValues={categoryFilter} onSelectedValuesChange={setCategoryFilter} />
      </PageFilters>
      <div className="w-full py-4">
        <ResponsiveDataTable columns={columns} data={paginatedData} renderMobileCard={p => <MobilePenaltyCard penalty={p} />} pageCount={pageCount} pagination={pagination} setPagination={setPagination} rowCount={filteredData.length} rowSelection={rowSelection} setRowSelection={setRowSelection} bulkActions={bulkActions} allSelectedRows={allSelectedRows} expanded={expanded} setExpanded={setExpanded} sorting={sorting} setSorting={setSorting as React.Dispatch<React.SetStateAction<{ id: string; desc: boolean }>>} columnVisibility={columnVisibility} setColumnVisibility={setColumnVisibility} columnOrder={columnOrder} setColumnOrder={setColumnOrder} pinnedColumns={pinnedColumns} setPinnedColumns={setPinnedColumns} onRowClick={handleRowClick} emptyTitle="Chưa có phiếu phạt" emptyDescription="Tạo phiếu phạt để ghi nhận vi phạm" />
      </div>
      <SimplePrintOptionsDialog open={printDialogOpen} onOpenChange={setPrintDialogOpen} onConfirm={handlePrintConfirm} selectedCount={itemsToPrint.length} title="In phiếu phạt" />
    </div>
  )
}

import * as React from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../../../components/ui/card';
import { Label } from '../../../components/ui/label';
import { Input } from '../../../components/ui/input';
import { Button } from '../../../components/ui/button';
import { Switch } from '../../../components/ui/switch';
import { Textarea } from '../../../components/ui/textarea';
import { Badge } from '../../../components/ui/badge';
import { CurrencyInput } from '../../../components/ui/currency-input';
import { 
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '../../../components/ui/select';
import { 
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '../../../components/ui/table';
import { 
  MoreHorizontal,
  Plus,
  Save,
  Pencil,
  Trash2,
  GripVertical,
} from 'lucide-react';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '../../../components/ui/dialog';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '../../../components/ui/dropdown-menu';
import { ConfirmDialog } from '../../../components/ui/confirm-dialog';
import { toast } from 'sonner';
import { usePenaltyTypes, usePenaltyTypeMutations } from '../../settings/penalty-types/hooks/use-penalty-types';
import type { PenaltyType, PenaltyCategory } from './types';
import { penaltyCategoryLabels, penaltyCategoryColors } from './types';
import { useSettingsPageHeader } from '../use-settings-page-header';

// ============================================
// PENALTY TYPES SETTINGS COMPONENT
// ============================================

export function PenaltyTypesSettings() {
  const { data: queryData } = usePenaltyTypes({ limit: 1000 });
  const penaltyTypes = React.useMemo(() => queryData?.data ?? [], [queryData?.data]);
  const { create, update, remove } = usePenaltyTypeMutations({
    onCreateSuccess: () => toast.success('Đã thêm loại phạt mới'),
    onUpdateSuccess: () => toast.success('Đã cập nhật loại phạt'),
    onDeleteSuccess: () => toast.success('Đã xóa loại phạt'),
    onError: (error) => toast.error(error.message),
  });
  
  // Page header
  useSettingsPageHeader({
    title: 'Loại phạt',
    subtitle: 'Quản lý các loại phạt cho nhân viên (khiếu nại, chấm công, hiệu suất)',
    breadcrumb: [
      { label: 'Trang chủ', href: '/' },
      { label: 'Cài đặt', href: '/settings' },
      { label: 'Loại phạt', href: '/settings/penalty-types', isCurrent: true }
    ],
  });
  
  // Dialog state
  const [isDialogOpen, setIsDialogOpen] = React.useState(false);
  const [editingType, setEditingType] = React.useState<PenaltyType | null>(null);
  const [deleteConfirmOpen, setDeleteConfirmOpen] = React.useState(false);
  const [typeToDelete, setTypeToDelete] = React.useState<PenaltyType | null>(null);
  
  // Form state
  const [formData, setFormData] = React.useState({
    name: '',
    description: '',
    defaultAmount: 100000,
    category: 'other' as PenaltyCategory,
    isActive: true,
  });
  
  // Sort by order
  const sortedTypes = React.useMemo(() => 
    [...penaltyTypes].sort((a, b) => ((a as any).order ?? 0) - ((b as any).order ?? 0)),
    [penaltyTypes]
  );
  
  // Open dialog for new type
  const handleAddNew = () => {
    setEditingType(null);
    setFormData({
      name: '',
      description: '',
      defaultAmount: 100000,
      category: 'other',
      isActive: true,
    });
    setIsDialogOpen(true);
  };
  
  // Open dialog for edit
  const handleEdit = (type: PenaltyType) => {
    setEditingType(type);
    setFormData({
      name: type.name,
      description: type.description || '',
      defaultAmount: type.defaultAmount,
      category: type.category,
      isActive: type.isActive,
    });
    setIsDialogOpen(true);
  };
  
  // Save type
  const handleSave = () => {
    if (!formData.name.trim()) {
      toast.error('Vui lòng nhập tên loại phạt');
      return;
    }
    
    if (editingType) {
      // Update existing
      update.mutate({
        systemId: editingType.systemId,
        data: {
          name: formData.name.trim(),
          description: formData.description.trim(),
          defaultAmount: formData.defaultAmount,
          category: formData.category,
          isActive: formData.isActive,
        },
      });
    } else {
      // Create new
      const _newId = `LP${String(penaltyTypes.length + 1).padStart(3, '0')}`;
      
      create.mutate({
        name: formData.name.trim(),
        description: formData.description.trim(),
        defaultAmount: formData.defaultAmount,
        category: formData.category,
        isActive: formData.isActive,
      } as any);
    }
    
    setIsDialogOpen(false);
  };
  
  // Delete type
  const handleDelete = (type: PenaltyType) => {
    setTypeToDelete(type);
    setDeleteConfirmOpen(true);
  };
  
  const confirmDelete = () => {
    if (typeToDelete) {
      remove.mutate(typeToDelete.systemId);
    }
    setDeleteConfirmOpen(false);
    setTypeToDelete(null);
  };
  
  // Toggle active
  const handleToggleActive = (type: PenaltyType) => {
    update.mutate({
      systemId: type.systemId,
      data: {
        isActive: !type.isActive,
      },
    });
  };
  
  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle>Loại phạt nhân viên</CardTitle>
              <CardDescription>
                Cấu hình các loại phạt và mức phạt mặc định cho từng loại vi phạm
              </CardDescription>
            </div>
            <Button onClick={handleAddNew} size="sm">
              <Plus className="h-4 w-4 mr-2" />
              Thêm loại phạt
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead className="w-12">#</TableHead>
                <TableHead>Tên loại phạt</TableHead>
                <TableHead>Phân loại</TableHead>
                <TableHead className="text-right">Mức phạt mặc định</TableHead>
                <TableHead className="text-center">Trạng thái</TableHead>
                <TableHead className="w-12"></TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {sortedTypes.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={6} className="text-center text-muted-foreground py-8">
                    Chưa có loại phạt nào. Nhấn "Thêm loại phạt" để tạo mới.
                  </TableCell>
                </TableRow>
              ) : (
                sortedTypes.map((type, index) => (
                  <TableRow key={type.systemId}>
                    <TableCell className="text-muted-foreground">
                      <div className="flex items-center gap-2">
                        <GripVertical className="h-4 w-4 text-muted-foreground/50 cursor-grab" />
                        {index + 1}
                      </div>
                    </TableCell>
                    <TableCell>
                      <div>
                        <p className="font-medium">{type.name}</p>
                        {type.description && (
                          <p className="text-xs text-muted-foreground">{type.description}</p>
                        )}
                      </div>
                    </TableCell>
                    <TableCell>
                      <Badge 
                        variant="outline" 
                        className={penaltyCategoryColors[type.category]}
                      >
                        {penaltyCategoryLabels[type.category]}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-right font-medium">
                      {type.defaultAmount.toLocaleString('vi-VN')}đ
                    </TableCell>
                    <TableCell className="text-center">
                      <Switch
                        checked={type.isActive}
                        onCheckedChange={() => handleToggleActive(type as any)}
                      />
                    </TableCell>
                    <TableCell>
                      <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                          <Button variant="ghost" size="icon" className="h-8 w-8">
                            <MoreHorizontal className="h-4 w-4" />
                          </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end">
                          <DropdownMenuItem onClick={() => handleEdit(type as any)}>
                            <Pencil className="h-4 w-4 mr-2" />
                            Chỉnh sửa
                          </DropdownMenuItem>
                          <DropdownMenuSeparator />
                          <DropdownMenuItem 
                            onClick={() => handleDelete(type as any)}
                            className="text-destructive"
                          >
                            <Trash2 className="h-4 w-4 mr-2" />
                            Xóa
                          </DropdownMenuItem>
                        </DropdownMenuContent>
                      </DropdownMenu>
                    </TableCell>
                  </TableRow>
                ))
              )}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
      
      {/* Add/Edit Dialog */}
      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>
              {editingType ? 'Chỉnh sửa loại phạt' : 'Thêm loại phạt mới'}
            </DialogTitle>
            <DialogDescription>
              {editingType 
                ? 'Cập nhật thông tin loại phạt'
                : 'Tạo loại phạt mới cho nhân viên'
              }
            </DialogDescription>
          </DialogHeader>
          
          <div className="space-y-4 py-4">
            <div className="space-y-2">
              <Label htmlFor="name">Tên loại phạt *</Label>
              <Input
                id="name"
                value={formData.name}
                onChange={(e) => setFormData(prev => ({ ...prev, name: e.target.value }))}
                placeholder="VD: Đi làm trễ, Làm hỏng hàng..."
              />
            </div>
            
            <div className="space-y-2">
              <Label htmlFor="description">Mô tả</Label>
              <Textarea
                id="description"
                value={formData.description}
                onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                placeholder="Mô tả chi tiết về loại phạt này..."
                rows={2}
              />
            </div>
            
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="category">Phân loại</Label>
                <Select
                  value={formData.category}
                  onValueChange={(value: PenaltyCategory) => 
                    setFormData(prev => ({ ...prev, category: value }))
                  }
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="complaint">Khiếu nại</SelectItem>
                    <SelectItem value="attendance">Chấm công</SelectItem>
                    <SelectItem value="performance">Hiệu suất</SelectItem>
                    <SelectItem value="other">Khác</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              
              <div className="space-y-2">
                <Label htmlFor="amount">Mức phạt mặc định</Label>
                <CurrencyInput
                  value={formData.defaultAmount}
                  onChange={(value) => setFormData(prev => ({ ...prev, defaultAmount: value }))}
                />
              </div>
            </div>
            
            <div className="flex items-center gap-2">
              <Switch
                id="isActive"
                checked={formData.isActive}
                onCheckedChange={(checked) => 
                  setFormData(prev => ({ ...prev, isActive: checked }))
                }
              />
              <Label htmlFor="isActive">Kích hoạt</Label>
            </div>
          </div>
          
          <DialogFooter>
            <Button variant="outline" onClick={() => setIsDialogOpen(false)}>
              Hủy
            </Button>
            <Button onClick={handleSave}>
              <Save className="h-4 w-4 mr-2" />
              {editingType ? 'Cập nhật' : 'Thêm mới'}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
      
      {/* Delete Confirm Dialog */}
      <ConfirmDialog
        open={deleteConfirmOpen}
        onOpenChange={setDeleteConfirmOpen}
        title="Xóa loại phạt?"
        description={`Bạn có chắc muốn xóa loại phạt "${typeToDelete?.name}"? Hành động này không thể hoàn tác.`}
        confirmText="Xóa"
        cancelText="Hủy"
        variant="destructive"
        onConfirm={confirmDelete}
      />
    </div>
  );
}

// ⚠️ MIGRATION NOTE: Old Zustand helper functions removed.
// Use React Query hooks instead:
// - usePenaltyTypes({ isActive: true }) to load active penalty types
// - usePenaltyType(systemId) to get penalty type by id

import * as React from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../../../../components/ui/card';
import { Button } from '../../../../components/ui/button';
import { Input } from '../../../../components/ui/input';
import { Badge } from '../../../../components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '../../../../components/ui/tabs';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from '../../../../components/ui/dialog';
import { Label } from '../../../../components/ui/label';
import { ScrollArea } from '../../../../components/ui/scroll-area';
import { Plus, Pencil, Trash2, RefreshCw, Search, Loader2, FolderTree, Link, Unlink, CheckCircle2, MoreHorizontal, ExternalLink, Upload, AlignLeft, FolderEdit, Link2 } from 'lucide-react';
import { Checkbox } from '../../../../components/ui/checkbox';
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuSeparator, DropdownMenuTrigger } from '../../../../components/ui/dropdown-menu';
import { getCategoryById, updateCategory } from '../../../../lib/pkgx/api-service';
import { toast } from 'sonner';
import { usePkgxSettings, usePkgxCategoryMappingMutations, usePkgxLogMutations, usePkgxCategoryMutations } from '../hooks/use-pkgx-settings';
import { useActiveCategories } from '@/features/categories/hooks/use-all-categories';
import { ResponsiveDataTable } from '../../../../components/data-table/responsive-data-table';
import type { ColumnDef } from '../../../../components/data-table/types';
import type { PkgxCategoryMapping, PkgxCategory, PkgxCategoryFromApi } from '../types';
import { useCategoryMappingValidation, usePkgxEntitySync } from '../hooks';
import type { HrmCategoryData } from '../hooks';
import type { CategoryMappingInput } from '../validation';
import { PkgxMappingDialog } from '../../../../components/shared/pkgx-mapping-dialog';
import { PkgxSyncConfirmDialog } from './pkgx-sync-confirm-dialog';
import { asSystemId } from '@/lib/id-types';

// Extended type for PKGX categories table
interface PkgxCategoryRow extends PkgxCategory {
  systemId: string;
  mappedToHrm?: string;
}

// Extended type for mappings table
interface MappingRow extends PkgxCategoryMapping {
  systemId: string;
}

export function CategoryMappingTab() {
  // All hooks MUST be called before any conditional returns
  const { data: settings } = usePkgxSettings();
  const { addCategoryMapping, updateCategoryMapping, deleteCategoryMapping } = usePkgxCategoryMappingMutations({ onSuccess: () => {} });
  const { setCategories: _setCategories } = usePkgxCategoryMutations({ onSuccess: () => {} });
  const { addLog } = usePkgxLogMutations();
  const { data: productCategoriesData = [] } = useActiveCategories();
  
  const [searchTerm, setSearchTerm] = React.useState('');
  const [activeTab, setActiveTab] = React.useState('pkgx-categories');
  const [isDialogOpen, setIsDialogOpen] = React.useState(false);
  const [editingMapping, setEditingMapping] = React.useState<PkgxCategoryMapping | null>(null);
  const [isSyncing, setIsSyncing] = React.useState(false);
  
  // Detail dialog state
  const [isDetailDialogOpen, setIsDetailDialogOpen] = React.useState(false);
  const [selectedCategoryForDetail, setSelectedCategoryForDetail] = React.useState<PkgxCategoryFromApi | null>(null);
  const [isLoadingDetail, setIsLoadingDetail] = React.useState(false);
  const [isPushing, setIsPushing] = React.useState(false);
  
  // Table state
  const [pagination, setPagination] = React.useState({ pageIndex: 0, pageSize: 20 });
  const [sorting, setSorting] = React.useState<{ id: string; desc: boolean }>({ id: 'id', desc: false });
  const [rowSelection, setRowSelection] = React.useState<Record<string, boolean>>({});
  
  // Form state
  const [selectedHrmCategory, setSelectedHrmCategory] = React.useState('');
  const [selectedPkgxCategory, setSelectedPkgxCategory] = React.useState('');
  const [showWarningConfirm, setShowWarningConfirm] = React.useState(false);
  
  // Use shared PKGX entity sync hook
  const entitySync = usePkgxEntitySync({
    entityType: 'category',
    onLog: (log) => addLog.mutate(log),
  });
  
  const hrmCategories = React.useMemo(
    () => [...productCategoriesData].sort((a, b) => (a.path || '').localeCompare(b.path || '')).map(c => ({
      ...c,
      systemId: asSystemId(c.systemId),
      parentId: c.parentId ? asSystemId(c.parentId) : undefined,
    })),
    [productCategoriesData]
  );
  
  // Validation hook
  const validation = useCategoryMappingValidation({
    existingMappings: settings?.categoryMappings || [],
    hrmCategories: hrmCategories,
    pkgxCategories: settings?.categories || [],
    editingMappingId: editingMapping?.id,
    debounceMs: 300,
  });
  
  // Find if PKGX category is mapped
  const findMapping = React.useCallback((pkgxCatId: number) => {
    return settings?.categoryMappings.find(m => m.pkgxCatId === pkgxCatId);
  }, [settings?.categoryMappings]);
  
  // PKGX Categories data for table
  const pkgxCategoriesData = React.useMemo((): PkgxCategoryRow[] => {
    if (!settings) return [];
    let filtered = settings.categories;
    if (searchTerm) {
      const term = searchTerm.toLowerCase();
      filtered = settings.categories.filter(c => 
        c.name.toLowerCase().includes(term) ||
        c.id.toString().includes(term)
      );
    }
    return filtered.map(c => ({
      ...c,
      systemId: c.id.toString(),
      mappedToHrm: findMapping(c.id)?.hrmCategoryName,
    }));
  }, [settings, searchTerm, findMapping]);
  
  // Mappings data for table
  const mappingsData = React.useMemo((): MappingRow[] => {
    if (!settings) return [];
    let filtered = settings.categoryMappings;
    if (searchTerm) {
      const term = searchTerm.toLowerCase();
      filtered = settings.categoryMappings.filter(m =>
        m.hrmCategoryName.toLowerCase().includes(term) ||
        m.pkgxCatName.toLowerCase().includes(term)
      );
    }
    return filtered.map(m => ({
      ...m,
      systemId: m.id,
    }));
  }, [settings, searchTerm]);
  
  // Paginated data
  const paginatedPkgxData = React.useMemo(() => {
    const start = pagination.pageIndex * pagination.pageSize;
    return pkgxCategoriesData.slice(start, start + pagination.pageSize);
  }, [pkgxCategoriesData, pagination]);
  
  const paginatedMappingsData = React.useMemo(() => {
    const start = pagination.pageIndex * pagination.pageSize;
    return mappingsData.slice(start, start + pagination.pageSize);
  }, [mappingsData, pagination]);
  
  // All selected rows and bulk actions for PKGX categories table
  const allSelectedPkgxRows = React.useMemo(() => 
    paginatedPkgxData.filter(p => rowSelection[p.systemId]),
  [paginatedPkgxData, rowSelection]);
  
  // Get selected PKGX categories that are NOT mapped (for bulk mapping)
  const _selectedUnmappedCategories = React.useMemo(() => 
    allSelectedPkgxRows.filter(c => !c.mappedToHrm),
  [allSelectedPkgxRows]);
  
  // Get selected PKGX categories that ARE mapped (for bulk unlink)
  const selectedMappedCategories = React.useMemo(() => 
    allSelectedPkgxRows.filter(c => c.mappedToHrm),
  [allSelectedPkgxRows]);
  
  // Bulk actions for PKGX categories table
  const pkgxBulkActions = React.useMemo(() => [
    {
      label: `Hủy liên kết (${selectedMappedCategories.length})`,
      icon: Unlink,
      variant: 'destructive' as const,
      disabled: selectedMappedCategories.length === 0,
      onSelect: () => {
        if (selectedMappedCategories.length === 0) {
          toast.error('Không có danh mục đã liên kết nào được chọn');
          return;
        }
        // Bulk delete mappings
        selectedMappedCategories.forEach(category => {
          const mapping = findMapping(category.id);
          if (mapping) {
            deleteCategoryMapping.mutate(mapping.id);
          }
        });
        toast.success(`Đã hủy liên kết ${selectedMappedCategories.length} danh mục`);
        setRowSelection({});
      },
    },
  ], [selectedMappedCategories, findMapping, deleteCategoryMapping]);
  
  // PKGX Categories columns
  const pkgxColumns: ColumnDef<PkgxCategoryRow>[] = React.useMemo(() => [
    {
      id: 'select',
      header: ({ isAllPageRowsSelected, isSomePageRowsSelected, onToggleAll }) => (
        <Checkbox
          checked={isAllPageRowsSelected ? true : isSomePageRowsSelected ? 'indeterminate' : false}
          onCheckedChange={onToggleAll}
          aria-label="Select all"
        />
      ),
      cell: ({ row: _row, isSelected, onToggleSelect }) => (
        <Checkbox
          checked={isSelected}
          onCheckedChange={onToggleSelect}
          aria-label="Select row"
          onClick={(e) => e.stopPropagation()}
        />
      ),
      size: 48,
      enableSorting: false,
      meta: { sticky: 'left', displayName: '' },
    },
    {
      id: 'id',
      accessorKey: 'id',
      header: 'ID',
      size: 70,
      cell: ({ row }) => <span className="font-mono text-xs">{row.id}</span>,
    },
    {
      id: 'name',
      accessorKey: 'name',
      header: 'Danh mục PKGX',
      cell: ({ row }) => {
        // Gộp danh mục cha > danh mục con
        const parent = row.parentId ? settings.categories.find(c => c.id === row.parentId) : null;
        return (
          <div className="flex items-center gap-1">
            {parent && (
              <>
                <span className="text-muted-foreground text-sm">{parent.name}</span>
                <span className="text-muted-foreground">›</span>
              </>
            )}
            <span className="font-medium">{row.name}</span>
          </div>
        );
      },
    },
    {
      id: 'mappedToHrm',
      header: 'Mapping HRM',
      cell: ({ row }) => (
        row.mappedToHrm ? (
          <Badge variant="default" className="bg-green-500">
            <CheckCircle2 className="h-3 w-3 mr-1" />
            {row.mappedToHrm}
          </Badge>
        ) : (
          <Badge variant="secondary">Chưa liên kết</Badge>
        )
      ),
    },
    {
      id: 'actions',
      header: '',
      size: 50,
      cell: ({ row }) => {
        // Get HRM category for sync actions
        const mapping = findMapping(row.id);
        const hrmCategory = mapping ? hrmCategories.find(c => c.systemId === mapping.hrmCategorySystemId) : null;
        
        // Helper to trigger sync with proper HRM data
        const triggerSync = (actionKey: 'sync_all' | 'sync_basic' | 'sync_seo' | 'sync_description') => {
          if (!mapping || !hrmCategory) {
            toast.error('Danh mục chưa được liên kết với HRM');
            return;
          }
          const hrmData: HrmCategoryData = {
            systemId: hrmCategory.systemId,
            name: hrmCategory.name,
            isActive: hrmCategory.isActive,
            seoKeywords: hrmCategory.seoKeywords ?? undefined,
            seoTitle: hrmCategory.seoTitle ?? undefined,
            metaDescription: hrmCategory.metaDescription ?? undefined,
            shortDescription: hrmCategory.shortDescription ?? undefined,
            longDescription: hrmCategory.longDescription ?? undefined,
            websiteSeo: hrmCategory.websiteSeo as HrmCategoryData['websiteSeo'],
          };
          entitySync.triggerSyncAction(actionKey, row.id, hrmData, row.name);
        };
        
        return (
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <Button variant="ghost" size="icon" className="h-8 w-8">
                <MoreHorizontal className="h-4 w-4" />
              </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
              {row.mappedToHrm ? (
                <>
                  {/* Sync All */}
                  <DropdownMenuItem 
                    onClick={() => triggerSync('sync_all')}
                    className="font-medium"
                    title="Đồng bộ: Tên, Keywords, Meta Title, Meta Desc, Mô tả ngắn, Mô tả dài"
                  >
                    <RefreshCw className="h-4 w-4 mr-2" />
                    Đồng bộ tất cả
                  </DropdownMenuItem>
                  <DropdownMenuSeparator />
                  
                  {/* Individual sync actions */}
                  <DropdownMenuItem 
                    onClick={() => triggerSync('sync_seo')}
                    title="Đồng bộ: Keywords, Meta Title, Meta Desc"
                  >
                    <Search className="h-4 w-4 mr-2" />
                    SEO
                  </DropdownMenuItem>
                  <DropdownMenuItem 
                    onClick={() => triggerSync('sync_description')}
                    title="Đồng bộ: Mô tả ngắn (Short Desc), Mô tả dài (Long Desc)"
                  >
                    <AlignLeft className="h-4 w-4 mr-2" />
                    Mô tả
                  </DropdownMenuItem>
                  <DropdownMenuItem 
                    onClick={() => triggerSync('sync_basic')}
                    title="Đồng bộ: Tên danh mục, Trạng thái hiển thị"
                  >
                    <FolderEdit className="h-4 w-4 mr-2" />
                    Thông tin cơ bản
                  </DropdownMenuItem>
                  
                  <DropdownMenuSeparator />
                  <DropdownMenuItem onClick={() => window.open(`https://phukiengiaxuong.com.vn/admin/category.php?act=edit&cat_id=${row.id}`, '_blank')}>
                    <ExternalLink className="h-4 w-4 mr-2" />
                    Xem trên PKGX
                  </DropdownMenuItem>
                  
                  {/* Hủy liên kết */}
                  <DropdownMenuSeparator />
                  <DropdownMenuItem 
                    onClick={() => entitySync.handleConfirm(
                      'Hủy liên kết PKGX',
                      `Bạn có chắc muốn hủy liên kết danh mục "${row.name}" với PKGX?`,
                      () => handleUnlinkCategory(row.id)
                    )}
                    className="text-destructive focus:text-destructive"
                  >
                    <Unlink className="h-4 w-4 mr-2" />
                    Hủy liên kết
                  </DropdownMenuItem>
                </>
              ) : (
                /* Not linked - show link option */
                <>
                  <DropdownMenuItem onClick={() => handleQuickMap(row)}>
                    <Link2 className="h-4 w-4 mr-2" />
                    Liên kết với HRM
                  </DropdownMenuItem>
                </>
              )}
            </DropdownMenuContent>
          </DropdownMenu>
        );
      },
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps -- handleUnlinkCategory and handleQuickMap are stable functions defined after
  ], [settings.categories, hrmCategories, findMapping, entitySync]);
  
  // Mappings columns
  const mappingColumns: ColumnDef<MappingRow>[] = React.useMemo(() => [
    {
      id: 'hrmCategoryName',
      accessorKey: 'hrmCategoryName',
      header: 'Danh mục HRM',
      cell: ({ row }) => <span className="font-medium">{row.hrmCategoryName}</span>,
    },
    {
      id: 'pkgxCatName',
      accessorKey: 'pkgxCatName',
      header: 'Danh mục PKGX',
      cell: ({ row }) => <span>{row.pkgxCatName}</span>,
    },
    {
      id: 'pkgxCatId',
      accessorKey: 'pkgxCatId',
      header: 'ID PKGX',
      size: 80,
      cell: ({ row }) => <span className="font-mono text-muted-foreground">{row.pkgxCatId}</span>,
    },
    {
      id: 'actions',
      header: 'Hành động',
      size: 100,
      cell: ({ row }) => (
        <div className="flex justify-end gap-1">
          <Button variant="ghost" size="sm" onClick={() => handleOpenDialog(row)}>
            <Pencil className="h-4 w-4" />
          </Button>
          <Button variant="ghost" size="sm" onClick={() => handleDelete(row.id)}>
            <Trash2 className="h-4 w-4 text-destructive" />
          </Button>
        </div>
      ),
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps -- handleOpenDialog and handleDelete are stable functions
  ], []);
  
  const handleQuickMap = (pkgxCategory: PkgxCategoryRow) => {
    setSelectedPkgxCategory(pkgxCategory.id.toString());
    setSelectedHrmCategory('');
    setEditingMapping(null);
    setIsDialogOpen(true);
  };
  
  const handleUnlinkCategory = (pkgxCatId: number) => {
    const mapping = findMapping(pkgxCatId);
    if (mapping) {
      deleteCategoryMapping.mutate(mapping.id);
      addLog.mutate({
        action: 'unlink_mapping',
        status: 'success',
        message: `Đã hủy liên kết danh mục: ${mapping.hrmCategoryName} ↔ ${mapping.pkgxCatName}`,
        details: { categoryId: pkgxCatId },
      });
      toast.success('Đã hủy liên kết danh mục');
    }
  };
  
  // Open detail dialog with category info
  const _handleViewDetail = async (catId: number) => {
    setIsDetailDialogOpen(true);
    setIsLoadingDetail(true);
    setSelectedCategoryForDetail(null);
    
    try {
      const response = await getCategoryById(catId);
      if (response.success && response.data?.data) {
        // API returns array, get first element
        const categories = response.data.data;
        if (Array.isArray(categories) && categories.length > 0) {
          setSelectedCategoryForDetail(categories[0]);
        } else {
          toast.error('Không tìm thấy danh mục');
        }
      } else {
        toast.error(response.error || 'Không thể lấy thông tin danh mục');
      }
    } catch (_error) {
      toast.error('Lỗi khi lấy thông tin danh mục');
    } finally {
      setIsLoadingDetail(false);
    }
  };
  
  // Push category info from HRM to PKGX
  const handlePushCategory = async (pkgxCatId: number) => {
    const mapping = findMapping(pkgxCatId);
    if (!mapping) {
      toast.error('Danh mục chưa được mapping với HRM');
      return;
    }
    
    const hrmCategory = hrmCategories.find(c => c.systemId === mapping.hrmCategorySystemId);
    if (!hrmCategory) {
      toast.error('Không tìm thấy danh mục HRM');
      return;
    }
    
    setIsPushing(true);
    try {
      const payload: { cat_name?: string; cat_desc?: string; keywords?: string } = {};
      
      // Push name
      if (hrmCategory.name) payload.cat_name = hrmCategory.name;
      // Push description (nếu HRM category có field này)
      if ((hrmCategory as { description?: string }).description) payload.cat_desc = (hrmCategory as { description?: string }).description;
      // Push keywords (nếu HRM category có field này)
      if ((hrmCategory as { seoKeywords?: string }).seoKeywords) payload.keywords = (hrmCategory as { seoKeywords?: string }).seoKeywords;
      
      const response = await updateCategory(pkgxCatId, payload);
      if (response.success) {
        toast.success('Đã đẩy thông tin danh mục lên PKGX');
        addLog({
          action: 'update_product',
          status: 'success',
          message: `Đã đẩy thông tin danh mục: ${mapping.hrmCategoryName} → ${mapping.pkgxCatName}`,
          details: { categoryId: pkgxCatId },
        });
        // Refresh detail if open
        if (isDetailDialogOpen && selectedCategoryForDetail?.cat_id === pkgxCatId) {
          (loadCategoryDetail as any).mutate(pkgxCatId);
        }
      } else {
        toast.error(response.error || 'Không thể cập nhật danh mục');
      }
    } catch (_error) {
      toast.error('Lỗi khi đẩy thông tin danh mục');
    } finally {
      setIsPushing(false);
    }
  };
  
  const handleOpenDialog = (mapping?: PkgxCategoryMapping) => {
    if (mapping) {
      setEditingMapping(mapping);
      setSelectedHrmCategory(mapping.hrmCategorySystemId);
      setSelectedPkgxCategory(mapping.pkgxCatId.toString());
    } else {
      setEditingMapping(null);
      setSelectedHrmCategory('');
      setSelectedPkgxCategory('');
    }
    setIsDialogOpen(true);
  };
  
  const handleCloseDialog = () => {
    setIsDialogOpen(false);
    setEditingMapping(null);
    setSelectedHrmCategory('');
    setSelectedPkgxCategory('');
    setShowWarningConfirm(false);
    validation.clearValidation();
  };
  
  // Validate when form values change
  React.useEffect(() => {
    if (isDialogOpen && (selectedHrmCategory || selectedPkgxCategory)) {
      const input: CategoryMappingInput = {
        hrmCategorySystemId: selectedHrmCategory || '',
        hrmCategoryName: hrmCategories.find(c => c.systemId === selectedHrmCategory)?.name || '',
        pkgxCatId: selectedPkgxCategory ? parseInt(selectedPkgxCategory) : '',
        pkgxCatName: settings.categories.find(c => c.id === parseInt(selectedPkgxCategory))?.name || '',
      };
      validation.validateAsync(input);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps -- hrmCategories, settings.categories, and validation are used for lookup only when selection changes
  }, [selectedHrmCategory, selectedPkgxCategory, isDialogOpen]);
  
  const handleSave = () => {
    // Build input for validation
    const input: CategoryMappingInput = {
      hrmCategorySystemId: selectedHrmCategory || '',
      hrmCategoryName: hrmCategories.find(c => c.systemId === selectedHrmCategory)?.name || '',
      pkgxCatId: selectedPkgxCategory ? parseInt(selectedPkgxCategory) : '',
      pkgxCatName: settings.categories.find(c => c.id === parseInt(selectedPkgxCategory))?.name || '',
    };
    
    // Run final validation
    const result = validation.validate(input);
    
    // Block if there are errors
    if (!result.isValid) {
      toast.error(result.errors[0]?.message || 'Vui lòng kiểm tra lại thông tin');
      return;
    }
    
    // Show warning confirmation if there are warnings and not yet confirmed
    if (result.warnings.length > 0 && !showWarningConfirm) {
      setShowWarningConfirm(true);
      return;
    }
    
    const hrmCategory = hrmCategories.find((c) => c.systemId === selectedHrmCategory);
    const pkgxCategory = settings.categories.find((c) => c.id === parseInt(selectedPkgxCategory));
    
    if (!hrmCategory || !pkgxCategory) {
      toast.error('Không tìm thấy danh mục');
      return;
    }
    
    if (editingMapping) {
      updateCategoryMapping.mutate({ id: editingMapping.id, updates: {
        hrmCategorySystemId: hrmCategory.systemId,
        hrmCategoryName: hrmCategory.name,
        pkgxCatId: pkgxCategory.id,
        pkgxCatName: pkgxCategory.name,
      }});
      addLog.mutate({
        action: 'save_mapping',
        status: 'success',
        message: `Cập nhật mapping danh mục: ${hrmCategory.name} → ${pkgxCategory.name}`,
        details: { categoryId: pkgxCategory.id },
      });
      toast.success('Đã cập nhật mapping danh mục');
    } else {
      addCategoryMapping.mutate({
        id: `catmap-${Date.now()}`,
        hrmCategorySystemId: hrmCategory.systemId,
        hrmCategoryName: hrmCategory.name,
        pkgxCatId: pkgxCategory.id,
        pkgxCatName: pkgxCategory.name,
      });
      addLog.mutate({
        action: 'save_mapping',
        status: 'success',
        message: `Thêm mapping danh mục: ${hrmCategory.name} → ${pkgxCategory.name}`,
        details: { categoryId: pkgxCategory.id },
      });
      toast.success('Đã thêm mapping danh mục');
    }
    
    handleCloseDialog();
  };
  
  const handleDelete = (id: string) => {
    const mapping = settings?.categoryMappings?.find(m => m.id === id);
    (deleteCategoryMapping as any).mutate(id);
    if (mapping) {
      addLog({
        action: 'save_mapping',
        status: 'info',
        message: `Xóa mapping danh mục: ${mapping.hrmCategoryName}`,
        details: { categoryId: mapping.pkgxCatId },
      });
    }
    toast.success('Đã xóa mapping danh mục');
  };
  
  const handleSyncFromPkgx = async () => {
    setIsSyncing(true);
    try {
      // Note: syncCategoriesFromPkgx needs implementation
      toast.info('Đồng bộ danh mục từ PKGX');
    } catch (error) {
      toast.error(error instanceof Error ? error.message : 'Lỗi khi đồng bộ danh mục');
    } finally {
      setIsSyncing(false);
    }
  };
  
  // Mobile card renderers
  const renderPkgxMobileCard = (row: PkgxCategoryRow) => (
    <div className="p-4 space-y-3">
      <div className="flex items-start justify-between">
        <div>
          <div className="font-medium">{row.name}</div>
          <div className="text-sm text-muted-foreground">ID: {row.id}</div>
        </div>
        {row.mappedToHrm ? (
          <Badge variant="default" className="bg-green-500 shrink-0">
            <CheckCircle2 className="h-3 w-3 mr-1" />
            Đã mapping
          </Badge>
        ) : (
          <Badge variant="secondary" className="shrink-0">Chưa mapping</Badge>
        )}
      </div>
      {row.mappedToHrm && (
        <div className="text-sm">
          <span className="text-muted-foreground">HRM: </span>
          <span>{row.mappedToHrm}</span>
        </div>
      )}
      {!row.mappedToHrm && (
        <Button
          variant="outline"
          size="sm"
          className="w-full"
          onClick={() => handleQuickMap(row)}
        >
          <Link className="h-4 w-4 mr-2" />
          Mapping nhanh
        </Button>
      )}
    </div>
  );
  
  const renderMappingMobileCard = (row: MappingRow) => (
    <div className="p-4 space-y-3">
      <div>
        <div className="font-medium">{row.hrmCategoryName}</div>
        <div className="text-sm text-muted-foreground">
          → {row.pkgxCatName} (ID: {row.pkgxCatId})
        </div>
      </div>
      <div className="flex gap-2">
        <Button variant="outline" size="sm" className="flex-1" onClick={() => handleOpenDialog(row)}>
          <Pencil className="h-4 w-4 mr-2" />
          Sửa
        </Button>
        <Button variant="outline" size="sm" className="flex-1" onClick={() => handleDelete(row.id)}>
          <Trash2 className="h-4 w-4 mr-2 text-destructive" />
          Xóa
        </Button>
      </div>
    </div>
  );
  
  // Guard: return early if settings not loaded (AFTER all hooks)
  if (!settings) {
    return <div className="p-4">Loading...</div>;
  }
  
  return (
    <div className="space-y-6">
      <Card>
        <CardHeader>
          <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
            <div>
              <CardTitle className="text-lg">Mapping danh mục sản phẩm</CardTitle>
              <CardDescription>
                Liên kết danh mục HRM với danh mục PKGX để đồng bộ sản phẩm
              </CardDescription>
            </div>
            <div className="flex gap-2">
              <Button onClick={handleSyncFromPkgx} disabled={isSyncing} variant="outline">
                {isSyncing ? <Loader2 className="h-4 w-4 mr-2 animate-spin" /> : <RefreshCw className="h-4 w-4 mr-2" />}
                Đồng bộ từ PKGX
              </Button>
              <Button onClick={() => handleOpenDialog()}>
                <Plus className="h-4 w-4 mr-2" />
                Thêm mapping
              </Button>
            </div>
          </div>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            <div className="flex flex-col sm:flex-row items-stretch sm:items-center gap-2">
              <div className="relative flex-1">
                <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
                <Input
                  placeholder="Tìm kiếm danh mục..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-9"
                />
              </div>
              <div className="text-sm text-muted-foreground whitespace-nowrap text-center sm:text-right">
                {settings.categories.length} danh mục PKGX | {settings.categoryMappings.length} mapping
              </div>
            </div>
            
            <Tabs value={activeTab} onValueChange={setActiveTab}>
              <TabsList>
                <TabsTrigger value="pkgx-categories">
                  <FolderTree className="h-4 w-4 mr-2" />
                  Danh mục PKGX ({settings.categories.length})
                </TabsTrigger>
                <TabsTrigger value="mappings">
                  <Link className="h-4 w-4 mr-2" />
                  Mapping ({settings.categoryMappings.length})
                </TabsTrigger>
              </TabsList>
              
              <TabsContent value="pkgx-categories" className="mt-4">
                {settings.categories.length === 0 ? (
                  <div className="text-center py-8 text-muted-foreground">
                    <FolderTree className="h-12 w-12 mx-auto mb-4 opacity-50" />
                    <p>Chưa có danh mục từ PKGX.</p>
                    <p className="text-sm mt-1">Bấm "Đồng bộ từ PKGX" để lấy danh sách.</p>
                  </div>
                ) : (
                  <ResponsiveDataTable
                    columns={pkgxColumns}
                    data={paginatedPkgxData}
                    renderMobileCard={renderPkgxMobileCard}
                    pageCount={Math.ceil(pkgxCategoriesData.length / pagination.pageSize)}
                    pagination={pagination}
                    setPagination={setPagination}
                    rowCount={pkgxCategoriesData.length}
                    sorting={sorting}
                    setSorting={setSorting}
                    rowSelection={rowSelection}
                    setRowSelection={setRowSelection}
                    bulkActions={pkgxBulkActions}
                    allSelectedRows={allSelectedPkgxRows}
                    emptyTitle="Không tìm thấy danh mục"
                  />
                )}
              </TabsContent>
              
              <TabsContent value="mappings" className="mt-4">
                {settings.categoryMappings.length === 0 ? (
                  <div className="text-center py-8 text-muted-foreground">
                    <Link className="h-12 w-12 mx-auto mb-4 opacity-50" />
                    <p>Chưa có mapping nào.</p>
                    <p className="text-sm mt-1">Bấm "Thêm mapping" để bắt đầu.</p>
                  </div>
                ) : (
                  <ResponsiveDataTable
                    columns={mappingColumns}
                    data={paginatedMappingsData}
                    renderMobileCard={renderMappingMobileCard}
                    pageCount={Math.ceil(mappingsData.length / pagination.pageSize)}
                    pagination={pagination}
                    setPagination={setPagination}
                    rowCount={mappingsData.length}
                    sorting={sorting}
                    setSorting={setSorting}
                    emptyTitle="Không tìm thấy mapping"
                  />
                )}
              </TabsContent>
            </Tabs>
          </div>
        </CardContent>
      </Card>
      
      {/* Mapping Dialog - Using shared PkgxMappingDialog component */}
      <PkgxMappingDialog
        open={isDialogOpen}
        onOpenChange={setIsDialogOpen}
        type="category"
        isEditing={!!editingMapping}
        hrmItems={hrmCategories.map((c) => ({
          id: c.systemId,
          name: c.path || c.name,
        }))}
        selectedHrmId={selectedHrmCategory}
        onSelectHrmId={setSelectedHrmCategory}
        pkgxItems={settings.categories.map((c) => ({
          id: c.id.toString(),
          name: c.name,
          subText: `ID: ${c.id}`,
        }))}
        selectedPkgxId={selectedPkgxCategory}
        onSelectPkgxId={setSelectedPkgxCategory}
        pkgxSuggestions={validation.suggestions.map(s => ({
          item: { id: s.category.id.toString(), name: s.category.name },
          score: s.score,
        }))}
        validation={validation.validationResult}
        hasErrors={validation.hasErrors}
        isValidating={validation.isValidating}
        showWarningConfirm={showWarningConfirm}
        onConfirm={handleSave}
        onCancel={handleCloseDialog}
      />
      
      {/* Category Detail Dialog */}
      <Dialog open={isDetailDialogOpen} onOpenChange={setIsDetailDialogOpen}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <FolderTree className="h-5 w-5" />
              Chi tiết danh mục PKGX
            </DialogTitle>
            <DialogDescription>
              {selectedCategoryForDetail ? `ID: ${selectedCategoryForDetail.cat_id}` : 'Đang tải...'}
            </DialogDescription>
          </DialogHeader>
          
          {isLoadingDetail ? (
            <div className="flex items-center justify-center py-8">
              <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
            </div>
          ) : selectedCategoryForDetail ? (
            <ScrollArea className="max-h-[60vh] pr-4">
              <div className="space-y-4">
                {/* Basic info */}
                <div className="space-y-2">
                  <Label className="text-sm font-medium">Tên danh mục</Label>
                  <div className="p-2 border rounded text-sm font-medium">
                    {selectedCategoryForDetail.cat_name}
                  </div>
                </div>
                
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <Label className="text-xs text-muted-foreground">Parent ID</Label>
                    <div className="p-2 border rounded text-sm">
                      {selectedCategoryForDetail.parent_id || 'Không có (Root)'}
                    </div>
                  </div>
                  <div className="space-y-1">
                    <Label className="text-xs text-muted-foreground">Thứ tự</Label>
                    <div className="p-2 border rounded text-sm">
                      {selectedCategoryForDetail.sort_order}
                    </div>
                  </div>
                </div>
                
                {/* SEO Info */}
                <div className="space-y-3">
                  <Label className="text-sm font-medium">Thông tin SEO</Label>
                  <div className="space-y-2">
                    <div className="space-y-1">
                      <Label className="text-xs text-muted-foreground">Alias (Slug)</Label>
                      <div className="p-2 border rounded text-sm">
                        {selectedCategoryForDetail.cat_alias || '-'}
                      </div>
                    </div>
                    <div className="space-y-1">
                      <Label className="text-xs text-muted-foreground">Keywords</Label>
                      <div className="p-2 border rounded text-sm">
                        {selectedCategoryForDetail.keywords || '-'}
                      </div>
                    </div>
                  </div>
                </div>
                
                {/* Description */}
                <div className="space-y-1">
                  <Label className="text-sm font-medium">Mô tả danh mục</Label>
                  {selectedCategoryForDetail.cat_desc ? (
                    <div 
                      className="p-3 border rounded text-sm max-h-40 overflow-y-auto bg-muted/30"
                      dangerouslySetInnerHTML={{ __html: selectedCategoryForDetail.cat_desc }}
                    />
                  ) : (
                    <div className="p-2 border rounded text-sm text-muted-foreground">Chưa có mô tả</div>
                  )}
                </div>
                
                {/* Mapping status */}
                {findMapping(selectedCategoryForDetail.cat_id) && (
                  <div className="p-3 bg-green-50 border border-green-200 rounded-lg">
                    <div className="flex items-center gap-2 text-green-700">
                      <CheckCircle2 className="h-4 w-4" />
                      <span className="font-medium">Đã mapping với HRM:</span>
                      <span>{findMapping(selectedCategoryForDetail.cat_id)?.hrmCategoryName}</span>
                    </div>
                  </div>
                )}
              </div>
            </ScrollArea>
          ) : null}
          
          <DialogFooter className="gap-2">
            {selectedCategoryForDetail && (
              <>
                {findMapping(selectedCategoryForDetail.cat_id) && (
                  <Button 
                    variant="outline" 
                    size="sm"
                    onClick={() => handlePushCategory(selectedCategoryForDetail.cat_id)}
                    disabled={isPushing}
                  >
                    {isPushing ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <Upload className="h-4 w-4 mr-2" />}
                    Đẩy HRM → PKGX
                  </Button>
                )}
                <Button 
                  variant="outline" 
                  size="sm"
                  onClick={() => window.open(`https://phukiengiaxuong.com.vn/admin/category.php?act=edit&cat_id=${selectedCategoryForDetail.cat_id}`, '_blank')}
                >
                  <ExternalLink className="h-4 w-4 mr-2" />
                  Xem trên PKGX
                </Button>
              </>
            )}
            <Button variant="outline" onClick={() => setIsDetailDialogOpen(false)}>
              Đóng
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
      
      {/* Confirmation Dialog for sync actions - using shared component */}
      <PkgxSyncConfirmDialog
        confirmAction={entitySync.confirmAction}
        isSyncing={entitySync.isSyncing}
        onConfirm={entitySync.executeAction}
        onCancel={entitySync.cancelConfirm}
      />
    </div>
  );
}

import * as React from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../../../../components/ui/card';
import { Label } from '../../../../components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '../../../../components/ui/select';
import { Button } from '../../../../components/ui/button';
import { Save } from 'lucide-react';
import { toast } from 'sonner';
import { usePkgxSettings, usePkgxPriceMappingMutations, usePkgxLogMutations } from '../hooks/use-pkgx-settings';
import { useAllPricingPolicies } from '../../pricing/hooks/use-all-pricing-policies';
import { PKGX_PRICE_FIELDS } from '../constants';
import type { SystemId } from '../../../../lib/id-types';

export function PriceMappingTab() {
  const { data: settings } = usePkgxSettings();
  const { updatePriceMapping } = usePkgxPriceMappingMutations({ onSuccess: () => {} });
  const { addLog } = usePkgxLogMutations();
  const { data: pricingPolicies = [] } = useAllPricingPolicies();

  // Filter only selling price policies
  const sellingPolicies = pricingPolicies.filter((p) => p.type === 'Bán hàng' && p.isActive);

  const handleChange = (field: keyof NonNullable<typeof settings>['priceMapping'], value: string) => {
    updatePriceMapping.mutate({ field, policyId: value === 'none' ? null : (value as SystemId) });
  };

  const handleSave = () => {
    // Log the mapping save
    const priceMapping = settings?.priceMapping ?? {};
    const _mappingSummary = PKGX_PRICE_FIELDS
      .filter(pf => priceMapping[pf.key as keyof NonNullable<typeof settings>['priceMapping']])
      .map(pf => {
        const policyId = priceMapping[pf.key as keyof NonNullable<typeof settings>['priceMapping']];
        const policy = pricingPolicies.find(p => p.systemId === policyId);
        return `${pf.field} → ${policy?.name || policyId}`;
      })
      .join(', ');
    
    addLog.mutate({
      action: 'save_mapping',
      status: 'success',
      message: 'Đã lưu mapping bảng giá',
      details: {
        total: PKGX_PRICE_FIELDS.filter(pf => priceMapping[pf.key as keyof NonNullable<typeof settings>['priceMapping']]).length,
      }
    });
    
    toast.success('Đã lưu mapping bảng giá');
  };

  const getPolicyName = (policyId: SystemId | null) => {
    if (!policyId) return '-- Không áp dụng --';
    const policy = pricingPolicies.find((p) => p.systemId === policyId);
    return policy?.name || policyId;
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle className="text-lg">Mapping Bảng giá HRM → PKGX</CardTitle>
        <CardDescription>
          Chọn bảng giá trong HRM tương ứng với mỗi loại giá trên PKGX
        </CardDescription>
      </CardHeader>
      <CardContent className="space-y-6">
        {PKGX_PRICE_FIELDS.map((priceField) => (
          <div key={priceField.key} className="grid grid-cols-1 md:grid-cols-2 gap-4 items-start">
            <div>
              <Label className="text-base font-medium">{priceField.label}</Label>
              <p className="text-sm text-muted-foreground">{priceField.description}</p>
            </div>
            <Select
              value={(settings?.priceMapping ?? {})[priceField.key as keyof NonNullable<typeof settings>['priceMapping']] || 'none'}
              onValueChange={(value) => handleChange(priceField.key as keyof NonNullable<typeof settings>['priceMapping'], value)}
            >
              <SelectTrigger>
                <SelectValue placeholder="Chọn bảng giá..." />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="none">-- Không áp dụng --</SelectItem>
                {sellingPolicies.map((policy) => (
                  <SelectItem key={policy.systemId} value={policy.systemId}>
                    {policy.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>
        ))}

        <div className="pt-4 border-t">
          <h4 className="font-medium mb-2">Tóm tắt mapping hiện tại:</h4>
          <div className="bg-muted p-4 rounded-lg text-sm space-y-1">
            {PKGX_PRICE_FIELDS.map((priceField) => (
              <div key={priceField.key} className="flex justify-between">
                <span className="text-muted-foreground">{priceField.field}:</span>
                <span className="font-medium">
                  {getPolicyName((settings?.priceMapping as any)?.[priceField.key])}
                </span>
              </div>
            ))}
          </div>
        </div>

        <div className="flex justify-end pt-4">
          <Button onClick={handleSave}>
            <Save className="h-4 w-4 mr-2" />
            Lưu mapping
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

'use client';

import * as React from "react";
import { asBusinessId, type SystemId } from "@/lib/id-types";
import { useTaxes, useTaxMutations } from "../taxes/hooks/use-taxes";
import type { Tax } from "../taxes/types";
import { TaxTable } from "./tax-table";
import { Button } from "../../../components/ui/button";
import { Dialog, DialogContent, DialogFooter, DialogHeader, DialogTitle, DialogDescription } from "../../../components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "../../../components/ui/alert-dialog";
import { Input } from "../../../components/ui/input";
import { Switch } from "../../../components/ui/switch";
import { Textarea } from "../../../components/ui/textarea";
import { toast } from 'sonner';
import { SettingsActionButton } from "../../../components/settings/SettingsActionButton";
import { PlusCircle, Percent } from "lucide-react";
import { useForm } from "react-hook-form";
import { Form, FormControl, FormDescription, FormField, FormItem, FormLabel, FormMessage } from "../../../components/ui/form";
import { NumberInput } from "../../../components/ui/number-input";

interface TaxContentProps {
    isActive: boolean;
    onRegisterActions: (actions: React.ReactNode[]) => void;
}

type TaxFormValues = {
    id: string;
    name: string;
    rate: number;
    isDefaultSale: boolean;
    isDefaultPurchase: boolean;
    description?: string;
};

export function TaxContent({ isActive: _isActive, onRegisterActions }: TaxContentProps) {
    const { data: queryData } = useTaxes({ limit: 1000 });
    const data = queryData?.data ?? [];
    const { create, update, remove, setDefaultSale, setDefaultPurchase } = useTaxMutations({
        onSuccess: () => {},
        onError: (err) => toast.error(err.message)
    });

    const [isFormOpen, setIsFormOpen] = React.useState(false);
    const [editingTax, setEditingTax] = React.useState<Tax | null>(null);
    const [isAlertOpen, setIsAlertOpen] = React.useState(false);
    const [idToDelete, setIdToDelete] = React.useState<SystemId | null>(null);

    const form = useForm<TaxFormValues>({
        defaultValues: {
            id: '',
            name: '',
            rate: 0,
            isDefaultSale: false,
            isDefaultPurchase: false,
            description: '',
        },
    });

    const handleAddNew = () => {
        setEditingTax(null);
        form.reset({
            id: '',
            name: '',
            rate: 0,
            isDefaultSale: false,
            isDefaultPurchase: false,
            description: '',
        });
        setIsFormOpen(true);
    };

    // Register actions when component mounts or onRegisterActions changes
    React.useEffect(() => {
        onRegisterActions([
            <SettingsActionButton key="add" onClick={handleAddNew}>
                <PlusCircle className="h-4 w-4" />
                Thêm thuế
            </SettingsActionButton>
        ]);
    }, [onRegisterActions]);
    
    const handleEdit = React.useCallback((tax: Tax) => {
        setEditingTax(tax);
        form.reset({
            id: tax.id,
            name: tax.name,
            rate: tax.rate,
            isDefaultSale: tax.isDefaultSale,
            isDefaultPurchase: tax.isDefaultPurchase,
            description: tax.description || '',
        });
        setIsFormOpen(true);
    }, [form]);
    
    const handleDeleteRequest = React.useCallback((systemId: SystemId) => {
        setIdToDelete(systemId);
        setIsAlertOpen(true);
    }, []);
    
    const confirmDelete = () => {
        if (idToDelete) {
            const tax = data.find(t => t.systemId === idToDelete);
            remove.mutate(idToDelete, {
                onSuccess: () => toast.success(`Đã xóa thuế "${tax?.name}"`),
                onError: (err) => toast.error(err.message)
            });
        }
        setIsAlertOpen(false);
        setIsFormOpen(false);
        setIdToDelete(null);
    };

    const handleFormSubmit = (values: TaxFormValues) => {
        const payload = {
            id: asBusinessId(values.id.trim().toUpperCase()),
            name: values.name.trim(),
            rate: values.rate,
            isDefaultSale: values.isDefaultSale,
            isDefaultPurchase: values.isDefaultPurchase,
            description: values.description?.trim() || undefined,
        };
        
        if (editingTax) {
            update.mutate({ systemId: editingTax.systemId, data: payload }, {
                onSuccess: () => toast.success(`Đã cập nhật thuế "${values.name}"`),
                onError: (err) => toast.error(err.message)
            });
        } else {
            create.mutate(payload, {
                onSuccess: () => toast.success(`Đã thêm thuế "${values.name}"`),
                onError: (err) => toast.error(err.message)
            });
        }
        setIsFormOpen(false);
    };
    
    const handleSetDefaultSale = React.useCallback((systemId: SystemId) => {
        const tax = data.find(t => t.systemId === systemId);
        setDefaultSale.mutate(systemId, {
            onSuccess: () => tax && toast.success(`Đã đặt "${tax.name}" làm thuế mặc định bán hàng`),
            onError: (err) => toast.error(err.message)
        });
    }, [data, setDefaultSale]);

    const handleSetDefaultPurchase = React.useCallback((systemId: SystemId) => {
        const tax = data.find(t => t.systemId === systemId);
        setDefaultPurchase.mutate(systemId, {
            onSuccess: () => tax && toast.success(`Đã đặt "${tax.name}" làm thuế mặc định nhập hàng`),
            onError: (err) => toast.error(err.message)
        });
    }, [data, setDefaultPurchase]);

    return (
        <>
            <p className="text-sm text-muted-foreground mb-4">
                Tất cả các loại thuế trong hệ thống (áp dụng cho cả nhập hàng và bán hàng)
            </p>
            <TaxTable
                data={data}
                allData={data}
                onEdit={handleEdit}
                onDelete={handleDeleteRequest}
                onSetDefaultSale={handleSetDefaultSale}
                onSetDefaultPurchase={handleSetDefaultPurchase}
            />

            <Dialog open={isFormOpen} onOpenChange={setIsFormOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>{editingTax ? 'Cập nhật thuế' : 'Thêm thuế mới'}</DialogTitle>
                        <DialogDescription>
                            {editingTax ? 'Chỉnh sửa thông tin thuế' : 'Tạo loại thuế mới cho hệ thống'}
                        </DialogDescription>
                    </DialogHeader>
                    
                    <Form {...form}>
                        <form id="tax-form" onSubmit={form.handleSubmit(handleFormSubmit)} className="space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                <FormField
                                    control={form.control}
                                    name="id"
                                    rules={{ required: 'Mã thuế là bắt buộc' }}
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel>Mã thuế</FormLabel>
                                            <FormControl>
                                                <Input placeholder="VD: VAT10" {...field} />
                                            </FormControl>
                                            <FormMessage />
                                        </FormItem>
                                    )}
                                />
                                <FormField
                                    control={form.control}
                                    name="rate"
                                    rules={{ required: 'Thuế suất là bắt buộc', min: { value: 0, message: 'Thuế suất phải >= 0' } }}
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel>Thuế suất (%)</FormLabel>
                                            <FormControl>
                                                <div className="relative">
                                                    <NumberInput 
                                                        value={field.value} 
                                                        onChange={field.onChange}
                                                        min={0}
                                                        max={100}
                                                        className="pr-8"
                                                    />
                                                    <Percent className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                                                </div>
                                            </FormControl>
                                            <FormMessage />
                                        </FormItem>
                                    )}
                                />
                            </div>
                            
                            <FormField
                                control={form.control}
                                name="name"
                                rules={{ required: 'Tên thuế là bắt buộc' }}
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Tên thuế</FormLabel>
                                        <FormControl>
                                            <Input placeholder="VD: VAT 10%" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="description"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Mô tả</FormLabel>
                                        <FormControl>
                                            <Textarea 
                                                placeholder="Mô tả về loại thuế này..." 
                                                className="resize-none"
                                                {...field} 
                                            />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="isDefaultSale"
                                render={({ field }) => (
                                    <FormItem className="flex flex-row items-center justify-between rounded-lg border p-3">
                                        <div className="space-y-0.5">
                                            <FormLabel>Mặc định bán hàng</FormLabel>
                                            <FormDescription>
                                                Thuế này sẽ được tự động áp dụng cho đơn bán hàng mới
                                            </FormDescription>
                                        </div>
                                        <FormControl>
                                            <Switch
                                                checked={field.value}
                                                onCheckedChange={field.onChange}
                                            />
                                        </FormControl>
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="isDefaultPurchase"
                                render={({ field }) => (
                                    <FormItem className="flex flex-row items-center justify-between rounded-lg border p-3">
                                        <div className="space-y-0.5">
                                            <FormLabel>Mặc định nhập hàng</FormLabel>
                                            <FormDescription>
                                                Thuế này sẽ được tự động áp dụng cho đơn nhập hàng mới
                                            </FormDescription>
                                        </div>
                                        <FormControl>
                                            <Switch
                                                checked={field.value}
                                                onCheckedChange={field.onChange}
                                            />
                                        </FormControl>
                                    </FormItem>
                                )}
                            />
                        </form>
                    </Form>

                    <DialogFooter className="flex-col-reverse sm:flex-row sm:justify-between sm:space-x-2">
                        {editingTax && (
                            <Button 
                                type="button" 
                                variant="destructive" 
                                onClick={() => handleDeleteRequest(editingTax.systemId)}
                                className="sm:mr-auto h-9"
                            >
                                Xóa
                            </Button>
                        )}
                        <div className="flex flex-col-reverse gap-2 sm:flex-row sm:justify-end">
                            <Button type="button" variant="outline" onClick={() => setIsFormOpen(false)} className="h-9">
                                Thoát
                            </Button>
                            <Button type="submit" form="tax-form" className="h-9">
                                Xác nhận
                            </Button>
                        </div>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            <AlertDialog open={isAlertOpen} onOpenChange={setIsAlertOpen}>
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>Bạn có chắc chắn muốn xóa?</AlertDialogTitle>
                        <AlertDialogDescription>
                            Hành động này không thể được hoàn tác. Thuế đã xóa sẽ không còn áp dụng được cho các đơn hàng.
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel className="h-9">Hủy</AlertDialogCancel>
                        <AlertDialogAction onClick={confirmDelete} className="h-9">Xóa</AlertDialogAction>
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>
        </>
    );
}

'use client'

import * as React from "react";
import dynamic from "next/dynamic";
import { useFuseFilter } from "@/hooks/use-fuse-search";
import { useProvinces, useDistricts, useWards, useProvinceMutations, useDistrictMutations, useWardMutations } from "./hooks/use-provinces";
import { asSystemId, asBusinessId } from "@/lib/id-types";
import { ProvinceForm, type ProvinceFormValues } from "./form";
import { WardForm, type WardFormValues } from "./ward-form";
import { DistrictForm, type DistrictFormValues } from "./district-form";
import type { Province, Ward, District } from '@/lib/types/prisma-extended';
import { useSettingsPageHeader } from "../use-settings-page-header";
import { SettingsActionButton } from "@/components/settings/SettingsActionButton";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "@/components/ui/alert-dialog";
import { Tabs, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { PlusCircle, Search, Upload, Download } from "lucide-react";
import { cn } from "@/lib/utils";
import { toast } from 'sonner';
import { ProvinceItem, DistrictItem, WardList } from "./components";

// Dynamic imports for dialogs
const ImportPreviewDialog = dynamic(() => import("./components/import-preview-dialog").then(m => m.ImportPreviewDialog), { ssr: false });

function useDebounce<T>(value: T, delay: number): T { const [d, setD] = React.useState(value); React.useEffect(() => { const t = setTimeout(() => setD(value), delay); return () => clearTimeout(t); }, [value, delay]); return d; }

type ImportPreviewState = { provinces: Array<Omit<Province, "systemId">>; wards: Array<Omit<Ward, "systemId">>; summary: { provinceCount: number; wardCount: number } };

export function ProvincesPage() {
  const { data: queryData } = useProvinces({ limit: 1000 });
  const allProvinces = React.useMemo(() => queryData?.data ?? [], [queryData?.data]);
  const { add: addProvince, update: updateProvince, remove: removeProvince } = useProvinceMutations({
    onSuccess: () => {},
    onError: (error) => toast.error(error.message),
  });
  const { add: addDistrict, update: updateDistrict, remove: removeDistrict } = useDistrictMutations({
    onSuccess: () => {},
    onError: (error) => toast.error(error.message),
  });
  const { add: addWard, update: updateWard, remove: removeWard } = useWardMutations({
    onSuccess: () => {},
    onError: (error) => toast.error(error.message),
  });
  const importInputRef = React.useRef<HTMLInputElement | null>(null);

  const [mode, setMode] = React.useState<"2-level" | "3-level">("3-level");
  const [selectedProvinceId, setSelectedProvinceId] = React.useState<string | null>(null);
  const [selectedDistrictId, setSelectedDistrictId] = React.useState<number | null>(null);
  const [provinceSearchInput, setProvinceSearchInput] = React.useState("");
  const [districtSearchInput, setDistrictSearchInput] = React.useState("");
  const [wardSearchInput, setWardSearchInput] = React.useState("");
  const provinceSearch = useDebounce(provinceSearchInput, 300);
  const districtSearch = useDebounce(districtSearchInput, 300);
  const wardSearch = useDebounce(wardSearchInput, 300);
  const [isProvinceFormOpen, setIsProvinceFormOpen] = React.useState(false);
  const [editingProvince, setEditingProvince] = React.useState<Province | null>(null);
  const [isWardFormOpen, setIsWardFormOpen] = React.useState(false);
  const [editingWard, setEditingWard] = React.useState<Ward | null>(null);
  const [isDistrictFormOpen, setIsDistrictFormOpen] = React.useState(false);
  const [editingDistrict, setEditingDistrict] = React.useState<District | null>(null);
  const [dialogState, setDialogState] = React.useState<{ type: "province" | "ward" | "district"; systemId: string } | null>(null);
  const [importPreview, setImportPreview] = React.useState<ImportPreviewState | null>(null);
  const [isImportDialogOpen, setIsImportDialogOpen] = React.useState(false);
  const [isImporting, setIsImporting] = React.useState(false);

  // Filter provinces by current mode (2-level or 3-level)
  const provinces = React.useMemo(() => 
    allProvinces.filter(p => p.level === mode), [allProvinces, mode]);

  const selectedProvince = React.useMemo(() => provinces.find(p => p.systemId === selectedProvinceId) ?? null, [provinces, selectedProvinceId]);
  React.useEffect(() => {
    if (!provinces.length) {
      if (selectedProvinceId !== null) setSelectedProvinceId(null);
      return;
    }

    // If nothing is selected, pick the first province
    if (selectedProvinceId === null) {
      const next = provinces[0]?.systemId ?? null;
      if (next !== null) setSelectedProvinceId(next);
      return;
    }

    // If current selection no longer exists, fall back to first
    if (!provinces.some(p => p.systemId === selectedProvinceId)) {
      const next = provinces[0]?.systemId ?? null;
      if (next !== selectedProvinceId) setSelectedProvinceId(next);
    }
  }, [provinces, selectedProvinceId]);

  const selectedProvinceBusinessId = selectedProvince?.id ?? null;

  // Fetch districts for 3-level mode
  const { data: districtsData = [] } = useDistricts(mode === "3-level" && selectedProvinceBusinessId ? selectedProvinceBusinessId as any : undefined);
  
  // Fetch wards based on mode (depend only on primitive ids to keep stable)
  const wardsFilter = React.useMemo(() => {
    if (!selectedProvinceBusinessId) return undefined;
    if (mode === "2-level") return { provinceId: selectedProvinceBusinessId, level: '2-level' as const };
    if (mode === "3-level" && selectedDistrictId) return { districtId: selectedDistrictId, level: '3-level' as const };
    return undefined;
  }, [mode, selectedProvinceBusinessId, selectedDistrictId]);
  const { data: wardsData = [] } = useWards(wardsFilter);

  const wardsForSelectedProvince = (wardsData as any)?.data ?? wardsData ?? [];
  const districtsForProvince = (districtsData as any)?.data ?? districtsData ?? [];

  const provinceFuseOptions = React.useMemo(() => ({ keys: ["name", "id"], threshold: 0.3 }), []);
  const searchedProvinces = useFuseFilter(provinces, provinceSearch, provinceFuseOptions);
  const filteredProvinces = React.useMemo(() => provinceSearch ? searchedProvinces : provinces, [searchedProvinces, provinceSearch, provinces]);
  const orderedProvinces = React.useMemo(() => [...filteredProvinces].sort((a, b) => a.name.localeCompare(b.name)), [filteredProvinces]);

  const districtFuseOptions = React.useMemo(() => ({ keys: ["name"], threshold: 0.3 }), []);
  const searchedDistricts = useFuseFilter(districtsForProvince as any, districtSearch, districtFuseOptions);
  const filteredDistricts = React.useMemo(() => districtSearch ? searchedDistricts : districtsForProvince, [searchedDistricts, districtSearch, districtsForProvince]);

  const wardFuseOptions = React.useMemo(() => ({ keys: ["name", "id"], threshold: 0.3 }), []);
  const searchedWards = useFuseFilter(wardsForSelectedProvince as any, wardSearch, wardFuseOptions);
  const filteredWards = React.useMemo(() => wardSearch ? searchedWards : wardsForSelectedProvince, [searchedWards, wardSearch, wardsForSelectedProvince]);

  const handleAddProvince = React.useCallback(() => { setEditingProvince(null); setIsProvinceFormOpen(true); }, []);
  const handleEditProvince = (p: Province) => { setEditingProvince(p); setIsProvinceFormOpen(true); };
  const handleDeleteProvince = (id: string) => setDialogState({ type: "province", systemId: id });
  const handleProvinceFormSubmit = (v: ProvinceFormValues) => { if (editingProvince) (updateProvince as any).mutate({ systemId: editingProvince.systemId, ...v }); else (addProvince as any).mutate(v); setIsProvinceFormOpen(false); };
  const handleAddWard = () => { setEditingWard(null); setIsWardFormOpen(true); };
  const handleEditWard = (w: Ward) => { setEditingWard(w); setIsWardFormOpen(true); };
  const handleDeleteWard = (id: string) => setDialogState({ type: "ward", systemId: id });
  const handleWardFormSubmit = (v: WardFormValues) => { if (!selectedProvince) return; const fv = { ...v, provinceId: selectedProvince.id }; if (editingWard) (updateWard as any).mutate({ systemId: editingWard.systemId, ...fv }); else (addWard as any).mutate(fv); setIsWardFormOpen(false); };
  const handleAddDistrict = () => { setEditingDistrict(null); setIsDistrictFormOpen(true); };
  const handleEditDistrict = (d: District) => { setEditingDistrict(d); setIsDistrictFormOpen(true); };
  const handleDeleteDistrict = (id: string) => setDialogState({ type: "district", systemId: id });
  const handleDistrictFormSubmit = (v: DistrictFormValues) => { if (!selectedProvince) return; const fv = { ...v, provinceId: selectedProvince.id }; if (editingDistrict) (updateDistrict as any).mutate({ systemId: editingDistrict.systemId, ...fv }); else (addDistrict as any).mutate(fv); setIsDistrictFormOpen(false); };

  const confirmDelete = () => { if (!dialogState) return; if (dialogState.type === "province") { if (dialogState.systemId === selectedProvinceId) { const fb = provinces.find(p => p.systemId !== dialogState.systemId); setSelectedProvinceId(fb?.systemId ?? null); setSelectedDistrictId(null); } removeProvince(asSystemId(dialogState.systemId)); } else if (dialogState.type === "ward") removeWard(asSystemId(dialogState.systemId)); else if (dialogState.type === "district") { const d = districtsForProvince.find(x => x.systemId === dialogState.systemId); if (d && d.id === selectedDistrictId) setSelectedDistrictId(null); removeDistrict(asSystemId(dialogState.systemId)); } setDialogState(null); };

  const handleImport = async (e: React.ChangeEvent<HTMLInputElement>) => { const file = e.target.files?.[0]; if (!file) return; const XLSX = await import('xlsx'); const reader = new FileReader(); reader.onload = le => { try { const data = le.target?.result; const wb = XLSX.read(data, { type: "binary" }); const ws = wb.Sheets[wb.SheetNames[0]]; const json = XLSX.utils.sheet_to_json<Record<string, unknown>>(ws); const pm = new Map<string, Omit<Province, "systemId">>(); const wards: Array<Omit<Ward, "systemId">> = []; json.forEach(r => { const pid = r["Mã tỉnh (BNV)"] ?? r["Ma Tinh"]; const pn = r["Tên tỉnh/TP mới"] ?? r["Ten tinh"]; const wc = r["Mã phường/xã mới"] ?? r["Ma phuong/xa"]; const wn = r["Tên Phường/Xã mới"] ?? r["Ten Phuong/Xa"]; if (!pid || !pn || !wc || !wn) return; const id = String(pid).padStart(2, "0"); if (!pm.has(id)) pm.set(id, { id: asBusinessId(id), name: String(pn).trim() }); wards.push({ id: String(wc).trim(), name: String(wn).trim(), provinceId: asBusinessId(id), provinceName: String(pn).trim() }); }); if (pm.size === 0 || wards.length === 0) { toast.error('Không tìm thấy dữ liệu hợp lệ'); return; } setImportPreview({ provinces: Array.from(pm.values()), wards, summary: { provinceCount: pm.size, wardCount: wards.length } }); setIsImportDialogOpen(true); } catch (err) { toast.error('Lỗi đọc file', { description: err instanceof Error ? err.message : 'File không hợp lệ' }); } }; reader.readAsBinaryString(file); e.target.value = ""; };
  const handleConfirmImport = () => { if (!importPreview) return; setIsImporting(true); try { 
    // Note: importAdministrativeUnits needs implementation
    toast.info('Import administrative units'); 
    setIsImportDialogOpen(false); setImportPreview(null); } catch (err) { toast.error('Không thể ghi dữ liệu', { description: err instanceof Error ? err.message : 'Thử lại sau' }); } finally { setIsImporting(false); } };
  
  // Use ref to avoid re-creating headerActions when provinces changes
  const provincesRef = React.useRef(provinces);
  provincesRef.current = provinces;
  const handleExport = React.useCallback(async () => { const pe = provincesRef.current.map(({ systemId: _s, ...r }) => ({ "Mã tỉnh": r.id, "Tên Tỉnh/Thành phố": r.name })); const res = await fetch('/api/administrative-units/wards?level=2-level&limit=20000'); const json = await res.json(); const w2 = json.success ? json.data : []; const we = w2.map(({ systemId: _s, ...r }: Ward) => ({ "Mã tỉnh": r.provinceId, "Mã Phường/Xã": r.id, "Tên Phường/Xã": r.name })); const XLSX = await import('xlsx'); const pws = XLSX.utils.json_to_sheet(pe); const wws = XLSX.utils.json_to_sheet(we); const wb = XLSX.utils.book_new(); XLSX.utils.book_append_sheet(wb, pws, "TinhThanh"); XLSX.utils.book_append_sheet(wb, wws, "PhuongXa"); XLSX.writeFile(wb, "Danh_sach_Don_vi_hanh_chinh.xlsx"); }, []);
  const handleImportButtonClick = React.useCallback(() => { importInputRef.current?.click(); }, []);

  const headerActions = React.useMemo(() => [<SettingsActionButton key="import" variant="outline" onClick={handleImportButtonClick}><Upload className="h-4 w-4" />Nhập file</SettingsActionButton>, <SettingsActionButton key="export" variant="outline" onClick={handleExport}><Download className="h-4 w-4" />Xuất file</SettingsActionButton>, <SettingsActionButton key="add" onClick={handleAddProvince}><PlusCircle className="h-4 w-4" />Thêm tỉnh thành</SettingsActionButton>], [handleImportButtonClick, handleExport, handleAddProvince]);
  useSettingsPageHeader({ title: "Tỉnh thành - Quận huyện", actions: headerActions });

  const handleSelectProvince = React.useCallback((id: string) => { setSelectedProvinceId(id); setSelectedDistrictId(null); }, []);

  const renderProvinceList = () => (<Card className={cn("flex flex-col", mode === "2-level" ? "w-1/3" : "w-1/4")}><CardHeader><div className="flex items-center justify-between"><CardTitle className={mode === "3-level" ? "text-base" : undefined}>{mode === "2-level" ? "Tỉnh/Thành phố" : "Tỉnh/TP"}</CardTitle><Button size="icon" variant="ghost" className="h-8 w-8" onClick={handleAddProvince}><PlusCircle className="h-4 w-4" /></Button></div><div className="relative pt-2"><Search className="pointer-events-none absolute left-2.5 top-[18px] h-4 w-4 text-muted-foreground" /><Input placeholder={mode === "2-level" ? "Tìm kiếm..." : "Tìm..."} className="h-9 pl-8" value={provinceSearchInput} onChange={e => setProvinceSearchInput(e.target.value)} /></div></CardHeader><CardContent className="flex-grow overflow-hidden p-2"><ScrollArea className="h-full"><div className="space-y-2 pb-2">{orderedProvinces.map(p => <ProvinceItem key={p.systemId} province={p} isActive={selectedProvinceId === p.systemId} onSelect={handleSelectProvince} onEdit={handleEditProvince} onDelete={handleDeleteProvince} />)}</div></ScrollArea></CardContent></Card>);

  const renderWardPanel = (showAdd: boolean) => (<>{filteredWards.length > 0 ? <div className="flex-1 h-full overflow-hidden"><WardList wards={filteredWards} onEdit={handleEditWard} onDelete={handleDeleteWard} /></div> : <div className="flex h-full flex-col items-center justify-center gap-2 p-4 text-center"><p className="font-medium text-muted-foreground">Chưa có phường/xã</p><p className="text-sm text-muted-foreground">Thêm phường/xã mới.</p>{showAdd && <Button size="sm" onClick={handleAddWard}><PlusCircle className="mr-2 h-4 w-4" />Thêm phường/xã</Button>}</div>}</>);

  return (
    <div className="flex h-full flex-col">
      <input ref={importInputRef} type="file" className="hidden" accept=".xlsx, .xls" onChange={handleImport} />
      <div className="mb-4 flex flex-shrink-0 items-center"><Tabs value={mode} onValueChange={v => { setMode(v as "2-level" | "3-level"); setSelectedDistrictId(null); }}><TabsList><TabsTrigger value="2-level">2 cấp (Tỉnh → Phường)</TabsTrigger><TabsTrigger value="3-level">3 cấp (Tỉnh → Quận → Phường)</TabsTrigger></TabsList></Tabs></div>

      {mode === "2-level" ? (<div className="flex min-h-0 flex-grow gap-4">{renderProvinceList()}<div className="flex w-2/3 flex-col">{selectedProvince ? <Card className="flex flex-grow flex-col"><CardHeader><div className="flex items-center justify-between"><div><CardTitle>{selectedProvince.name}</CardTitle><CardDescription>Mã: {selectedProvince.id} • {filteredWards.length} phường/xã</CardDescription></div><Button size="sm" onClick={handleAddWard}><PlusCircle className="mr-2 h-4 w-4" />Thêm phường/xã</Button></div><div className="relative pt-2"><Search className="pointer-events-none absolute left-2.5 top-[18px] h-4 w-4 text-muted-foreground" /><Input placeholder="Tìm phường/xã..." className="h-9 pl-8" value={wardSearchInput} onChange={e => setWardSearchInput(e.target.value)} /></div></CardHeader><CardContent className="flex flex-grow flex-col p-0">{renderWardPanel(true)}</CardContent></Card> : <Card className="flex h-full items-center justify-center"><div className="text-center text-muted-foreground">Chọn một Tỉnh/Thành phố.</div></Card>}</div></div>) : (<div className="flex min-h-0 flex-grow gap-4">{renderProvinceList()}<Card className="flex w-1/4 flex-col"><CardHeader><div className="flex items-center justify-between"><CardTitle className="text-base">Quận/Huyện</CardTitle>{selectedProvince && <Button size="icon" variant="ghost" className="h-8 w-8" onClick={handleAddDistrict}><PlusCircle className="h-4 w-4" /></Button>}</div>{selectedProvince && <div className="relative pt-2"><Search className="pointer-events-none absolute left-2.5 top-[18px] h-4 w-4 text-muted-foreground" /><Input placeholder="Tìm quận/huyện..." className="h-9 pl-8" value={districtSearchInput} onChange={e => setDistrictSearchInput(e.target.value)} /></div>}</CardHeader><CardContent className="flex-grow overflow-hidden p-2">{selectedProvince ? <ScrollArea className="h-full"><div className="space-y-2 pb-2">{filteredDistricts.map(d => <DistrictItem key={d.systemId} district={d} isActive={selectedDistrictId === d.id} onSelect={setSelectedDistrictId} onEdit={handleEditDistrict} onDelete={handleDeleteDistrict} />)}</div></ScrollArea> : <div className="flex h-full items-center justify-center text-sm text-muted-foreground">Chọn tỉnh/TP trước</div>}</CardContent></Card><Card className="flex flex-1 flex-col"><CardHeader><div className="flex items-center justify-between"><div><CardTitle className="text-base">Phường/Xã</CardTitle>{selectedDistrictId && <CardDescription className="mt-1 text-xs">{districtsForProvince.find(d => d.id === selectedDistrictId)?.name} • {filteredWards.length} phường/xã</CardDescription>}</div>{selectedDistrictId && <Button size="sm" onClick={handleAddWard}><PlusCircle className="mr-2 h-4 w-4" />Thêm</Button>}</div>{selectedDistrictId && <div className="relative pt-2"><Search className="pointer-events-none absolute left-2.5 top-[18px] h-4 w-4 text-muted-foreground" /><Input placeholder="Tìm phường/xã..." className="h-9 pl-8" value={wardSearchInput} onChange={e => setWardSearchInput(e.target.value)} /></div>}</CardHeader><CardContent className="flex flex-1 flex-col p-0">{selectedDistrictId ? renderWardPanel(true) : <div className="flex h-full items-center justify-center text-muted-foreground">Chọn quận/huyện để xem phường/xã</div>}</CardContent></Card></div>)}

