// ✅ Update interface to match component
interface CounterInfo extends CounterTableRow {
  // Additional fields if needed
}

export function IDCounterSettingsPage() {
  const _router = useRouter();
  const [searchQuery, setSearchQuery] = React.useState('');
  const [selectedCategory, setSelectedCategory] = React.useState<string>('all');
  const [selectedEntity, setSelectedEntity] = React.useState<CounterInfo | null>(null);

  // Page header
  useSettingsPageHeader({
    title: 'Quản lý ID & Prefix',
    breadcrumb: [
      { label: 'Trang chủ', href: '/' },
      { label: 'Cài đặt', href: '/settings' },
      { label: 'Quản lý ID & Prefix', href: '/settings/id-counters', isCurrent: true },
    ],
  });

  // Fetch data from React Query hooks
  const { data: employeesData } = useEmployees({ limit: 10000 });
  const { data: customersData } = useCustomers({ limit: 10000 });
  const { data: complaintsData } = useComplaints({ limit: 10000 });
  const { data: warrantiesData } = useWarranties({ limit: 10000 });
  const { data: ordersData } = useOrders({ limit: 10000 });
  const { data: productsData } = useProducts({ limit: 10000 });
  const { data: branchesData } = useBranches();
  const { data: departmentsData } = useDepartments();
  const { data: jobTitlesData } = useJobTitles();
  const { data: penaltiesData } = usePenalties({ limit: 10000 });
  const { data: leavesData } = useLeaves({ limit: 10000 });
  const { data: suppliersData } = useSuppliers({ limit: 10000 });
  const { data: purchaseOrdersData } = usePurchaseOrders({ limit: 10000 });
  const { data: purchaseReturnsData } = usePurchaseReturns({ limit: 10000 });
  const { data: inventoryReceiptsData } = useInventoryReceipts({ limit: 10000 });
  const { data: receiptTypesData } = useReceiptTypes();
  const { data: paymentTypesData } = usePaymentTypes();
  const { data: paymentMethodsData } = usePaymentMethods();
  const { data: provincesData } = useProvinces();
  const { data: unitsData } = useUnits();

  // Gather counter data from React Query hooks
  const counterData = React.useMemo((): CounterInfo[] => {
    const data: CounterInfo[] = [];
    
    // Helper to add counter info
    const addCounter = (
      entityType: EntityType,
      counter: number,
      items: unknown[],
      lastItem?: { id?: string }
    ) => {
      const config = ID_CONFIG[entityType];
      if (!config) return;
      
      const nextId = `${config.prefix}${String(counter + 1).padStart(config.digitCount, '0')}`;
      
      // Health check
      let health: 'good' | 'warning' | 'error' = 'good';
      if (items.length > 0 && counter === 0) health = 'warning';
      if (items.length > counter + 10) health = 'warning'; // Counter too low
      
      data.push({
        entityType,
        config,
        currentCounter: counter,
        totalItems: items.length,
        nextId,
        lastCreated: lastItem?.id,
        health,
      });
    };

    // Employees
    const employees = employeesData?.data ?? [];
    addCounter('employees', 0, employees, employees[employees.length - 1]);

    // Customers
    const customers = customersData?.data ?? [];
    addCounter('customers', 0, customers, customers[customers.length - 1]);

    // Complaints
    const complaints = complaintsData?.data ?? [];
    addCounter('complaints', 0, complaints, complaints[complaints.length - 1]);

    // Warranty
    const warranties = warrantiesData?.data ?? [];
    addCounter('warranty', 0, warranties, warranties[warranties.length - 1]);

    // Orders
    const orders = ordersData?.data ?? [];
    addCounter('orders', 0, orders, orders[orders.length - 1]);

    // Products
    const products = productsData?.data ?? [];
    addCounter('products', 0, products, products[products.length - 1]);

    // Branches
    const branches = (branchesData as any)?.data ?? branchesData ?? [];
    addCounter('branches', 0, branches as any, branches[branches.length - 1]);

    // Departments
    const departments = (departmentsData as any)?.data ?? departmentsData ?? [];
    addCounter('departments', 0, departments as any, departments[departments.length - 1]);

    // Job Titles
    const jobTitles = (jobTitlesData as any)?.data ?? jobTitlesData ?? [];
    addCounter('job-titles', 0, jobTitles as any, jobTitles[jobTitles.length - 1]);

    // Penalties
    const penalties = penaltiesData?.data ?? [];
    addCounter('penalties', 0, penalties, penalties[penalties.length - 1]);

    // Leaves
    const leaves = leavesData?.data ?? [];
    addCounter('leaves', 0, leaves, leaves[leaves.length - 1]);

    // Suppliers
    const suppliers = suppliersData?.data ?? [];
    addCounter('suppliers', 0, suppliers, suppliers[suppliers.length - 1]);

    // Purchase Orders
    const purchaseOrders = purchaseOrdersData?.data ?? [];
    addCounter('purchase-orders', 0, purchaseOrders, purchaseOrders[purchaseOrders.length - 1]);

    // Purchase Returns
    const purchaseReturns = purchaseReturnsData?.data ?? [];
    addCounter('purchase-returns', 0, purchaseReturns, purchaseReturns[purchaseReturns.length - 1]);

    // Inventory Receipts
    const inventoryReceipts = inventoryReceiptsData?.data ?? [];
    addCounter('inventory-receipts', 0, inventoryReceipts, inventoryReceipts[inventoryReceipts.length - 1]);

    // Receipt Types
    const receiptTypes = (receiptTypesData as any)?.data ?? receiptTypesData ?? [];
    addCounter('receipt-types', 0, receiptTypes as any, receiptTypes[receiptTypes.length - 1]);

    // Payment Types
    const paymentTypes = (paymentTypesData as any)?.data ?? paymentTypesData ?? [];
    addCounter('payment-types', 0, paymentTypes as any, paymentTypes[paymentTypes.length - 1]);

    // Payment Methods
    const paymentMethods = (paymentMethodsData as any)?.data ?? paymentMethodsData ?? [];
    addCounter('payment-methods', 0, paymentMethods as any, paymentMethods[paymentMethods.length - 1]);

    // Provinces
    const provinces = (provincesData as any)?.data ?? provincesData ?? [];
    addCounter('provinces', 0, provinces as any, provinces[provinces.length - 1]);

    // Units
    const units = Array.isArray(unitsData) ? unitsData : (unitsData as any)?.items ?? [];
    addCounter('units', 0, units, units[units.length - 1]);

    return data;
  }, [
    employeesData,
    customersData,
    complaintsData,
    warrantiesData,
    ordersData,
    productsData,
    branchesData,
    departmentsData,
    jobTitlesData,
    penaltiesData,
    leavesData,
    suppliersData,
    purchaseOrdersData,
    purchaseReturnsData,
    inventoryReceiptsData,
    receiptTypesData,
    paymentTypesData,
    paymentMethodsData,
    provincesData,
    unitsData,
  ]);

  // Filter data
  const filteredData = React.useMemo(() => {
    let filtered = counterData;
    
    if (searchQuery) {
      filtered = filtered.filter(item => 
        item.config.displayName.toLowerCase().includes(searchQuery.toLowerCase()) ||
        item.config.prefix.toLowerCase().includes(searchQuery.toLowerCase()) ||
        item.entityType.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }
    
    if (selectedCategory !== 'all') {
      const categories = getEntityCategories();
      const categoryEntities = categories[selectedCategory] || [];
      filtered = filtered.filter(item => categoryEntities.includes(item.entityType as EntityType));
    }
    
    return filtered;
  }, [counterData, searchQuery, selectedCategory]);

  // Statistics
  const stats = React.useMemo(() => {
    const total = counterData.reduce((sum, item) => sum + item.totalItems, 0);
    const maxCounter = Math.max(...counterData.map(item => item.currentCounter));
    const withWarnings = counterData.filter(item => item.health === 'warning').length;
    const withErrors = counterData.filter(item => item.health === 'error').length;
    
    return {
      totalEntities: counterData.length,
      totalItems: total,
      maxCounter,
      withWarnings,
      withErrors,
    };
  }, [counterData]);

  const categories = getEntityCategories();

  return (
    <div className="space-y-6">
      {/* Statistics Cards - Using StatsCard component */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <StatsCard
          title="Entity Types"
          value={stats.totalEntities}
          description="Đang theo dõi"
          icon={Hash}
        />
        <StatsCard
          title="Tổng Records"
          value={stats.totalItems.toLocaleString()}
          description="Trên tất cả entities"
          icon={TrendingUp}
        />
        <StatsCard
          title="Counter cao nhất"
          value={stats.maxCounter}
          description="Số thứ tự"
          icon={RefreshCw}
        />
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-sm font-medium flex items-center gap-2">
              <CheckCircle2 className="h-4 w-4" />
              Health Status
            </CardTitle>
          </CardHeader>
          <CardContent>
            {stats.withErrors > 0 ? (
              <Badge variant="destructive">Lỗi: {stats.withErrors}</Badge>
            ) : stats.withWarnings > 0 ? (
              <Badge variant="secondary">Cảnh báo: {stats.withWarnings}</Badge>
            ) : (
              <Badge variant="default">Hoạt động tốt</Badge>
            )}
            <p className="text-xs text-muted-foreground mt-2">
              {stats.withErrors === 0 && stats.withWarnings === 0 ? 'Không có vấn đề' : 'Cần kiểm tra'}
            </p>
          </CardContent>
        </Card>
      </div>

      <Tabs defaultValue="counters" className="space-y-4">
        <TabsList>
          <TabsTrigger value="counters">Counters</TabsTrigger>
          <TabsTrigger value="tester">ID Tester</TabsTrigger>
          <TabsTrigger value="config">Configuration</TabsTrigger>
        </TabsList>

        {/* Counters Tab */}
        <TabsContent value="counters" className="space-y-4">
          {/* Filters */}
          <Card>
            <CardHeader>
              <CardTitle className="text-base">Bộ lọc</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="flex gap-4">
                <div className="flex-1">
                  <Label>Tìm kiếm</Label>
                  <div className="relative">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                    <Input
                      placeholder="Tìm theo tên, prefix, entity type..."
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
                      className="pl-9"
                    />
                  </div>
                </div>
                
                <div className="w-64">
                  <Label>Danh mục</Label>
                  <select
                    className="w-full h-9 rounded-md border border-input bg-background px-3 text-sm"
                    value={selectedCategory}
                    onChange={(e) => setSelectedCategory(e.target.value)}
                  >
                    <option value="all">Tất cả</option>
                    {Object.keys(categories).map(cat => (
                      <option key={cat} value={cat}>{cat}</option>
                    ))}
                  </select>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Counter Table - Using CounterTable component */}
          <Card>
            <CardHeader>
              <CardTitle>Chi tiết Counters</CardTitle>
              <CardDescription>
                {filteredData.length} entity types
              </CardDescription>
            </CardHeader>
            <CardContent>
              <CounterTable 
                data={filteredData} 
                onViewDetails={setSelectedEntity}
              />
            </CardContent>
          </Card>
        </TabsContent>

        {/* ID Tester Tab - Using IDTester component */}
        <TabsContent value="tester" className="space-y-4">
          <IDTester 
            defaultEntityType="employees"
            onTestResult={(result) => {
              if (result.valid) {
                toast.success('✅ ID hợp lệ!');
              } else {
                toast.error(`❌ ${result.error}`);
              }
            }}
          />
        </TabsContent>

        {/* Configuration Tab */}
        <TabsContent value="config" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Cấu hình ID</CardTitle>
              <CardDescription>Danh sách tất cả cấu hình prefix và format</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {Object.entries(getEntityCategories()).map(([category, entities]) => (
                  <div key={category}>
                    <h3 className="font-semibold text-sm mb-2">{category}</h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-2">
                      {entities.map(entityType => {
                        const config = ID_CONFIG[entityType];
                        if (!config) return null;
                        return (
                          <div key={entityType} className="p-3 border rounded-md space-y-2">
                            <div className="flex items-center justify-between">
                              <span className="text-sm font-medium">{config.displayName}</span>
                            </div>
                            
                            <div className="space-y-1">
                              <div className="flex items-center gap-2">
                                <span className="text-xs text-muted-foreground">SystemId:</span>
                                <Badge variant="outline" className="text-xs font-mono">{config.systemIdPrefix}</Badge>
                                <code className="text-xs text-blue-600">{config.systemIdPrefix}{'0'.repeat(config.digitCount - 1)}1</code>
                              </div>
                              
                              <div className="flex items-center gap-2">
                                <span className="text-xs text-muted-foreground">Business ID:</span>
                                <Badge variant="secondary" className="text-xs font-mono">{config.prefix}</Badge>
                                <code className="text-xs text-green-600">{config.prefix}{'0'.repeat(config.digitCount - 1)}1</code>
                              </div>
                            </div>
                            
                            <div className="text-xs text-muted-foreground">
                              Digits: {config.digitCount}
                            </div>
                            {config.validation?.allowCustomId && (
                              <Badge variant="secondary" className="text-[10px]">Custom ID OK</Badge>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      {/* Entity Detail Dialog */}
      <Dialog open={!!selectedEntity} onOpenChange={() => setSelectedEntity(null)}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{selectedEntity?.config.displayName}</DialogTitle>
            <DialogDescription>
              Chi tiết cấu hình và counter
            </DialogDescription>
          </DialogHeader>
          
          {selectedEntity && (
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label className="text-xs text-muted-foreground">Entity Type</Label>
                  <p className="font-mono text-sm">{selectedEntity.entityType}</p>
                </div>
                <div>
                  <Label className="text-xs text-muted-foreground">Prefix</Label>
                  <p className="font-mono text-sm">{selectedEntity.config.prefix}</p>
                </div>
                <div>
                  <Label className="text-xs text-muted-foreground">Current Counter</Label>
                  <p className="font-mono text-sm">{selectedEntity.currentCounter}</p>
                </div>
                <div>
                  <Label className="text-xs text-muted-foreground">Total Items</Label>
                  <p className="font-mono text-sm">{selectedEntity.totalItems}</p>
                </div>
                <div>
                  <Label className="text-xs text-muted-foreground">Next ID</Label>
                  <p className="font-mono text-sm">{selectedEntity.nextId}</p>
                </div>
                <div>
                  <Label className="text-xs text-muted-foreground">Digit Count</Label>
                  <p className="font-mono text-sm">{selectedEntity.config.digitCount}</p>
                </div>
                <div>
                  <Label className="text-xs text-muted-foreground">System ID Prefix</Label>
                  <p className="font-mono text-sm">{selectedEntity.config.systemIdPrefix}</p>
                </div>
                <div>
                  <Label className="text-xs text-muted-foreground">Custom ID Allowed</Label>
                  <p className="font-mono text-sm">
                    {selectedEntity.config.validation?.allowCustomId ? 'Yes' : 'No'}
                  </p>
                </div>
              </div>
              
              {selectedEntity.lastCreated && (
                <div>
                  <Label className="text-xs text-muted-foreground">Last Created ID</Label>
                  <code className="text-sm bg-muted px-2 py-1 rounded block mt-1">
                    {selectedEntity.lastCreated}
                  </code>
                </div>
              )}
              
              <div className="p-3 border rounded-md bg-muted/50">
                <p className="text-sm font-medium mb-1">Sample IDs:</p>
                <div className="space-y-1 text-xs font-mono">
                  <div>{selectedEntity.config.prefix}{String(1).padStart(selectedEntity.config.digitCount, '0')}</div>
                  <div>{selectedEntity.config.prefix}{String(100).padStart(selectedEntity.config.digitCount, '0')}</div>
                  <div>{selectedEntity.config.prefix}{String(999999).padStart(selectedEntity.config.digitCount, '0')}</div>
                </div>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

import * as React from "react";
import { Plus } from "lucide-react";
import { useTargetGroups, useTargetGroupMutations } from "./hooks/use-target-groups";
import type { TargetGroup } from '@/lib/types/prisma-extended';
import { TargetGroupForm, type TargetGroupFormValues } from "./form";
import { asBusinessId, type SystemId } from "@/lib/id-types";
import { Button } from "../../../components/ui/button";
import { Dialog, DialogContent, DialogFooter, DialogHeader, DialogTitle } from "../../../components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from "../../../components/ui/alert-dialog";
import { SimpleSettingsTable } from "../../../components/settings/SimpleSettingsTable";
import { getTargetGroupColumns } from "./columns";
import { toast } from "sonner";
import { SettingsActionButton } from "../../../components/settings/SettingsActionButton";
import type { RegisterTabActions } from "../use-tab-action-registry";

type TargetGroupsPageContentProps = {
  isActive: boolean;
  onRegisterActions: RegisterTabActions;
};

export function TargetGroupsPageContent({ isActive, onRegisterActions }: TargetGroupsPageContentProps) {
  const { data: queryData } = useTargetGroups({ limit: 1000 });
  const data = React.useMemo(() => queryData?.data ?? [], [queryData?.data]);
  const { create, update, remove } = useTargetGroupMutations({
    onSuccess: () => {},
    onError: (err) => toast.error(err.message)
  });
  
  const [isFormOpen, setIsFormOpen] = React.useState(false);
  const [editingItem, setEditingItem] = React.useState<TargetGroup | null>(null);
  const [isAlertOpen, setIsAlertOpen] = React.useState(false);
  const [idToDelete, setIdToDelete] = React.useState<SystemId | null>(null);
  
  const handleAddNew = React.useCallback(() => {
    setEditingItem(null);
    setIsFormOpen(true);
  }, []);

  const handleEdit = React.useCallback((item: TargetGroup) => { setEditingItem(item); setIsFormOpen(true); }, []);
  const handleDeleteRequest = React.useCallback((systemId: SystemId) => { 
    setIdToDelete(systemId);
    setIsAlertOpen(true);
  }, []);
  
  const handleToggleDefault = React.useCallback((item: TargetGroup, isDefault: boolean) => {
    if (isDefault) {
      // Tắt mặc định của tất cả các nhóm khác
      data.forEach(d => {
        if (d.systemId !== item.systemId && d.isDefault) {
          (update as any).mutate({ systemId: d.systemId, isDefault: false });
        }
      });
      (update as any).mutate({ systemId: item.systemId, isDefault: true });
      toast.success(`Đã đặt "${item.name}" làm mặc định`);
    } else {
      const other = data.find(d => d.systemId !== item.systemId && d.isActive !== false);
      if (other) {
        (update as any).mutate({ systemId: item.systemId, isDefault: false });
        (update as any).mutate({ systemId: other.systemId, isDefault: true });
        toast.success(`Đã chuyển mặc định sang "${other.name}"`);
      } else {
        toast.error("Phải có ít nhất một nhóm đối tượng mặc định");
      }
    }
  }, [data, update]);

  const handleToggleStatus = React.useCallback((item: TargetGroup, isActive: boolean) => {
    (update as any).mutate({ systemId: item.systemId, isActive });
    toast.success(isActive ? "Đã kích hoạt" : "Đã ngừng hoạt động");
  }, [data, update]);
  
  const confirmDelete = () => {
    if (idToDelete) {
      remove.mutate(idToDelete, {
        onSuccess: () => toast.success("Đã xóa thành công"),
        onError: (err) => toast.error(err.message)
      });
    }
    setIsAlertOpen(false);
    setIdToDelete(null);
  };
  
  const handleFormSubmit = (values: TargetGroupFormValues) => {
    try {
      const name = values.name.trim();
      const normalizedId = values.id?.trim().toUpperCase();
      if (editingItem) {
        update.mutate({
          systemId: editingItem.systemId,
          data: {
            name,
            id: normalizedId ? asBusinessId(normalizedId) : editingItem.id,
          }
        }, {
          onSuccess: () => toast.success("Cập nhật thành công"),
          onError: (err) => toast.error(err.message)
        });
      } else {
        create.mutate({
          id: normalizedId ? asBusinessId(normalizedId) : asBusinessId(""),
          name,
          isActive: true,
        }, {
          onSuccess: () => toast.success("Thêm mới thành công"),
          onError: (err) => toast.error(err.message)
        });
      }
      setIsFormOpen(false);
    } catch (error) {
      toast.error("Có lỗi xảy ra", {
        description: error instanceof Error ? error.message : "Lỗi không xác định",
      });
    }
  };

  React.useEffect(() => {
    if (!isActive) {
      return;
    }

    onRegisterActions([
      <SettingsActionButton key="add-target-group" onClick={handleAddNew}>
        <Plus className="mr-2 h-4 w-4" /> Thêm nhóm đối tượng
      </SettingsActionButton>,
    ]);
  }, [handleAddNew, isActive, onRegisterActions]);

  const columns = React.useMemo(
    () => getTargetGroupColumns({
      onEdit: handleEdit,
      onDelete: handleDeleteRequest,
      onToggleStatus: handleToggleStatus,
      onToggleDefault: handleToggleDefault,
    }),
    [handleEdit, handleDeleteRequest, handleToggleStatus, handleToggleDefault]
  );

  return (
    <div className="space-y-4">
      <div className="rounded-md border">
        <SimpleSettingsTable
          data={data}
          columns={columns}
          emptyTitle="Chưa có nhóm đối tượng"
          emptyDescription="Thêm nhóm đối tượng đầu tiên để phân loại"
          emptyAction={
            <Button size="sm" onClick={handleAddNew}>
              Thêm nhóm đối tượng
            </Button>
          }
        />
      </div>
      
      <Dialog open={isFormOpen} onOpenChange={setIsFormOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{editingItem ? 'Cập nhật nhóm đối tượng' : 'Thêm nhóm đối tượng'}</DialogTitle>
          </DialogHeader>
          <TargetGroupForm initialData={editingItem} onSubmit={handleFormSubmit} />
          <DialogFooter>
            <Button type="button" variant="outline" onClick={() => setIsFormOpen(false)}>Hủy</Button>
            <Button type="submit" form="target-group-form">Lưu</Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <AlertDialog open={isAlertOpen} onOpenChange={setIsAlertOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Xác nhận xóa?</AlertDialogTitle>
            <AlertDialogDescription>
              Hành động này không thể hoàn tác. Nhóm đối tượng sẽ bị xóa vĩnh viễn.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Hủy</AlertDialogCancel>
            <AlertDialogAction onClick={confirmDelete}>Xóa</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

import * as React from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '../../../../components/ui/card';
import { Label } from '../../../../components/ui/label';
import { Input } from '../../../../components/ui/input';
import { Button } from '../../../../components/ui/button';
import { Switch } from '../../../../components/ui/switch';
import { Badge } from '../../../../components/ui/badge';
import { Eye, EyeOff, RefreshCw, CheckCircle2, XCircle, Loader2, Save } from 'lucide-react';
import { toast } from 'sonner';
import { useTrendtechSettings, useTrendtechConfigMutations, useTrendtechSyncSettingsMutations, useTrendtechLogMutations } from '../hooks/use-trendtech-settings';
import { ping, testConnection } from '../../../../lib/trendtech/api-service';

export function GeneralConfigTab() {
  const { data: settings } = useTrendtechSettings();
  const { setApiUrl, setApiKey, setEnabled, setConnectionStatus } = useTrendtechConfigMutations({ onSuccess: () => {} });
  const { updateSyncSetting } = useTrendtechSyncSettingsMutations({ onSuccess: () => {} });
  const { addLog } = useTrendtechLogMutations();
  const [showApiKey, setShowApiKey] = React.useState(false);
  const [isTesting, setIsTesting] = React.useState(false);
  const [localApiUrl, setLocalApiUrl] = React.useState(settings?.apiUrl ?? '');
  const [localApiKey, setLocalApiKey] = React.useState(settings?.apiKey ?? '');
  
  // Update local state when settings change
  React.useEffect(() => {
    if (settings) {
      setLocalApiUrl(settings.apiUrl);
      setLocalApiKey(settings.apiKey);
    }
  }, [settings]);
  
  const handleSaveConfig = () => {
    setApiUrl.mutate(localApiUrl);
    setApiKey.mutate(localApiKey);
    addLog.mutate({
      action: 'save_config',
      status: 'success',
      message: 'Đã lưu cấu hình API',
      details: { url: localApiUrl },
    });
    toast.success('Đã lưu cấu hình API');
  };
  
  const handleTestConnection = async () => {
    if (!localApiKey) {
      toast.error('Vui lòng nhập API Key trước khi test');
      return;
    }
    
    if (!localApiUrl) {
      toast.error('Vui lòng nhập API URL trước khi test');
      return;
    }
    
    setIsTesting(true);
    const startTime = Date.now();
    
    try {
      // Save config first so API service can use it
      setApiUrl.mutate(localApiUrl);
      setApiKey.mutate(localApiKey);
      
      // Step 1: Ping server
      const pingResult = await (ping as any)();
      
      if (!pingResult.success) {
        addLog.mutate({
          action: 'ping',
          status: 'error',
          message: `Server không phản hồi: ${pingResult.error}`,
          details: { url: localApiUrl, error: pingResult.error },
        });
        throw new Error(pingResult.error || 'Server không phản hồi');
      }
      
      addLog.mutate({
        action: 'ping',
        status: 'success',
        message: 'Server hoạt động',
        details: { url: localApiUrl, responseTime: Date.now() - startTime },
      });
      
      // Step 2: Test với API key
      const testStartTime = Date.now();
      const testResult = await (testConnection as any)();
      
      if (testResult.success && testResult.data) {
        setConnectionStatus.mutate({ status: 'connected' });
        const stats = testResult.data.stats;
        addLog.mutate({
          action: 'test_connection',
          status: 'success',
          message: `Kết nối thành công! SP: ${stats?.totalProducts || 0}, DM: ${stats?.totalCategories || 0}, TH: ${stats?.totalBrands || 0}`,
          details: { 
            url: localApiUrl, 
            responseTime: Date.now() - testStartTime,
            total: stats?.totalProducts || 0,
          },
        });
        toast.success(`Kết nối thành công! Sản phẩm: ${stats?.totalProducts || 0}, Danh mục: ${stats?.totalCategories || 0}`);
      } else {
        setConnectionStatus.mutate({ status: 'error', error: testResult.error });
        addLog.mutate({
          action: 'test_connection',
          status: 'error',
          message: `Lỗi xác thực: ${testResult.error}`,
          details: { url: localApiUrl, error: testResult.error },
        });
        toast.error(`Lỗi: ${testResult.error}`);
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : 'Không thể kết nối';
      setConnectionStatus.mutate({ status: 'error', error: errorMessage });
      addLog.mutate({
        action: 'test_connection',
        status: 'error',
        message: `Lỗi kết nối: ${errorMessage}`,
        details: { error: errorMessage, responseTime: Date.now() - startTime },
      });
      toast.error(`Không thể kết nối đến server Trendtech: ${errorMessage}`);
    } finally {
      setIsTesting(false);
    }
  };
  
  const getStatusBadge = () => {
    switch (settings?.connectionStatus) {
      case 'connected':
        return <Badge variant="default" className="bg-green-500"><CheckCircle2 className="h-3 w-3 mr-1" />Đã kết nối</Badge>;
      case 'error':
        return <Badge variant="destructive"><XCircle className="h-3 w-3 mr-1" />Lỗi kết nối</Badge>;
      default:
        return <Badge variant="secondary">Chưa kết nối</Badge>;
    }
  };

  return (
    <div className="space-y-6">
      {/* API Connection Card */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Thông tin kết nối API</CardTitle>
          <CardDescription>Cấu hình kết nối với website Trendtech (Next.js)</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="apiUrl">API URL</Label>
            <Input
              id="apiUrl"
              value={localApiUrl}
              onChange={(e) => setLocalApiUrl(e.target.value)}
              placeholder="https://trendtech.vn/api/hrm"
            />
            <p className="text-sm text-muted-foreground">
              URL API endpoint của Trendtech (VD: https://trendtech.vn/api/hrm)
            </p>
          </div>
          
          <div className="space-y-2">
            <Label htmlFor="apiKey">API Key</Label>
            <div className="flex gap-2">
              <div className="relative flex-1">
                <Input
                  id="apiKey"
                  type={showApiKey ? 'text' : 'password'}
                  value={localApiKey}
                  onChange={(e) => setLocalApiKey(e.target.value)}
                  placeholder="Nhập API Key..."
                  className="pr-10"
                />
                <Button
                  type="button"
                  variant="ghost"
                  size="icon"
                  className="absolute right-0 top-0 h-full"
                  onClick={() => setShowApiKey(!showApiKey)}
                >
                  {showApiKey ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                </Button>
              </div>
            </div>
          </div>
          
          <div className="flex items-center gap-2 pt-2">
            <Button onClick={handleSaveConfig} variant="default">
              <Save className="h-4 w-4 mr-2" />
              Lưu cấu hình
            </Button>
            <Button onClick={handleTestConnection} variant="outline" disabled={isTesting}>
              {isTesting ? (
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
              ) : (
                <RefreshCw className="h-4 w-4 mr-2" />
              )}
              Test Connection
            </Button>
          </div>
          
          <div className="flex items-center gap-2 pt-2">
            <span className="text-sm text-muted-foreground">Trạng thái:</span>
            {getStatusBadge()}
          </div>
        </CardContent>
      </Card>

      {/* Integration Status Card */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Trạng thái tích hợp</CardTitle>
          <CardDescription>Bật/tắt đồng bộ với Trendtech</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-center justify-between">
            <div>
              <Label className="text-base">Bật tích hợp Trendtech</Label>
              <p className="text-sm text-muted-foreground">Cho phép đồng bộ sản phẩm với website</p>
            </div>
            <Switch
              checked={settings?.enabled ?? false}
              onCheckedChange={(checked) => {
                setEnabled.mutate(checked);
                addLog.mutate({
                  action: 'save_config',
                  status: 'info',
                  message: checked ? 'Đã bật tích hợp Trendtech' : 'Đã tắt tích hợp Trendtech',
                  details: {},
                });
                toast.success(checked ? 'Đã bật tích hợp Trendtech' : 'Đã tắt tích hợp Trendtech');
              }}
            />
          </div>
          
          <div className="flex items-center justify-between">
            <div>
              <Label className="text-base">Bật Auto Sync</Label>
              <p className="text-sm text-muted-foreground">Tự động đồng bộ dữ liệu theo lịch</p>
            </div>
            <Switch
              checked={settings?.syncSettings?.autoSyncEnabled ?? false}
              onCheckedChange={(checked) => {
                updateSyncSetting.mutate({ key: 'autoSyncEnabled', value: checked });
                addLog.mutate({
                  action: 'save_config',
                  status: 'info',
                  message: checked ? 'Đã bật Auto Sync' : 'Đã tắt Auto Sync',
                  details: {},
                });
              }}
              disabled={!settings?.enabled}
            />
          </div>
        </CardContent>
      </Card>
      
      {/* Info Card */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Hướng dẫn cài đặt</CardTitle>
        </CardHeader>
        <CardContent className="space-y-3 text-sm text-muted-foreground">
          <p>
            <strong>1.</strong> Trendtech cần có các API endpoints tại <code>/api/hrm/*</code>
          </p>
          <p>
            <strong>2.</strong> API endpoints cần thiết:
          </p>
          <ul className="list-disc list-inside ml-4 space-y-1">
            <li><code>GET /api/hrm/ping</code> - Kiểm tra server</li>
            <li><code>GET /api/hrm/test</code> - Test với API Key</li>
            <li><code>GET /api/hrm/products</code> - Lấy danh sách sản phẩm</li>
            <li><code>POST /api/hrm/products</code> - Tạo sản phẩm</li>
            <li><code>PUT /api/hrm/products/[id]</code> - Cập nhật sản phẩm</li>
            <li><code>GET /api/hrm/categories</code> - Lấy danh mục</li>
            <li><code>GET /api/hrm/brands</code> - Lấy thương hiệu</li>
          </ul>
          <p>
            <strong>3.</strong> Authentication: Header <code>Authorization: Bearer YOUR_API_KEY</code>
          </p>
        </CardContent>
      </Card>
    </div>
  );
}

/**
 * Trendtech Settings Store - Sync Slice
 * Sync actions, logs, status, and products cache
 * 
 * @module features/settings/trendtech/store/sync-slice
 */

import type { 
  TrendtechSettings, 
  TrendtechSyncSettings, 
  TrendtechSyncResult, 
  TrendtechSyncLog,
  TrendtechCategory,
  TrendtechBrand,
  TrendtechProduct,
} from './types';
import { getCategories as fetchTrendtechCategories, getBrands as fetchTrendtechBrands } from '../../../../lib/trendtech/api-service';

type StateWithSettings = { settings: TrendtechSettings };

// ========================================
// Sync Settings Actions
// ========================================

export const syncSettingsActions = {
  setSyncSettings: (state: StateWithSettings, syncSettings: TrendtechSyncSettings) => ({
    settings: { ...state.settings, syncSettings },
  }),
  
  updateSyncSetting: <K extends keyof TrendtechSyncSettings>(
    state: StateWithSettings,
    key: K,
    value: TrendtechSyncSettings[K]
  ) => ({
    settings: {
      ...state.settings,
      syncSettings: {
        ...state.settings.syncSettings,
        [key]: value,
      },
    },
  }),
};

// ========================================
// Log Actions
// ========================================

export const createAddLogAction = (
  set: (fn: (state: StateWithSettings) => Partial<StateWithSettings>) => void
) => (log: Omit<TrendtechSyncLog, 'id' | 'timestamp'>) => {
  const newLog: TrendtechSyncLog = {
    ...log,
    id: `log-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`,
    timestamp: new Date().toISOString(),
  };
  
  set((state) => ({
    settings: {
      ...state.settings,
      logs: [newLog, ...state.settings.logs].slice(0, 100),
    },
  }));
};

export const logActions = {
  clearLogs: (state: StateWithSettings) => ({
    settings: { ...state.settings, logs: [] },
  }),
};

// ========================================
// Sync Actions
// ========================================

export const createSyncCategoriesAction = (
  get: () => StateWithSettings & { 
    addLog: (log: Omit<TrendtechSyncLog, 'id' | 'timestamp'>) => void;
    setCategories: (categories: TrendtechCategory[]) => void;
  }
) => async (apiSettings?: any) => {
  const { addLog, setCategories } = get();
  try {
    const response = await (fetchTrendtechCategories as any)(apiSettings);
    if (response.success && response.data) {
      const categories = response.data.categories;
      setCategories(categories);
      addLog({
        action: 'sync_categories',
        status: 'success',
        message: `Đã đồng bộ ${categories.length} danh mục từ Trendtech`,
        details: { total: categories.length, success: categories.length, failed: 0 },
      });
    } else {
      throw new Error(response.error || 'Không thể lấy danh sách danh mục');
    }
  } catch (error) {
    addLog({
      action: 'sync_categories',
      status: 'error',
      message: 'Lỗi khi đồng bộ danh mục từ Trendtech',
      details: { error: error instanceof Error ? error.message : String(error) },
    });
    throw error;
  }
};

export const createSyncBrandsAction = (
  get: () => StateWithSettings & { 
    addLog: (log: Omit<TrendtechSyncLog, 'id' | 'timestamp'>) => void;
    setBrands: (brands: TrendtechBrand[]) => void;
  }
) => async (apiSettings?: any) => {
  const { addLog, setBrands } = get();
  try {
    const response = await (fetchTrendtechBrands as any)(apiSettings);
    if (response.success && response.data) {
      const brands = response.data.brands;
      setBrands(brands);
      addLog({
        action: 'sync_brands',
        status: 'success',
        message: `Đã đồng bộ ${brands.length} thương hiệu từ Trendtech`,
        details: { total: brands.length, success: brands.length, failed: 0 },
      });
    } else {
      throw new Error(response.error || 'Không thể lấy danh sách thương hiệu');
    }
  } catch (error) {
    addLog({
      action: 'sync_brands',
      status: 'error',
      message: 'Lỗi khi đồng bộ thương hiệu từ Trendtech',
      details: { error: error instanceof Error ? error.message : String(error) },
    });
    throw error;
  }
};

// ========================================
// Products Cache Actions
// ========================================

export const productsActions = {
  setTrendtechProducts: (state: StateWithSettings, products: TrendtechProduct[]) => ({
    settings: {
      ...state.settings,
      trendtechProducts: products,
      trendtechProductsLastFetch: new Date().toISOString(),
    },
  }),
  
  clearTrendtechProducts: (state: StateWithSettings) => ({
    settings: {
      ...state.settings,
      trendtechProducts: [],
      trendtechProductsLastFetch: undefined,
    },
  }),
};

// ========================================
// Status Actions
// ========================================

export const statusActions = {
  setLastSyncAt: (state: StateWithSettings, timestamp: string) => ({
    settings: { ...state.settings, lastSyncAt: timestamp },
  }),
  
  setLastSyncResult: (state: StateWithSettings, result: TrendtechSyncResult) => ({
    settings: { ...state.settings, lastSyncResult: result },
  }),
  
  setConnectionStatus: (
    state: StateWithSettings, 
    status: 'connected' | 'disconnected' | 'error', 
    error?: string
  ) => ({
    settings: {
      ...state.settings,
      connectionStatus: status,
      connectionError: error,
    },
  }),
};

