type _WarrantySettingsState = {
  sla: SLASettings;
  templates: ResponseTemplate[];
  notifications: NotificationSettings;
  publicTracking: PublicTrackingSettings;
  cardColors: CardColorSettings;
};

const _clone = <T,>(value: T): T => {
  if (typeof structuredClone === 'function') {
    return structuredClone(value);
  }
  return JSON.parse(JSON.stringify(value));
};

import { useWarrantySettings, useWarrantySettingsMutations, loadCardColorSettings } from './hooks/use-warranty-settings';

export { loadCardColorSettings };

// ============================================
// MAIN COMPONENT
// ============================================

export function WarrantySettingsPage() {
  const [activeTab, setActiveTab] = React.useState('sla');
  const { headerActions, registerActions } = useTabActionRegistry(activeTab);

  // Fetch settings from React Query
  const { data: settings, isLoading: _isLoadingSettings } = useWarrantySettings();
  const { updateSection } = useWarrantySettingsMutations();

  const registerSlaActions = React.useMemo(() => registerActions('sla'), [registerActions]);
  const registerTemplateActions = React.useMemo(() => registerActions('templates'), [registerActions]);
  const registerNotificationActions = React.useMemo(() => registerActions('notifications'), [registerActions]);
  const registerPublicTrackingActions = React.useMemo(() => registerActions('public-tracking'), [registerActions]);
  const registerCardColorActions = React.useMemo(() => registerActions('card-colors'), [registerActions]);

  // Get stored values from React Query
  const storedSla = settings.sla;
  const storedTemplates = settings.templates as ResponseTemplate[];
  const storedNotifications = settings.notifications;
  const storedPublicTracking = settings.publicTracking;
  const storedCardColors = settings.cardColors;

  // SLA State - cast to proper type
  const [sla, setSLA] = React.useState<SLASettings>(storedSla as any);

  // Templates State
  const [templates, setTemplates] = React.useState<ResponseTemplate[]>(storedTemplates);
  const [editingTemplate, setEditingTemplate] = React.useState<ResponseTemplate | null>(null);
  const [isAddingTemplate, setIsAddingTemplate] = React.useState(false);
  const [showDeleteDialog, setShowDeleteDialog] = React.useState(false);
  const [templateToDelete, setTemplateToDelete] = React.useState<string | null>(null);
  const [showEditDialog, setShowEditDialog] = React.useState(false);

  // Notifications State
  const [notifications, setNotifications] = React.useState<NotificationSettings>(storedNotifications as any);

  // Public Tracking State
  const [publicTracking, setPublicTracking] = React.useState<PublicTrackingSettings>(storedPublicTracking);

  // Card Colors State
  const [cardColors, setCardColors] = React.useState<CardColorSettings>(storedCardColors as any);

  React.useEffect(() => {
    setSLA(storedSla as any);
  }, [storedSla]);

  React.useEffect(() => {
    setTemplates(storedTemplates);
  }, [storedTemplates]);

  React.useEffect(() => {
    setNotifications(storedNotifications as any);
  }, [storedNotifications]);

  React.useEffect(() => {
    setPublicTracking(storedPublicTracking);
  }, [storedPublicTracking]);

  React.useEffect(() => {
    setCardColors(storedCardColors as any);
  }, [storedCardColors]);

  useSettingsPageHeader({
    title: 'Cài đặt bảo hành',
    actions: headerActions,
  });

  // ============================================
  // SLA HANDLERS
  // ============================================

  const handleSLAChange = (priority: keyof SLASettings, field: 'responseTime' | 'resolveTime', value: string) => {
    const numValue = parseInt(value) || 0;
    setSLA(prev => ({
      ...prev,
      [priority]: {
        ...prev[priority],
        [field]: numValue,
      }
    }));
  };

  const handleSaveSLA = () => {
    // Validation
    const priorities: Array<keyof SLASettings> = ['low', 'medium', 'high', 'urgent'];
    for (const priority of priorities) {
      if (sla[priority].responseTime <= 0) {
        toast.error('Lỗi validation', {
          description: `Thời gian phản hồi cho mức ${priority} phải lớn hơn 0`,
        });
        return;
      }
      if (sla[priority].resolveTime <= 0) {
        toast.error('Lỗi validation', {
          description: `Thời gian xử lý cho mức ${priority} phải lớn hơn 0`,
        });
        return;
      }
    }

    updateSection.mutate(
      { type: 'sla-targets', data: sla as any },
      {
        onSuccess: () => {
          toast.success('Đã lưu cài đặt SLA', {
            description: 'Thời gian phản hồi và giải quyết đã được cập nhật.',
          });
        },
      }
    );
  };

  const _handleResetSLA = () => {
    const defaults = clone(defaultSLA);
    setSLA(defaults);
    updateSection.mutate(
      { type: 'sla-targets', data: defaults as any },
      {
        onSuccess: () => {
          toast.info('Đã đặt lại mặc định', {
            description: 'Cài đặt SLA đã được khôi phục về giá trị mặc định.',
          });
        },
      }
    );
  };

  // ============================================
  // TEMPLATE HANDLERS
  // ============================================

  const handleAddTemplate = () => {
    setEditingTemplate({
      id: Date.now().toString(),
      name: '',
      content: '',
      category: 'general',
      order: templates.length + 1,
    });
    setIsAddingTemplate(true);
    setShowEditDialog(true);
  };

  const handleSaveTemplate = () => {
    if (!editingTemplate) return;

    // Validation
    if (!editingTemplate.name.trim()) {
      toast.error('Lỗi validation', {
        description: 'Vui lòng nhập tên mẫu.',
      });
      return;
    }

    if (!editingTemplate.content.trim()) {
      toast.error('Lỗi validation', {
        description: 'Vui lòng nhập nội dung mẫu.',
      });
      return;
    }

    let updatedTemplates: ResponseTemplate[];
    
    if (isAddingTemplate) {
      updatedTemplates = [...templates, editingTemplate];
    } else {
      updatedTemplates = templates.map(t => 
        t.id === editingTemplate.id ? editingTemplate : t
      );
    }

    setTemplates(updatedTemplates);
    updateSection.mutate(
      { type: 'reminder-templates', data: updatedTemplates },
      {
        onSuccess: () => {
          toast.success(isAddingTemplate ? 'Đã thêm mẫu' : 'Đã cập nhật mẫu', {
            description: `Mẫu "${editingTemplate.name}" đã được lưu.`,
          });
        },
      }
    );

    setEditingTemplate(null);
    setIsAddingTemplate(false);
    setShowEditDialog(false);
  };

  const handleDeleteTemplate = (id: string) => {
    setTemplateToDelete(id);
    setShowDeleteDialog(true);
  };

  const confirmDeleteTemplate = () => {
    if (!templateToDelete) return;
    
    const template = templates.find(t => t.id === templateToDelete);
    const updatedTemplates = templates.filter(t => t.id !== templateToDelete);
    setTemplates(updatedTemplates);
    updateSection.mutate(
      { type: 'reminder-templates', data: updatedTemplates },
      {
        onSuccess: () => {
          toast.success('Đã xóa mẫu', {
            description: `Mẫu "${template?.name}" đã được xóa.`,
          });
        },
      }
    );
    
    setShowDeleteDialog(false);
    setTemplateToDelete(null);
  };

  const handleCancelEdit = () => {
    setEditingTemplate(null);
    setIsAddingTemplate(false);
    setShowEditDialog(false);
  };

  // ============================================
  // NOTIFICATION HANDLERS
  // ============================================

  const handleNotificationChange = (key: keyof NotificationSettings) => {
    setNotifications(prev => ({
      ...prev,
      [key]: !prev[key],
    }));
  };

  const handleSaveNotifications = () => {
    updateSection.mutate(
      { type: 'notifications', data: notifications as any },
      {
        onSuccess: () => {
          toast.success('Đã lưu cài đặt thông báo', {
            description: 'Các tùy chọn thông báo đã được cập nhật.',
          });
        },
      }
    );
  };

  // ============================================
  // PUBLIC TRACKING HANDLERS
  // ============================================

  const handlePublicTrackingChange = (key: keyof PublicTrackingSettings) => {
    setPublicTracking(prev => ({
      ...prev,
      [key]: !prev[key],
    }));
  };

  const handleSavePublicTracking = () => {
    updateSection.mutate(
      { type: 'tracking', data: publicTracking },
      {
        onSuccess: () => {
          // Show different message based on enabled state
          if (publicTracking.enabled) {
            toast.success('Đã bật tracking công khai', {
              description: 'Khách hàng giờ có thể theo dõi tiến độ bảo hành qua link công khai.',
            });
          } else {
            toast.success('Đã tắt tracking công khai', {
              description: 'Tính năng tracking công khai đã được vô hiệu hóa.',
            });
          }
        },
      }
    );
  };

  // ============================================
  // CARD COLOR HANDLERS
  // ============================================

  const handleCardColorChange = (category: 'statusColors' | 'overdueColor', key: string, value: string) => {
    if (category === 'overdueColor') {
      setCardColors(prev => ({ ...prev, overdueColor: value }));
    } else {
      setCardColors(prev => ({
        ...prev,
        statusColors: { ...prev.statusColors, [key]: value }
      }));
    }
  };

  const handleCardColorToggle = (key: 'enableStatusColors' | 'enableOverdueColor') => {
    setCardColors(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const handleSaveCardColors = () => {
    updateSection.mutate(
      { type: 'cardColors', data: cardColors },
      {
        onSuccess: () => {
          toast.success('Đã lưu màu card', {
            description: 'Cài đặt màu sắc card bảo hành đã được cập nhật. Refresh trang để xem thay đổi.',
          });
        },
      }
    );
  };

  const _handleResetCardColors = () => {
    const defaults = clone(defaultCardColors);
    setCardColors(defaults);
    updateSection.mutate(
      { type: 'cardColors', data: defaults },
      {
        onSuccess: () => {
          toast.info('Đã đặt lại mặc định', {
            description: 'Màu card đã được khôi phục về giá trị mặc định.',
          });
        },
      }
    );
  };

  // ============================================
  // RENDER
  // ============================================

    React.useEffect(() => {
      if (activeTab !== 'sla') {
        return;
      }

      registerSlaActions([
        <SettingsActionButton key="save" onClick={handleSaveSLA}>
          <Save className="h-4 w-4" /> Lưu cài đặt
        </SettingsActionButton>,
      ]);
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [activeTab, registerSlaActions]);

    React.useEffect(() => {
      if (activeTab !== 'templates') {
        return;
      }

      registerTemplateActions([
        <SettingsActionButton key="add" onClick={handleAddTemplate}>
          <Plus className="h-4 w-4" /> Thêm mẫu
        </SettingsActionButton>,
      ]);
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [activeTab, registerTemplateActions]);

    React.useEffect(() => {
      if (activeTab !== 'notifications') {
        return;
      }

      registerNotificationActions([
        <SettingsActionButton key="save" onClick={handleSaveNotifications}>
          <Save className="h-4 w-4" /> Lưu cài đặt
        </SettingsActionButton>,
      ]);
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [activeTab, registerNotificationActions]);

    React.useEffect(() => {
      if (activeTab !== 'public-tracking') {
        return;
      }

      registerPublicTrackingActions([
        <SettingsActionButton key="save" onClick={handleSavePublicTracking}>
          <Save className="h-4 w-4" /> Lưu cài đặt
        </SettingsActionButton>,
      ]);
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [activeTab, registerPublicTrackingActions]);

    React.useEffect(() => {
      if (activeTab !== 'card-colors') {
        return;
      }

      registerCardColorActions([
        <SettingsActionButton key="save" onClick={handleSaveCardColors}>
          <Save className="h-4 w-4" /> Lưu cài đặt
        </SettingsActionButton>,
      ]);
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [activeTab, registerCardColorActions]);

  const tabs = React.useMemo(
    () => [
      { value: 'sla', label: 'SLA' },
      { value: 'templates', label: 'Mẫu biểu' },
      { value: 'notifications', label: 'Thông báo' },
      { value: 'public-tracking', label: 'Tracking' },
      { value: 'card-colors', label: 'Màu card' },
    ],
    [],
  );

  return (
      <div className="space-y-6">
        <SettingsVerticalTabs value={activeTab} onValueChange={setActiveTab} tabs={tabs}>

        {/* ============================================ */}
        {/* TAB 1: SLA SETTINGS */}
        {/* ============================================ */}
        <TabsContent value="sla" className="mt-0 space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Cài đặt SLA (Service Level Agreement)</CardTitle>
              <CardDescription>
                Thiết lập thời gian phản hồi và xử lý bảo hành theo mức độ ưu tiên
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
              {WARRANTY_SLA_PRIORITY_CONFIGS.map(({ key, label, description, indicatorClass }) => (
                <SettingsFormSection
                  key={key}
                  title={label}
                  description={description}
                  badge={(
                    <span className="inline-flex items-center gap-2 rounded-full border px-3 py-1 text-xs font-medium">
                      <span className={cn('h-2 w-2 rounded-full', indicatorClass)} />
                      SLA
                    </span>
                  )}
                >
                  <SettingsFormGrid>
                    <div className="space-y-2">
                      <Label htmlFor={`${key}-response`}>Thời gian phản hồi tối đa (phút)</Label>
                      <Input
                        id={`${key}-response`}
                        type="number"
                        min="0"
                        value={sla[key].responseTime}
                        onChange={(e) => handleSLAChange(key, 'responseTime', e.target.value)}
                      />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor={`${key}-resolve`}>Thời gian xử lý tối đa (giờ)</Label>
                      <Input
                        id={`${key}-resolve`}
                        type="number"
                        min="0"
                        value={sla[key].resolveTime}
                        onChange={(e) => handleSLAChange(key, 'resolveTime', e.target.value)}
                      />
                    </div>
                  </SettingsFormGrid>
                </SettingsFormSection>
              ))}
            </CardContent>
          </Card>

          {/* Simple Warranty SLA Targets Card */}
          <Card>
            <CardHeader>
              <CardTitle>Mục tiêu SLA đơn giản</CardTitle>
              <CardDescription>
                Cấu hình thời gian xử lý chuẩn cho toàn bộ phiếu bảo hành
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid gap-4 md:grid-cols-3">
                <div className="space-y-2">
                  <Label htmlFor="sla-response">
                    Phản hồi (phút)
                    <span className="text-xs text-muted-foreground block">
                      Nhận → Bắt đầu xử lý
                    </span>
                  </Label>
                  <Input
                    id="sla-response"
                    type="number"
                    defaultValue="120"
                    placeholder="120"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="sla-processing">
                    Xử lý (phút)
                    <span className="text-xs text-muted-foreground block">
                      Hoàn tất xử lý SP
                    </span>
                  </Label>
                  <Input
                    id="sla-processing"
                    type="number"
                    defaultValue="1440"
                    placeholder="1440"
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="sla-return">
                    Trả hàng (phút)
                    <span className="text-xs text-muted-foreground block">
                      Hoàn thành → Trả khách
                    </span>
                  </Label>
                  <Input
                    id="sla-return"
                    type="number"
                    defaultValue="2880"
                    placeholder="2880"
                  />
                </div>
              </div>
              <Button variant="outline" className="w-full">
                <Save className="h-4 w-4 mr-2" />
                Lưu SLA đơn giản
              </Button>
            </CardContent>
          </Card>
        </TabsContent>

        {/* ============================================ */}
        {/* TAB 2: RESPONSE TEMPLATES */}
        {/* ============================================ */}
        <TabsContent value="templates" className="mt-0 space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Mẫu phản hồi</CardTitle>
              <CardDescription>
                Tạo và quản lý các mẫu phản hồi nhanh cho bảo hành
              </CardDescription>
            </CardHeader>
            <CardContent>
              {templates.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground">
                  Chưa có mẫu phản hồi nào. Nhấn "Thêm mẫu" để tạo mẫu mới.
                </div>
              ) : (
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Tên mẫu</TableHead>
                      <TableHead>Danh mục</TableHead>
                      <TableHead className="text-right">Thao tác</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {templates.map(template => (
                      <TableRow key={template.id}>
                        <TableCell className="font-medium">{template.name}</TableCell>
                        <TableCell>
                          <span className="text-xs px-2 py-1 rounded-md bg-muted">
                            {template.category === 'general' && 'Chung'}
                            {template.category === 'processing-error' && 'Lỗi xử lý'}
                            {template.category === 'customer-damage' && 'Lỗi khách hàng'}
                            {template.category === 'inspection-result' && 'Kết quả kiểm tra'}
                            {template.category === 'warranty-approved' && 'Chấp nhận BH'}
                            {template.category === 'warranty-rejected' && 'Từ chối BH'}
                          </span>
                        </TableCell>
                        <TableCell className="text-right">
                          <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                              <Button variant="ghost" size="icon" className="h-8 w-8">
                                <MoreHorizontal className="h-4 w-4" />
                              </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end">
                              <DropdownMenuItem onClick={() => {
                                setEditingTemplate(template);
                                setIsAddingTemplate(false);
                                setShowEditDialog(true);
                              }}>
                                Sửa
                              </DropdownMenuItem>
                              <DropdownMenuSeparator />
                              <DropdownMenuItem 
                                onClick={() => handleDeleteTemplate(template.id)}
                                className="text-destructive focus:text-destructive"
                              >
                                Xóa
                              </DropdownMenuItem>
                            </DropdownMenuContent>
                          </DropdownMenu>
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        {/* ============================================ */}
        {/* TAB 3: NOTIFICATIONS */}
        {/* ============================================ */}
        <TabsContent value="notifications" className="mt-0 space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Cài đặt thông báo</CardTitle>
              <CardDescription>
                Quản lý thông báo qua email, SMS và in-app cho các sự kiện bảo hành
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
              <SettingsFormSection
                title="Thông báo Email"
                description="Gửi cập nhật đến khách hàng và đội bảo hành cho từng giai đoạn."
                badge={<Bell className="h-4 w-4 text-muted-foreground" />}
                contentClassName="space-y-3"
              >
                <div className="space-y-3">
                  <div className="flex items-center justify-between">
                    <Label htmlFor="email-create" className="cursor-pointer">
                      Khi bảo hành mới được tạo
                    </Label>
                    <Switch
                      id="email-create"
                      checked={notifications.emailOnCreate}
                      onCheckedChange={() => handleNotificationChange('emailOnCreate')}
                    />
                  </div>

                  <div className="flex items-center justify-between">
                    <Label htmlFor="email-assign" className="cursor-pointer">
                      Khi được phân công xử lý
                    </Label>
                    <Switch
                      id="email-assign"
                      checked={notifications.emailOnAssign}
                      onCheckedChange={() => handleNotificationChange('emailOnAssign')}
                    />
                  </div>

                  <div className="flex items-center justify-between">
                    <Label htmlFor="email-inspected" className="cursor-pointer">
                      Khi hoàn thành kiểm tra
                    </Label>
                    <Switch
                      id="email-inspected"
                      checked={notifications.emailOnInspected}
                      onCheckedChange={() => handleNotificationChange('emailOnInspected')}
                    />
                  </div>

                  <div className="flex items-center justify-between">
                    <Label htmlFor="email-approved" className="cursor-pointer">
                      Khi chấp nhận bảo hành
                    </Label>
                    <Switch
                      id="email-approved"
                      checked={notifications.emailOnApproved}
                      onCheckedChange={() => handleNotificationChange('emailOnApproved')}
                    />
                  </div>

                  <div className="flex items-center justify-between">
                    <Label htmlFor="email-rejected" className="cursor-pointer">
                      Khi từ chối bảo hành
                    </Label>
                    <Switch
                      id="email-rejected"
                      checked={notifications.emailOnRejected}
                      onCheckedChange={() => handleNotificationChange('emailOnRejected')}
                    />
                  </div>

                  <div className="flex items-center justify-between">
                    <Label htmlFor="email-overdue" className="cursor-pointer">
                      Khi bảo hành quá hạn SLA
                    </Label>
                    <Switch
                      id="email-overdue"
                      checked={notifications.emailOnOverdue}
                      onCheckedChange={() => handleNotificationChange('emailOnOverdue')}
                    />
                  </div>
                </div>
              </SettingsFormSection>

              <SettingsFormSection
                title="Thông báo SMS"
                description="Chỉ bật cho các sự kiện cần phản hồi tức thì để tránh spam."
                badge={<AlertCircle className="h-4 w-4 text-muted-foreground" />}
              >
                <div className="flex items-center justify-between">
                  <Label htmlFor="sms-overdue" className="cursor-pointer">
                    Cảnh báo quá hạn SLA
                  </Label>
                  <Switch
                    id="sms-overdue"
                    checked={notifications.smsOnOverdue}
                    onCheckedChange={() => handleNotificationChange('smsOnOverdue')}
                  />
                </div>
              </SettingsFormSection>

              <SettingsFormSection
                title="Thông báo trong ứng dụng"
                description="Hiển thị trong bell icon của hệ thống HRM."
                badge={<Bell className="h-4 w-4 text-muted-foreground" />}
              >
                <div className="flex items-center justify-between">
                  <Label htmlFor="inapp" className="cursor-pointer">
                    Bật thông báo in-app (bell icon)
                  </Label>
                  <Switch
                    id="inapp"
                    checked={notifications.inAppNotifications}
                    onCheckedChange={() => handleNotificationChange('inAppNotifications')}
                  />
                </div>
              </SettingsFormSection>
            </CardContent>
          </Card>
        </TabsContent>

        {/* ============================================ */}
        {/* TAB 4: PUBLIC TRACKING */}
        {/* ============================================ */}
        <TabsContent value="public-tracking" className="mt-0 space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Liên kết theo dõi công khai</CardTitle>
              <CardDescription>
                Cho phép khách hàng theo dõi tiến độ xử lý bảo hành qua link công khai
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
              <SettingsFormSection
                title="Cấu hình truy cập công khai"
                description="Kiểm soát dữ liệu nào được chia sẻ cho khách hàng qua link bảo hành."
              >
                <div className="space-y-4">
                  <div className="flex items-center justify-between">
                    <div className="space-y-1">
                      <Label htmlFor="tracking-enabled" className="cursor-pointer">
                        Bật tính năng tracking công khai
                      </Label>
                      <p className="text-sm text-muted-foreground">
                        Tạo link công khai để khách hàng tự theo dõi tiến độ
                      </p>
                    </div>
                    <Switch
                      id="tracking-enabled"
                      checked={publicTracking.enabled}
                      onCheckedChange={() => handlePublicTrackingChange('enabled')}
                    />
                  </div>

                  {publicTracking.enabled && (
                    <div className="space-y-4">
                      <div className="flex items-center justify-between">
                        <div className="space-y-1">
                          <Label htmlFor="allow-comments" className="cursor-pointer">
                            Cho phép khách hàng comment
                          </Label>
                          <p className="text-sm text-muted-foreground">
                            Thu thập thêm bằng chứng trực tiếp từ khách hàng
                          </p>
                        </div>
                        <Switch
                          id="allow-comments"
                          checked={publicTracking.allowCustomerComments}
                          onCheckedChange={() => handlePublicTrackingChange('allowCustomerComments')}
                        />
                      </div>

                      <div className="flex items-center justify-between">
                        <div className="space-y-1">
                          <Label htmlFor="show-employee" className="cursor-pointer">
                            Hiển thị tên nhân viên xử lý
                          </Label>
                          <p className="text-sm text-muted-foreground">
                            Tăng tính minh bạch và trách nhiệm
                          </p>
                        </div>
                        <Switch
                          id="show-employee"
                          checked={publicTracking.showEmployeeName}
                          onCheckedChange={() => handlePublicTrackingChange('showEmployeeName')}
                        />
                      </div>

                      <div className="flex items-center justify-between">
                        <div className="space-y-1">
                          <Label htmlFor="show-timeline" className="cursor-pointer">
                            Hiển thị timeline xử lý
                          </Label>
                          <p className="text-sm text-muted-foreground">
                            Cho phép khách hàng xem toàn bộ lịch sử thao tác
                          </p>
                        </div>
                        <Switch
                          id="show-timeline"
                          checked={publicTracking.showTimeline}
                          onCheckedChange={() => handlePublicTrackingChange('showTimeline')}
                        />
                      </div>
                    </div>
                  )}
                </div>
              </SettingsFormSection>

              {/* Example */}
              {publicTracking.enabled && (
                <div className="p-4 bg-muted rounded-lg space-y-2">
                  <p className="text-sm font-medium">Ví dụ link tracking:</p>
                  <code className="text-xs bg-background px-2 py-1 rounded block">
                    https://yoursite.com/warranty/tracking/abc123xyz
                  </code>
                  <p className="text-xs text-muted-foreground">
                    Link này sẽ được tạo tự động khi tạo yêu cầu bảo hành mới
                  </p>
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        {/* ============================================ */}
        {/* TAB 5: CARD COLORS */}
        {/* ============================================ */}
        <TabsContent value="card-colors" className="mt-0 space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Màu sắc card bảo hành (Kanban View)</CardTitle>
              <CardDescription>
                Tùy chỉnh màu nền và viền card theo trạng thái bảo hành trong chế độ Kanban
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
              <SettingsFormSection
                title="Kiểu màu hiển thị"
                description="Ưu tiên: quá hạn → trạng thái → màu mặc định."
              >
                <div className="space-y-4">
                  <div className="flex items-center justify-between">
                    <div className="space-y-0.5">
                      <Label htmlFor="enable-overdue">Màu quá hạn SLA</Label>
                      <p className="text-sm text-muted-foreground">
                        Override tất cả màu khác khi phiếu quá hạn
                      </p>
                    </div>
                    <Switch
                      id="enable-overdue"
                      checked={cardColors.enableOverdueColor}
                      onCheckedChange={() => handleCardColorToggle('enableOverdueColor')}
                    />
                  </div>

                  <div className="flex items-center justify-between">
                    <div className="space-y-0.5">
                      <Label htmlFor="enable-status">Màu theo trạng thái</Label>
                      <p className="text-sm text-muted-foreground">
                        Hiển thị màu dựa trên tiến trình xử lý
                      </p>
                    </div>
                    <Switch
                      id="enable-status"
                      checked={cardColors.enableStatusColors}
                      onCheckedChange={() => handleCardColorToggle('enableStatusColors')}
                    />
                  </div>
                </div>
              </SettingsFormSection>

              {cardColors.enableOverdueColor && (
                <SettingsFormSection
                  title="Màu quá hạn SLA"
                  description="Áp dụng ngay khi phiếu vượt SLA, bỏ qua các thiết lập khác."
                  className="bg-red-50/50 dark:bg-red-950/20"
                >
                  <TailwindColorPicker
                    value={cardColors.overdueColor}
                    onChange={(value) => handleCardColorChange('overdueColor', '', value)}
                    label="Màu nền và viền"
                    placeholder="Ví dụ: bg-red-50 border-red-400"
                  />
                </SettingsFormSection>
              )}

              {cardColors.enableStatusColors && (
                <SettingsFormSection
                  title="Màu theo trạng thái"
                  description="Sử dụng dải màu trực quan để phân biệt tiến độ bảo hành."
                >
                  <div className="space-y-4">
                    <TailwindColorPicker
                      value={cardColors.statusColors.new}
                      onChange={(value) => handleCardColorChange('statusColors', 'new', value)}
                      label="Mới (New)"
                      placeholder="Ví dụ: bg-blue-50 border-blue-200"
                    />

                    <TailwindColorPicker
                      value={cardColors.statusColors.pending}
                      onChange={(value) => handleCardColorChange('statusColors', 'pending', value)}
                      label="Chưa xử lý (Pending)"
                      placeholder="Ví dụ: bg-yellow-50 border-yellow-200"
                    />

                    <TailwindColorPicker
                      value={cardColors.statusColors.processed}
                      onChange={(value) => handleCardColorChange('statusColors', 'processed', value)}
                      label="Đã xử lý (Processed)"
                      placeholder="Ví dụ: bg-green-50 border-green-200"
                    />

                    <TailwindColorPicker
                      value={cardColors.statusColors.returned}
                      onChange={(value) => handleCardColorChange('statusColors', 'returned', value)}
                      label="Đã trả (Returned)"
                      placeholder="Ví dụ: bg-gray-50 border-gray-200"
                    />
                  </div>
                </SettingsFormSection>
              )}

              {/* Info Box */}
              <div className="rounded-lg bg-blue-50 dark:bg-blue-950/20 p-4 text-sm">
                <p className="font-medium text-blue-900 dark:text-blue-100 mb-1">
                  💡 Thứ tự ưu tiên màu sắc
                </p>
                <ol className="text-blue-800 dark:text-blue-200 space-y-1 list-decimal list-inside">
                  <li>Màu quá hạn SLA (nếu bật) - Ưu tiên cao nhất</li>
                  <li>Màu theo trạng thái (nếu bật) - Ưu tiên thấp</li>
                  <li>Màu mặc định (nếu tắt tất cả)</li>
                </ol>
              </div>
            </CardContent>
          </Card>
        </TabsContent>
        </SettingsVerticalTabs>

      {/* Edit/Add Template Dialog */}
      <Dialog open={showEditDialog} onOpenChange={setShowEditDialog}>
        <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>
              {isAddingTemplate ? 'Thêm mẫu phản hồi mới' : 'Chỉnh sửa mẫu phản hồi'}
            </DialogTitle>
            <DialogDescription>
              Tạo hoặc chỉnh sửa mẫu phản hồi nhanh cho khách hàng
            </DialogDescription>
          </DialogHeader>

          {editingTemplate && (
            <div className="space-y-4 py-4">
              <div className="space-y-2">
                <Label htmlFor="template-name">Tên mẫu *</Label>
                <Input
                  id="template-name"
                  value={editingTemplate.name}
                  onChange={(e) => setEditingTemplate({ ...editingTemplate, name: e.target.value })}
                  placeholder="VD: Xác nhận tiếp nhận bảo hành"
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="template-category">Danh mục *</Label>
                <Select
                  value={editingTemplate.category}
                  onValueChange={(value) => setEditingTemplate({ 
                    ...editingTemplate, 
                    category: value as ResponseTemplate['category']
                  })}
                >
                  <SelectTrigger id="template-category">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="general">Chung</SelectItem>
                    <SelectItem value="processing-error">Lỗi xử lý</SelectItem>
                    <SelectItem value="customer-damage">Lỗi khách hàng</SelectItem>
                    <SelectItem value="inspection-result">Kết quả kiểm tra</SelectItem>
                    <SelectItem value="warranty-approved">Chấp nhận bảo hành</SelectItem>
                    <SelectItem value="warranty-rejected">Từ chối bảo hành</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label htmlFor="template-content">Nội dung mẫu *</Label>
                <Textarea
                  id="template-content"
                  value={editingTemplate.content}
                  onChange={(e) => setEditingTemplate({ ...editingTemplate, content: e.target.value })}
                  placeholder="Nhập nội dung phản hồi..."
                  rows={12}
                  className="font-mono text-sm"
                />
                <p className="text-xs text-muted-foreground">
                  Tip: Sử dụng biến như [TÊN SẢN PHẨM], [MÃ BẢO HÀNH], [NGÀY] để tùy chỉnh
                </p>
              </div>
            </div>
          )}

          <DialogFooter>
            <Button variant="outline" onClick={handleCancelEdit}>
              Hủy
            </Button>
            <Button onClick={handleSaveTemplate}>
              <Save className="h-4 w-4 mr-2" />
              Lưu mẫu
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Delete Template Confirmation Dialog */}
      <ConfirmDialog
        open={showDeleteDialog}
        onOpenChange={setShowDeleteDialog}
        title="Xác nhận xóa mẫu phản hồi"
        description={`Bạn có chắc chắn muốn xóa mẫu "${templates.find(t => t.id === templateToDelete)?.name || ''}"? Hành động này không thể hoàn tác.`}
        confirmText="Xóa mẫu"
        cancelText="Hủy"
        variant="destructive"
        onConfirm={confirmDeleteTemplate}
      />

    </div>
  );
}

/**
 * Stock Transfers Store - Main Entry
 * Combined store with all slices
 * 
 * @module features/stock-transfers/store
 */

import { create } from 'zustand';
import { asBusinessId, type SystemId, type BusinessId as _BusinessId } from '../../../lib/id-types';

// Types
import type { StockTransferState, StockTransfer } from './types';
export type { StockTransferState, StockTransfer, StockTransferStatus } from './types';

// Helpers
import { generateNextId, generateSystemId } from './helpers';

// Slices
import { confirmTransfer, confirmReceive, cancelTransfer } from './status-slice';

// ========================================
// STORE CREATION
// ========================================

export const useStockTransferStore = create<StockTransferState>()(
    (set, get) => ({
      data: [],
      isLoading: false,
      error: null,
      counter: 0,

      add: (transfer) => {
        const currentCounter = get().counter;
        const { id, referenceCode, note, ...rest } = transfer;
        const businessId = id && id.trim() 
          ? asBusinessId(id.trim())
          : generateNextId(currentCounter);
        const normalizedReferenceCode = referenceCode?.trim();
        const normalizedNote = note?.trim();
          
        const newTransfer: StockTransfer = {
          ...rest,
          systemId: generateSystemId(currentCounter),
          id: businessId,
          ...(normalizedReferenceCode ? { referenceCode: normalizedReferenceCode } : {}),
          ...(normalizedNote ? { note: normalizedNote } : {}),
          status: 'pending',
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString(),
        };
        
        set(state => ({
          data: [...state.data, newTransfer],
          counter: state.counter + 1,
        }));
        
        return newTransfer;
      },

      update: (systemId, transfer) => {
        set(state => ({
          data: state.data.map(t => 
            t.systemId === systemId 
              ? { ...t, ...transfer, updatedAt: new Date().toISOString() }
              : t
          ),
        }));
      },

      remove: (systemId) => {
        set(state => ({
          data: state.data.filter(t => t.systemId !== systemId),
        }));
      },

      findById: (systemId) => {
        return get().data.find(t => t.systemId === systemId);
      },

      findByBusinessId: (id) => {
        return get().data.find(t => t.id === id);
      },

      getNextId: () => generateNextId(get().counter),
      
      isBusinessIdExists: (id: string) => {
        return get().data.some(t => t.id === id);
      },

      // Status operations (deprecated - use React Query mutations)
      confirmTransfer: (systemId: SystemId, employeeId: SystemId, products: Array<{ systemId: SystemId; inventoryByBranch?: Record<string, number> }> = [], employee?: { systemId: SystemId; fullName: string }) => 
        confirmTransfer(get, set, systemId, employeeId, products, employee),

      confirmReceive: (systemId: SystemId, employeeId: SystemId, products: Array<{ systemId: SystemId; inventoryByBranch?: Record<string, number> }> = [], employee?: { systemId: SystemId; fullName: string }, receivedItems?: { productSystemId: SystemId; receivedQuantity: number }[]) => 
        confirmReceive(get, set, systemId, employeeId, products, employee, receivedItems),

      cancelTransfer: (systemId: SystemId, employeeId: SystemId, products: string[] = [], reason?: string) => 
        cancelTransfer(get, set, systemId, employeeId, products as any, undefined, reason),
    })
);

import * as React from "react";
import { useSupplierMutations } from "../hooks/use-suppliers";
import { toast } from 'sonner';
import { useProvinces, useWards2Level } from "../../settings/provinces/hooks/use-administrative-units";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "../../../components/ui/dialog";
import { Button } from "../../../components/ui/button";
import { Input } from "../../../components/ui/input";
import { Label } from "../../../components/ui/label";
import { VirtualizedCombobox } from "../../../components/ui/virtualized-combobox";
import { asBusinessId } from "@/lib/id-types";

interface QuickAddSupplierDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSuccess?: (supplierId: string) => void;
}

export function QuickAddSupplierDialog({
  open,
  onOpenChange,
  onSuccess,
}: QuickAddSupplierDialogProps) {
  const { create: _create } = useSupplierMutations({
    onCreateSuccess: (supplier: any) => {
      toast.success(`Đã thêm nhà cung cấp "${supplier.name}"`);
      if (onSuccess) onSuccess(supplier.id);
      onOpenChange(false);
    },
    onError: (err) => toast.error(err.message)
  });
  const { data: provinces = [] } = useProvinces();
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  // Form state
  const [formData, setFormData] = React.useState({
    name: "",
    phone: "",
    email: "",
    address: "",
    city: "",
    district: "",
  });

  // Validation errors
  const [errors, setErrors] = React.useState<Record<string, string>>({});

  // Auto-focus first input when dialog opens
  const nameInputRef = React.useRef<HTMLInputElement>(null);
  React.useEffect(() => {
    if (open) {
      setTimeout(() => nameInputRef.current?.focus(), 100);
    }
  }, [open]);

  // Reset form when dialog closes
  React.useEffect(() => {
    if (!open) {
      setFormData({
        name: "",
        phone: "",
        email: "",
        address: "",
        city: "",
        district: "",
      });
      setErrors({});
      setIsSubmitting(false);
    }
  }, [open]);

  const validateForm = (): boolean => {
    const newErrors: Record<string, string> = {};

    if (!formData.name.trim()) {
      newErrors.name = "Tên nhà cung cấp là bắt buộc";
    }

    if (formData.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
      newErrors.email = "Email không hợp lệ";
    }

    if (formData.phone && !/^[0-9]{10,11}$/.test(formData.phone.replace(/\s/g, ""))) {
      newErrors.phone = "Số điện thoại không hợp lệ (10-11 số)";
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  // Prepare combobox options
  const provinceOptions = React.useMemo(
    () => provinces.map((p) => ({ value: p.name, label: p.name })),
    [provinces]
  );

  // Find selected province
  const selectedProvince = React.useMemo(
    () => provinces.find((p) => p.name === formData.city),
    [provinces, formData.city]
  );

  // Get wards for selected province using React Query hook
  const { data: availableWards = [] } = useWards2Level(selectedProvince?.id);

  const wardOptions = React.useMemo(
    () => availableWards.map((w) => ({ value: w.name, label: w.name })),
    [availableWards]
  );

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validateForm()) {
      return;
    }

    setIsSubmitting(true);

    try {
      const newSupplier = {
        id: asBusinessId(""), // Let store auto-generate business ID
        name: formData.name.trim(),
        phone: formData.phone.trim(),
        email: formData.email.trim(),
        address: formData.address.trim() + (formData.city ? `, ${formData.city}` : "") + (formData.district ? `, ${formData.district}` : ""),
        taxCode: "",
        accountManager: "",
        status: "Đang Giao Dịch" as const,
      };

      (add as any).mutate(newSupplier);

      toast.success(`Đã thêm nhà cung cấp "${newSupplier.name}"`);

      onOpenChange(false);
      
      // Call success callback with new supplier systemId
      if (onSuccess) {
        onSuccess((newSupplier as any).systemId || '');
      }
    } catch (_error) {
      toast.error('Không thể thêm nhà cung cấp. Vui lòng thử lại.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Thêm mới nhà cung cấp</DialogTitle>
          <DialogDescription>
            Nhập thông tin nhà cung cấp mới. Các trường có dấu * là bắt buộc.
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Tên nhà cung cấp */}
          <div className="space-y-2">
            <Label htmlFor="supplier-name">
              Tên nhà cung cấp <span className="text-destructive">*</span>
            </Label>
            <Input
              id="supplier-name"
              ref={nameInputRef}
              placeholder="Nhập họ tên"
              value={formData.name}
              onChange={(e) =>
                setFormData((prev) => ({ ...prev, name: e.target.value }))
              }
              className={errors.name ? "border-destructive" : ""}
            />
            {errors.name && (
              <p className="text-sm text-destructive">{errors.name}</p>
            )}
          </div>

          {/* Row 1: Phone + Email */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="supplier-phone">Số điện thoại</Label>
              <Input
                id="supplier-phone"
                placeholder="Nhập số điện thoại"
                value={formData.phone}
                onChange={(e) =>
                  setFormData((prev) => ({ ...prev, phone: e.target.value }))
                }
                className={errors.phone ? "border-destructive" : ""}
              />
              {errors.phone && (
                <p className="text-sm text-destructive">{errors.phone}</p>
              )}
            </div>

            <div className="space-y-2">
              <Label htmlFor="supplier-email">Email</Label>
              <Input
                id="supplier-email"
                type="email"
                placeholder="Nhập email"
                value={formData.email}
                onChange={(e) =>
                  setFormData((prev) => ({ ...prev, email: e.target.value }))
                }
                className={errors.email ? "border-destructive" : ""}
              />
              {errors.email && (
                <p className="text-sm text-destructive">{errors.email}</p>
              )}
            </div>
          </div>

          {/* Địa chỉ chi tiết */}
          <div className="space-y-2">
            <Label htmlFor="supplier-address">Địa chỉ chi tiết</Label>
            <Input
              id="supplier-address"
              placeholder="Nhập số nhà, tên đường, tên khu vực"
              value={formData.address}
              onChange={(e) =>
                setFormData((prev) => ({ ...prev, address: e.target.value }))
              }
            />
          </div>

          {/* Row 2: City + District */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="supplier-city">Tỉnh/Thành phố</Label>
              <VirtualizedCombobox
                options={provinceOptions}
                value={
                  formData.city
                    ? { value: formData.city, label: formData.city }
                    : null
                }
                onChange={(option) => {
                  setFormData((prev) => ({
                    ...prev,
                    city: option?.value || "",
                    district: "", // Reset district when province changes
                  }));
                }}
                placeholder="Chọn Tỉnh/Thành phố"
                searchPlaceholder="Tìm tỉnh/thành phố..."
                emptyPlaceholder="Không tìm thấy"
                estimatedItemHeight={36}
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="supplier-district">Phường/Xã</Label>
              <VirtualizedCombobox
                options={wardOptions}
                value={
                  formData.district
                    ? { value: formData.district, label: formData.district }
                    : null
                }
                onChange={(option) => {
                  setFormData((prev) => ({
                    ...prev,
                    district: option?.value || "",
                  }));
                }}
                placeholder={selectedProvince ? "Chọn Phường/Xã" : "Chọn tỉnh trước"}
                searchPlaceholder="Tìm phường/xã..."
                emptyPlaceholder="Không tìm thấy"
                disabled={!selectedProvince}
                estimatedItemHeight={36}
              />
            </div>
          </div>

          <DialogFooter className="gap-2">
            <Button
              type="button"
              variant="outline"
              onClick={() => onOpenChange(false)}
              disabled={isSubmitting}
            >
              Thoát
            </Button>
            <Button type="submit" disabled={isSubmitting}>
              {isSubmitting ? "Đang thêm..." : "Thêm"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

'use client';

import * as React from 'react';
import FullCalendar from '@fullcalendar/react';
import dayGridPlugin from '@fullcalendar/daygrid';
import timeGridPlugin from '@fullcalendar/timegrid';
import interactionPlugin from '@fullcalendar/interaction';
import listPlugin from '@fullcalendar/list';
import type { EventClickArg, EventDropArg } from '@fullcalendar/core';
import type { EventResizeDoneArg } from '@fullcalendar/interaction';
import type { EventContentArg } from '@fullcalendar/core';
import { useTasks, useTaskMutations } from '../hooks/use-tasks';
import type { Task, TaskPriority } from '../types';
import { usePageHeader } from '@/contexts/page-header-context';
import { useRouter } from 'next/navigation';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { ArrowLeft } from 'lucide-react';
import { toast } from 'sonner';

export function TaskCalendarView() {
  usePageHeader();
  const { data: tasksData } = useTasks({ limit: 1000 });
  const tasks = tasksData?.data ?? [];
  const { update: updateMutation } = useTaskMutations();
  
  const update = React.useCallback((systemId: string, data: Partial<Task>) => {
    updateMutation.mutate({ systemId, data });
  }, [updateMutation]);
  
  const router = useRouter();
  const calendarRef = React.useRef<FullCalendar>(null);

  const getPriorityColor = (priority: TaskPriority): string => {
    const colors = {
      'Thấp': '#6B7280',        // gray
      'Trung bình': '#3B82F6',  // blue
      'Cao': '#F59E0B',         // orange
      'Khẩn cấp': '#EF4444',    // red
    };
    return colors[priority];
  };

  const getStatusColor = (status: Task['status']): string => {
    const colors = {
      'Chưa bắt đầu': '#9CA3AF',
      'Đang thực hiện': '#F59E0B',
      'Đang chờ': '#8B5CF6',
      'Hoàn thành': '#10B981',
      'Đã hủy': '#6B7280',
    };
    return colors[status];
  };

  // Convert tasks to calendar events
  const events = React.useMemo(() => {
    return tasks.map(task => ({
      id: task.systemId,
      title: task.title,
      start: task.startDate,
      end: task.dueDate,
      backgroundColor: getPriorityColor(task.priority),
      borderColor: getStatusColor(task.status),
      extendedProps: {
        task: task,
        assigneeName: task.assigneeName,
        progress: task.progress,
        priority: task.priority,
        status: task.status,
      },
      editable: task.status !== 'Hoàn thành' && task.status !== 'Đã hủy',
    }));
  }, [tasks]);

  // Handle event click - navigate to detail
  const handleEventClick = (info: EventClickArg) => {
    const task = info.event.extendedProps.task as Task;
    router.push(`/tasks/${task.systemId}`);
  };

  // Handle event drag & drop - update dates
  const handleEventDrop = (info: EventDropArg) => {
    const task = info.event.extendedProps.task as Task;
    const newStart = info.event.start?.toISOString().split('T')[0];
    const newEnd = info.event.end?.toISOString().split('T')[0] || newStart;

    update(task.systemId, {
      ...task,
      startDate: newStart!,
      dueDate: newEnd,
    });

    toast.success("Đã cập nhật ngày", {
      description: `${task.title} - Từ ${newStart} đến ${newEnd}`,
    });
  };

  // Handle event resize - update due date
  const handleEventResize = (info: EventResizeDoneArg) => {
    const task = info.event.extendedProps.task as Task;
    const newEnd = info.event.end?.toISOString().split('T')[0];

    if (newEnd) {
      update(task.systemId, {
        ...task,
        dueDate: newEnd,
      });

      toast.success("Đã cập nhật deadline", {
        description: `${task.title} - Deadline mới: ${newEnd}`,
      });
    }
  };

  // Custom event render
  const renderEventContent = (eventInfo: EventContentArg) => {
    const progress = eventInfo.event.extendedProps.progress || 0;
    const assigneeName = eventInfo.event.extendedProps.assigneeName;
    
    return (
      <div className="fc-event-main-frame">
        <div className="fc-event-time">{eventInfo.timeText}</div>
        <div className="fc-event-title-container">
          <div className="fc-event-title fc-sticky">
            {eventInfo.event.title}
          </div>
          {eventInfo.view.type === 'dayGridMonth' && (
            <div className="text-xs opacity-80 mt-1">
              {assigneeName} • {progress}%
            </div>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <Button onClick={() => router.push('/tasks')} size="sm" variant="outline">
          <ArrowLeft className="mr-2 h-4 w-4" /> Về danh sách
        </Button>
        <Button onClick={() => router.push('/tasks/new')} size="sm">
          Tạo công việc mới
        </Button>
      </div>

      <Card>
        <CardContent className="p-6">
          <style>{`
            .fc {
              --fc-border-color: var(--border);
              --fc-button-bg-color: var(--primary);
              --fc-button-border-color: var(--primary);
              --fc-button-hover-bg-color: color-mix(in oklch, var(--primary), transparent 10%);
              --fc-button-hover-border-color: color-mix(in oklch, var(--primary), transparent 10%);
              --fc-button-active-bg-color: color-mix(in oklch, var(--primary), transparent 20%);
              --fc-button-active-border-color: color-mix(in oklch, var(--primary), transparent 20%);
              --fc-today-bg-color: var(--accent);
            }
            .fc .fc-button {
              text-transform: none;
              font-size: 0.875rem;
              padding: 0.375rem 0.75rem;
            }
            .fc .fc-toolbar-title {
              font-size: 1.25rem;
              font-weight: 600;
            }
            .fc-event {
              cursor: pointer;
              border-width: 2px !important;
              border-left-width: 4px !important;
              padding: 2px 4px;
            }
            .fc-event:hover {
              opacity: 0.85;
            }
            .fc-daygrid-event {
              white-space: normal !important;
            }
            .fc-event-title {
              font-weight: 500;
            }
          `}</style>
          
          <FullCalendar
            ref={calendarRef}
            plugins={[dayGridPlugin, timeGridPlugin, interactionPlugin, listPlugin]}
            initialView="dayGridMonth"
            headerToolbar={{
              left: 'prev,next today',
              center: 'title',
              right: 'dayGridMonth,timeGridWeek,timeGridDay,listWeek'
            }}
            buttonText={{
              today: 'Hôm nay',
              month: 'Tháng',
              week: 'Tuần',
              day: 'Ngày',
              list: 'Danh sách'
            }}
            locale="vi"
            firstDay={1} // Monday
            height="auto"
            events={events}
            eventClick={handleEventClick}
            eventDrop={handleEventDrop}
            eventResize={handleEventResize}
            eventContent={renderEventContent}
            editable={true}
            droppable={true}
            dayMaxEvents={3}
            eventTimeFormat={{
              hour: '2-digit',
              minute: '2-digit',
              hour12: false
            }}
            slotLabelFormat={{
              hour: '2-digit',
              minute: '2-digit',
              hour12: false
            }}
            allDayText="Cả ngày"
            noEventsText="Không có công việc"
            moreLinkText={(num) => `+${num} công việc`}
            nowIndicator={true}
          />
        </CardContent>
      </Card>

      {/* Legend */}
      <Card>
        <CardContent className="p-4">
          <div className="text-sm font-semibold mb-2">Chú thích:</div>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3 text-xs">
            <div className="flex items-center gap-2">
              <div className="w-4 h-4 rounded" style={{ backgroundColor: '#6B7280' }}></div>
              <span>Độ ưu tiên Thấp</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-4 h-4 rounded" style={{ backgroundColor: '#3B82F6' }}></div>
              <span>Độ ưu tiên Trung bình</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-4 h-4 rounded" style={{ backgroundColor: '#F59E0B' }}></div>
              <span>Độ ưu tiên Cao</span>
            </div>
            <div className="flex items-center gap-2">
              <div className="w-4 h-4 rounded" style={{ backgroundColor: '#EF4444' }}></div>
              <span>Độ ưu tiên Khẩn cấp</span>
            </div>
          </div>
          <div className="text-xs text-muted-foreground mt-2">
            💡 Kéo thả để thay đổi ngày, kéo góc để thay đổi deadline. Viền trái thể hiện trạng thái.
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

