    title: '',
    description: '',
    priority: 'Trung bình' as TaskPriority,
    estimatedHours: 8,
    assignees: [] as TaskAssignee[],
    frequency: 'weekly' as RecurrenceFrequency,
    interval: 1,
    startDate: '',
    durationDays: 1,
    createDaysBefore: 0,
  });

  const handleProcessRecurring = () => {
    // Note: recurringStore.processRecurringTasks needs migration to React Query
    toast.info('Xử lý công việc lặp lại');
  };

  usePageHeader({
    actions: [
      <Button key="create" onClick={() => setShowCreateDialog(true)}>
        <Plus className="mr-2 h-4 w-4" />
        Tạo công việc lặp lại
      </Button>,
      <Button 
        key="process" 
        variant="outline"
        onClick={handleProcessRecurring}
      >
        <Repeat className="mr-2 h-4 w-4" />
        Xử lý ngay
      </Button>
    ],
  });

  const activeTasks = recurringTasks?.filter(t => t.isActive && !t.isPaused) ?? [];
  const pausedTasks = recurringTasks?.filter(t => t.isActive && t.isPaused) ?? [];

  const handleCreateRecurring = () => {
    if (!formData.title.trim()) {
      toast.error('Vui lòng nhập tiêu đề');
      return;
    }
    if (!formData.startDate) {
      toast.error('Vui lòng chọn ngày bắt đầu');
      return;
    }
    if (formData.assignees.length === 0) {
      toast.error('Vui lòng chọn người thực hiện');
      return;
    }

    const pattern: RecurrencePattern = {
      frequency: formData.frequency,
      interval: formData.interval,
    };

    const owner = formData.assignees.find(a => a.role === 'owner') || formData.assignees[0];

    const recurringTask: Omit<RecurringTask, 'systemId'> = {
      id: '',
      title: formData.title,
      description: formData.description,
      priority: formData.priority,
      estimatedHours: formData.estimatedHours,
      assignees: formData.assignees,
      assignerId: owner.employeeSystemId,
      assignerName: owner.employeeName,
      recurrencePattern: pattern,
      startDate: formData.startDate,
      nextOccurrenceDate: formData.startDate,
      createDaysBefore: formData.createDaysBefore,
      durationDays: formData.durationDays,
      isActive: true,
      isPaused: false,
      createdTaskIds: [],
      occurrenceCount: 0,
      createdBy: 'CURRENT_USER',
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    (createRecurring as any).mutate(recurringTask);
    toast.success('Đã tạo công việc lặp lại');
    setShowCreateDialog(false);
    
    // Reset form
    setFormData({
      title: '',
      description: '',
      priority: 'Trung bình',
      estimatedHours: 8,
      assignees: [],
      frequency: 'weekly',
      interval: 1,
      startDate: '',
      durationDays: 1,
      createDaysBefore: 0,
    });
  };

  return (
    <div className="space-y-6">
      {/* Stats */}
      <div className="grid gap-4 md:grid-cols-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Đang hoạt động</CardTitle>
            <Play className="h-4 w-4 text-green-600" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{activeTasks.length}</div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Tạm dừng</CardTitle>
            <Pause className="h-4 w-4 text-orange-600" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{pausedTasks.length}</div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Tổng công việc đã tạo</CardTitle>
            <CheckCircle2 className="h-4 w-4 text-blue-600" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {recurringTasks?.reduce((sum, rt) => sum + (rt.occurrenceCount || 0), 0) ?? 0}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Sắp tới hôm nay</CardTitle>
            <Calendar className="h-4 w-4 text-purple-600" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {0} {/* Note: getTasksToCreateToday needs implementation */}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Active Tasks */}
      {activeTasks.length > 0 && (
        <div className="space-y-4">
          <h2 className="text-xl font-semibold">Đang hoạt động</h2>
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
            {activeTasks.map(task => (
              <RecurringTaskCard
                key={task.systemId}
                task={task}
                onTogglePause={() => (updateRecurring as any).mutate({ systemId: task.systemId, isPaused: !task.isPaused })}
                onDeactivate={() => (updateRecurring as any).mutate({ systemId: task.systemId, isActive: false })}
              />
            ))}
          </div>
        </div>
      )}

      {/* Paused Tasks */}
      {pausedTasks.length > 0 && (
        <div className="space-y-4">
          <h2 className="text-xl font-semibold">Tạm dừng</h2>
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
            {pausedTasks.map(task => (
              <RecurringTaskCard
                key={task.systemId}
                task={task}
                onTogglePause={() => (updateRecurring as any).mutate({ systemId: task.systemId, isPaused: !task.isPaused })}
                onDeactivate={() => (updateRecurring as any).mutate({ systemId: task.systemId, isActive: false })}
              />
            ))}
          </div>
        </div>
      )}

      {/* Empty State */}
      {activeTasks.length === 0 && pausedTasks.length === 0 && (
        <Card>
          <CardContent className="py-12 text-center">
            <Repeat className="mx-auto h-12 w-12 text-muted-foreground mb-4" />
            <h3 className="text-lg font-semibold mb-2">Chưa có công việc lặp lại</h3>
            <p className="text-muted-foreground mb-4">
              Tạo công việc lặp lại để tự động hóa các tác vụ định kỳ
            </p>
            <Button onClick={() => setShowCreateDialog(true)}>
              <Plus className="mr-2 h-4 w-4" />
              Tạo công việc lặp lại
            </Button>
          </CardContent>
        </Card>
      )}

      {/* Create Dialog */}
      <Dialog open={showCreateDialog} onOpenChange={setShowCreateDialog}>
        <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Tạo công việc lặp lại</DialogTitle>
            <DialogDescription>
              Thiết lập công việc sẽ tự động tạo theo lịch trình
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4 py-4">
            <div>
              <Label>Tiêu đề *</Label>
              <Input
                value={formData.title}
                onChange={(e) => setFormData({ ...formData, title: e.target.value })}
                placeholder="Báo cáo tuần..."
              />
            </div>

            <div>
              <Label>Mô tả</Label>
              <Textarea
                value={formData.description}
                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                placeholder="Mô tả công việc..."
                rows={3}
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <Label>Độ ưu tiên</Label>
                <Select value={formData.priority} onValueChange={(v) => setFormData({ ...formData, priority: v as TaskPriority })}>
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="Thấp">Thấp</SelectItem>
                    <SelectItem value="Trung bình">Trung bình</SelectItem>
                    <SelectItem value="Cao">Cao</SelectItem>
                    <SelectItem value="Khẩn cấp">Khẩn cấp</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div>
                <Label>Ước tính (giờ)</Label>
                <Input
                  type="number"
                  value={formData.estimatedHours}
                  onChange={(e) => setFormData({ ...formData, estimatedHours: parseInt(e.target.value) })}
                />
              </div>
            </div>

            <div>
              <Label>Người thực hiện *</Label>
              <AssigneeMultiSelect
                assignees={formData.assignees}
                availableEmployees={employees.map(e => ({
                  systemId: e.systemId,
                  name: e.fullName,
                }))}
                onChange={(assignees) => setFormData({ ...formData, assignees })}
                showRoles={true}
              />
            </div>

            <div className="border-t pt-4">
              <h3 className="font-semibold mb-4">Lịch lặp lại</h3>
              
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <Label>Tần suất</Label>
                  <Select value={formData.frequency} onValueChange={(v) => setFormData({ ...formData, frequency: v as RecurrenceFrequency })}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="daily">Hàng ngày</SelectItem>
                      <SelectItem value="weekly">Hàng tuần</SelectItem>
                      <SelectItem value="monthly">Hàng tháng</SelectItem>
                      <SelectItem value="yearly">Hàng năm</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div>
                  <Label>Mỗi</Label>
                  <Input
                    type="number"
                    min={1}
                    value={formData.interval}
                    onChange={(e) => setFormData({ ...formData, interval: parseInt(e.target.value) })}
                  />
                  <p className="text-xs text-muted-foreground mt-1">
                    {formData.frequency === 'daily' && `ngày`}
                    {formData.frequency === 'weekly' && `tuần`}
                    {formData.frequency === 'monthly' && `tháng`}
                    {formData.frequency === 'yearly' && `năm`}
                  </p>
                </div>
              </div>

              <div className="grid grid-cols-3 gap-4 mt-4">
                <div>
                  <Label>Ngày bắt đầu *</Label>
                  <Input
                    type="date"
                    value={formData.startDate}
                    onChange={(e) => setFormData({ ...formData, startDate: e.target.value })}
                  />
                </div>

                <div>
                  <Label>Thời lượng (ngày)</Label>
                  <Input
                    type="number"
                    min={1}
                    value={formData.durationDays}
                    onChange={(e) => setFormData({ ...formData, durationDays: parseInt(e.target.value) })}
                  />
                </div>

                <div>
                  <Label>Tạo trước (ngày)</Label>
                  <Input
                    type="number"
                    min={0}
                    value={formData.createDaysBefore}
                    onChange={(e) => setFormData({ ...formData, createDaysBefore: parseInt(e.target.value) })}
                  />
                </div>
              </div>
            </div>
          </div>

          <DialogFooter>
            <Button variant="outline" onClick={() => setShowCreateDialog(false)}>
              Hủy
            </Button>
            <Button onClick={handleCreateRecurring}>
              <Plus className="mr-2 h-4 w-4" />
              Tạo
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

function RecurringTaskCard({
  task,
  onTogglePause,
  onDeactivate,
}: {
  task: RecurringTask;
  onTogglePause: () => void;
  onDeactivate: () => void;
}) {
  return (
    <Card className={cn(task.isPaused && 'opacity-60')}>
      <CardHeader>
        <div className="flex items-start justify-between">
          <div className="space-y-1 flex-1">
            <CardTitle className="text-base">{task.title}</CardTitle>
            <CardDescription className="line-clamp-2">
              {task.description || 'Không có mô tả'}
            </CardDescription>
          </div>
          <Badge variant="outline">
            {frequencyLabels[task.recurrencePattern.frequency]}
          </Badge>
        </div>
      </CardHeader>
      <CardContent className="space-y-4">
        <div className="flex items-center gap-4 text-sm text-muted-foreground">
          <div className="flex items-center gap-1">
            <Calendar className="h-3 w-3" />
            <span>Lần sau: {task.nextOccurrenceDate || 'N/A'}</span>
          </div>
        </div>

        <div className="flex items-center gap-4 text-sm text-muted-foreground">
          <div className="flex items-center gap-1">
            <CheckCircle2 className="h-3 w-3" />
            <span>Đã tạo: {task.occurrenceCount} lần</span>
          </div>
        </div>

        <div className="flex gap-2 pt-2">
          <Button
            size="sm"
            variant={task.isPaused ? 'default' : 'outline'}
            className="flex-1"
            onClick={onTogglePause}
          >
            {task.isPaused ? (
              <>
                <Play className="mr-1 h-3 w-3" />
                Tiếp tục
              </>
            ) : (
              <>
                <Pause className="mr-1 h-3 w-3" />
                Tạm dừng
              </>
            )}
          </Button>
          <Button
            size="sm"
            variant="outline"
            onClick={onDeactivate}
          >
            <Trash2 className="h-3 w-3" />
          </Button>
        </div>
      </CardContent>
    </Card>
  );
}

'use client'

import { useState, useMemo } from 'react';
import { useRouter } from 'next/navigation';
import { useTasks, useTaskMutations } from '../hooks/use-tasks';
import { useAuth } from '@/contexts/auth-context';
import { usePageHeader } from '@/contexts/page-header-context';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Search, RefreshCw, CheckCircle, Clock, AlertTriangle, ListTodo } from 'lucide-react';
import { TaskCheckboxItem } from './TaskCheckboxItem';
import { CompletionDialog } from './CompletionDialog';
import { EvidenceViewer } from './EvidenceViewer';
import type { Task } from '../types';
import { toast } from 'sonner';

export function UserTasksPage() {
  const router = useRouter();
  const { employee } = useAuth();
  const { data: tasksData } = useTasks({ limit: 1000 });
  const allTasks = tasksData?.data ?? [];
  const { update: updateMutation } = useTaskMutations();
  
  const update = React.useCallback((systemId: string, data: Partial<Task>) => {
    updateMutation.mutate({ systemId, data });
  }, [updateMutation]);
  
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedTab, setSelectedTab] = useState('not-started');
  const [completionTask, setCompletionTask] = useState<Task | null>(null);
  const [evidenceTask, setEvidenceTask] = useState<Task | null>(null);

  usePageHeader({
    title: 'Công việc của tôi',
    breadcrumb: [
      { label: 'Trang chủ', href: '/' },
      { label: 'Công việc của tôi', href: '/my-tasks' },
    ],
  });

  // Filter tasks assigned to current user
  const myTasks = useMemo(() => {
    if (!employee) return [];
    
    return allTasks.filter(task => {
      // Check if user is in assignees
      const isAssigned = task.assignees?.some(
        assignee => assignee.employeeSystemId === employee.systemId
      );
      
      // Or check legacy assigneeId
      const isLegacyAssigned = task.assigneeId === employee.systemId;
      
      return isAssigned || isLegacyAssigned;
    });
  }, [allTasks, employee]);

  // Categorize tasks
  const categorizedTasks = useMemo(() => {
    const now = new Date();
    
    const notStarted = myTasks.filter(
      task => task.status === 'Chưa bắt đầu' && task.approvalStatus !== 'pending'
    );
    
    const inProgress = myTasks.filter(
      task => task.status === 'Đang thực hiện' && task.approvalStatus !== 'pending'
    );
    
    const overdue = myTasks.filter(task => {
      const isOverdue = new Date(task.dueDate) < now;
      const isNotCompleted = task.status !== 'Hoàn thành';
      const isNotPending = task.approvalStatus !== 'pending';
      return isOverdue && isNotCompleted && isNotPending;
    });
    
    const completed = myTasks.filter(
      task => task.status === 'Hoàn thành' && task.approvalStatus === 'approved'
    );

    const pendingApproval = myTasks.filter(
      task => task.approvalStatus === 'pending'
    );

    const rejected = myTasks.filter(
      task => task.approvalStatus === 'rejected'
    );

    return {
      notStarted,
      inProgress,
      overdue,
      completed,
      pendingApproval,
      rejected,
    };
  }, [myTasks]);

  // Search filter
  const filterTasks = (tasks: Task[]) => {
    if (!searchQuery.trim()) return tasks;
    
    const query = searchQuery.toLowerCase();
    return tasks.filter(task =>
      task.title.toLowerCase().includes(query) ||
      task.description?.toLowerCase().includes(query) ||
      task.id.toLowerCase().includes(query)
    );
  };

  const getTabTasks = (tab: string) => {
    switch (tab) {
      case 'not-started':
        return filterTasks(categorizedTasks.notStarted);
      case 'in-progress':
        return filterTasks([...categorizedTasks.inProgress, ...categorizedTasks.rejected]);
      case 'overdue':
        return filterTasks(categorizedTasks.overdue);
      case 'completed':
        return filterTasks(categorizedTasks.completed);
      case 'pending':
        return filterTasks(categorizedTasks.pendingApproval);
      default:
        return [];
    }
  };

  const handleCompleteTask = async (taskId: string, evidence: { images: string[]; note: string }) => {
    if (!employee) return;

    try {
      const task = myTasks.find(t => t.systemId === taskId);
      if (!task) throw new Error('Task not found');

      await update(taskId, {
        ...task,
        approvalStatus: 'pending',
        completionEvidence: {
          images: evidence.images,
          note: evidence.note,
          submittedAt: new Date().toISOString(),
          submittedBy: employee.systemId,
          submittedByName: employee.fullName,
        },
        activities: [
          ...(task.activities || []),
          {
            id: `activity_${Date.now()}`,
            taskId: task.systemId,
            userId: employee.systemId,
            userName: employee.fullName,
            action: 'evidence_submitted',
            description: 'Đã gửi bằng chứng hoàn thành công việc',
            timestamp: new Date().toISOString(),
          },
        ],
      });

      toast.success('Đã gửi bằng chứng hoàn thành công việc', {
        description: 'Vui lòng đợi admin phê duyệt',
      });

      setCompletionTask(null);
    } catch (error) {
      console.error('Error completing task:', error);
      throw error;
    }
  };

  const handleViewDetails = (task: Task) => {
    if (task.completionEvidence) {
      setEvidenceTask(task);
    } else {
      router.push(`/tasks/${task.systemId}`);
    }
  };

  const handleRefresh = () => {
    toast.info('Đã làm mới danh sách công việc');
  };

  const currentTabTasks = getTabTasks(selectedTab);

  return (
    <div className="p-6 space-y-6">
      {/* Stats cards */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
              <ListTodo className="h-4 w-4" />
              Chưa bắt đầu
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{categorizedTasks.notStarted.length}</div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
              <Clock className="h-4 w-4" />
              Đang làm
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-blue-600">
              {categorizedTasks.inProgress.length + categorizedTasks.rejected.length}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
              <AlertTriangle className="h-4 w-4" />
              Quá hạn
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-red-600">
              {categorizedTasks.overdue.length}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
              <Clock className="h-4 w-4 text-yellow-600" />
              Chờ duyệt
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-yellow-600">
              {categorizedTasks.pendingApproval.length}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
              <CheckCircle className="h-4 w-4" />
              Hoàn thành
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold text-green-600">
              {categorizedTasks.completed.length}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Search and filters */}
      <div className="flex items-center gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder="Tìm kiếm công việc..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="pl-10"
          />
        </div>
        <Button variant="outline" size="icon" onClick={handleRefresh}>
          <RefreshCw className="h-4 w-4" />
        </Button>
      </div>

      {/* Tabs */}
      <Tabs value={selectedTab} onValueChange={setSelectedTab}>
        <TabsList className="w-full grid grid-cols-5">
          <TabsTrigger value="not-started" className="flex items-center gap-2">
            <ListTodo className="h-4 w-4" />
            <span className="hidden sm:inline">Chưa bắt đầu</span>
            <span className="sm:hidden">Mới</span>
            {categorizedTasks.notStarted.length > 0 && (
              <span className="ml-1 bg-muted px-1.5 py-0.5 rounded text-xs">
                {categorizedTasks.notStarted.length}
              </span>
            )}
          </TabsTrigger>

          <TabsTrigger value="in-progress" className="flex items-center gap-2">
            <Clock className="h-4 w-4" />
            <span className="hidden sm:inline">Đang làm</span>
            <span className="sm:hidden">Làm</span>
            {(categorizedTasks.inProgress.length + categorizedTasks.rejected.length) > 0 && (
              <span className="ml-1 bg-muted px-1.5 py-0.5 rounded text-xs">
                {categorizedTasks.inProgress.length + categorizedTasks.rejected.length}
              </span>
            )}
          </TabsTrigger>

          <TabsTrigger value="overdue" className="flex items-center gap-2">
            <AlertTriangle className="h-4 w-4" />
            <span className="hidden sm:inline">Quá hạn</span>
            <span className="sm:hidden">Hạn</span>
            {categorizedTasks.overdue.length > 0 && (
              <span className="ml-1 bg-red-100 text-red-800 px-1.5 py-0.5 rounded text-xs">
                {categorizedTasks.overdue.length}
              </span>
            )}
          </TabsTrigger>

          <TabsTrigger value="pending" className="flex items-center gap-2">
            <Clock className="h-4 w-4" />
            <span className="hidden sm:inline">Chờ duyệt</span>
            <span className="sm:hidden">Chờ</span>
            {categorizedTasks.pendingApproval.length > 0 && (
              <span className="ml-1 bg-yellow-100 text-yellow-800 px-1.5 py-0.5 rounded text-xs">
                {categorizedTasks.pendingApproval.length}
              </span>
            )}
          </TabsTrigger>

          <TabsTrigger value="completed" className="flex items-center gap-2">
            <CheckCircle className="h-4 w-4" />
            <span className="hidden sm:inline">Hoàn thành</span>
            <span className="sm:hidden">Xong</span>
            {categorizedTasks.completed.length > 0 && (
              <span className="ml-1 bg-green-100 text-green-800 px-1.5 py-0.5 rounded text-xs">
                {categorizedTasks.completed.length}
              </span>
            )}
          </TabsTrigger>
        </TabsList>

        {/* Tab contents */}
        {['not-started', 'in-progress', 'overdue', 'pending', 'completed'].map((tab) => (
          <TabsContent key={tab} value={tab} className="mt-4">
            {currentTabTasks.length === 0 ? (
              <Card>
                <CardContent className="py-12 text-center text-muted-foreground">
                  {searchQuery ? (
                    <>Không tìm thấy công việc nào phù hợp</>
                  ) : (
                    <>Không có công việc nào trong mục này</>
                  )}
                </CardContent>
              </Card>
            ) : (
              <div className="space-y-2">
                {currentTabTasks.map((task) => (
                  <TaskCheckboxItem
                    key={task.systemId}
                    task={task}
                    onComplete={setCompletionTask}
                    onViewDetails={handleViewDetails}
                  />
                ))}
              </div>
            )}
          </TabsContent>
        ))}
      </Tabs>

      {/* Completion dialog */}
      {completionTask && (
        <CompletionDialog
          task={completionTask}
          open={!!completionTask}
          onClose={() => setCompletionTask(null)}
          onSubmit={handleCompleteTask}
        />
      )}

      {/* Evidence viewer */}
      {evidenceTask?.completionEvidence && (
        <EvidenceViewer
          evidence={evidenceTask.completionEvidence}
          open={!!evidenceTask}
          onClose={() => setEvidenceTask(null)}
        />
      )}
    </div>
  );
}

/**
 * Cancel Warranty Dialog
 * Dialog để hủy phiếu bảo hành với lý do
 */

import * as React from 'react';
import { toast } from 'sonner';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '../../../../components/ui/alert-dialog';
import { Textarea } from '../../../../components/ui/textarea';
import type { WarrantyTicket, WarrantyHistory } from '../../types';
import { useWarrantyMutations } from '../../hooks/use-warranties';
import { useWarrantyFinder } from '../../hooks/use-all-warranties';
import { asSystemId } from '@/lib/id-types';
import { useAllReceipts } from '../../../receipts/hooks/use-all-receipts';
import { useAllOrders } from '../../../orders/hooks/use-all-orders';
import { usePaymentMutations } from '../../../payments/hooks/use-payments';
import { useReceiptMutations } from '../../../receipts/hooks/use-receipts';
import { useOrderMutations } from '../../../orders/hooks/use-order-mutations';
import { useAuth } from '../../../../contexts/auth-context';
import { toISODateTime, getCurrentDate } from '../../../../lib/date-utils';

interface WarrantyCancelDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  ticket: WarrantyTicket | null;
  onCancelled?: (ticket: WarrantyTicket) => void;
}

export function WarrantyCancelDialog({ open, onOpenChange, ticket, onCancelled }: WarrantyCancelDialogProps) {
  const [cancelReason, setCancelReason] = React.useState('');
  const { user: currentUser } = useAuth();
  const { update: updateWarranty } = useWarrantyMutations({
    onUpdateSuccess: () => toast.success('Đã hủy phiếu bảo hành'),
    onError: (err) => toast.error(err.message)
  });
  const { update: updatePayment } = usePaymentMutations();
  const { update: updateReceipt } = useReceiptMutations();
  const { update: updateOrder } = useOrderMutations();
  const { findById } = useWarrantyFinder();
  const { data: allPayments = [] } = useAllReceipts();
  const { data: receipts = [] } = useAllReceipts();
  const { data: orders = [] } = useAllOrders();

  const handleCancel = React.useCallback(async () => {
    
    if (!currentUser) {
      toast.error('Vui lòng đăng nhập');
      return;
    }

    if (!ticket || !cancelReason.trim()) {
      toast.error('Vui lòng nhập lý do hủy phiếu');
      return;
    }

    try {
      const timestamp = toISODateTime(getCurrentDate());
      // ✅ ROLLBACK KHO khi hủy - Phân biệt theo trạng thái
      const { rollbackWarrantyStock, uncommitWarrantyStock } = await import('../../store/stock-management');
      
      // Check nếu đã xuất kho (completed hoặc returned sau khi completed)
      const hasDeductedStock = ticket.stockDeducted || ticket.status === 'completed';
      
      if (hasDeductedStock) {
        // Đã xuất kho → Hoàn hàng về kho
        (rollbackWarrantyStock as any)(ticket, ticket.systemId);
      } else if (ticket.status === 'pending' || ticket.status === 'processed') {
        // Chưa xuất kho, chỉ uncommit (giải phóng hàng giữ chỗ)
        (uncommitWarrantyStock as any)(ticket, ticket.systemId);
      } else if (ticket.status === 'returned') {
        // Đã trả hàng nhưng chưa kết thúc → vẫn đang giữ hàng thay thế
        (uncommitWarrantyStock as any)(ticket, ticket.systemId);
      }
      // incomplete: không làm gì cả (chưa commit)
      
      // CANCEL ALL PAYMENT & RECEIPT VOUCHERS linked to this warranty
      const relatedPayments = allPayments.filter(p => 
        p.linkedWarrantySystemId === ticket.systemId && 
        p.status !== 'cancelled'
      );
      const relatedReceipts = receipts.filter(r => 
        r.linkedWarrantySystemId === ticket.systemId && 
        r.status !== 'cancelled'
      );
      
      
      const allVouchers = [...relatedPayments, ...relatedReceipts];
      
      if (allVouchers.length > 0) {
        const cancelledCount = { payments: 0, receipts: 0 };
        
        // Soft delete payments - update status to 'cancelled' + save cancelReason in description
        relatedPayments.forEach(payment => {
          const newDescription = `[HỦY] ${cancelReason}${payment.description ? ` | Gốc: ${payment.description}` : ''}`;
          
          (updatePayment as any).mutate({
            systemId: payment.systemId,
            status: 'cancelled',
            cancelledAt: timestamp,
            description: newDescription,
          });
          cancelledCount.payments++;
          
          // ✅ UPDATE ORDER: Remove payment from order.payments and decrease paidAmount
          if (payment.linkedOrderSystemId) {
            const order = orders.find(o => o.systemId === payment.linkedOrderSystemId);
            if (order) {
              // Remove this payment from order.payments array
              const updatedPayments = order.payments.filter(p => p.systemId !== payment.systemId);
              
              // Decrease paidAmount (payment.amount is negative, so we subtract it back)
              const newPaidAmount = (order.paidAmount || 0) - Math.abs(payment.amount);
              
              
              updateOrder.mutate({
                id: payment.linkedOrderSystemId,
                payments: updatedPayments,
                paidAmount: Math.max(0, newPaidAmount), // Ensure not negative
              });
            }
          }
        });
        
        // Soft delete receipts - update status to 'cancelled' + save cancelReason in description
        relatedReceipts.forEach(receipt => {
          updateReceipt.mutate({
            systemId: receipt.systemId,
            data: {
              ...receipt,
              status: 'cancelled',
              cancelledAt: timestamp,
              description: `[HỦY] ${cancelReason}${receipt.description ? ` | Gốc: ${receipt.description}` : ''}`,
            }
          });
          cancelledCount.receipts++;
        });
        
        const voucherList = allVouchers.map(v => `${v.id} (${v.amount.toLocaleString('vi-VN')}đ)`).join(', ');
        
        toast.warning(`Đã hủy ${cancelledCount.payments} phiếu chi và ${cancelledCount.receipts} phiếu thu`, {
          description: voucherList,
          duration: 5000
        });
        
        const addHistory = (_systemId: string, _action: string, _user: string, _note?: string) => {};
        addHistory(
          ticket.systemId,
          `🗑️ Hủy ${allVouchers.length} phiếu thu/chi (${cancelledCount.payments} phiếu chi, ${cancelledCount.receipts} phiếu thu)`,
          currentUser.name ?? 'Unknown',
          `Danh sách: ${voucherList}`
        );
      }
      
      // Update warranty ticket status to 'cancelled'
      const latestTicket = findById(ticket.systemId);
      if (!latestTicket) {
        toast.error('Không tìm thấy phiếu');
        return;
      }

      const newHistory: WarrantyHistory = {
        systemId: asSystemId(`history_${Date.now()}`),
        action: 'Hủy phiếu bảo hành',
        actionLabel: 'Đã hủy phiếu',
        entityType: 'status',
        performedBy: currentUser.name ?? 'Unknown',
        performedAt: timestamp,
        note: `Lý do: ${cancelReason}`,
      };

      const updatedTicket: WarrantyTicket = {
        ...latestTicket,
        status: 'cancelled',
        cancelledAt: timestamp,
        cancelReason,
        linkedOrderSystemId: undefined,
        stockDeducted: false,
        history: [...latestTicket.history, newHistory],
      };

      (updateWarranty as any).mutate({ systemId: ticket.systemId, data: updatedTicket });
      onCancelled?.(updatedTicket);
      
      onOpenChange(false);
      setCancelReason('');
      toast.success('Đã hủy phiếu bảo hành');
    } catch (error) {
      console.error('Failed to cancel ticket:', error);
      toast.error('Không thể hủy phiếu');
    }
  }, [ticket, cancelReason, updateWarranty, currentUser, findById, onOpenChange, orders, onCancelled]);

  return (
    <AlertDialog open={open} onOpenChange={onOpenChange}>
      <AlertDialogContent>
        <AlertDialogHeader>
          <AlertDialogTitle>Xác nhận hủy phiếu bảo hành</AlertDialogTitle>
          <AlertDialogDescription>
            Bạn có chắc chắn muốn hủy phiếu bảo hành này? Vui lòng nhập lý do hủy.
          </AlertDialogDescription>
        </AlertDialogHeader>
        <Textarea
          value={cancelReason}
          onChange={(e) => setCancelReason(e.target.value)}
          placeholder="Nhập lý do hủy phiếu (bắt buộc)..."
          className="min-h-[100px]"
        />
        <AlertDialogFooter>
          <AlertDialogCancel onClick={() => setCancelReason('')}>Hủy</AlertDialogCancel>
          <AlertDialogAction
            onClick={handleCancel}
            className="bg-destructive hover:bg-destructive/90"
          >
            Hủy phiếu
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

/**
 * Reopen From Cancelled Dialog
 * Dialog để mở lại phiếu bảo hành từ trạng thái đã hủy
 */

import * as React from 'react';
import { toast } from 'sonner';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '../../../../components/ui/alert-dialog';
import { Textarea } from '../../../../components/ui/textarea';
import type { WarrantyTicket, WarrantyHistory } from '../../types';
import { useWarrantyMutations } from '../../hooks/use-warranties';
import { useWarrantyFinder } from '../../hooks/use-all-warranties';
import { useProducts } from '../../../products/hooks/use-products';
import { useProductMutations } from '../../../products/hooks/use-products';
import { useAuth } from '../../../../contexts/auth-context';
import { toISODateTime, getCurrentDate } from '../../../../lib/date-utils';
import { asSystemId, type SystemId } from '../../../../lib/id-types';
import { getMaxSystemIdCounter } from '../../../../lib/id-utils';

interface WarrantyReopenFromCancelledDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  ticket: WarrantyTicket | null;
}

const HISTORY_ID_PREFIX = 'WARRANTYHISTORY';

const generateHistorySystemId = (historyEntries: WarrantyHistory[] = []): SystemId => {
  const latestCounter = getMaxSystemIdCounter(historyEntries, HISTORY_ID_PREFIX);
  return asSystemId(`${HISTORY_ID_PREFIX}${String(latestCounter + 1).padStart(6, '0')}`);
};

export function WarrantyReopenFromCancelledDialog({ open, onOpenChange, ticket }: WarrantyReopenFromCancelledDialogProps) {
  const [reopenReason, setReopenReason] = React.useState('');
  const { user, employee } = useAuth();
  const performerName = employee?.fullName ?? user?.name ?? 'Hệ thống';
  const performerSystemId = employee?.systemId ?? user?.employeeId;
  const { update } = useWarrantyMutations({
    onUpdateSuccess: () => toast.success('Đã mở lại phiếu bảo hành'),
    onError: (err) => toast.error(err.message)
  });
  const { update: updateProduct } = useProductMutations();
  const { findById } = useWarrantyFinder();
  const { data: productsData } = useProducts({ limit: 1000 });
  const products = productsData?.data ?? [];

  const handleReopen = React.useCallback(() => {
    if (!ticket || !reopenReason.trim()) {
      toast.error('Vui lòng nhập lý do mở lại phiếu');
      return;
    }

    try {
      // ✅ RE-COMMIT STOCK: Commit stock again when reopening from cancelled
      const replacedProducts = ticket.products.filter(p => p.resolution === 'replace');
      
      if (replacedProducts.length > 0) {
        replacedProducts.forEach(warrantyProduct => {
          const fallbackProduct = warrantyProduct.productSystemId
            ? products.find(p => p.systemId === warrantyProduct.productSystemId)
            : warrantyProduct.sku
              ? products.find(p => p.id === warrantyProduct.sku)
              : undefined;

          const productSystemId = warrantyProduct.productSystemId ?? fallbackProduct?.systemId;

          if (!productSystemId) {
            return;
          }

          const product = products.find(p => p.systemId === productSystemId);
          if (!product) return;

          const quantityToCommit = warrantyProduct.quantity || 1;
          const branchInventory = (product as any).inventory?.find((inv: any) => inv.branchSystemId === ticket.branchSystemId);
          
          if (branchInventory) {
            updateProduct.mutate({
              systemId: productSystemId,
              inventory: (product as any).inventory?.map((inv: any) => 
                  inv.branchSystemId === ticket.branchSystemId
                    ? { ...inv, committed: inv.committed + quantityToCommit }
                    : inv
                )
            });
          }
        });
        
        toast.info('Đã giữ hàng cho phiếu bảo hành', {
          description: `${replacedProducts.length} sản phẩm đã được giữ lại trong kho`,
          duration: 3000
        });
      }
      
      // ✅ Add history entry WITH REASON
      const inventoryNote = replacedProducts.length > 0 
        ? ` (Đã giữ lại ${replacedProducts.length} sản phẩm)` 
        : '';
      
      // ✅ Get latest ticket from store to avoid stale history
      const latestTicket = findById(ticket.systemId);
      if (!latestTicket) {
        toast.error('Không tìm thấy phiếu');
        return;
      }
      
      const newHistory: WarrantyHistory = {
        systemId: generateHistorySystemId(latestTicket.history ?? []),
        action: 'Mở lại phiếu từ trạng thái Đã hủy',
        actionLabel: 'Đã mở lại phiếu từ trạng thái Đã hủy',
        entityType: 'status',
        performedBy: performerName,
        performedBySystemId: performerSystemId ? asSystemId(performerSystemId) : undefined,
        performedAt: toISODateTime(getCurrentDate()),
        note: `Lý do mở lại: ${reopenReason}${inventoryNote}`,
      };

      (update as any).mutate({ systemId: ticket.systemId, data: {
        cancelledAt: undefined,
        status: 'pending', // ✅ Reset to pending (ready to process) instead of incomplete
        returnedAt: undefined, // ✅ Clear returnedAt timestamp
        processedAt: undefined, // ✅ Clear processedAt timestamp
        processingStartedAt: undefined, // ✅ Clear processingStartedAt timestamp
        linkedOrderSystemId: undefined, // ✅ Clear order link
        history: [...latestTicket.history, newHistory],
      }});
      
      onOpenChange(false);
      setReopenReason('');
      toast.success('Đã mở lại phiếu bảo hành');
    } catch (error) {
      console.error('Failed to reopen ticket:', error);
      toast.error('Không thể mở lại phiếu');
    }
  }, [ticket, reopenReason, update, performerName, performerSystemId, findById, onOpenChange]);

  return (
    <AlertDialog open={open} onOpenChange={onOpenChange}>
      <AlertDialogContent>
        <AlertDialogHeader>
          <AlertDialogTitle>Xác nhận mở lại phiếu</AlertDialogTitle>
          <AlertDialogDescription>
            Bạn có chắc chắn muốn mở lại phiếu bảo hành này? Vui lòng nhập lý do mở lại.
          </AlertDialogDescription>
        </AlertDialogHeader>
        <Textarea
          value={reopenReason}
          onChange={(e) => setReopenReason(e.target.value)}
          placeholder="Nhập lý do mở lại phiếu (bắt buộc)..."
          className="min-h-[100px]"
        />
        <AlertDialogFooter>
          <AlertDialogCancel onClick={() => setReopenReason('')}>Hủy</AlertDialogCancel>
          <AlertDialogAction onClick={handleReopen}>
            Mở lại
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

/**
 * Reopen From Returned Dialog
 * Dialog để mở lại phiếu bảo hành từ trạng thái đã trả/kết thúc
 */

import * as React from 'react';
import { toast } from 'sonner';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '../../../../components/ui/alert-dialog';
import { Textarea } from '../../../../components/ui/textarea';
import type { WarrantyTicket } from '../../types';
import { useWarrantyMutations } from '../../hooks/use-warranties';
import { useAuth } from '../../../../contexts/auth-context';

interface WarrantyReopenFromReturnedDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  ticket: WarrantyTicket | null;
}

export function WarrantyReopenFromReturnedDialog({ open, onOpenChange, ticket }: WarrantyReopenFromReturnedDialogProps) {
  const [reopenReason, setReopenReason] = React.useState('');
  const { user: _currentUser } = useAuth();
  const { update } = useWarrantyMutations({
    onUpdateSuccess: () => toast.success('Đã mở lại phiếu bảo hành'),
    onError: (err) => toast.error(err.message)
  });

  const handleReopen = React.useCallback(() => {
    if (!ticket || !reopenReason.trim()) {
      toast.error('Vui lòng nhập lý do mở lại');
      return;
    }

    try {
      // Determine target status based on current status
      const targetStatus = ticket.status === 'completed' ? 'returned' : 'processed';
      
      // ⚠️ KHÔNG ĐỘNG CHẠM GÌ KHI MỞ LẠI TỪ COMPLETED
      // Lý do:
      // - Kết thúc = Đơn đã xong, hàng đã xuất, tiền đã thanh toán
      // - Mở lại CHỈ để xem lại, không được sửa/thay đổi gì
      // - Nếu muốn điều chỉnh → Phải thao tác thêm (tạo phiếu mới, hoàn hàng thủ công, etc.)
      if (ticket.status === 'completed') {
        // No-op: Completed tickets are reopened for viewing only
      }
      
      // ✅ Pass lý do mở lại vào note parameter
      (update as any).mutate({ systemId: ticket.systemId, data: { status: targetStatus } });
      
      // Clear returnedAt và linkedOrderSystemId only when going back to processed (not from completed)
      if (targetStatus === 'processed') {
        (update as any).mutate({ systemId: ticket.systemId, data: {
          returnedAt: undefined,
          linkedOrderSystemId: undefined,
        }});
      }
      
      onOpenChange(false);
      setReopenReason('');
      toast.success(`Đã mở lại phiếu`, {
        description: ticket.status === 'completed' 
          ? 'Phiếu đã mở lại để xem. Không thay đổi kho hàng hay thanh toán.' 
          : undefined
      });
    } catch (error) {
      console.error('Failed to reopen ticket:', error);
      toast.error('Không thể mở lại phiếu');
    }
  }, [ticket, reopenReason, update, updateStatus, onOpenChange]);

  return (
    <AlertDialog open={open} onOpenChange={onOpenChange}>
      <AlertDialogContent>
        <AlertDialogHeader>
          <AlertDialogTitle>Xác nhận mở lại phiếu đã trả</AlertDialogTitle>
          <AlertDialogDescription>
            Phiếu này đã trả hàng cho khách. Vui lòng nhập lý do cần mở lại.
          </AlertDialogDescription>
        </AlertDialogHeader>
        <Textarea
          value={reopenReason}
          onChange={(e) => setReopenReason(e.target.value)}
          placeholder="Nhập lý do mở lại (bắt buộc)..."
          className="min-h-[100px]"
        />
        <AlertDialogFooter>
          <AlertDialogCancel onClick={() => setReopenReason('')}>Hủy</AlertDialogCancel>
          <AlertDialogAction onClick={handleReopen}>
            Mở lại
          </AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

