    productPermanentFiles: Record<string, SimpleImageFile[]>;
    productStagingFiles: Record<string, StagingFile[]>;
    productSessionIds: Record<string, string>;
    productFilesToDelete: Record<string, string[]>;
  }) => void;
}

export function WarrantyProductsSection({ 
  disabled = false, 
  onProductImagesStateChange 
}: WarrantyProductsSectionProps) {
  const { control, setValue, watch } = useFormContext();
  const { fields, append, remove } = useFieldArray({
    control,
    name: 'products',
  });

  // Local UI state
  const [isProductSelectionOpen, setIsProductSelectionOpen] = React.useState(false);
  const [selectedValue, setSelectedValue] = React.useState<ComboboxOption | null>(null);
  const [enableSplitLine, setEnableSplitLine] = React.useState(false);
  const [showSettingsDialog, setShowSettingsDialog] = React.useState(false);
  const [settings, setSettings] = React.useState<ProductsSectionSettings>({
    discountDefaultType: 'value',
    productInsertPosition: 'top',
  });

  // Use extracted hooks
  const {
    productPermanentFiles,
    productStagingFiles,
    productSessionIds,
    productFilesToDelete,
    setProductPermanentFiles,
    handleMarkForDeletion,
    handleStagingFilesChange,
    handleSessionChange,
  } = useProductImagesState();

  // Store data
  const { findById: _findById } = useProductFinder();
  const { data: allProductsData } = useProducts({ limit: 1000 });
  const activeProducts = React.useMemo(() => (allProductsData as any)?.data ?? [], [allProductsData]);
  const { data: allOrders } = useAllOrders();
  
  // Watch customer and products
  const customer = watch('customer');
  const customerName = customer?.name || '';
  const watchedProducts = watch('products');
  const products: WarrantyProductField[] = React.useMemo(() => watchedProducts || [], [watchedProducts]);

  // Use product selection hook
  const { handleSelectProduct, handleSelectProducts } = useProductSelection({
    customerName,
    allOrders: allOrders || [],
    productInsertPosition: settings.productInsertPosition,
    append,
  });

  // Get active products for combobox
  const availableProducts = React.useMemo(() => activeProducts, [activeProducts]);

  const productOptions: ComboboxOption[] = React.useMemo(() => {
    return availableProducts.map((p) => ({
      value: p.systemId,
      label: p.name,
      subtitle: p.id,
      metadata: {
        costPrice: p.costPrice || 0,
      },
    }));
  }, [availableProducts]);

  // ===== LOAD EXISTING PRODUCT IMAGES INTO STATE =====
  React.useEffect(() => {
    const initialFiles = initializePermanentFiles(products);
    if (Object.keys(initialFiles).length > 0) {
      setProductPermanentFiles(prev => {
        // Only update if there are new products with images
        const newProducts = Object.keys(initialFiles).filter(key => !prev[key]);
        if (newProducts.length === 0) return prev;
        return { ...prev, ...initialFiles };
      });
    }
  }, [products, setProductPermanentFiles]);

  // ===== SYNC STATE TO FORM =====
  React.useEffect(() => {
    const updatedProducts = syncFilesToProductImages(products, productPermanentFiles, productStagingFiles);
    if (JSON.stringify(updatedProducts) !== JSON.stringify(products)) {
      setValue('products', updatedProducts, { shouldDirty: false });
    }
  }, [productPermanentFiles, productStagingFiles, products, setValue]);

  // ===== NOTIFY PARENT OF STATE CHANGES =====
  React.useEffect(() => {
    onProductImagesStateChange?.({
      productPermanentFiles,
      productStagingFiles,
      productSessionIds,
      productFilesToDelete,
    });
  }, [productPermanentFiles, productStagingFiles, productSessionIds, productFilesToDelete, onProductImagesStateChange]);

  // ===== AUTO-FILTER MARKED IMAGES =====
  React.useEffect(() => {
    const { updatedProducts, hasChanges } = filterDeletedImagesFromProducts(products, productFilesToDelete);
    if (hasChanges) {
      setValue('products', updatedProducts, { shouldDirty: true });
    }
  }, [productFilesToDelete, products, setValue]);

  // Combobox handler
  const handleComboboxChange = (option: ComboboxOption | null) => {
    if (option) {
      const product = availableProducts.find((p) => p.systemId === option.value);
      if (product) {
        handleSelectProduct(product);
      }
    }
    setSelectedValue(null);
  };

  return (
    <Card className="flex flex-col">
      <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-4">
        <CardTitle className="text-h4">Danh sách sản phẩm bảo hành</CardTitle>

        {/* Toolbar */}
        <div className="flex items-center gap-2">
          <div className="flex items-center gap-2">
            <Switch
              id="split-line"
              checked={enableSplitLine}
              onCheckedChange={setEnableSplitLine}
              disabled={disabled}
            />
            <Label htmlFor="split-line" className="text-body-sm font-normal cursor-pointer">
              Tách dòng
            </Label>
          </div>

          <Button
            type="button"
            variant="ghost"
            size="icon"
            onClick={() => setShowSettingsDialog(true)}
            disabled={disabled}
            title="Tùy chỉnh hiển thị"
          >
            <Settings className="h-4 w-4" />
          </Button>
        </div>
      </CardHeader>

      <CardContent className="space-y-6">
        {/* Product search */}
        <div className="flex items-center gap-2">
          <div className="flex-1">
            <VirtualizedCombobox
              options={productOptions}
              value={selectedValue}
              onChange={handleComboboxChange}
              placeholder="Thêm sản phẩm (F3)"
              searchPlaceholder="Tìm kiếm theo tên, mã SKU..."
              disabled={disabled}
            />
          </div>
          <Button
            type="button"
            variant="outline"
            onClick={() => setIsProductSelectionOpen(true)}
            disabled={disabled}
          >
            Chọn nhanh
          </Button>
        </div>

        {/* Products table */}
        {fields.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-12 text-center border-2 border-dashed rounded-lg">
            <PackageOpen className="h-12 w-12 text-muted-foreground mb-4" />
            <p className="text-body-sm text-muted-foreground">Chưa có sản phẩm nào</p>
            <p className="text-body-xs text-muted-foreground mt-1">
              Sử dụng ô tìm kiếm bên trên để thêm sản phẩm
            </p>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="border rounded-lg overflow-auto">
              <Table className="table-fixed w-full">
                <TableHeader>
                  <TableRow>
                    <TableHead className="w-[40px]">STT</TableHead>
                    <TableHead className="w-[220px]">Tên sản phẩm</TableHead>
                    <TableHead className="w-[90px]">Số lượng</TableHead>
                    <TableHead className="w-[160px]">Đơn giá</TableHead>
                    <TableHead className="w-[280px]">Hình ảnh</TableHead>
                    <TableHead className="w-[110px]">Kết quả</TableHead>
                    <TableHead className="w-[280px]">Ghi chú</TableHead>
                    <TableHead className="w-[130px] text-right">Thành tiền</TableHead>
                    <TableHead className="w-[40px]"></TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {fields.map((field, index) => {
                    const typedField = field as unknown as WarrantyProductField;
                    const productSystemId = typedField.systemId || '';
                    
                    return (
                      <WarrantyProductRow
                        key={field.id}
                        index={index}
                        field={typedField}
                        control={control}
                        availableProducts={availableProducts.map(p => ({
                          systemId: p.systemId,
                          id: p.id,
                          name: p.name,
                          costPrice: p.costPrice,
                          warrantyPeriodMonths: p.warrantyPeriodMonths,
                        }))}
                        disabled={disabled}
                        permanentFiles={productPermanentFiles[productSystemId] || []}
                        stagingFiles={productStagingFiles[productSystemId] || []}
                        sessionId={productSessionIds[productSystemId]}
                        filesToDelete={productFilesToDelete[productSystemId] || []}
                        onMarkForDeletion={(fileId) => handleMarkForDeletion(productSystemId, fileId)}
                        onStagingFilesChange={(files) => handleStagingFilesChange(productSystemId, files)}
                        onSessionChange={(sessionId) => handleSessionChange(productSystemId, sessionId)}
                        onRemove={() => remove(index)}
                      />
                    );
                  })}
                </TableBody>
              </Table>
            </div>
          </div>
        )}
      </CardContent>

      {/* Product selection dialog */}
      <ProductSelectionDialog
        isOpen={isProductSelectionOpen}
        onOpenChange={setIsProductSelectionOpen}
        onSelect={handleSelectProducts}
      />

      {/* Settings dialog */}
      <WarrantyProductsSettingsDialog
        open={showSettingsDialog}
        onOpenChange={setShowSettingsDialog}
        settings={settings}
        onSettingsChange={setSettings}
      />
    </Card>
  );
}

/**
 * Hook chứa các handlers sử dụng trong WarrantyListPage
 * Tách từ warranty-list-page.tsx để giảm kích thước file
 */
import React from 'react';
import { useRouter } from 'next/navigation';
import { toast } from 'sonner';
import type { WarrantyTicket } from '../types';
import { useWarranties, useWarrantyMutations } from './use-warranties';
import { asSystemId } from '@/lib/id-types';
import { ROUTES, generatePath } from '@/lib/router';

type CancelWorkflowOptions = {
  bulk?: boolean;
};

export function useWarrantyListHandlers() {
  const router = useRouter();
  const { data: warrantyData } = useWarranties({ limit: 1000 });
  const tickets = warrantyData?.data ?? [];
  const { update: updateMutation } = useWarrantyMutations();

  const handleEdit = React.useCallback(
    (ticket: WarrantyTicket) => {
      router.push(`/warranty/${ticket.systemId}/edit`);
    },
    [router]
  );

  const handleGetLink = React.useCallback((systemId: string) => {
    const ticket = tickets.find(t => t.systemId === asSystemId(systemId));
    if (!ticket) {
      toast.error('Không tìm thấy phiếu bảo hành');
      return;
    }
    const trackingPath = generatePath(ROUTES.INTERNAL.WARRANTY_TRACKING, {
      trackingCode: ticket.publicTrackingCode || ticket.id,
    });
    const trackingUrl = `${window.location.origin}${trackingPath}`;
    navigator.clipboard.writeText(trackingUrl);
    toast.success('Đã copy link tracking vào clipboard');
  }, [tickets]);

  const handleStartProcessing = React.useCallback((systemId: string) => {
    const normalizedId = asSystemId(systemId);
    const ticket = tickets.find(t => t.systemId === normalizedId);
    if (!ticket) {
      toast.error('Không tìm thấy phiếu bảo hành');
      return;
    }

    updateMutation.mutate({ systemId: normalizedId, data: { status: 'pending', statusReason: 'Bắt đầu xử lý từ danh sách' } });
    toast.success('Đã chuyển sang trạng thái Chưa xử lý');
  }, [tickets, updateMutation]);

  const handleMarkProcessed = React.useCallback((systemId: string) => {
    const normalizedId = asSystemId(systemId);
    const ticket = tickets.find(t => t.systemId === normalizedId);
    if (!ticket) {
      toast.error('Không tìm thấy phiếu bảo hành');
      return;
    }

    updateMutation.mutate({ systemId: normalizedId, data: { status: 'processed', statusReason: 'Hoàn thành xử lý từ danh sách' } });
    toast.success('Đã hoàn thành xử lý');
  }, [tickets, updateMutation]);

  const handleMarkReturned = React.useCallback((systemId: string) => {
    router.push(`/warranty/${systemId}`); // Go to detail page to link order
  }, [router]);

  return {
    handleEdit,
    handleGetLink,
    handleStartProcessing,
    handleMarkProcessed,
    handleMarkReturned,
  };
}

export function useWarrantyCancelWorkflow(
  setRowSelection: React.Dispatch<React.SetStateAction<Record<string, boolean>>>
) {
  const { data: warrantyData } = useWarranties({ limit: 1000 });
  const tickets = warrantyData?.data ?? [];
  
  const [cancelDialogOpen, setCancelDialogOpen] = React.useState(false);
  const [cancelQueue, setCancelQueue] = React.useState<WarrantyTicket[]>([]);
  const bulkCancelRef = React.useRef(false);
  const bulkCancelTicketIdsRef = React.useRef<Set<string>>(new Set());
  const bulkCancelPendingRef = React.useRef(0);
  const bulkCancelCompletedRef = React.useRef(0);
  const currentCancelTicket = cancelQueue[0] ?? null;

  const startCancelWorkflow = React.useCallback((ticketsToCancel: WarrantyTicket[], options?: CancelWorkflowOptions) => {
    if (!ticketsToCancel || ticketsToCancel.length === 0) {
      toast.error('Không có phiếu hợp lệ để hủy');
      return;
    }

    const normalized = ticketsToCancel
      .filter((ticket): ticket is WarrantyTicket => Boolean(ticket))
      .filter((ticket, index, self) => self.findIndex((item) => item.systemId === ticket.systemId) === index)
      .filter((ticket) => ticket.status !== 'cancelled' && !ticket.cancelledAt);

    const skipped = ticketsToCancel.length - normalized.length;

    if (normalized.length === 0) {
      toast.info('Các phiếu đã chọn đều đã bị hủy trước đó');
      return;
    }

    if (skipped > 0) {
      toast.info(`${skipped} phiếu đã được bỏ qua vì đã hủy trước đó.`);
    }

    const isBulk = Boolean(options?.bulk);
    if (isBulk && bulkCancelPendingRef.current === 0) {
      bulkCancelCompletedRef.current = 0;
    }

    setCancelQueue(prevQueue => {
      if (prevQueue.length === 0) {
        if (isBulk) {
          normalized.forEach(ticket => bulkCancelTicketIdsRef.current.add(ticket.systemId));
          bulkCancelPendingRef.current += normalized.length;
          bulkCancelRef.current = true;
        }
        return normalized;
      }

      const existingIds = new Set(prevQueue.map(ticket => ticket.systemId));
      const additionalTickets = normalized.filter(ticket => !existingIds.has(ticket.systemId));

      if (additionalTickets.length === 0) {
        toast.info('Các phiếu đã nằm trong hàng chờ hủy');
        return prevQueue;
      }

      if (isBulk) {
        additionalTickets.forEach(ticket => bulkCancelTicketIdsRef.current.add(ticket.systemId));
        bulkCancelPendingRef.current += additionalTickets.length;
        bulkCancelRef.current = true;
      }

      return [...prevQueue, ...additionalTickets];
    });
    setCancelDialogOpen(true);
  }, []);

  const handleCancel = React.useCallback((systemId: string) => {
    const normalizedId = asSystemId(systemId);
    const ticket = tickets.find((t) => t.systemId === normalizedId);
    if (!ticket) {
      toast.error('Không tìm thấy phiếu bảo hành');
      return;
    }
    startCancelWorkflow([ticket]);
  }, [tickets, startCancelWorkflow]);

  const handleCancelSuccess = React.useCallback((ticket: WarrantyTicket) => {
    let queueBecameEmpty = false;

    setCancelQueue(prevQueue => {
      const [, ...rest] = prevQueue;
      queueBecameEmpty = rest.length === 0;
      return rest;
    });

    if (queueBecameEmpty) {
      setCancelDialogOpen(false);
    }

    if (bulkCancelTicketIdsRef.current.has(ticket.systemId)) {
      bulkCancelTicketIdsRef.current.delete(ticket.systemId);
      bulkCancelPendingRef.current = Math.max(0, bulkCancelPendingRef.current - 1);
      bulkCancelCompletedRef.current += 1;
    }

    if (bulkCancelRef.current && bulkCancelPendingRef.current === 0) {
      const completed = bulkCancelCompletedRef.current || 0;
      toast.success(`Đã hủy ${completed} phiếu bảo hành`);
      setRowSelection({});
      bulkCancelRef.current = false;
      bulkCancelPendingRef.current = 0;
      bulkCancelCompletedRef.current = 0;
      bulkCancelTicketIdsRef.current.clear();
    }

    if (queueBecameEmpty && !bulkCancelRef.current) {
      bulkCancelTicketIdsRef.current.clear();
    }
  }, [setRowSelection]);

  const handleCancelDialogOpenChange = React.useCallback((open: boolean) => {
    setCancelDialogOpen(open);
    if (!open) {
      setCancelQueue([]);
      bulkCancelTicketIdsRef.current.clear();
      bulkCancelPendingRef.current = 0;
      bulkCancelCompletedRef.current = 0;
      bulkCancelRef.current = false;
    }
  }, []);

  return {
    cancelDialogOpen,
    currentCancelTicket,
    startCancelWorkflow,
    handleCancel,
    handleCancelSuccess,
    handleCancelDialogOpenChange,
  };
}

export function useWarrantyBulkActions(
  selectedTickets: WarrantyTicket[],
  setRowSelection: React.Dispatch<React.SetStateAction<Record<string, boolean>>>,
  startCancelWorkflow: (tickets: WarrantyTicket[], options?: CancelWorkflowOptions) => void
) {
  const handleBulkGetTrackingLink = React.useCallback(() => {
    if (selectedTickets.length === 0) {
      toast.error('Vui lòng chọn ít nhất một phiếu');
      return;
    }

    try {
      const trackingLinks = selectedTickets.map(ticket => {
        const publicCode = ticket.publicTrackingCode || ticket.id;
        const trackingPath = generatePath(ROUTES.INTERNAL.WARRANTY_TRACKING, { trackingCode: publicCode });
        const trackingUrl = `${window.location.origin}${trackingPath}`;
        return `${publicCode}: ${trackingUrl}`;
      });
      
      navigator.clipboard.writeText(trackingLinks.join('\n'));
      toast.success(`Đã copy ${selectedTickets.length} link tracking vào clipboard`);
    } catch (_error) {
      toast.error('Không thể copy link tracking');
    }
  }, [selectedTickets]);

  const handleBulkCancel = React.useCallback(() => {
    if (selectedTickets.length === 0) {
      toast.error('Vui lòng chọn ít nhất một phiếu');
      return;
    }
    startCancelWorkflow([...selectedTickets], { bulk: true });
  }, [selectedTickets, startCancelWorkflow]);

  return {
    handleBulkGetTrackingLink,
    handleBulkCancel,
  };
}

/**
 * Warranty Reminders Hook
 * Auto-scheduling and reminder management for warranty tickets
 * Pattern copied from Complaints system
 */

import { useState, useCallback } from 'react';
import { updateWarranty } from '../api/warranties-api';
import type { WarrantyTicket } from '../types';
import { notifyWarrantyReminder } from '../notification-utils';
import { useWarrantyReminderTemplates, DEFAULT_WARRANTY_REMINDER_TEMPLATES } from '../../../hooks/use-reminder-settings';

export interface ReminderTemplate {
  id: string;
  name: string;
  message: string;
  isDefault?: boolean;
}

// Re-export default templates for backward compatibility
export const DEFAULT_REMINDER_TEMPLATES = DEFAULT_WARRANTY_REMINDER_TEMPLATES;

export interface WarrantyReminder {
  id: string;
  ticketSystemId: string;
  ticketId: string;
  templateId: string;
  message: string;
  assignedTo: string; // Employee ID
  createdBy: string;
  createdAt: Date;
  status: 'pending' | 'sent' | 'dismissed';
  scheduledFor?: Date;
}

/**
 * Load reminder templates from hook (deprecated - use useWarrantyReminderTemplates directly)
 * @deprecated Use useWarrantyReminderTemplates hook instead
 */
export function loadReminderTemplates(): ReminderTemplate[] {
  // Returns default templates for backward compatibility
  // New code should use useWarrantyReminderTemplates hook
  return DEFAULT_REMINDER_TEMPLATES;
}

/**
 * Save custom reminder templates (deprecated - use useWarrantyReminderTemplates hook)
 * @deprecated Use useWarrantyReminderTemplates hook instead
 */
export function saveReminderTemplates(_templates: ReminderTemplate[]): void {
}

/**
 * Format reminder message with ticket data
 */
export function formatReminderMessage(template: string, ticket: WarrantyTicket): string {
  return template
    .replace(/{ticketId}/g, ticket.id)
    .replace(/{customerName}/g, ticket.customerName)
    .replace(/{customerPhone}/g, ticket.customerPhone)
    .replace(/{trackingCode}/g, ticket.trackingCode || 'N/A');
}

/**
 * Hook for warranty reminders management
 */
export function useWarrantyReminders() {
  const [isReminderModalOpen, setIsReminderModalOpen] = useState(false);
  const [selectedTicket, setSelectedTicket] = useState<WarrantyTicket | null>(null);
  const [templates] = useWarrantyReminderTemplates();

  /**
   * Open reminder modal for a ticket
   */
  const openReminderModal = useCallback((ticket: WarrantyTicket) => {
    setSelectedTicket(ticket);
    setIsReminderModalOpen(true);
  }, []);

  /**
   * Close reminder modal
   */
  const closeReminderModal = useCallback(() => {
    setIsReminderModalOpen(false);
    setSelectedTicket(null);
  }, []);

  /**
   * Send reminder for a ticket
   */
  const sendReminder = useCallback(async (
    ticket: WarrantyTicket,
    templateId: string,
    customMessage?: string,
    assignedTo?: string,
  ): Promise<boolean> => {
    try {
      const template = templates.find(t => t.id === templateId);
      if (!template) {
        throw new Error('Template not found');
      }

      const message = customMessage || formatReminderMessage(template.message, ticket);

      const _reminder: WarrantyReminder = {
        id: `reminder_${Date.now()}`,
        ticketSystemId: ticket.systemId,
        ticketId: ticket.id,
        templateId,
        message,
        assignedTo: assignedTo || ticket.employeeSystemId || 'unassigned',
        createdBy: 'current_user', // TODO: Get from auth context
        createdAt: new Date(),
        status: 'sent',
      };

      // Store reminder via API update
      await updateWarranty(ticket.systemId, {
        history: [
          ...(ticket.history || []),
          {
            systemId: `WH_${Date.now()}_${Math.random().toString(36).substr(2, 9)}` as any,
            action: 'reminder_sent',
            actionLabel: 'Gửi nhắc nhở',
            performedBy: 'current_user',
            performedAt: new Date().toISOString(),
            note: message,
          }
        ]
      });

      // Send notification
      notifyWarrantyReminder(ticket.id, message);

      return true;
    } catch (error) {
      console.error('Failed to send reminder:', error);
      return false;
    }
  }, [templates]);

  /**
   * Schedule automatic reminder for overdue tickets
   */
  const scheduleAutoReminder = useCallback((_ticket: WarrantyTicket): void => {
    // This would be called by a background job
    // For now, it's a placeholder for future implementation
  }, []);

  /**
   * Get pending reminders for a ticket
   */
  const getTicketReminders = useCallback((_ticketSystemId: string): WarrantyReminder[] => {
    // TODO: Load from store or API
    return [];
  }, []);

  /**
   * Dismiss a reminder
   */
  const dismissReminder = useCallback((_reminderId: string): void => {
    // TODO: Update reminder status
  }, []);

  return {
    // Modal state
    isReminderModalOpen,
    openReminderModal,
    closeReminderModal,
    selectedTicket,

    // Templates
    templates,

    // Actions
    sendReminder,
    scheduleAutoReminder,
    getTicketReminders,
    dismissReminder,

    // Utils
    formatReminderMessage,
  };
}

