// ========================================
// Types
// ========================================

type ApiResponse<T> = {
  success: boolean;
  data?: T;
  error?: string;
};

type CreateProductResponse = {
  error: boolean;
  message: string;
  goods_id: number;
  created_slug: string;
};

type UpdateProductResponse = {
  error: boolean;
  message: string;
  goods_id: number;
  updated_slug?: string;
};

// ========================================
// Helper Functions
// ========================================

function getApiConfig(settings?: PkgxSettings) {
  return {
    apiUrl: settings?.apiUrl || PKGX_API_CONFIG.baseUrl,
    apiKey: settings?.apiKey || '',
    enabled: settings?.enabled || false,
  };
}

async function fetchWithAuth<T>(settings: PkgxSettings, url: string, options: RequestInit = {}): Promise<ApiResponse<T>> {
  const { apiKey, enabled } = getApiConfig(settings);

  if (!enabled) {
    return { success: false, error: 'Tích hợp PKGX chưa được bật' };
  }

  if (!apiKey) {
    return { success: false, error: 'Chưa cấu hình API Key' };
  }

  // DEBUG: Log request details
  if (options.body) {
    // Debug: console.log('Request body:', options.body);
  }

  try {
    const fetchOptions: RequestInit = {
      ...options,
      mode: 'cors',
      credentials: 'omit',
      headers: {
        'X-API-KEY': apiKey,
        'Content-Type': 'application/json',
        ...options.headers,
      },
    };
    
    const response = await fetch(url, fetchOptions);

    const responseText = await response.text();
    
    const data = JSON.parse(responseText);
    
    // DEBUG: Log response

    if (data.error) {
      return { success: false, error: data.message || 'Lỗi từ server PKGX' };
    }

    return { success: true, data };
  } catch (error) {
    return {
      success: false,
      error: error instanceof Error ? error.message : 'Không thể kết nối đến server PKGX',
    };
  }
}

