  settings: PkgxSettings = {} as any
): Promise<ApiResponse<{ error: boolean; message: string; cat_id: number; changes?: Record<string, { old: unknown; new: unknown }> }>> {
  const { apiUrl } = getApiConfig(settings);
  const timestamp = Date.now();
